CREATE OR REPLACE FUNCTION "audit"."fn_assert_webhook_signing_state"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
DECLARE
  v_secret text := current_setting('app.webhook_signing_secret', true);
  v_strict boolean := COALESCE(lower(current_setting('app.webhook_strict_signing', true)) = 'true', false);
  v_blocked int := 0;
BEGIN
  IF v_strict AND (v_secret IS NULL OR length(v_secret) = 0) THEN
    UPDATE audit.webhook_outbox
    SET last_error = 'strict_signing_no_secret',
        next_attempt_at = now() + interval '5 minutes'
    WHERE delivered_at IS NULL
      AND dead_lettered_at IS NULL
      AND next_attempt_at <= now();
    GET DIAGNOSTICS v_blocked = ROW_COUNT;
    RAISE WARNING 'Webhook strict signing is ON but secret is unset. % outbox rows deferred.', v_blocked;
  END IF;

  RETURN jsonb_build_object(
    'strict_mode', v_strict,
    'secret_set', v_secret IS NOT NULL AND length(v_secret) > 0,
    'blocked_rows', v_blocked
  );
END;
$$;


ALTER FUNCTION "audit"."fn_assert_webhook_signing_state"() OWNER TO "postgres";


COMMENT ON FUNCTION "audit"."fn_assert_webhook_signing_state"() IS 'Phase P. Called at the top of fn_dispatch_webhook_outbox. When strict signing is ON and the secret is unset, defers all eligible rows by 5 minutes and tags them with last_error=strict_signing_no_secret. Returns a jsonb summary.';



CREATE OR REPLACE FUNCTION "audit"."fn_chain_verify"("p_lenser_id" "uuid", "p_chain_kind" "text" DEFAULT 'gateway'::"text") RETURNS TABLE("ok" boolean, "total_rows" bigint, "first_break_id" "uuid", "first_break_seq" bigint, "reason" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'lensers', 'public', 'extensions'
    AS $$
DECLARE
  v_row             audit.hash_chains%ROWTYPE;
  v_event           audit.events%ROWTYPE;
  v_prev_hash       TEXT;
  v_canonical       TEXT;
  v_expected_hash   TEXT;
  v_total           BIGINT := 0;
  v_break_id        UUID;
  v_break_seq       BIGINT;
  v_break_reason    TEXT;
  v_caller_role     TEXT := COALESCE(auth.role(), current_user);
  v_caller_owns     BOOLEAN := false;
BEGIN
  IF p_chain_kind NOT IN ('gateway') THEN
    RAISE EXCEPTION 'unsupported_chain_kind';
  END IF;

  IF p_lenser_id IS NULL THEN
    RAISE EXCEPTION 'lenser_required' USING ERRCODE = '22023';
  END IF;

  IF v_caller_role <> 'service_role' THEN
    SELECT EXISTS (
      SELECT 1
      FROM lensers.profiles lp
      WHERE lp.id = p_lenser_id
        AND lp.user_id = auth.uid()
    ) INTO v_caller_owns;

    IF NOT COALESCE(v_caller_owns, false) THEN
      RAISE EXCEPTION 'chain_verify_owner_required' USING ERRCODE = '42501';
    END IF;
  END IF;

  v_prev_hash := NULL;
  FOR v_row IN
    SELECT *
    FROM audit.hash_chains
    WHERE chain_kind = p_chain_kind
      AND subject_lenser_id = p_lenser_id
    ORDER BY sub_sequence_no ASC
  LOOP
    v_total := v_total + 1;
    SELECT * INTO v_event FROM audit.events WHERE id = v_row.event_id;
    IF v_event.id IS NULL THEN
      v_break_id := v_row.id;
      v_break_seq := v_row.sub_sequence_no;
      v_break_reason := 'event_missing';
      EXIT;
    END IF;

    v_canonical := jsonb_strip_nulls(jsonb_build_object(
      'event_id',   v_event.id,
      'event_type', v_event.event_type,
      'lenser_id',  v_row.subject_lenser_id,
      'device_id',  v_row.subject_device_id,
      'payload',    v_event.payload,
      'sub_seq',    v_row.sub_sequence_no
    ))::text;

    v_expected_hash := encode(
      extensions.digest(COALESCE(v_prev_hash, '') || v_canonical, 'sha256'),
      'hex'
    );

    IF v_expected_hash IS DISTINCT FROM v_row.payload_hash THEN
      v_break_id := v_row.id;
      v_break_seq := v_row.sub_sequence_no;
      v_break_reason := 'payload_hash_mismatch';
      EXIT;
    END IF;
    IF COALESCE(v_row.prev_hash, '') IS DISTINCT FROM COALESCE(v_prev_hash, '') THEN
      v_break_id := v_row.id;
      v_break_seq := v_row.sub_sequence_no;
      v_break_reason := 'prev_hash_mismatch';
      EXIT;
    END IF;

    v_prev_hash := v_row.payload_hash;
  END LOOP;

  IF v_break_id IS NULL THEN
    RETURN QUERY SELECT true, v_total, NULL::UUID, NULL::BIGINT, NULL::TEXT;
  ELSE
    RETURN QUERY SELECT false, v_total, v_break_id, v_break_seq, v_break_reason;
  END IF;
END;
$$;


ALTER FUNCTION "audit"."fn_chain_verify"("p_lenser_id" "uuid", "p_chain_kind" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "audit"."fn_chain_verify"("p_lenser_id" "uuid", "p_chain_kind" "text") IS 'Walk a caller-owned gateway hash chain and verify every link. service_role may verify any chain; authenticated users may verify only their own Lenser chain.';



CREATE OR REPLACE FUNCTION "audit"."fn_cron_dispatch_webhook_outbox"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
DECLARE
  v_state jsonb;
  v_dispatched int;
BEGIN
  v_state := audit.fn_assert_webhook_signing_state();
  IF (v_state->>'strict_mode')::boolean AND NOT (v_state->>'secret_set')::boolean THEN
    RETURN 0;
  END IF;
  SELECT audit.fn_dispatch_webhook_outbox(50) INTO v_dispatched;
  RETURN v_dispatched;
END;
$$;


ALTER FUNCTION "audit"."fn_cron_dispatch_webhook_outbox"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "audit"."fn_dispatch_webhook_outbox"("p_batch" integer DEFAULT 50) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'extensions', 'public'
    AS $$
DECLARE
  r              record;
  v_secret       text;
  v_signature    text;
  v_body_text    text;
  v_processed    int := 0;
  v_new_attempts int;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'pg_net') THEN
    RAISE NOTICE 'fn_dispatch_webhook_outbox: pg_net not installed; skipping.';
    RETURN 0;
  END IF;

  v_secret := NULLIF(current_setting('app.webhook_signing_secret', true), '');

  FOR r IN
    SELECT id, event_type, payload, target_url, attempts, max_attempts
    FROM   audit.webhook_outbox
    WHERE  delivered_at      IS NULL
      AND  dead_lettered_at  IS NULL
      AND  next_attempt_at   <= now()
    ORDER BY next_attempt_at ASC
    LIMIT  p_batch
    FOR UPDATE SKIP LOCKED
  LOOP
    v_processed := v_processed + 1;

    BEGIN
      v_body_text := r.payload::text;

      IF v_secret IS NULL THEN
        -- No secret configured — emit a placeholder so receivers can detect
        -- mis-configuration rather than silently accept unsigned traffic.
        v_signature := 'unsigned';
      ELSE
        v_signature :=
          'sha256=' ||
          encode(extensions.hmac(v_body_text, v_secret, 'sha256'), 'hex');
      END IF;

      PERFORM net.http_post(
        url     := r.target_url,
        headers := jsonb_build_object(
          'Content-Type',             'application/json',
          'X-Lenserfight-Webhook',    r.event_type,
          'X-Lenserfight-Version',    '1',
          'X-Lenserfight-Signature',  v_signature
        ),
        body    := r.payload,
        timeout_milliseconds := 5000
      );

      UPDATE audit.webhook_outbox
      SET    delivered_at = now(),
             last_error   = NULL
      WHERE  id = r.id;

    EXCEPTION WHEN OTHERS THEN
      v_new_attempts := r.attempts + 1;

      UPDATE audit.webhook_outbox
      SET    attempts        = v_new_attempts,
             last_error      = left(SQLERRM, 1000),
             next_attempt_at = now() + (interval '1 minute' * power(2, v_new_attempts)::int),
             dead_lettered_at = CASE
               WHEN v_new_attempts >= r.max_attempts THEN now()
               ELSE dead_lettered_at
             END
      WHERE  id = r.id;
    END;
  END LOOP;

  RETURN v_processed;
END;
$$;


ALTER FUNCTION "audit"."fn_dispatch_webhook_outbox"("p_batch" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "audit"."fn_dispatch_webhook_outbox"("p_batch" integer) IS 'Phase P3: drains audit.webhook_outbox in batches. Signs body with HMAC-SHA256 using app.webhook_signing_secret (header X-Lenserfight-Signature: sha256=<hex>). On exception increments attempts, schedules exponential backoff (2^attempts minutes), and dead-letters at attempts >= max_attempts. Returns rows processed in the batch.';



CREATE OR REPLACE FUNCTION "audit"."fn_notify_moderation_flagged"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
DECLARE
  v_url     text;
  v_payload jsonb;
BEGIN
  IF NEW.decision_type IS DISTINCT FROM 'flagged' THEN
    RETURN NEW;
  END IF;

  v_url := NULLIF(current_setting('app.moderation_webhook_url', true), '');
  IF v_url IS NULL THEN
    RETURN NEW;
  END IF;

  v_payload := jsonb_build_object(
    'webhook_version',       1,
    'event',                 'moderation_flagged',
    'decision_id',           NEW.id,
    'target_entity_schema',  NEW.target_entity_schema,
    'target_entity_table',   NEW.target_entity_table,
    'target_entity_id',      NEW.target_entity_id,
    'decision_type',         NEW.decision_type,
    'reason',                NEW.reason,
    'is_ai_moderated',       NEW.is_ai_moderated,
    'ai_confidence',         NEW.ai_confidence,
    'moderator_lenser_id',   NEW.moderator_lenser_id,
    'occurred_at',           to_char(NEW.occurred_at AT TIME ZONE 'UTC',
                                     'YYYY-MM-DD"T"HH24:MI:SS"Z"'),
    'battle_id',             CASE
                               WHEN NEW.target_entity_schema = 'battles'
                                AND NEW.target_entity_table  = 'battles'
                               THEN NEW.target_entity_id
                               ELSE NULL
                             END,
    'submission_id',         CASE
                               WHEN NEW.target_entity_schema = 'battles'
                                AND NEW.target_entity_table  IN ('contenders', 'submissions')
                               THEN NEW.target_entity_id
                               ELSE NULL
                             END
  );

  INSERT INTO audit.webhook_outbox (event_type, payload, target_url)
  VALUES ('moderation_flagged', v_payload, v_url);

  RETURN NEW;
END;
$$;


ALTER FUNCTION "audit"."fn_notify_moderation_flagged"() OWNER TO "postgres";


COMMENT ON FUNCTION "audit"."fn_notify_moderation_flagged"() IS 'Phase P3: AFTER INSERT trigger on audit.moderation_decisions. Enqueues a moderation_flagged webhook row in audit.webhook_outbox when decision_type=flagged and app.moderation_webhook_url is set. Delivery is handled by audit.fn_dispatch_webhook_outbox.';



CREATE OR REPLACE FUNCTION "audit"."log_event"("p_event_type" "text", "p_entity_schema" "text" DEFAULT NULL::"text", "p_entity_table" "text" DEFAULT NULL::"text", "p_entity_id" "uuid" DEFAULT NULL::"uuid", "p_actor_lenser_id" "uuid" DEFAULT NULL::"uuid", "p_actor_actor_id" "uuid" DEFAULT NULL::"uuid", "p_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_severity" "text" DEFAULT 'info'::"text", "p_ip_hash" "text" DEFAULT NULL::"text", "p_user_agent_hash" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit'
    AS $$
DECLARE
    v_id uuid;
BEGIN
    INSERT INTO "audit"."events" (
        event_type, entity_schema, entity_table, entity_id,
        actor_lenser_id, actor_actor_id, payload, severity,
        ip_hash, user_agent_hash
    ) VALUES (
        p_event_type, p_entity_schema, p_entity_table, p_entity_id,
        p_actor_lenser_id, p_actor_actor_id, p_payload, p_severity,
        p_ip_hash, p_user_agent_hash
    ) RETURNING id INTO v_id;
    RETURN v_id;
END;
$$;


ALTER FUNCTION "audit"."log_event"("p_event_type" "text", "p_entity_schema" "text", "p_entity_table" "text", "p_entity_id" "uuid", "p_actor_lenser_id" "uuid", "p_actor_actor_id" "uuid", "p_payload" "jsonb", "p_severity" "text", "p_ip_hash" "text", "p_user_agent_hash" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "audit"."log_event"("p_event_type" "text", "p_entity_schema" "text", "p_entity_table" "text", "p_entity_id" "uuid", "p_actor_lenser_id" "uuid", "p_actor_actor_id" "uuid", "p_payload" "jsonb", "p_severity" "text", "p_ip_hash" "text", "p_user_agent_hash" "text") IS 'DEPRECATED (2026-03-25): Use audit.log_event_v2 instead. This 10-parameter overload uses a split actor model (actor_lenser_id + actor_actor_id) that has been superseded by the unified actor model in log_event_v2 (actor_type + actor_id). Will be removed after all call sites migrate. Do not add new call sites.';



CREATE OR REPLACE FUNCTION "audit"."log_event_v2"("p_event_type" "text", "p_actor_type" "text" DEFAULT 'system'::"text", "p_actor_id" "uuid" DEFAULT NULL::"uuid", "p_entity_schema" "text" DEFAULT NULL::"text", "p_entity_table" "text" DEFAULT NULL::"text", "p_entity_id" "uuid" DEFAULT NULL::"uuid", "p_payload" "jsonb" DEFAULT '{}'::"jsonb", "p_severity" "text" DEFAULT 'info'::"text", "p_ip_hash" "text" DEFAULT NULL::"text", "p_user_agent_hash" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
DECLARE
    v_id "uuid";
BEGIN
    IF "p_actor_type" NOT IN ('lenser', 'ai_actor', 'system') THEN
        RAISE EXCEPTION 'Invalid actor_type: %. Must be lenser, ai_actor, or system.', "p_actor_type";
    END IF;

    INSERT INTO "audit"."events" (
        "event_type", "actor_type", "actor_id",
        "entity_schema", "entity_table", "entity_id",
        "payload", "severity", "ip_hash", "user_agent_hash",
        -- also populate old split columns for backward compat
        "actor_lenser_id", "actor_actor_id"
    )
    VALUES (
        "p_event_type", "p_actor_type", "p_actor_id",
        "p_entity_schema", "p_entity_table", "p_entity_id",
        "p_payload", "p_severity", "p_ip_hash", "p_user_agent_hash",
        CASE WHEN "p_actor_type" = 'lenser'   THEN "p_actor_id" ELSE NULL END,
        CASE WHEN "p_actor_type" = 'ai_actor' THEN "p_actor_id" ELSE NULL END
    )
    RETURNING "id" INTO v_id;

    RETURN v_id;
END;
$$;


ALTER FUNCTION "audit"."log_event_v2"("p_event_type" "text", "p_actor_type" "text", "p_actor_id" "uuid", "p_entity_schema" "text", "p_entity_table" "text", "p_entity_id" "uuid", "p_payload" "jsonb", "p_severity" "text", "p_ip_hash" "text", "p_user_agent_hash" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "audit"."log_event_v2"("p_event_type" "text", "p_actor_type" "text", "p_actor_id" "uuid", "p_entity_schema" "text", "p_entity_table" "text", "p_entity_id" "uuid", "p_payload" "jsonb", "p_severity" "text", "p_ip_hash" "text", "p_user_agent_hash" "text") IS 'Preferred audit event insertion. Uses unified actor_type + actor_id. Replaces audit.log_event() which uses split actor_lenser_id/actor_actor_id columns. SECURITY DEFINER — call from triggers or Edge Functions.';



CREATE OR REPLACE FUNCTION "audit"."trg_artifact_visibility_changed_fn"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'execution', 'public'
    AS $$
DECLARE
    v_requester_id uuid;
BEGIN
    IF OLD."visibility" = NEW."visibility" THEN
        RETURN NEW;
    END IF;

    -- Resolve the requester through run → request chain
    SELECT req."requester_lenser_id" INTO v_requester_id
    FROM "execution"."runs" r
    JOIN "execution"."requests" req ON req."id" = r."request_id"
    WHERE r."id" = NEW."run_id";

    INSERT INTO "audit"."events" (
        "event_type",
        "entity_schema",
        "entity_table",
        "entity_id",
        "actor_type",
        "actor_id",
        "payload"
    ) VALUES (
        'artifact.visibility_changed',
        'execution',
        'artifacts',
        NEW."id",
        'lenser',
        v_requester_id,
        jsonb_build_object(
            'run_id', NEW."run_id",
            'old_visibility', OLD."visibility",
            'new_visibility', NEW."visibility"
        )
    );

    RETURN NEW;
END;
$$;


ALTER FUNCTION "audit"."trg_artifact_visibility_changed_fn"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "audit"."trg_backfill_unified_actor"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
BEGIN
  -- If unified columns are already set, nothing to do
  IF NEW.actor_type IS NOT NULL AND NEW.actor_id IS NOT NULL THEN
    RETURN NEW;
  END IF;

  -- Backfill from legacy columns
  IF NEW.actor_type IS NULL AND NEW.actor_lenser_id IS NOT NULL THEN
    NEW.actor_type := 'lenser';
    NEW.actor_id   := NEW.actor_lenser_id;
  ELSIF NEW.actor_type IS NULL AND NEW.actor_actor_id IS NOT NULL THEN
    NEW.actor_type := 'ai_actor';
    NEW.actor_id   := NEW.actor_actor_id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "audit"."trg_backfill_unified_actor"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "audit"."trg_battle_status_audit"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'battles', 'lensers'
    AS $$
DECLARE
    v_event_type text;
BEGIN
    -- Map status transitions to event types
    v_event_type := CASE NEW.status
        WHEN 'open'      THEN 'battle.published'
        WHEN 'voting'    THEN 'battle.voting_opened'
        WHEN 'scoring'   THEN 'battle.scoring_started'
        WHEN 'closed'    THEN 'battle.finalized'
        WHEN 'archived'  THEN 'battle.closed'
        ELSE 'battle.status_changed'
    END;

    IF OLD.status IS DISTINCT FROM NEW.status THEN
        PERFORM audit.log_event(
            v_event_type,
            'battles',
            'battles',
            NEW.id,
            NEW.creator_lenser_id,
            NULL,
            jsonb_build_object(
                'old_status', OLD.status,
                'new_status', NEW.status,
                'title',      NEW.title,
                'slug',       NEW.slug
            ),
            'info'
        );
    END IF;

    RETURN NEW;
END;
$$;


ALTER FUNCTION "audit"."trg_battle_status_audit"() OWNER TO "postgres";


