    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'wallet'
    AS $$
BEGIN
    IF OLD.frozen IS DISTINCT FROM NEW.frozen THEN
        PERFORM "audit"."log_event"(
            CASE WHEN NEW.frozen THEN 'wallet_account_frozen' ELSE 'wallet_account_unfrozen' END,
            'wallet', 'accounts', NEW.id,
            NEW.lenser_id, NULL,
            jsonb_build_object('frozen', NEW.frozen),
            CASE WHEN NEW.frozen THEN 'warn' ELSE 'info' END
        );
    END IF;
    RETURN NEW;
END;
$$;


