CREATE OR REPLACE FUNCTION "battles"."fn_auto_publish_battles"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
DECLARE
  r         RECORD;
  published INT := 0;
BEGIN
  FOR r IN
    SELECT id
    FROM   battles.battles
    WHERE  status       = 'closed'
    AND    auto_publish = TRUE
    FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      PERFORM battles.fn_battles_publish_internal(r.id);
      published := published + 1;
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'fn_auto_publish_battles: battle % failed: %', r.id, SQLERRM;
    END;
  END LOOP;

  RETURN published;
END;
