CREATE OR REPLACE FUNCTION "battles"."fn_auto_start_battles"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
DECLARE
  r          RECORD;
  started    INT := 0;
  cont       RECORD;
BEGIN
  FOR r IN
    SELECT b.id, b.voting_duration_hours
    FROM   battles.battles b
    WHERE  b.status = 'open'
    AND    b.execution_starts_at <= now()
    AND    b.battle_type IN ('ai_vs_ai', 'workflow_battle')
    FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      -- Transition to executing
      UPDATE battles.battles
      SET    status               = 'executing',
             executing_started_at = now()
      WHERE  id = r.id;

      -- Create one job per contender
      FOR cont IN
        SELECT id, slot
        FROM   battles.contenders
        WHERE  battle_id = r.id
        ORDER  BY slot
      LOOP
        INSERT INTO battles.battle_execution_jobs
          (battle_id, contender_id, slot, status)
        VALUES
          (r.id, cont.id, cont.slot, 'queued')
        ON CONFLICT (battle_id, contender_id) DO NOTHING;
      END LOOP;

      -- Audit log
      INSERT INTO audit.events (event_type, payload)
      VALUES ('battle.auto_started', jsonb_build_object('battle_id', r.id));

      started := started + 1;
    EXCEPTION WHEN OTHERS THEN
      -- Per-battle errors must not abort the whole sweep.
      RAISE WARNING 'fn_auto_start_battles: battle % failed: %', r.id, SQLERRM;
    END;
  END LOOP;

  RETURN started;
END;
$$;


ALTER FUNCTION "battles"."fn_auto_start_battles"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_battle_lifecycle_tick"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'agents', 'admin', 'audit', 'public', 'lensers'
    AS $$
DECLARE
  r         RECORD;
  sub       RECORD;
  processed INT := 0;
  daily_cnt INT;
BEGIN
  IF public.fn_kill_switch_active('system', NULL) THEN
    RAISE NOTICE 'fn_battle_lifecycle_tick: system kill switch active — skipping';
    RETURN 0;
  END IF;

  -- 1. draft → open + auto-enrollment
  FOR r IN
    SELECT b.id, b.status, b.battle_type
    FROM   battles.battles b
    JOIN   battles.schedules s ON s.battle_id = b.id
    WHERE  b.status      = 'draft'
    AND    s.open_at    <= now()
    AND    b.deleted_at IS NULL
    FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      CONTINUE WHEN public.fn_kill_switch_active('battle', r.id);

      UPDATE battles.battles
      SET    status = 'open', updated_at = now()
      WHERE  id = r.id;

      INSERT INTO audit.events (event_type, actor_type, severity, payload)
      VALUES ('battle.lifecycle.auto_opened', 'system', 'info',
              jsonb_build_object('battle_id', r.id, 'tick', now()));

      -- Auto-enroll matching subscriptions
      FOR sub IN
        SELECT
          bs.id          AS sub_id,
          bs.agent_id,
          bs.execution_mode,
          bs.workflow_id,
          bs.require_owner_approval,
          bs.max_joins_per_day,
          al.profile_id  AS lenser_id
        FROM   agents.battle_subscriptions bs
        JOIN   agents.ai_lensers al ON al.id = bs.agent_id
        WHERE  bs.active = true
        AND    al.is_active = true
        AND    al.suspended_at IS NULL
        AND    (bs.category IS NULL)  -- TODO: match battle category when field added
      LOOP
        BEGIN
          -- Per-agent kill switch
          CONTINUE WHEN public.fn_kill_switch_active('agent', sub.agent_id);

          -- Daily rate limit
          daily_cnt := public.fn_agent_daily_join_count(sub.agent_id);
          IF daily_cnt >= sub.max_joins_per_day THEN
            INSERT INTO audit.events (event_type, actor_type, severity, payload)
            VALUES ('battle.auto_enroll.rate_limited', 'system', 'info',
                    jsonb_build_object('battle_id', r.id, 'agent_id', sub.agent_id,
                                       'daily_count', daily_cnt, 'max', sub.max_joins_per_day));
            CONTINUE;
          END IF;

          IF sub.require_owner_approval THEN
            -- Create a notification for the owner to approve
            INSERT INTO audit.events (event_type, actor_type, severity, payload)
            VALUES ('battle.auto_enroll.pending_approval', 'system', 'info',
                    jsonb_build_object('battle_id', r.id, 'agent_id', sub.agent_id,
                                       'subscription_id', sub.sub_id));
            CONTINUE;
          END IF;

          -- Auto-join: insert contender if not already registered
          INSERT INTO battles.contenders (battle_id, lenser_id, contender_status)
          SELECT r.id, sub.lenser_id, 'active'
          WHERE NOT EXISTS (
            SELECT 1 FROM battles.contenders
            WHERE battle_id = r.id AND lenser_id = sub.lenser_id
          )
          AND (SELECT count(*) FROM battles.contenders WHERE battle_id = r.id) <
              (SELECT max_contenders FROM battles.battles WHERE id = r.id);

          INSERT INTO audit.events (event_type, actor_type, severity, payload)
          VALUES ('battle.auto_enrolled', 'system', 'info',
                  jsonb_build_object('battle_id', r.id, 'agent_id', sub.agent_id,
                                     'lenser_id', sub.lenser_id));
        EXCEPTION WHEN OTHERS THEN
          RAISE WARNING 'lifecycle_tick.enroll: agent % battle % failed: %', sub.agent_id, r.id, SQLERRM;
        END;
      END LOOP;

      processed := processed + 1;
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'lifecycle_tick.open: battle % failed: %', r.id, SQLERRM;
    END;
  END LOOP;

  -- 2. scoring → closed (auto-judge)
  FOR r IN
    SELECT b.id
    FROM   battles.battles b
    JOIN   battles.schedules s ON s.battle_id = b.id
    WHERE  b.status     = 'scoring'
    AND    s.auto_judge = true
    AND    s.judge_at  <= now()
    AND    b.deleted_at IS NULL
    FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      CONTINUE WHEN public.fn_kill_switch_active('battle', r.id);
      UPDATE battles.battles SET status = 'closed', updated_at = now() WHERE id = r.id;
      INSERT INTO audit.events (event_type, actor_type, severity, payload)
      VALUES ('battle.lifecycle.auto_judged', 'system', 'info',
              jsonb_build_object('battle_id', r.id, 'tick', now()));
      processed := processed + 1;
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'lifecycle_tick.judge: battle % failed: %', r.id, SQLERRM;
    END;
  END LOOP;

  -- 3. closed → published
  FOR r IN
    SELECT b.id
    FROM   battles.battles b
    JOIN   battles.schedules s ON s.battle_id = b.id
    WHERE  b.status        = 'closed'
    AND    s.auto_publish  = true
    AND    s.publish_at   <= now()
    AND    b.deleted_at   IS NULL
    FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      CONTINUE WHEN public.fn_kill_switch_active('battle', r.id);
      UPDATE battles.battles
      SET    status       = 'published',
             published_at = now(),
             updated_at   = now()
      WHERE  id = r.id;
      INSERT INTO audit.events (event_type, actor_type, severity, payload)
      VALUES ('battle.lifecycle.auto_published', 'system', 'info',
              jsonb_build_object('battle_id', r.id, 'tick', now()));
      processed := processed + 1;
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'lifecycle_tick.publish: battle % failed: %', r.id, SQLERRM;
    END;
  END LOOP;

  RETURN processed;
END;
$$;


ALTER FUNCTION "battles"."fn_battle_lifecycle_tick"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_battles_publish_internal"("p_battle_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
DECLARE
  v_battle  battles.battles;
  v_winner  battles.contenders;
  v_ca      battles.contenders;
  v_cb      battles.contenders;
BEGIN
  UPDATE battles.battles
  SET    status       = 'published',
         published_at = now()
  WHERE  id     = p_battle_id
  AND    status = 'closed';

  SELECT * INTO v_battle FROM battles.battles WHERE id = p_battle_id;

  SELECT * INTO v_ca FROM battles.contenders WHERE battle_id = p_battle_id AND slot = 'A' LIMIT 1;
  SELECT * INTO v_cb FROM battles.contenders WHERE battle_id = p_battle_id AND slot = 'B' LIMIT 1;

  IF v_battle.winner_contender_id IS NOT NULL THEN
    SELECT * INTO v_winner FROM battles.contenders WHERE id = v_battle.winner_contender_id;
  END IF;

  -- Fire OG image generation (pg_net, graceful degradation)
  IF EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'pg_net')
     AND current_setting('app.supabase_url', true) IS NOT NULL
  THEN
    PERFORM net.http_post(
      url     := current_setting('app.supabase_url') || '/functions/v1/generate-battle-og-image',
      headers := jsonb_build_object(
        'Content-Type',  'application/json',
        'Authorization', 'Bearer ' || current_setting('app.service_role_key', true)
      ),
      body    := jsonb_build_object(
        'battle_id',          p_battle_id,
        'title',              v_battle.title,
        'winner_name',        COALESCE(v_winner.display_name, null),
        'contender_a_name',   COALESCE(v_ca.display_name, 'Contender A'),
        'contender_b_name',   COALESCE(v_cb.display_name, 'Contender B')
      )
    );
  END IF;

  -- Notify participants
  IF EXISTS (
    SELECT 1 FROM pg_proc
    WHERE  proname = 'fn_notify_battle_result'
    AND    pronamespace = (SELECT oid FROM pg_namespace WHERE nspname = 'public')
  ) THEN
    PERFORM public.fn_notify_battle_result(p_battle_id);
  END IF;

  INSERT INTO audit.events (event_type, payload)
  VALUES ('battle.auto_published', jsonb_build_object('battle_id', p_battle_id));
END;
$$;


ALTER FUNCTION "battles"."fn_battles_publish_internal"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_battles_start_voting_internal"("p_battle_id" "uuid", "p_voting_closes_at" timestamp with time zone) RETURNS "void"
