         voting_opens_at  = now(),
         voting_closes_at = p_voting_closes_at
  WHERE  id     = p_battle_id
  AND    status = 'executing';

  INSERT INTO audit.events (event_type, payload)
  VALUES ('battle.voting_started_internal', jsonb_build_object(
    'battle_id',        p_battle_id,
    'voting_closes_at', p_voting_closes_at
  ));
END;
$$;


