CREATE OR REPLACE FUNCTION "battles"."fn_trg_notify_agent_battle_won"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'agents', 'lensers', 'public'
    AS $$
DECLARE
  v_ai_lenser_id    UUID;
  v_ai_profile_id   UUID;
  v_owner_lenser_id UUID;
BEGIN
  -- Check if the winning contender is an AI lenser
  SELECT cem.ai_lenser_id
  INTO   v_ai_lenser_id
  FROM   battles.contender_entity_map cem
  WHERE  cem.contender_id   = NEW.winner_contender_id
    AND  cem.ai_lenser_id   IS NOT NULL;

  IF NOT FOUND OR v_ai_lenser_id IS NULL THEN
    RETURN NEW;  -- winner is a human contender, handled by fn_notify_battle_result
  END IF;

  -- Resolve the AI's own profile_id
  SELECT al.profile_id INTO v_ai_profile_id
  FROM   agents.ai_lensers al
  WHERE  al.id = v_ai_lenser_id;

  -- Find the human owner
  SELECT o.owner_lenser_id INTO v_owner_lenser_id
  FROM   agents.ownerships o
  WHERE  o.ai_lenser_id = v_ai_lenser_id
    AND  o.role         = 'owner'
    AND  o.revoked_at   IS NULL
  LIMIT  1;

  -- Notify the AI's profile (self-notification)
  IF v_ai_profile_id IS NOT NULL THEN
    PERFORM public.fn_insert_notification(
      v_ai_profile_id,
      'agent_battle_won',
      'You won the battle: ' || NEW.title,
      NULL,
      '/battles/' || NEW.slug || '/result',
      jsonb_build_object(
        'ai_lenser_id',  v_ai_lenser_id,
        'battle_id',     NEW.id,
        'battle_slug',   NEW.slug,
        'battle_title',  NEW.title
      )
    );
  END IF;

  -- Notify the human owner
  IF v_owner_lenser_id IS NOT NULL THEN
    PERFORM public.fn_insert_notification(
      v_owner_lenser_id,
      'agent_battle_won',
      'Your AI agent won the battle: ' || NEW.title,
      NULL,
      '/battles/' || NEW.slug || '/result',
      jsonb_build_object(
        'ai_lenser_id',  v_ai_lenser_id,
        'battle_id',     NEW.id,
        'battle_slug',   NEW.slug,
        'battle_title',  NEW.title
      )
    );
  END IF;

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'fn_trg_notify_agent_battle_won failed for battle %: %', NEW.id, SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "battles"."fn_trg_notify_agent_battle_won"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_trg_notify_battle_comment"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
DECLARE
  v_creator_id  UUID;
  v_battle_slug TEXT;
  v_commenter   lensers.profiles%ROWTYPE;
  v_notif_id    UUID;
BEGIN
  SELECT b.creator_lenser_id, b.slug
  INTO   v_creator_id, v_battle_slug
  FROM   battles.battles b
  WHERE  b.id = NEW.battle_id;

  IF NOT FOUND OR v_creator_id = NEW.lenser_id THEN
    RETURN NEW;
  END IF;

  -- Anti-spam: 5-minute window per battle
  IF NOT public.fn_check_and_upsert_aggregate(
    v_creator_id, NEW.lenser_id, 'battle_comment', NEW.battle_id, '5 minutes'
  ) THEN
    RETURN NEW;
  END IF;

  SELECT * INTO v_commenter FROM lensers.profiles WHERE id = NEW.lenser_id;

  v_notif_id := public.fn_insert_notification(
    v_creator_id,
    'battle_comment',
    COALESCE(v_commenter.display_name, v_commenter.handle) || ' commented on your battle',
    NULL,
    '/battles/' || v_battle_slug,
    jsonb_build_object(
      'commenter_id',           NEW.lenser_id,
      'commenter_handle',       v_commenter.handle,
      'commenter_display_name', v_commenter.display_name,
      'battle_id',              NEW.battle_id,
      'battle_slug',            v_battle_slug,
      'preview',                LEFT(NEW.body, 120)
    ),
    NEW.lenser_id
  );

  IF v_notif_id IS NOT NULL THEN
    UPDATE public.notification_aggregates
    SET    notification_id = v_notif_id
    WHERE  recipient_id      = v_creator_id
      AND  notification_type = 'battle_comment'
      AND  entity_id         = NEW.battle_id
      AND  notification_id   IS NULL
      AND  window_end        > now();
  END IF;

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'fn_trg_notify_battle_comment failed: %', SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "battles"."fn_trg_notify_battle_comment"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_trg_notify_battle_joined"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
DECLARE
  v_battle_id       UUID;
  v_creator_id      UUID;
  v_battle_slug     TEXT;
  v_battle_title    TEXT;
  v_joiner          lensers.profiles%ROWTYPE;
BEGIN
  -- Resolve battle from the contender row
  SELECT c.battle_id, b.creator_lenser_id, b.slug, b.title
  INTO   v_battle_id, v_creator_id, v_battle_slug, v_battle_title
  FROM   battles.contenders c
  JOIN   battles.battles b ON b.id = c.battle_id
  WHERE  c.id = NEW.contender_id;

  IF NOT FOUND OR v_creator_id = NEW.profile_id THEN
    RETURN NEW;  -- battle not found or self-join
  END IF;

  SELECT * INTO v_joiner FROM lensers.profiles WHERE id = NEW.profile_id;

  PERFORM public.fn_insert_notification(
    v_creator_id,
    'battle_joined',
    COALESCE(v_joiner.display_name, v_joiner.handle) || ' joined your battle',
    v_battle_title,
    '/battles/' || v_battle_slug,
    jsonb_build_object(
      'battle_id',           v_battle_id,
      'battle_slug',         v_battle_slug,
      'contender_id',        NEW.contender_id,
      'joiner_id',           NEW.profile_id,
      'joiner_handle',       v_joiner.handle,
      'joiner_display_name', v_joiner.display_name
    ),
    NEW.profile_id  -- p_actor_id for block/mute gate
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'fn_trg_notify_battle_joined failed: %', SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "battles"."fn_trg_notify_battle_joined"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_trg_notify_battle_started"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'agents', 'lensers', 'public'
    AS $$
DECLARE
  v_participant RECORD;
BEGIN
  -- Collect all contender profile_ids: human (cem.profile_id) and AI (ai_lensers.profile_id)
  FOR v_participant IN
    SELECT COALESCE(cem.profile_id, al.profile_id) AS lenser_id
    FROM   battles.contenders c
    JOIN   battles.contender_entity_map cem ON cem.contender_id = c.id
    LEFT   JOIN agents.ai_lensers al ON al.id = cem.ai_lenser_id
    WHERE  c.battle_id = NEW.id
      AND  COALESCE(cem.profile_id, al.profile_id) IS NOT NULL
  LOOP
    PERFORM public.fn_insert_notification(
      v_participant.lenser_id,
      'battle_started',
      'Battle is now open: ' || NEW.title,
      'Submit your entry — voting begins soon.',
      '/battles/' || NEW.slug,
      jsonb_build_object(
        'battle_id',    NEW.id,
        'battle_slug',  NEW.slug,
        'battle_title', NEW.title
      )
      -- p_actor_id = NULL: system event, skip block/mute gate
    );
  END LOOP;

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'fn_trg_notify_battle_started failed for battle %: %', NEW.id, SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "battles"."fn_trg_notify_battle_started"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "battles"."fn_trg_template_battle_status_notify"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public', 'lensers'
    AS $_$
DECLARE
  v_type  TEXT;
  v_title TEXT;
  v_body  TEXT;
BEGIN
  IF NEW.template_id IS NULL THEN
    RETURN NEW;
  END IF;
  IF NEW.status::text NOT IN ('open', 'published') THEN
    RETURN NEW;
  END IF;
  IF OLD.status IS NOT DISTINCT FROM NEW.status THEN
    RETURN NEW;
  END IF;
  IF NEW.creator_lenser_id IS NULL THEN
    RETURN NEW;
  END IF;

  v_type  := 'template_battle_' || NEW.status::text;
  v_title := CASE NEW.status::text
               WHEN 'open'      THEN format($f$Your template battle "%s" is now open$f$, NEW.title)
               WHEN 'published' THEN format($f$Your template battle "%s" has been published$f$, NEW.title)
             END;
  v_body  := CASE NEW.status::text
               WHEN 'open'      THEN 'Contenders can now submit entries.'
               WHEN 'published' THEN 'Results are live.'
             END;

  PERFORM public.fn_insert_notification(
    NEW.creator_lenser_id,
    v_type,
    v_title,
    v_body,
    '/battles/' || COALESCE(NEW.slug, NEW.id::text),
    jsonb_build_object(
      'battle_id',   NEW.id,
      'template_id', NEW.template_id,
      'title',       NEW.title,
      'status',      NEW.status::text
    )
  );

  RETURN NEW;
END $_$;


