CREATE OR REPLACE FUNCTION "content"."fn_check_reaction_target"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
DECLARE
  ok boolean;
BEGIN
  IF NEW.entity_type = 'lens' THEN
    SELECT EXISTS(SELECT 1 FROM lenses.lenses WHERE id = NEW.entity_id) INTO ok;
  ELSIF NEW.entity_type = 'thread' THEN
    SELECT EXISTS(SELECT 1 FROM content.threads WHERE id = NEW.entity_id) INTO ok;
  ELSIF NEW.entity_type = 'thread_reply' THEN
    SELECT EXISTS(SELECT 1 FROM content.thread_replies WHERE id = NEW.entity_id) INTO ok;
  ELSIF NEW.entity_type = 'workflow' THEN
    SELECT EXISTS(SELECT 1 FROM lenses.workflows WHERE id = NEW.entity_id) INTO ok;
  ELSE
    RAISE EXCEPTION 'unsupported reaction entity_type: %', NEW.entity_type
      USING ERRCODE = 'check_violation';
  END IF;

  IF NOT ok THEN
    RAISE EXCEPTION 'reaction target %/% does not exist', NEW.entity_type, NEW.entity_id
      USING ERRCODE = 'foreign_key_violation';
  END IF;

  RETURN NEW;
END $$;


ALTER FUNCTION "content"."fn_check_reaction_target"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "content"."fn_cleanup_entity_refs"("p_entity_type" "content"."entity_type_enum", "p_entity_id" "uuid") RETURNS "void"
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  DELETE FROM "content"."reactions"
    WHERE "entity_type" = "p_entity_type"
      AND "entity_id"   = "p_entity_id";

  DELETE FROM "content"."tag_map"
    WHERE "entity_type" = "p_entity_type"
      AND "entity_id"   = "p_entity_id";

  DELETE FROM "content"."entity_translations"
    WHERE "entity_type" = "p_entity_type"
      AND "entity_id"   = "p_entity_id";

  DELETE FROM "content"."tag_suggestions"
    WHERE "entity_type" = "p_entity_type"
      AND "entity_id"   = "p_entity_id";

  DELETE FROM "content"."reports"
    WHERE "target_type" = "p_entity_type"
      AND "target_id"   = "p_entity_id";
$$;


ALTER FUNCTION "content"."fn_cleanup_entity_refs"("p_entity_type" "content"."entity_type_enum", "p_entity_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "content"."fn_cleanup_entity_refs"("p_entity_type" "content"."entity_type_enum", "p_entity_id" "uuid") IS 'Deletes all polymorphic content references for a given entity when it is deleted. Called by AFTER DELETE triggers on lenses.lenses, content.threads, and content.thread_replies. Enforces referential integrity for entity_type + entity_id patterns that cannot use FK constraints.';



CREATE OR REPLACE FUNCTION "content"."fn_trg_notify_lens_comment"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'content', 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_linked_lens_id UUID;
  v_lens_owner_id  UUID;
  v_lens_vis       content.visibility_enum;
  v_commenter      lensers.profiles%ROWTYPE;
  v_lens_title     TEXT;
  v_notif_id       UUID;
BEGIN
  -- Resolve parent thread's linked lens
  SELECT t.linked_lens_id
  INTO   v_linked_lens_id
  FROM   content.threads t
  WHERE  t.id = NEW.thread_id;

  IF v_linked_lens_id IS NULL THEN
    RETURN NEW;  -- not a lens-linked thread
  END IF;

  -- Fetch lens owner and visibility; skip private lenses
  SELECT l.lenser_id, l.visibility
  INTO   v_lens_owner_id, v_lens_vis
  FROM   lenses.lenses l
  WHERE  l.id = v_linked_lens_id;

  IF NOT FOUND OR v_lens_vis = 'private'::content.visibility_enum THEN
    RETURN NEW;
  END IF;

  -- Anti-spam: 5-minute window per lens entity
  IF NOT public.fn_check_and_upsert_aggregate(
    v_lens_owner_id, NEW.lenser_id, 'lens_comment', v_linked_lens_id, '5 minutes'
  ) THEN
    RETURN NEW;  -- already notified recently
  END IF;

  SELECT * INTO v_commenter FROM lensers.profiles WHERE id = NEW.lenser_id;

  SELECT et.title
  INTO   v_lens_title
  FROM   content.entity_translations et
  WHERE  et.entity_id   = v_linked_lens_id
    AND  et.entity_type = 'lens'::content.entity_type_enum
    AND  et.is_original = true
  LIMIT  1;

  v_notif_id := public.fn_insert_notification(
    v_lens_owner_id,
    'lens_comment',
    COALESCE(v_commenter.display_name, v_commenter.handle) || ' commented on your lens',
    COALESCE(v_lens_title, 'Your lens'),
    '/lenses/' || v_linked_lens_id,
    jsonb_build_object(
      'commenter_id',           NEW.lenser_id,
      'commenter_handle',       v_commenter.handle,
      'commenter_display_name', v_commenter.display_name,
      'entity_id',              v_linked_lens_id,
      'entity_type',            'lens',
      'preview',                LEFT(NEW.content, 120)
    ),
    NEW.lenser_id  -- p_actor_id for block/mute gate
  );

  -- Back-fill notification_id on the aggregate for title-update support
  IF v_notif_id IS NOT NULL THEN
    UPDATE public.notification_aggregates
    SET    notification_id = v_notif_id
    WHERE  recipient_id      = v_lens_owner_id
      AND  notification_type = 'lens_comment'
      AND  entity_id         = v_linked_lens_id
      AND  notification_id   IS NULL
      AND  window_end        > now();
  END IF;

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'fn_trg_notify_lens_comment failed: %', SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "content"."fn_trg_notify_lens_comment"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "content"."fn_xp_on_workflow_reaction"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'content', 'lenses', 'xp', 'public'
    AS $$
DECLARE
  v_owner_id   uuid;
  v_forum_app  uuid;
BEGIN
  -- Only process INSERT of workflow reactions (trigger WHEN clause already filters entity_type)
  IF TG_OP != 'INSERT' THEN RETURN NEW; END IF;

  -- Resolve forum app_id (cached as a constant; global fallback if not seeded)
  SELECT id INTO v_forum_app FROM xp.apps WHERE slug = 'forum' LIMIT 1;
  IF v_forum_app IS NULL THEN
    v_forum_app := '00000000-0000-0000-0000-000000000000'::uuid;
  END IF;

  -- Look up the workflow owner
  SELECT lenser_id INTO v_owner_id
  FROM lenses.workflows
  WHERE id = NEW.entity_id;

  IF NEW.reaction = 'like'::content.reaction_enum THEN
    -- Award XP to the liker
    BEGIN
      PERFORM xp.apply(NEW.lenser_id, 'WORKFLOW_LIKED', 'content'::xp.source_enum, 'workflow', NEW.entity_id, v_forum_app);
    EXCEPTION WHEN OTHERS THEN NULL; END;

    -- Award XP to the workflow owner (skip self-reactions)
    IF v_owner_id IS NOT NULL AND v_owner_id != NEW.lenser_id THEN
      BEGIN
        PERFORM xp.apply(v_owner_id, 'WORKFLOW_LIKE_RECEIVED', 'content'::xp.source_enum, 'workflow', NEW.entity_id, v_forum_app);
      EXCEPTION WHEN OTHERS THEN NULL; END;
    END IF;

  ELSIF NEW.reaction = 'saved'::content.reaction_enum THEN
    BEGIN
      PERFORM xp.apply(NEW.lenser_id, 'WORKFLOW_SAVED', 'content'::xp.source_enum, 'workflow', NEW.entity_id, v_forum_app);
    EXCEPTION WHEN OTHERS THEN NULL; END;

    IF v_owner_id IS NOT NULL AND v_owner_id != NEW.lenser_id THEN
      BEGIN
        PERFORM xp.apply(v_owner_id, 'WORKFLOW_SAVE_RECEIVED', 'content'::xp.source_enum, 'workflow', NEW.entity_id, v_forum_app);
      EXCEPTION WHEN OTHERS THEN NULL; END;
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "content"."fn_xp_on_workflow_reaction"() OWNER TO "postgres";


