CREATE OR REPLACE FUNCTION "content"."trg_notify_lens_reaction"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'content', 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_owner_id UUID;
  v_reactor  lensers.profiles%ROWTYPE;
  v_slug     TEXT;
BEGIN
  -- Resolve entity owner (only lens and workflow supported)
  IF NEW.entity_type = 'lens' THEN
    SELECT lenser_id INTO v_owner_id FROM lenses.lenses WHERE id = NEW.entity_id;
    v_slug := '/lenses/' || NEW.entity_id;
  ELSIF NEW.entity_type = 'workflow' THEN
    SELECT lenser_id INTO v_owner_id FROM lenses.workflows WHERE id = NEW.entity_id;
    v_slug := '/workflows/' || NEW.entity_id;
  ELSE
    RETURN NEW;
  END IF;

  -- Skip if owner not found or this is a self-reaction
  IF v_owner_id IS NULL OR v_owner_id = NEW.lenser_id THEN
    RETURN NEW;
  END IF;

  SELECT * INTO v_reactor FROM lensers.profiles WHERE id = NEW.lenser_id;

  PERFORM public.fn_insert_notification(
    v_owner_id,
    'lens_reaction',
    COALESCE(v_reactor.display_name, v_reactor.handle) || ' reacted to your ' || NEW.entity_type::text,
    NULL,
    v_slug,
    jsonb_build_object(
      'reactor_id',           NEW.lenser_id,
      'reactor_handle',       v_reactor.handle,
      'reactor_display_name', v_reactor.display_name,
      'reactor_avatar_url',   v_reactor.avatar_url,
      'reaction',             NEW.reaction::text,
      'entity_type',          NEW.entity_type::text,
      'entity_id',            NEW.entity_id
    )
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'trg_notify_lens_reaction failed: %', SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "content"."trg_notify_lens_reaction"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "content"."update_lens_reaction_counters"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'lenses', 'content', 'public'
    AS $$
DECLARE
  v_template_id uuid;
BEGIN
  IF NEW.entity_type = 'lens' THEN
    v_template_id := NEW.target_id;

    UPDATE lenses.lenses
    SET reaction_totals = (
      SELECT jsonb_object_agg(reaction, count)
      FROM (
        SELECT reaction, COUNT(*) AS count
        FROM content.reactions
        WHERE target_type = 'lens'
          AND target_id   = v_template_id
        GROUP BY reaction
      ) sub
    )
    WHERE id = v_template_id;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "content"."update_lens_reaction_counters"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "content"."update_workflow_reaction_counters"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'lenses', 'content', 'public'
    AS $$
DECLARE
  v_workflow_id uuid;
BEGIN
  -- Determine which workflow was affected (works for INSERT and DELETE)
  IF TG_OP = 'DELETE' THEN
    IF OLD.entity_type::text != 'workflow' THEN RETURN OLD; END IF;
    v_workflow_id := OLD.entity_id;
  ELSE
    IF NEW.entity_type::text != 'workflow' THEN RETURN NEW; END IF;
    v_workflow_id := NEW.entity_id;
  END IF;

  UPDATE lenses.workflows
  SET reaction_totals = COALESCE((
    SELECT jsonb_object_agg(reaction, cnt)
    FROM (
      SELECT reaction, COUNT(*) AS cnt
      FROM content.reactions
      WHERE entity_type = 'workflow'::content.entity_type_enum
        AND entity_id   = v_workflow_id
      GROUP BY reaction
    ) sub
  ), '{}'::jsonb)
  WHERE id = v_workflow_id;

  IF TG_OP = 'DELETE' THEN RETURN OLD; END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "content"."update_workflow_reaction_counters"() OWNER TO "postgres";


