CREATE OR REPLACE FUNCTION "devices"."fn_xp_on_device_trust_elevated"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'devices', 'xp', 'execution', 'public', 'extensions'
    AS $$
BEGIN
  IF NEW.trust_level IN ('approved', 'trusted')
     AND COALESCE(OLD.trust_level, 'pending') NOT IN ('approved', 'trusted')
  THEN
    PERFORM execution.fn_xp_apply_safe(
      NEW.lenser_id,
      'DEVICE_VERIFIED',
      'system'::xp.source_enum,
      'device',
      NEW.id,
      '00000000-0000-0000-0000-000000000003'::uuid
    );
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "devices"."fn_xp_on_device_trust_elevated"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "execution"."fn_async_run_idempotent_complete"("p_run_id" "uuid", "p_media_url" "text", "p_mime_type" "text", "p_bytes" bigint DEFAULT NULL::bigint, "p_width" integer DEFAULT NULL::integer, "p_height" integer DEFAULT NULL::integer, "p_duration_s" numeric DEFAULT NULL::numeric) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'public'
    AS $$
DECLARE
  v_status TEXT;
BEGIN
  SELECT status INTO v_status
  FROM execution.runs
  WHERE id = p_run_id
  FOR UPDATE;

  IF v_status IS NULL THEN
    RETURN FALSE;  -- run does not exist
  END IF;

  -- Already terminal — no-op success so the worker can ack.
  IF v_status IN ('succeeded', 'failed', 'canceled', 'timed_out') THEN
    RETURN FALSE;
  END IF;

  PERFORM execution.fn_complete_async_run(
    p_run_id, p_media_url, p_mime_type, p_bytes, p_width, p_height, p_duration_s
  );
  RETURN TRUE;
END;
$$;


ALTER FUNCTION "execution"."fn_async_run_idempotent_complete"("p_run_id" "uuid", "p_media_url" "text", "p_mime_type" "text", "p_bytes" bigint, "p_width" integer, "p_height" integer, "p_duration_s" numeric) OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_async_run_idempotent_complete"("p_run_id" "uuid", "p_media_url" "text", "p_mime_type" "text", "p_bytes" bigint, "p_width" integer, "p_height" integer, "p_duration_s" numeric) IS 'Phase AM: idempotent wrapper around fn_complete_async_run. Returns TRUE when the run was transitioned, FALSE when the run is already terminal (no-op) or does not exist. Lets poll workers retry without producing duplicate media.objects rows.';



CREATE OR REPLACE FUNCTION "execution"."fn_b64url_decode"("p_in" "text") RETURNS "bytea"
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_padded TEXT;
  v_pad_len INT;
BEGIN
  IF p_in IS NULL OR length(p_in) = 0 THEN
    RETURN NULL;
  END IF;
  v_padded := translate(p_in, '-_', '+/');
  v_pad_len := (4 - (length(v_padded) % 4)) % 4;
  IF v_pad_len > 0 THEN
    v_padded := v_padded || repeat('=', v_pad_len);
  END IF;
  RETURN decode(v_padded, 'base64');
END;
$$;


ALTER FUNCTION "execution"."fn_b64url_decode"("p_in" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_b64url_decode"("p_in" "text") IS 'Decode RFC 4648 base64url (no padding) to bytea. Used by signature verification helpers.';



CREATE OR REPLACE FUNCTION "execution"."fn_chain_on_attestation_verified"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'devices', 'audit', 'public'
    AS $$
DECLARE
  v_lenser_id UUID;
BEGIN
  SELECT rd.lenser_id INTO v_lenser_id
  FROM devices.registered_devices rd
  WHERE rd.id = NEW.device_id;

  IF v_lenser_id IS NULL THEN
    RETURN NEW;
  END IF;

  PERFORM audit.fn_append_gateway_event_safe(
    CASE WHEN NEW.verified
         THEN 'GATEWAY_ATTESTATION_VERIFIED'
         ELSE 'GATEWAY_ATTESTATION_REJECTED'
    END,
    v_lenser_id,
    NEW.device_id,
    jsonb_build_object(
      'attestation_id', NEW.attestation_id,
      'envelope_kid',   NEW.envelope_kid,
      'envelope_iat',   NEW.envelope_iat,
      'invalid_reason', NEW.invalid_reason
    )
  );
  RETURN NEW;
END;
$$;


ALTER FUNCTION "execution"."fn_chain_on_attestation_verified"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "execution"."fn_claim_queued_run"() RETURNS TABLE("run_id" "uuid", "request_id" "uuid", "requester_lenser_id" "uuid", "workspace_id" "uuid", "lens_id" "uuid", "version_id" "uuid", "model_id" "uuid", "model_key" "text", "provider_key" "text", "funding_source" "text", "byok_key_ref_id" "uuid", "input_snapshot" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'ai', 'public'
    AS $$
DECLARE
  v_run_id uuid;
BEGIN
  IF auth.role() IS DISTINCT FROM 'service_role' THEN
    RAISE EXCEPTION 'Forbidden: only service_role can claim queued runs';
  END IF;

  WITH next_run AS (
    SELECT r.id
    FROM execution.runs r
    JOIN execution.requests req
      ON req.id = r.request_id
    WHERE r.status = 'queued'
      AND r.is_active = true
      AND req.is_active = true
    ORDER BY r.created_at ASC
    FOR UPDATE SKIP LOCKED
    LIMIT 1
  )
  UPDATE execution.runs r
     SET status = 'running',
         started_at = COALESCE(r.started_at, now())
    FROM next_run nr
   WHERE r.id = nr.id
  RETURNING r.id INTO v_run_id;

  IF v_run_id IS NULL THEN
    RETURN;
  END IF;

  RETURN QUERY
  SELECT
    r.id AS run_id,
    req.id AS request_id,
    req.requester_lenser_id,
    req.workspace_id,
    req.lens_id,
    req.version_id,
    r.model_id,
    m.key AS model_key,
    p.key AS provider_key,
    req.funding_source,
    req.byok_key_ref_id,
    req.input_snapshot
  FROM execution.runs r
  JOIN execution.requests req
    ON req.id = r.request_id
  LEFT JOIN ai.models m
    ON m.id = r.model_id
  LEFT JOIN ai.providers p
    ON p.id = m.provider_id
  WHERE r.id = v_run_id;
END;
$$;


ALTER FUNCTION "execution"."fn_claim_queued_run"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "execution"."fn_complete_async_run"("p_run_id" "uuid", "p_media_url" "text", "p_mime_type" "text", "p_bytes" bigint DEFAULT NULL::bigint, "p_width" integer DEFAULT NULL::integer, "p_height" integer DEFAULT NULL::integer, "p_duration_s" numeric DEFAULT NULL::numeric) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'media', 'public'
    AS $$
DECLARE
  v_request_id      UUID;
  v_model_id        UUID;
  v_output_modality TEXT;
  v_media_object_id UUID;
  v_credit_cost     NUMERIC := 0;
  v_rate            NUMERIC;
  v_rate_unit       TEXT;
  v_media_type      TEXT;
BEGIN
  -- Lock the run row
  SELECT request_id INTO v_request_id
  FROM execution.runs
  WHERE id = p_run_id AND is_async = TRUE AND status = 'running'
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Run % not found or not in running/async state', p_run_id;
  END IF;

  -- Pull model_id and output_modality from the request
  SELECT model_id, output_modality
  INTO v_model_id, v_output_modality
  FROM execution.requests
  WHERE id = v_request_id;

  -- Resolve credit cost from modality_pricing
  SELECT credit_rate, rate_unit
  INTO v_rate, v_rate_unit
  FROM ai.modality_pricing
  WHERE model_id = v_model_id
    AND output_modality = COALESCE(v_output_modality, 'image')
    AND is_active = TRUE
  LIMIT 1;

  IF FOUND THEN
    v_credit_cost := CASE v_rate_unit
      WHEN 'per_image'    THEN v_rate
      WHEN 'per_second'   THEN v_rate * COALESCE(p_duration_s, 0)
      WHEN 'per_1k_chars' THEN 0
      WHEN 'per_request'  THEN v_rate
      ELSE 0
    END;
  END IF;

  -- Determine media_type for media.objects
  v_media_type := CASE
    WHEN p_mime_type LIKE 'image/%' THEN 'image'
    WHEN p_mime_type LIKE 'video/%' THEN 'video'
    WHEN p_mime_type LIKE 'audio/%' THEN 'audio'
    ELSE 'binary'
  END;

  -- Create media.objects row — AN: populate first-class dimension/duration columns
  INSERT INTO media.objects (
    bucket,
    object_key,
    external_url,
    mime_type,
    media_type,
    byte_size,
    visibility,
    lifecycle_state,
    metadata,
    request_id,
    duration_seconds,
    video_width,
    video_height
  )
  VALUES (
    'generated-media',
    'async/' || p_run_id::TEXT || '.' || split_part(p_mime_type, '/', 2),
    p_media_url,
    p_mime_type,
    v_media_type,
    p_bytes,
    'private',
    'active',
    jsonb_build_object(
      'width',      p_width,
      'height',     p_height,
      'duration_s', p_duration_s
    ),
    v_request_id,
    p_duration_s,
    p_width,
    p_height
  )
  RETURNING id INTO v_media_object_id;

  -- Write primary artifact
  INSERT INTO execution.artifacts (
    run_id,
    artifact_kind,
    content_text,
    visibility,
    is_primary_output,
    media_object_id,
    output_type
  )
  VALUES (
    p_run_id,
    COALESCE(v_output_modality, 'image')::TEXT,
    p_media_url,
    'private',
    TRUE,
    v_media_object_id,
    COALESCE(v_output_modality, 'image')
  );

  -- Mark run succeeded
  UPDATE execution.runs
  SET
    status         = 'succeeded',
    completed_at   = now(),
    latency_ms     = EXTRACT(EPOCH FROM (now() - started_at))::BIGINT * 1000,
    credit_cost    = v_credit_cost,
    billing_status = CASE WHEN v_credit_cost > 0 THEN 'pending' ELSE 'free' END
  WHERE id = p_run_id;
END;
$$;


ALTER FUNCTION "execution"."fn_complete_async_run"("p_run_id" "uuid", "p_media_url" "text", "p_mime_type" "text", "p_bytes" bigint, "p_width" integer, "p_height" integer, "p_duration_s" numeric) OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_complete_async_run"("p_run_id" "uuid", "p_media_url" "text", "p_mime_type" "text", "p_bytes" bigint, "p_width" integer, "p_height" integer, "p_duration_s" numeric) IS 'AN: Updated to populate media.objects.duration_seconds, video_width, video_height. Called by poll-async-executions Edge Function when a video/audio provider signals done.';



CREATE OR REPLACE FUNCTION "execution"."fn_complete_execution_run"("p_run_id" "uuid", "p_status" "text", "p_token_input" integer DEFAULT NULL::integer, "p_token_output" integer DEFAULT NULL::integer, "p_credit_cost" bigint DEFAULT NULL::bigint, "p_billing_status" "text" DEFAULT 'free'::"text", "p_response_text" "text" DEFAULT NULL::"text", "p_response_meta" "jsonb" DEFAULT '{}'::"jsonb", "p_error_code" "text" DEFAULT NULL::"text", "p_error_message" "text" DEFAULT NULL::"text", "p_latency_ms" integer DEFAULT NULL::integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'public'
    AS $$
BEGIN
    UPDATE "execution"."runs"
    SET
        "status"         = p_status,
        "token_input"    = COALESCE(p_token_input,    "token_input"),
        "token_output"   = COALESCE(p_token_output,   "token_output"),
        "credit_cost"    = COALESCE(p_credit_cost,    "credit_cost"),
        "billing_status" = p_billing_status,
        "response_text"  = p_response_text,
        "response_meta"  = COALESCE(p_response_meta,  "response_meta"),
        "error_code"     = p_error_code,
        "error_message"  = p_error_message,
        "latency_ms"     = COALESCE(p_latency_ms,     "latency_ms"),
        "completed_at"   = now()
    WHERE "id" = p_run_id;
END;
$$;


ALTER FUNCTION "execution"."fn_complete_execution_run"("p_run_id" "uuid", "p_status" "text", "p_token_input" integer, "p_token_output" integer, "p_credit_cost" bigint, "p_billing_status" "text", "p_response_text" "text", "p_response_meta" "jsonb", "p_error_code" "text", "p_error_message" "text", "p_latency_ms" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_complete_execution_run"("p_run_id" "uuid", "p_status" "text", "p_token_input" integer, "p_token_output" integer, "p_credit_cost" bigint, "p_billing_status" "text", "p_response_text" "text", "p_response_meta" "jsonb", "p_error_code" "text", "p_error_message" "text", "p_latency_ms" integer) IS 'Updates execution.runs with final status, token counts, credit cost, and response. Called fire-and-forget after provider execution completes or fails. SECURITY DEFINER; callable only by service_role.';



CREATE OR REPLACE FUNCTION "execution"."fn_compute_submission_trust"("p_submission_id" "uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'devices', 'battles', 'lensers', 'public', 'extensions'
    AS $$
DECLARE
  v_run_id            UUID;
  v_attestation       execution.attestations%ROWTYPE;
  v_verification      execution.attestation_verifications%ROWTYPE;
  v_trust_level       TEXT := 'unverified';
  v_factors           JSONB := '{}';
  v_account_ok        BOOLEAN := false;
  v_agent_ok          BOOLEAN := false;
  v_signature_verified BOOLEAN := false;
BEGIN
  -- Account / run ownership
  SELECT er.id INTO v_run_id
  FROM battles.submissions s
  JOIN execution.runs er ON er.id = s.execution_run_id
  WHERE s.id = p_submission_id
  LIMIT 1;

  v_account_ok := (v_run_id IS NOT NULL);
  v_factors := v_factors || jsonb_build_object('account_authenticated', v_account_ok);

  IF NOT v_account_ok THEN
    INSERT INTO execution.trust_evaluations (submission_id, trust_level, factors, evaluated_at)
    VALUES (p_submission_id, 'unverified', v_factors, now())
    ON CONFLICT (submission_id) DO UPDATE
      SET trust_level = EXCLUDED.trust_level,
          factors = EXCLUDED.factors,
          evaluated_at = EXCLUDED.evaluated_at;
    RETURN 'unverified';
  END IF;

  v_trust_level := 'account_verified';

  SELECT EXISTS (
    SELECT 1 FROM battles.contenders bc
    WHERE bc.battle_id = (SELECT battle_id FROM battles.submissions WHERE id = p_submission_id)
      AND bc.contender_type IN ('ai_agent','ai_runner')
  ) INTO v_agent_ok;
  v_factors := v_factors || jsonb_build_object('agent_owner_verified', v_agent_ok);
  IF v_agent_ok THEN v_trust_level := 'agent_verified'; END IF;

  -- Latest attestation for this run
  SELECT * INTO v_attestation
  FROM execution.attestations
  WHERE run_id = v_run_id
  ORDER BY created_at DESC
  LIMIT 1;

  IF v_attestation.id IS NOT NULL THEN
    SELECT * INTO v_verification
    FROM execution.attestation_verifications
    WHERE attestation_id = v_attestation.id;

    v_signature_verified := COALESCE(v_verification.verified, false);

    v_factors := v_factors || jsonb_build_object(
      'device_trusted',         v_attestation.device_trusted,
      'runner_connected',       v_attestation.device_id IS NOT NULL,
      'execution_signed',       v_attestation.signed,
      'signature_verified',     v_signature_verified,
      'signature_invalid_reason', v_verification.invalid_reason,
      'policy_passed',          v_attestation.policy_passed,
      'workflow_hash_recorded', v_attestation.workflow_hash IS NOT NULL,
      'lens_hash_recorded',     v_attestation.lens_hash IS NOT NULL,
      'envelope_recorded',      v_attestation.envelope_kid IS NOT NULL
    );

    IF v_attestation.device_trusted THEN
      v_trust_level := 'device_verified';
    END IF;
    IF v_attestation.device_id IS NOT NULL AND v_attestation.device_trusted THEN
      v_trust_level := 'runner_verified';
    END IF;

    -- Phase F: execution_verified now requires a positive signature verification.
    -- The legacy `gateway_verified` flag is no longer accepted.
    IF v_attestation.signed AND v_signature_verified THEN
      v_trust_level := 'execution_verified';
    END IF;

    IF v_attestation.signed
       AND v_signature_verified
       AND v_attestation.device_trusted
       AND v_attestation.policy_passed
       AND v_attestation.workflow_hash IS NOT NULL
       AND v_attestation.lens_hash IS NOT NULL
       AND v_attestation.envelope_kid IS NOT NULL
    THEN
      v_trust_level := 'fully_trusted';
    END IF;
  END IF;

  INSERT INTO execution.trust_evaluations (
    submission_id, attestation_id, trust_level, factors, evaluated_at
  ) VALUES (
    p_submission_id,
    v_attestation.id,
    v_trust_level,
    v_factors,
    now()
  )
  ON CONFLICT (submission_id) DO UPDATE
    SET attestation_id = EXCLUDED.attestation_id,
        trust_level    = EXCLUDED.trust_level,
        factors        = EXCLUDED.factors,
        evaluated_at   = EXCLUDED.evaluated_at;

  RETURN v_trust_level;
END;
$$;


ALTER FUNCTION "execution"."fn_compute_submission_trust"("p_submission_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "execution"."fn_get_lens_execution_history"("p_lens_id" "uuid", "p_limit" integer DEFAULT 20, "p_offset" integer DEFAULT 0) RETURNS TABLE("request_id" "uuid", "lens_id" "uuid", "version_id" "uuid", "version_number" integer, "model_id" "uuid", "model_key" "text", "provider_key" "text", "funding_source" "text", "run_id" "uuid", "run_status" "text", "latency_ms" integer, "token_input" integer, "token_output" integer, "credit_cost" bigint, "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'lenses', 'ai', 'lensers', 'public'
    AS $$
DECLARE
  v_caller_id uuid := "lensers"."get_auth_lenser_id"();
BEGIN
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  RETURN QUERY
  SELECT
    req."id"                    AS request_id,
    req."lens_id"               AS lens_id,
    req."version_id"            AS version_id,
    lv."version_number"         AS version_number,
    req."model_id"              AS model_id,
    m."key"                     AS model_key,
    p."key"                     AS provider_key,
    req."funding_source"        AS funding_source,
    r."id"                      AS run_id,
    r."status"                  AS run_status,
    r."latency_ms"              AS latency_ms,
    r."token_input"             AS token_input,
    r."token_output"            AS token_output,
    r."credit_cost"             AS credit_cost,
    req."created_at"            AS created_at
  FROM  "execution"."requests"  req
  LEFT JOIN "execution"."runs"  r   ON r."request_id"  = req."id"
                                   AND r."is_active"   = true
  LEFT JOIN "lenses"."versions" lv  ON lv."id"         = req."version_id"
  LEFT JOIN "ai"."models"       m   ON m."id"          = req."model_id"
  LEFT JOIN "ai"."providers"    p   ON p."id"          = m."provider_id"
  WHERE req."lens_id"              = p_lens_id
    AND req."requester_lenser_id"  = v_caller_id
    AND req."is_active"            = true
  ORDER BY req."created_at" DESC
  LIMIT  p_limit
  OFFSET p_offset;
END;
$$;


ALTER FUNCTION "execution"."fn_get_lens_execution_history"("p_lens_id" "uuid", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_get_lens_execution_history"("p_lens_id" "uuid", "p_limit" integer, "p_offset" integer) IS 'GRASP Controller: returns caller-scoped execution history for a lens, enriched with model key, provider key, and version number. Used by LabExecutionTimeline to display model/provider/version badges. SECURITY DEFINER: filters to requester_lenser_id only. Replaces the deprecated execution.vw_ray_runs (compatibility shim) for app-layer reads.';



CREATE OR REPLACE FUNCTION "execution"."fn_get_run_details"("p_run_id" "uuid") RETURNS TABLE("id" "uuid", "request_id" "uuid", "status" "text", "model_id" "uuid", "model_key" "text", "provider_key" "text", "started_at" timestamp with time zone, "completed_at" timestamp with time zone, "latency_ms" integer, "token_input" integer, "token_output" integer, "credit_cost" bigint, "billing_status" "text", "error_code" "text", "error_message" "text", "artifacts" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'lenses', 'lensers', 'ai', 'public'
    AS $$
DECLARE
  v_caller_id uuid := lensers.get_auth_lenser_id();
BEGIN
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  RETURN QUERY
  SELECT
    r.id,
    r.request_id,
    r.status,
    r.model_id,
    m.key AS model_key,
    p.key AS provider_key,
    r.started_at,
    r.completed_at,
    r.latency_ms,
    r.token_input,
    r.token_output,
    r.credit_cost,
    r.billing_status,
    r.error_code,
    r.error_message,
    COALESCE(
      jsonb_agg(
        jsonb_build_object(
          'id', a.id,
          'artifactKind', a.artifact_kind,
          'contentText', a.content_text,
          'contentJson', a.content_json,
          'visibility', a.visibility,
          'isPrimaryOutput', a.is_primary_output,
          'createdAt', a.created_at
        )
      ) FILTER (WHERE a.id IS NOT NULL),
      '[]'::jsonb
    ) AS artifacts
  FROM execution.runs r
  JOIN execution.requests req
    ON req.id = r.request_id
  LEFT JOIN ai.models m
    ON m.id = r.model_id
  LEFT JOIN ai.providers p
    ON p.id = m.provider_id
  LEFT JOIN execution.artifacts a
    ON a.run_id = r.id
  WHERE r.id = p_run_id
    AND req.requester_lenser_id = v_caller_id
    AND req.is_active = true
    AND r.is_active = true
  GROUP BY
    r.id, r.request_id, r.status, r.model_id, m.key, p.key, r.started_at,
    r.completed_at, r.latency_ms, r.token_input, r.token_output, r.credit_cost,
    r.billing_status, r.error_code, r.error_message;
END;
$$;


ALTER FUNCTION "execution"."fn_get_run_details"("p_run_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "execution"."fn_get_submission_trust"("p_submission_id" "uuid") RETURNS TABLE("submission_id" "uuid", "trust_level" "text", "factors" "jsonb", "attestation_id" "uuid", "evaluated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'battles', 'lensers', 'public', 'extensions'
    AS $$
DECLARE
  v_caller_lenser_id UUID;
  v_owner_lenser_id  UUID;
BEGIN
  SELECT lp.id INTO v_caller_lenser_id
  FROM lensers.profiles lp
  WHERE lp.user_id = auth.uid()
  LIMIT 1;

  SELECT req.requester_lenser_id INTO v_owner_lenser_id
  FROM battles.submissions s
  JOIN execution.runs r       ON r.id   = s.execution_run_id
  JOIN execution.requests req ON req.id = r.request_id
  WHERE s.id = p_submission_id
  LIMIT 1;

  RETURN QUERY
  SELECT
    te.submission_id,
    te.trust_level,
    CASE
      WHEN v_caller_lenser_id IS NOT NULL
       AND v_caller_lenser_id = v_owner_lenser_id THEN te.factors
      ELSE jsonb_build_object('redacted', true)
    END AS factors,
    CASE
      WHEN v_caller_lenser_id IS NOT NULL
       AND v_caller_lenser_id = v_owner_lenser_id THEN te.attestation_id
      ELSE NULL::UUID
    END AS attestation_id,
    te.evaluated_at
  FROM execution.trust_evaluations te
  WHERE te.submission_id = p_submission_id;
END;
$$;


ALTER FUNCTION "execution"."fn_get_submission_trust"("p_submission_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_get_submission_trust"("p_submission_id" "uuid") IS 'Phase A (RFC-0003): owner-scoped read of submission trust. Anonymous and non-owner callers receive a redacted factors object. Direct table reads are no longer permitted by RLS.';



CREATE OR REPLACE FUNCTION "execution"."fn_media_finalize_sync_upload"("p_run_id" "uuid", "p_object_key" "text", "p_mime_type" "text", "p_bytes" bigint DEFAULT NULL::bigint, "p_width" integer DEFAULT NULL::integer, "p_height" integer DEFAULT NULL::integer, "p_duration_s" numeric DEFAULT NULL::numeric) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'media', 'ai', 'public'
    AS $$
DECLARE
  v_request_id      UUID;
  v_model_id        UUID;
  v_output_modality TEXT;
  v_owner_lenser_id UUID;
  v_workspace_id    UUID;
  v_media_object_id UUID;
  v_credit_cost     NUMERIC := 0;
  v_rate            NUMERIC;
  v_rate_unit       TEXT;
  v_media_type      TEXT;
BEGIN
  -- Validate MIME type against the bucket's allowed list. We re-check at the
  -- RPC layer because storage.objects-level enforcement happens at upload
  -- time and a buggy worker might call this RPC with a mismatched type.
  IF p_mime_type IS NULL OR NOT (
    p_mime_type LIKE 'image/%' OR
    p_mime_type LIKE 'video/%' OR
    p_mime_type LIKE 'audio/%'
  ) THEN
    RAISE EXCEPTION 'Unsupported MIME type for sync media finalize: %', p_mime_type
      USING ERRCODE = 'check_violation';
  END IF;

  IF p_object_key IS NULL OR length(p_object_key) = 0 THEN
    RAISE EXCEPTION 'object_key is required'
      USING ERRCODE = 'check_violation';
  END IF;

  -- Lock the running row. Sync runs are typically `is_async = FALSE` but we
  -- accept both — the discriminator is `status = 'running'`.
  SELECT request_id
  INTO v_request_id
  FROM execution.runs
  WHERE id = p_run_id AND status = 'running'
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Run % not found or not in running state', p_run_id;
  END IF;

  -- requester_lenser_id + workspace_id live on execution.requests (not runs).
  SELECT model_id, output_modality, requester_lenser_id, workspace_id
  INTO v_model_id, v_output_modality, v_owner_lenser_id, v_workspace_id
  FROM execution.requests
  WHERE id = v_request_id;

  -- Credit cost lookup mirrors fn_complete_async_run exactly.
  SELECT credit_rate, rate_unit
  INTO v_rate, v_rate_unit
  FROM ai.modality_pricing
  WHERE model_id = v_model_id
    AND output_modality = COALESCE(v_output_modality, 'image')
    AND is_active = TRUE
  LIMIT 1;

  IF FOUND THEN
    v_credit_cost := CASE v_rate_unit
      WHEN 'per_image'    THEN v_rate
      WHEN 'per_second'   THEN v_rate * COALESCE(p_duration_s, 0)
      WHEN 'per_1k_chars' THEN 0
      WHEN 'per_request'  THEN v_rate
      ELSE 0
    END;
  END IF;

  v_media_type := CASE
    WHEN p_mime_type LIKE 'image/%' THEN 'image'
    WHEN p_mime_type LIKE 'video/%' THEN 'video'
    WHEN p_mime_type LIKE 'audio/%' THEN 'audio'
    ELSE 'binary'
  END;

  INSERT INTO media.objects (
    workspace_id,
    owner_lenser_id,
    bucket,
    object_key,
    mime_type,
    media_type,
    byte_size,
    visibility,
    lifecycle_state,
    metadata,
    request_id
  )
  VALUES (
    v_workspace_id,
    v_owner_lenser_id,
    'generated-media',
    p_object_key,
    p_mime_type,
    v_media_type,
    p_bytes,
    'private',
    'active',
    jsonb_build_object(
      'width', p_width,
      'height', p_height,
      'duration_s', p_duration_s,
      'finalize_path', 'sync'
    ),
    v_request_id
  )
  RETURNING id INTO v_media_object_id;

  INSERT INTO execution.artifacts (
    run_id,
    artifact_kind,
    content_text,
    visibility,
    is_primary_output,
    media_object_id,
    output_type
  )
  VALUES (
    p_run_id,
    COALESCE(v_output_modality, 'image')::TEXT,
    NULL,                       -- sync uploads have no external_url
    'private',
    TRUE,
    v_media_object_id,
    COALESCE(v_output_modality, 'image')
  );

  UPDATE execution.runs
  SET status         = 'succeeded',
      completed_at   = now(),
      latency_ms     = EXTRACT(EPOCH FROM (now() - started_at))::BIGINT * 1000,
      credit_cost    = v_credit_cost,
      billing_status = CASE WHEN v_credit_cost > 0 THEN 'pending' ELSE 'free' END
  WHERE id = p_run_id;

  RETURN v_media_object_id;
END;
$$;


ALTER FUNCTION "execution"."fn_media_finalize_sync_upload"("p_run_id" "uuid", "p_object_key" "text", "p_mime_type" "text", "p_bytes" bigint, "p_width" integer, "p_height" integer, "p_duration_s" numeric) OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_media_finalize_sync_upload"("p_run_id" "uuid", "p_object_key" "text", "p_mime_type" "text", "p_bytes" bigint, "p_width" integer, "p_height" integer, "p_duration_s" numeric) IS 'Phase AK: sync-provider counterpart to fn_complete_async_run. Called by the platform-api worker after uploading a synchronously-generated asset (TTS, sync image) to the generated-media bucket. Inserts media.objects + execution.artifacts, computes credit cost via ai.modality_pricing, and marks the run succeeded. service_role only.';



CREATE OR REPLACE FUNCTION "execution"."fn_persist_execution_artifacts"("p_run_id" "uuid", "p_lenser_id" "uuid", "p_workspace_id" "uuid", "p_ai_model_id" "uuid", "p_kind" "text", "p_content_text" "text" DEFAULT NULL::"text", "p_content_json" "jsonb" DEFAULT NULL::"jsonb", "p_media_ids" "uuid"[] DEFAULT '{}'::"uuid"[]) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'public'
    AS $$
DECLARE
    v_artifact_id "uuid";
    v_media_id    "uuid";
BEGIN
    INSERT INTO "execution"."artifacts" (
        "run_id",
        "artifact_kind",
        "content_text",
        "content_json",
        "visibility",
        "is_primary_output",
        "output_type"
    ) VALUES (
        p_run_id,
        p_kind,
        p_content_text,
        p_content_json,
        'private',
        true,
        p_kind
    )
    RETURNING "id" INTO v_artifact_id;

    -- Link each media object
    FOREACH v_media_id IN ARRAY p_media_ids LOOP
        INSERT INTO "execution"."artifact_medias" ("artifact_id", "media_id")
        VALUES (v_artifact_id, v_media_id);
    END LOOP;

    RETURN v_artifact_id;
END;
$$;


ALTER FUNCTION "execution"."fn_persist_execution_artifacts"("p_run_id" "uuid", "p_lenser_id" "uuid", "p_workspace_id" "uuid", "p_ai_model_id" "uuid", "p_kind" "text", "p_content_text" "text", "p_content_json" "jsonb", "p_media_ids" "uuid"[]) OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_persist_execution_artifacts"("p_run_id" "uuid", "p_lenser_id" "uuid", "p_workspace_id" "uuid", "p_ai_model_id" "uuid", "p_kind" "text", "p_content_text" "text", "p_content_json" "jsonb", "p_media_ids" "uuid"[]) IS 'Persist an execution artifact and link N media objects (images, audio, video). p_media_ids defaults to empty array for text-only artifacts. SECURITY DEFINER; callable only by service_role.';



CREATE OR REPLACE FUNCTION "execution"."fn_persist_local_execution"("p_lens_id" "uuid", "p_version_id" "uuid" DEFAULT NULL::"uuid", "p_provider" "text" DEFAULT 'ollama'::"text", "p_model" "text" DEFAULT ''::"text", "p_content_text" "text" DEFAULT ''::"text", "p_token_input" integer DEFAULT 0, "p_token_output" integer DEFAULT 0) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'lensers', 'public'
    AS $$
DECLARE
    v_caller_id   uuid := "lensers"."get_auth_lenser_id"();
    v_request_id  uuid;
    v_run_id      uuid;
    v_now         timestamptz := now();
BEGIN
    IF v_caller_id IS NULL THEN
        RAISE EXCEPTION 'Authentication required'
            USING ERRCODE = 'insufficient_privilege';
    END IF;

    -- 1. Create the execution request
    INSERT INTO "execution"."requests" (
        "requester_lenser_id",
        "origin_type",
        "lens_id",
        "version_id",
        "input_snapshot",
        "runtime_origin",
        "funding_source",
        "created_at"
    ) VALUES (
        v_caller_id,
        'lens_preview',
        p_lens_id,
        p_version_id,
        '{}'::jsonb,
        'local',
        'user_byok_local',
        v_now
    )
    RETURNING "id" INTO v_request_id;

    -- 2. Create the run record (already completed)
    INSERT INTO "execution"."runs" (
        "request_id",
        "status",
        "started_at",
        "completed_at",
        "token_input",
        "token_output",
        "credit_cost",
        "billing_status",
        "response_text",
        "response_meta",
        "created_at"
    ) VALUES (
        v_request_id,
        'succeeded',
        v_now,
        v_now,
        p_token_input,
        p_token_output,
        0,
        'free',
        p_content_text,
        jsonb_build_object('provider', p_provider, 'model', p_model, 'source', 'local_byok'),
        v_now
    )
    RETURNING "id" INTO v_run_id;

    -- 3. Create the primary text artifact
    INSERT INTO "execution"."artifacts" (
        "run_id",
        "artifact_kind",
        "content_text",
        "visibility",
        "is_primary_output",
        "output_type",
        "created_at"
    ) VALUES (
        v_run_id,
        'text',
        p_content_text,
        'private',
        true,
        'text',
        v_now
    );

    RETURN v_run_id;
END;
$$;


ALTER FUNCTION "execution"."fn_persist_local_execution"("p_lens_id" "uuid", "p_version_id" "uuid", "p_provider" "text", "p_model" "text", "p_content_text" "text", "p_token_input" integer, "p_token_output" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_persist_local_execution"("p_lens_id" "uuid", "p_version_id" "uuid", "p_provider" "text", "p_model" "text", "p_content_text" "text", "p_token_input" integer, "p_token_output" integer) IS 'Persists a completed local BYOK execution (browser-side streaming) into execution.requests + runs + artifacts. Called from the client after streamLocalProvider finishes so that local runs appear in execution history and survive page refresh. SECURITY DEFINER: resolves requester from auth.uid(). Credits always 0 for local runs.';



CREATE OR REPLACE FUNCTION "execution"."fn_poll_async_run"("p_stale_after_seconds" integer DEFAULT 30, "p_limit" integer DEFAULT 10) RETURNS TABLE("run_id" "uuid", "provider_task_id" "text", "model_key" "text", "provider_key" "text", "output_modality" "text", "started_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'ai', 'public'
    AS $$
DECLARE
  v_ids UUID[];
BEGIN
  -- 1. Claim a batch of due runs with SKIP LOCKED. Order by NULLS FIRST so
  -- runs that have never been polled get priority over recently-polled ones.
  WITH claimed AS (
    SELECT r.id
    FROM execution.runs r
    WHERE r.is_async = TRUE
      AND r.status   = 'running'
      AND r.provider_task_id IS NOT NULL
      AND (
        r.last_polled_at IS NULL
        OR r.last_polled_at < now() - (p_stale_after_seconds || ' seconds')::INTERVAL
      )
    ORDER BY r.last_polled_at NULLS FIRST, r.started_at
    FOR UPDATE SKIP LOCKED
    LIMIT GREATEST(1, LEAST(p_limit, 50))
  )
  SELECT array_agg(id) INTO v_ids FROM claimed;

  IF v_ids IS NULL THEN
    RETURN;  -- nothing to poll; quiet exit
  END IF;

  -- 2. Bump last_polled_at on the claimed rows so the next tick avoids them
  -- until p_stale_after_seconds has elapsed.
  UPDATE execution.runs
  SET last_polled_at = now()
  WHERE id = ANY(v_ids);

  -- 3. Return the join shape the worker expects.
  RETURN QUERY
    SELECT
      r.id              AS run_id,
      r.provider_task_id,
      m.key             AS model_key,
      p.key             AS provider_key,
      req.output_modality,
      r.started_at
    FROM execution.runs r
    JOIN execution.requests req ON req.id = r.request_id
    LEFT JOIN ai.models   m ON m.id = req.model_id
    LEFT JOIN ai.providers p ON p.id = m.provider_id
    WHERE r.id = ANY(v_ids)
    ORDER BY r.started_at;
END;
$$;


ALTER FUNCTION "execution"."fn_poll_async_run"("p_stale_after_seconds" integer, "p_limit" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_poll_async_run"("p_stale_after_seconds" integer, "p_limit" integer) IS 'Phase AM: SKIP LOCKED batch-claims pending async runs and bumps last_polled_at. Concurrent workers do not double-poll. Caller queries the provider status endpoint and calls fn_complete_async_run on success or fn_async_run_idempotent_complete to handle retries. service_role only.';



CREATE OR REPLACE FUNCTION "execution"."fn_record_execution_attestation"("p_run_id" "uuid", "p_device_id" "uuid" DEFAULT NULL::"uuid", "p_signed" boolean DEFAULT false, "p_signature" "text" DEFAULT NULL::"text", "p_gateway_verified" boolean DEFAULT false, "p_device_trusted" boolean DEFAULT false, "p_policy_passed" boolean DEFAULT false, "p_workflow_hash" "text" DEFAULT NULL::"text", "p_lens_hash" "text" DEFAULT NULL::"text", "p_agent_config_hash" "text" DEFAULT NULL::"text", "p_runner_version" "text" DEFAULT NULL::"text", "p_cli_version" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'devices', 'lensers', 'public', 'extensions'
    AS $$
DECLARE
  v_attestation_id UUID;
BEGIN
  INSERT INTO execution.attestations (
    run_id, device_id, signed, signature,
    gateway_verified, device_trusted, policy_passed,
    workflow_hash, lens_hash, agent_config_hash,
    runner_version, cli_version
  ) VALUES (
    p_run_id, p_device_id, p_signed, p_signature,
    p_gateway_verified, p_device_trusted, p_policy_passed,
    p_workflow_hash, p_lens_hash, p_agent_config_hash,
    p_runner_version, p_cli_version
  )
  RETURNING id INTO v_attestation_id;

  RETURN v_attestation_id;
END;
$$;


ALTER FUNCTION "execution"."fn_record_execution_attestation"("p_run_id" "uuid", "p_device_id" "uuid", "p_signed" boolean, "p_signature" "text", "p_gateway_verified" boolean, "p_device_trusted" boolean, "p_policy_passed" boolean, "p_workflow_hash" "text", "p_lens_hash" "text", "p_agent_config_hash" "text", "p_runner_version" "text", "p_cli_version" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "execution"."fn_record_signed_attestation"("p_run_id" "uuid", "p_envelope_kid" "uuid", "p_envelope_iat" timestamp with time zone, "p_envelope_nonce" "text", "p_canonical_jcs_b64url" "text", "p_signature_b64url" "text", "p_workflow_hash" "text" DEFAULT NULL::"text", "p_lens_hash" "text" DEFAULT NULL::"text", "p_agent_config_hash" "text" DEFAULT NULL::"text", "p_runner_version" "text" DEFAULT NULL::"text", "p_cli_version" "text" DEFAULT NULL::"text", "p_policy_passed" boolean DEFAULT false) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'devices', 'lensers', 'public', 'extensions'
    AS $$
DECLARE
  v_attestation_id   UUID;
  v_canonical_bytes  BYTEA;
  v_signature_bytes  BYTEA;
  v_envelope_hash    TEXT;
  v_verify_row       RECORD;
  v_device_trusted   BOOLEAN := false;
BEGIN
  IF p_run_id IS NULL OR p_envelope_kid IS NULL THEN
    RAISE EXCEPTION 'invalid_input' USING ERRCODE = '22023';
  END IF;

  v_canonical_bytes := execution.fn_b64url_decode(p_canonical_jcs_b64url);
  v_signature_bytes := execution.fn_b64url_decode(p_signature_b64url);
  IF v_canonical_bytes IS NULL OR v_signature_bytes IS NULL THEN
    RAISE EXCEPTION 'invalid_envelope' USING ERRCODE = '22023';
  END IF;

  v_envelope_hash := encode(extensions.digest(v_canonical_bytes, 'sha256'), 'hex');

  SELECT (rd.trust_level IN ('approved','trusted'))
    INTO v_device_trusted
  FROM devices.registered_devices rd
  WHERE rd.id = p_envelope_kid;
  v_device_trusted := COALESCE(v_device_trusted, false);

  -- Insert the attestation row (append-only)
  INSERT INTO execution.attestations (
    run_id, device_id, signed, signature,
    gateway_verified, device_trusted, policy_passed,
    workflow_hash, lens_hash, agent_config_hash,
    runner_version, cli_version,
    envelope_kid, envelope_iat, envelope_nonce, envelope_body_jcs_sha256
  ) VALUES (
    p_run_id, p_envelope_kid, true, p_signature_b64url,
    false,                  -- gateway_verified is now derived from the verification row
    v_device_trusted, p_policy_passed,
    p_workflow_hash, p_lens_hash, p_agent_config_hash,
    p_runner_version, p_cli_version,
    p_envelope_kid, p_envelope_iat, p_envelope_nonce, v_envelope_hash
  )
  RETURNING id INTO v_attestation_id;

  -- Verify and persist verification result
  SELECT * INTO v_verify_row
  FROM execution.fn_verify_attestation_signature(
    p_envelope_kid, v_canonical_bytes, v_signature_bytes
  );

  INSERT INTO execution.attestation_verifications (
    attestation_id, verified, verified_at, invalid_reason,
    device_id, envelope_kid, envelope_iat, envelope_nonce, envelope_hash
  ) VALUES (
    v_attestation_id, COALESCE(v_verify_row.verified, false),
    now(), v_verify_row.invalid_reason,
    p_envelope_kid, p_envelope_kid, p_envelope_iat, p_envelope_nonce, v_envelope_hash
  );

  RETURN v_attestation_id;
END;
$$;


ALTER FUNCTION "execution"."fn_record_signed_attestation"("p_run_id" "uuid", "p_envelope_kid" "uuid", "p_envelope_iat" timestamp with time zone, "p_envelope_nonce" "text", "p_canonical_jcs_b64url" "text", "p_signature_b64url" "text", "p_workflow_hash" "text", "p_lens_hash" "text", "p_agent_config_hash" "text", "p_runner_version" "text", "p_cli_version" "text", "p_policy_passed" boolean) OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_record_signed_attestation"("p_run_id" "uuid", "p_envelope_kid" "uuid", "p_envelope_iat" timestamp with time zone, "p_envelope_nonce" "text", "p_canonical_jcs_b64url" "text", "p_signature_b64url" "text", "p_workflow_hash" "text", "p_lens_hash" "text", "p_agent_config_hash" "text", "p_runner_version" "text", "p_cli_version" "text", "p_policy_passed" boolean) IS 'Atomic record+verify path for signed execution attestations (RFC-0003 Phase F). Verification result is always persisted to execution.attestation_verifications.';



CREATE OR REPLACE FUNCTION "execution"."fn_run_lens"("p_lens_id" "uuid", "p_version_id" "uuid", "p_model_id" "uuid", "p_inputs" "jsonb" DEFAULT '{}'::"jsonb", "p_funding_source" "text" DEFAULT 'platform_credit'::"text", "p_byok_key_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'lenses', 'lensers', 'tenancy', 'public'
    AS $$
DECLARE
  v_lenser_id    uuid := "lensers"."get_auth_lenser_id"();
  v_workspace_id uuid;
  v_request_id   uuid;
  v_run_id       uuid;
  v_param_rec    RECORD;
  v_value        text;
BEGIN
  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- Verify the lens exists and is accessible by the caller
  IF NOT EXISTS (
    SELECT 1 FROM "lenses"."lenses" l
    WHERE  l."id" = p_lens_id
      AND  (l."visibility" = 'public' OR l."lenser_id" = v_lenser_id)
  ) THEN
    RAISE EXCEPTION 'Lens % not found or access denied', p_lens_id
      USING ERRCODE = 'no_data_found';
  END IF;

  -- Validate inputs against version_parameters schema (DB-level enforcement)
  -- Raises check_violation if required params missing, types incompatible, or
  -- select values not in options. No-op if p_version_id IS NULL.
  PERFORM "lenses"."fn_validate_inputs"(p_version_id, p_inputs);

  -- Resolve workspace: fall back to lenser's personal workspace
  v_workspace_id := (
    SELECT "w"."id"
    FROM   "tenancy"."workspaces" w
    WHERE  "w"."owner_lenser_id" = v_lenser_id
      AND  "w"."type"            = 'personal'
      AND  "w"."status"          = 'active'
    ORDER  BY "w"."created_at" ASC
    LIMIT  1
  );

  -- Create execution request
  INSERT INTO "execution"."requests" (
    "requester_lenser_id",
    "lens_id",
    "version_id",
    "model_id",
    "input_snapshot",
    "funding_source",
    "byok_key_ref_id",
    "origin_type",
    "runtime_origin"
  ) VALUES (
    v_lenser_id,
    p_lens_id,
    p_version_id,
    p_model_id,
    p_inputs,
    p_funding_source,
    p_byok_key_id,
    'web',
    'cloud'
  )
  RETURNING "id" INTO v_request_id;

  -- Create execution run (queued → picked up by cloud worker)
  INSERT INTO "execution"."runs" (
    "request_id",
    "model_id",
    "status",
    "created_at"
  ) VALUES (
    v_request_id,
    p_model_id,
    'queued',
    now()
  )
  RETURNING "id" INTO v_run_id;

  -- Upsert used parameter values into lenses.version_parameter_contents so the
  -- user's last-used inputs are persisted per (parameter, workspace, lenser).
  -- Input keys are matched by parameter label (consistent with fn_create_lens).
  IF p_version_id IS NOT NULL AND v_workspace_id IS NOT NULL THEN
    FOR v_param_rec IN
      SELECT vp."id", vp."label" AS "key"
      FROM   "lenses"."version_parameters" vp
      WHERE  vp."version_id" = p_version_id
      LIMIT  200
    LOOP
      v_value := p_inputs->>v_param_rec."key";
      CONTINUE WHEN v_value IS NULL;

      INSERT INTO "lenses"."version_parameter_contents" (
        "parameter_id",
        "lenser_id",
        "workspace_id",
        "contents"
      ) VALUES (
        v_param_rec."id",
        v_lenser_id,
        v_workspace_id,
        jsonb_build_object('value', v_value)
      )
      ON CONFLICT ("parameter_id", "workspace_id", "lenser_id")
      DO UPDATE SET
        "contents"   = jsonb_build_object('value', v_value),
        "updated_at" = now();
    END LOOP;
  END IF;

  RETURN v_run_id;
END;
$$;


ALTER FUNCTION "execution"."fn_run_lens"("p_lens_id" "uuid", "p_version_id" "uuid", "p_model_id" "uuid", "p_inputs" "jsonb", "p_funding_source" "text", "p_byok_key_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_run_lens"("p_lens_id" "uuid", "p_version_id" "uuid", "p_model_id" "uuid", "p_inputs" "jsonb", "p_funding_source" "text", "p_byok_key_id" "uuid") IS 'SECURITY DEFINER: Creates execution.requests (with version_id) and execution.runs atomically. Validates p_inputs against lenses.version_parameters before creating the request — rejects missing required params, type mismatches, and invalid select values. Upserts supplied parameter values into lenses.version_parameter_contents so the user''s last-used inputs are persisted per (parameter, workspace, lenser). Returns the run_id. Caller must be authenticated. Lens must be public or owned by caller.';



CREATE OR REPLACE FUNCTION "execution"."fn_run_lens"("p_lens_id" "uuid", "p_version_id" "uuid", "p_model_id" "uuid", "p_inputs" "jsonb" DEFAULT '{}'::"jsonb", "p_funding_source" "text" DEFAULT 'platform_credit'::"text", "p_byok_key_id" "uuid" DEFAULT NULL::"uuid", "p_workspace_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'lenses', 'lensers', 'tenancy', 'public'
    AS $$
DECLARE
  v_lenser_id    uuid := "lensers"."get_auth_lenser_id"();
  v_workspace_id uuid;
  v_request_id   uuid;
  v_run_id       uuid;
  v_param_rec    RECORD;
  v_value        text;
BEGIN
  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- Verify the lens exists and is accessible by the caller
  IF NOT EXISTS (
    SELECT 1 FROM "lenses"."lenses" l
    WHERE  l."id" = p_lens_id
      AND  (l."visibility" = 'public' OR l."lenser_id" = v_lenser_id)
  ) THEN
    RAISE EXCEPTION 'Lens % not found or access denied', p_lens_id
      USING ERRCODE = 'no_data_found';
  END IF;

  -- Validate inputs against version_parameters schema
  -- (required presence, type compatibility, select enum membership)
  PERFORM "lenses"."fn_validate_inputs"(p_version_id, p_inputs);

  -- Resolve workspace: use provided value or fall back to lenser's personal workspace
  v_workspace_id := COALESCE(p_workspace_id, (
    SELECT "w"."id"
    FROM   "tenancy"."workspaces" w
    WHERE  "w"."owner_lenser_id" = v_lenser_id
      AND  "w"."type"            = 'personal'
      AND  "w"."status"          = 'active'
    ORDER  BY "w"."created_at" ASC
    LIMIT  1
  ));

  -- Create execution request
  INSERT INTO "execution"."requests" (
    "requester_lenser_id",
    "lens_id",
    "version_id",
    "model_id",
    "input_snapshot",
    "funding_source",
    "byok_key_ref_id",
    "workspace_id",
    "origin_type",
    "runtime_origin"
  ) VALUES (
    v_lenser_id,
    p_lens_id,
    p_version_id,
    p_model_id,
    p_inputs,
    p_funding_source,
    p_byok_key_id,
    v_workspace_id,
    'web',
    'cloud'
  )
  RETURNING "id" INTO v_request_id;

  -- Create execution run (queued → picked up by cloud worker)
  INSERT INTO "execution"."runs" (
    "request_id",
    "model_id",
    "status",
    "created_at"
  ) VALUES (
    v_request_id,
    p_model_id,
    'queued',
    now()
  )
  RETURNING "id" INTO v_run_id;

  -- Upsert used parameter values into lenses.version_parameter_contents.
  -- Input keys are matched by parameter label (consistent with fn_create_lens).
  IF p_version_id IS NOT NULL AND v_workspace_id IS NOT NULL THEN
    FOR v_param_rec IN
      SELECT vp."id", vp."label" AS "key"
      FROM   "lenses"."version_parameters" vp
      WHERE  vp."version_id" = p_version_id
      LIMIT  200
    LOOP
      v_value := p_inputs->>v_param_rec."key";
      CONTINUE WHEN v_value IS NULL;

      INSERT INTO "lenses"."version_parameter_contents" (
        "parameter_id",
        "lenser_id",
        "workspace_id",
        "contents"
      ) VALUES (
        v_param_rec."id",
        v_lenser_id,
        v_workspace_id,
        jsonb_build_object('value', v_value)
      )
      ON CONFLICT ("parameter_id", "workspace_id", "lenser_id")
      DO UPDATE SET
        "contents"   = jsonb_build_object('value', v_value),
        "updated_at" = now();
    END LOOP;
  END IF;

  RETURN v_run_id;
END;
$$;


ALTER FUNCTION "execution"."fn_run_lens"("p_lens_id" "uuid", "p_version_id" "uuid", "p_model_id" "uuid", "p_inputs" "jsonb", "p_funding_source" "text", "p_byok_key_id" "uuid", "p_workspace_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_run_lens"("p_lens_id" "uuid", "p_version_id" "uuid", "p_model_id" "uuid", "p_inputs" "jsonb", "p_funding_source" "text", "p_byok_key_id" "uuid", "p_workspace_id" "uuid") IS 'SECURITY DEFINER: Creates execution.requests (with version_id) and execution.runs atomically. Validates p_inputs against lenses.version_parameters before creating the request. Upserts supplied parameter values into lenses.version_parameter_contents. Returns the run_id. Caller must be authenticated. Lens must be public or owned by caller.';



CREATE OR REPLACE FUNCTION "execution"."fn_run_lens_api"("p_lens_id" "uuid", "p_version_id" "uuid", "p_model_id" "uuid", "p_inputs" "jsonb" DEFAULT '{}'::"jsonb", "p_funding_source" "text" DEFAULT 'platform_credit'::"text", "p_byok_key_id" "uuid" DEFAULT NULL::"uuid", "p_idempotency_key" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'lenses', 'lensers', 'tenancy', 'public'
    AS $$
DECLARE
  v_lenser_id uuid := lensers.get_auth_lenser_id();
  v_workspace_id uuid;
  v_request_id uuid;
  v_run_id uuid;
  v_existing_run_id uuid;
  v_param_rec RECORD;
  v_value text;
BEGIN
  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  IF p_idempotency_key IS NOT NULL THEN
    SELECT r.id
      INTO v_existing_run_id
    FROM execution.requests req
    JOIN execution.runs r
      ON r.request_id = req.id
     AND r.is_active = true
    WHERE req.requester_lenser_id = v_lenser_id
      AND req.idempotency_key = p_idempotency_key
      AND req.lens_id = p_lens_id
      AND req.is_active = true
    ORDER BY req.created_at DESC
    LIMIT 1;

    IF v_existing_run_id IS NOT NULL THEN
      RETURN v_existing_run_id;
    END IF;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM lenses.lenses l
    WHERE l.id = p_lens_id
      AND (l.visibility = 'public' OR l.lenser_id = v_lenser_id)
  ) THEN
    RAISE EXCEPTION 'Lens % not found or access denied', p_lens_id
      USING ERRCODE = 'no_data_found';
  END IF;

  PERFORM lenses.fn_validate_inputs(p_version_id, p_inputs);

  v_workspace_id := (
    SELECT w.id
    FROM tenancy.workspaces w
    WHERE w.owner_lenser_id = v_lenser_id
      AND w.type = 'personal'
      AND w.status = 'active'
    ORDER BY w.created_at ASC
    LIMIT 1
  );

  INSERT INTO execution.requests (
    requester_lenser_id,
    lens_id,
    version_id,
    model_id,
    input_snapshot,
    funding_source,
    byok_key_ref_id,
    workspace_id,
    origin_type,
    runtime_origin,
    idempotency_key
  ) VALUES (
    v_lenser_id,
    p_lens_id,
    p_version_id,
    p_model_id,
    p_inputs,
    p_funding_source,
    p_byok_key_id,
    v_workspace_id,
    'api',
    'cloud',
    p_idempotency_key
  )
  RETURNING id INTO v_request_id;

  INSERT INTO execution.runs (
    request_id,
    model_id,
    status,
    created_at
  ) VALUES (
    v_request_id,
    p_model_id,
    'queued',
    now()
  )
  RETURNING id INTO v_run_id;

  IF p_version_id IS NOT NULL AND v_workspace_id IS NOT NULL THEN
    FOR v_param_rec IN
      SELECT id, key
      FROM lenses.version_parameters
      WHERE version_id = p_version_id
    LOOP
      v_value := p_inputs->>v_param_rec.key;
      CONTINUE WHEN v_value IS NULL;

      INSERT INTO lenses.version_parameter_contents (
        parameter_id,
        lenser_id,
        workspace_id,
        contents
      ) VALUES (
        v_param_rec.id,
        v_lenser_id,
        v_workspace_id,
        jsonb_build_object('value', v_value)
      )
      ON CONFLICT (parameter_id, workspace_id, lenser_id)
      DO UPDATE SET
        contents = jsonb_build_object('value', v_value),
        updated_at = now();
    END LOOP;
  END IF;

  RETURN v_run_id;
END;
$$;


ALTER FUNCTION "execution"."fn_run_lens_api"("p_lens_id" "uuid", "p_version_id" "uuid", "p_model_id" "uuid", "p_inputs" "jsonb", "p_funding_source" "text", "p_byok_key_id" "uuid", "p_idempotency_key" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "execution"."fn_runner_bind_device"("p_runner_id" "uuid", "p_device_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'devices', 'lensers', 'public', 'extensions'
    AS $$
DECLARE
  v_lenser_id UUID;
  v_binding_id UUID;
BEGIN
  SELECT id INTO v_lenser_id
  FROM lensers.profiles
  WHERE user_id = auth.uid() AND status = 'active'
  LIMIT 1;

  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'active_lenser_required';
  END IF;

  -- Verify the device belongs to the caller
  IF NOT EXISTS (
    SELECT 1 FROM devices.registered_devices
    WHERE id = p_device_id
      AND lenser_id = v_lenser_id
      AND trust_level IN ('approved','trusted')
  ) THEN
    RAISE EXCEPTION 'device_not_found_or_not_trusted';
  END IF;

  INSERT INTO execution.runner_device_bindings (runner_id, device_id, status)
  VALUES (p_runner_id, p_device_id, 'active')
  ON CONFLICT (runner_id, device_id) DO UPDATE
    SET status = 'active', bound_at = now()
  RETURNING id INTO v_binding_id;

  RETURN v_binding_id;
END;
$$;


ALTER FUNCTION "execution"."fn_runner_bind_device"("p_runner_id" "uuid", "p_device_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "execution"."fn_runner_list_with_devices"("p_limit" integer DEFAULT 50, "p_cursor" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("runner_id" "uuid", "device_id" "uuid", "device_name" "text", "trust_level" "text", "binding_status" "text", "bound_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'devices', 'lensers', 'public', 'extensions'
    AS $$
DECLARE
  v_lenser_id UUID;
BEGIN
  SELECT id INTO v_lenser_id
  FROM lensers.profiles
  WHERE user_id = auth.uid()
  LIMIT 1;

  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'auth_required';
  END IF;

  p_limit := LEAST(p_limit, 100);

  RETURN QUERY
  SELECT
    b.runner_id,
    b.device_id,
    d.name  AS device_name,
    d.trust_level,
    b.status AS binding_status,
    b.bound_at
  FROM execution.runner_device_bindings b
  JOIN devices.registered_devices d ON d.id = b.device_id
  WHERE d.lenser_id = v_lenser_id
    AND (p_cursor IS NULL OR b.id > p_cursor)
  ORDER BY b.bound_at DESC
  LIMIT p_limit;
END;
$$;


ALTER FUNCTION "execution"."fn_runner_list_with_devices"("p_limit" integer, "p_cursor" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "execution"."fn_set_artifact_visibility"("p_artifact_id" "uuid", "p_visibility" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'lensers', 'public'
    AS $$
DECLARE
  v_caller_id   uuid := "lensers"."get_auth_lenser_id"();
  v_run_status  text;
  v_owner_id    uuid;
BEGIN
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- Validate visibility value
  IF p_visibility NOT IN ('private', 'public', 'contender_only', 'archived') THEN
    RAISE EXCEPTION 'Invalid visibility value: %', p_visibility
      USING ERRCODE = 'check_violation';
  END IF;

  -- Fetch run status + owner
  SELECT r."status", req."requester_lenser_id"
  INTO   v_run_status, v_owner_id
  FROM   "execution"."artifacts" a
  JOIN   "execution"."runs"     r   ON r."id"  = a."run_id"
  JOIN   "execution"."requests" req ON req."id" = r."request_id"
  WHERE  a."id" = p_artifact_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Artifact % not found', p_artifact_id
      USING ERRCODE = 'no_data_found';
  END IF;

  -- Ownership check
  IF v_owner_id <> v_caller_id THEN
    RAISE EXCEPTION 'Permission denied: you do not own this artifact'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- Non-succeeded runs can only be set to 'private'
  IF v_run_status <> 'succeeded' AND p_visibility <> 'private' THEN
    RAISE EXCEPTION
      'Artifact from a % run can only be set to private visibility',
      v_run_status
      USING ERRCODE = 'check_violation';
  END IF;

  -- Apply
  UPDATE "execution"."artifacts"
  SET    "visibility" = p_visibility
  WHERE  "id" = p_artifact_id;
END;
$$;


ALTER FUNCTION "execution"."fn_set_artifact_visibility"("p_artifact_id" "uuid", "p_visibility" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_set_artifact_visibility"("p_artifact_id" "uuid", "p_visibility" "text") IS 'SECURITY DEFINER: allows the artifact creator (owner) to change visibility. Validates: caller owns artifact via run→request→requester_lenser_id; non-succeeded run artifacts can only be private; valid visibility values only. Values: private (default), public (all users), contender_only, archived (owner only).';



CREATE OR REPLACE FUNCTION "execution"."fn_start_execution"("p_lenser_id" "uuid", "p_origin_type" "text", "p_funding_source" "text", "p_model_id" "uuid" DEFAULT NULL::"uuid", "p_lens_id" "uuid" DEFAULT NULL::"uuid", "p_workspace_id" "uuid" DEFAULT NULL::"uuid", "p_byok_key_ref_id" "uuid" DEFAULT NULL::"uuid", "p_input_snapshot" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("request_id" "uuid", "run_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'tenancy', 'public'
    AS $$
DECLARE
    v_request_id   "uuid";
    v_run_id       "uuid";
    v_workspace_id "uuid";
BEGIN
    -- Resolve workspace: caller may pass an explicit workspace_id (e.g. an org
    -- workspace), or NULL in which case we fall back to the lenser's personal
    -- workspace.  If that also doesn't exist the INSERT will error with a clear
    -- FK violation rather than silently using a wrong UUID.
    v_workspace_id := COALESCE(
        p_workspace_id,
        (
            SELECT w.id
            FROM   tenancy.workspaces w
            WHERE  w.owner_lenser_id = p_lenser_id
              AND  w.type            = 'personal'
              AND  w.status          = 'active'
            ORDER  BY w.created_at ASC
            LIMIT  1
        )
    );

    INSERT INTO "execution"."requests" (
        "requester_lenser_id",
        "origin_type",
        "funding_source",
        "model_id",
        "lens_id",
        "workspace_id",
        "byok_key_ref_id",
        "input_snapshot"
    ) VALUES (
        p_lenser_id,
        p_origin_type,
        p_funding_source,
        p_model_id,
        p_lens_id,
        v_workspace_id,
        p_byok_key_ref_id,
        p_input_snapshot
    )
    RETURNING "id" INTO v_request_id;

    INSERT INTO "execution"."runs" (
        "request_id",
        "status",
        "model_id",
        "started_at"
    ) VALUES (
        v_request_id,
        'running',
        p_model_id,
        now()
    )
    RETURNING "id" INTO v_run_id;

    RETURN QUERY SELECT v_request_id, v_run_id;
END;
$$;


ALTER FUNCTION "execution"."fn_start_execution"("p_lenser_id" "uuid", "p_origin_type" "text", "p_funding_source" "text", "p_model_id" "uuid", "p_lens_id" "uuid", "p_workspace_id" "uuid", "p_byok_key_ref_id" "uuid", "p_input_snapshot" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_start_execution"("p_lenser_id" "uuid", "p_origin_type" "text", "p_funding_source" "text", "p_model_id" "uuid", "p_lens_id" "uuid", "p_workspace_id" "uuid", "p_byok_key_ref_id" "uuid", "p_input_snapshot" "jsonb") IS 'Atomically creates execution.requests + execution.runs before the provider is called. Returns (request_id, run_id). Run is opened with status=running. When p_workspace_id is NULL, auto-resolves the lenser''s personal workspace (same pattern as execution.fn_run_lens). SECURITY DEFINER; callable only by service_role.';



CREATE OR REPLACE FUNCTION "execution"."fn_timeout_stale_runs"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'public'
    AS $$
DECLARE
  v_count INT;
BEGIN
  UPDATE execution.runs
  SET status = 'timed_out', completed_at = now()
  WHERE is_async = TRUE
    AND status = 'running'
    AND started_at < now() - INTERVAL '15 minutes';
  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;


ALTER FUNCTION "execution"."fn_timeout_stale_runs"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "execution"."fn_verify_attestation_signature"("p_kid" "uuid", "p_canonical_jcs" "bytea", "p_signature" "bytea") RETURNS TABLE("verified" boolean, "invalid_reason" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'devices', 'extensions', 'public'
    AS $_$
DECLARE
  v_pk_b64       TEXT;
  v_pk           BYTEA;
  v_pgsodium_ok  BOOLEAN;
  v_ok           BOOLEAN;
BEGIN
  IF p_kid IS NULL OR p_canonical_jcs IS NULL OR p_signature IS NULL THEN
    RETURN QUERY SELECT false, 'missing_input';
    RETURN;
  END IF;

  IF length(p_signature) <> 64 THEN
    RETURN QUERY SELECT false, 'bad_signature_length';
    RETURN;
  END IF;

  SELECT rd.public_key INTO v_pk_b64
  FROM devices.registered_devices rd
  WHERE rd.id = p_kid
    AND COALESCE(rd.signing_algo, 'ed25519') = 'ed25519';

  IF v_pk_b64 IS NULL THEN
    RETURN QUERY SELECT false, 'unknown_device_or_algo';
    RETURN;
  END IF;

  -- The keychain stores raw 32-byte Ed25519 public keys as base64url.
  v_pk := execution.fn_b64url_decode(v_pk_b64);
  IF v_pk IS NULL OR length(v_pk) <> 32 THEN
    -- Some clients may have submitted standard base64; try that as a fallback.
    BEGIN
      v_pk := decode(v_pk_b64, 'base64');
    EXCEPTION WHEN OTHERS THEN
      v_pk := NULL;
    END;
    IF v_pk IS NULL OR length(v_pk) <> 32 THEN
      RETURN QUERY SELECT false, 'malformed_public_key';
      RETURN;
    END IF;
  END IF;

  SELECT EXISTS (SELECT 1 FROM pg_extension WHERE extname = 'pgsodium')
    INTO v_pgsodium_ok;
  IF NOT v_pgsodium_ok THEN
    RETURN QUERY SELECT false, 'pgsodium_unavailable';
    RETURN;
  END IF;

  BEGIN
    EXECUTE 'SELECT pgsodium.crypto_sign_verify_detached($1, $2, $3)'
      INTO v_ok
      USING p_signature, p_canonical_jcs, v_pk;
  EXCEPTION WHEN OTHERS THEN
    v_ok := NULL;
  END;

  IF v_ok IS TRUE THEN
    RETURN QUERY SELECT true, NULL::TEXT;
  ELSIF v_ok IS FALSE THEN
    RETURN QUERY SELECT false, 'signature_invalid';
  ELSE
    RETURN QUERY SELECT false, 'pgsodium_call_failed';
  END IF;
END;
$_$;


ALTER FUNCTION "execution"."fn_verify_attestation_signature"("p_kid" "uuid", "p_canonical_jcs" "bytea", "p_signature" "bytea") OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."fn_verify_attestation_signature"("p_kid" "uuid", "p_canonical_jcs" "bytea", "p_signature" "bytea") IS 'Ed25519 verification of an attestation envelope. Returns (verified, invalid_reason). Never grants verified=true silently if pgsodium is missing.';



CREATE OR REPLACE FUNCTION "execution"."fn_xp_apply_safe"("p_lenser_id" "uuid", "p_rule_key" "text", "p_source" "xp"."source_enum", "p_source_ref_type" "text", "p_source_ref_id" "uuid", "p_app_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'xp', 'public', 'extensions'
    AS $$
BEGIN
  IF p_lenser_id IS NULL OR p_rule_key IS NULL THEN
    RETURN;
  END IF;
  BEGIN
    PERFORM xp.apply(
      p_lenser_id, p_rule_key, p_source,
      p_source_ref_type, p_source_ref_id, p_app_id
    );
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'xp.apply failed for rule % on lenser %: %',
      p_rule_key, p_lenser_id, SQLERRM;
  END;
END;
$$;


ALTER FUNCTION "execution"."fn_xp_apply_safe"("p_lenser_id" "uuid", "p_rule_key" "text", "p_source" "xp"."source_enum", "p_source_ref_type" "text", "p_source_ref_id" "uuid", "p_app_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "execution"."fn_xp_on_full_trust"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'battles', 'lensers', 'xp', 'public', 'extensions'
    AS $$
DECLARE
  v_owner_lenser_id uuid;
  v_should_award    boolean := false;
BEGIN
  IF NEW.trust_level <> 'fully_trusted' THEN
    RETURN NEW;
  END IF;
  IF TG_OP = 'UPDATE' AND OLD.trust_level = 'fully_trusted' THEN
    -- already at full trust; do not re-award
    RETURN NEW;
  END IF;
  v_should_award := true;

  -- Owner = the run requester (and the submission belongs to them).
  SELECT req.requester_lenser_id INTO v_owner_lenser_id
  FROM battles.submissions s
  JOIN execution.runs r       ON r.id = s.execution_run_id
  JOIN execution.requests req ON req.id = r.request_id
  WHERE s.id = NEW.submission_id
  LIMIT 1;

  IF NOT v_should_award OR v_owner_lenser_id IS NULL THEN
    RETURN NEW;
  END IF;

  PERFORM execution.fn_xp_apply_safe(
    v_owner_lenser_id,
    'VERIFIED_LOCAL_EXECUTION_COMPLETED',
    'battle'::xp.source_enum,
    'submission',
    NEW.submission_id,
    '00000000-0000-0000-0000-000000000002'::uuid
  );
  RETURN NEW;
END;
$$;


ALTER FUNCTION "execution"."fn_xp_on_full_trust"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "execution"."fn_xp_on_runner_bound"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'devices', 'xp', 'public', 'extensions'
    AS $$
DECLARE
  v_lenser_id uuid;
  v_trust_ok  boolean;
BEGIN
  IF COALESCE(NEW.status, 'inactive') <> 'active' THEN
    RETURN NEW;
  END IF;
  IF TG_OP = 'UPDATE'
     AND COALESCE(OLD.status, 'inactive') = 'active'
  THEN
    -- already active before; do not re-award
    RETURN NEW;
  END IF;

  SELECT rd.lenser_id, rd.trust_level IN ('approved', 'trusted')
    INTO v_lenser_id, v_trust_ok
  FROM devices.registered_devices rd
  WHERE rd.id = NEW.device_id;

  IF v_lenser_id IS NULL OR NOT COALESCE(v_trust_ok, false) THEN
    RETURN NEW;
  END IF;

  PERFORM execution.fn_xp_apply_safe(
    v_lenser_id,
    'RUNNER_CONNECTED',
    'system'::xp.source_enum,
    'runner',
    NEW.runner_id,
    '00000000-0000-0000-0000-000000000003'::uuid
  );
  RETURN NEW;
END;
$$;


ALTER FUNCTION "execution"."fn_xp_on_runner_bound"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "execution"."fn_xp_on_submission_evaluated"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'battles', 'lensers', 'xp', 'public', 'extensions'
    AS $$
DECLARE
  v_owner_lenser_id uuid;
BEGIN
  -- Only fire on initial INSERT; updates are re-evaluations of the same
  -- submission and would double-award.
  IF TG_OP <> 'INSERT' THEN
    RETURN NEW;
  END IF;
  IF NEW.trust_level = 'unverified' THEN
    RETURN NEW;
  END IF;

  SELECT req.requester_lenser_id INTO v_owner_lenser_id
  FROM battles.submissions s
  JOIN execution.runs r       ON r.id = s.execution_run_id
  JOIN execution.requests req ON req.id = r.request_id
  WHERE s.id = NEW.submission_id
  LIMIT 1;

  IF v_owner_lenser_id IS NULL THEN
    RETURN NEW;
  END IF;

  PERFORM execution.fn_xp_apply_safe(
    v_owner_lenser_id,
    'BATTLE_SUBMISSION_COMPLETED',
    'battle'::xp.source_enum,
    'submission',
    NEW.submission_id,
    '00000000-0000-0000-0000-000000000002'::uuid
  );
  RETURN NEW;
END;
$$;


ALTER FUNCTION "execution"."fn_xp_on_submission_evaluated"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "execution"."insert_stream_run"("p_run_id" "uuid", "p_lenser_id" "uuid", "p_model_id" "uuid", "p_provider_key" "text", "p_model_key" "text", "p_input_snapshot" "jsonb", "p_token_input" integer, "p_token_output" integer, "p_credit_cost" bigint, "p_status" "text", "p_error_code" "text" DEFAULT NULL::"text", "p_bytes_sent" integer DEFAULT 0) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'public'
    AS $$
DECLARE
    v_request_id uuid;
    v_billing_status text;
BEGIN
    -- Resolve billing_status from credit cost
    v_billing_status := CASE WHEN p_credit_cost > 0 THEN 'charged' ELSE 'free' END;

    -- Insert execution request row
    INSERT INTO execution.requests (
        requester_lenser_id,
        origin_type,
        model_id,
        input_snapshot,
        funding_source,
        runtime_origin
    ) VALUES (
        p_lenser_id,
        'api_stream',
        p_model_id,
        p_input_snapshot,
        'platform_credit',
        'cloud'
    )
    RETURNING id INTO v_request_id;

    -- Insert execution run row (id = p_run_id for idempotency via pending_charges FK)
    INSERT INTO execution.runs (
        id,
        request_id,
        status,
        model_id,
        token_input,
        token_output,
        credit_cost,
        billing_status,
        started_at,
        completed_at
    ) VALUES (
        p_run_id,
        v_request_id,
        p_status,
        p_model_id,
        p_token_input,
        p_token_output,
        p_credit_cost,
        v_billing_status,
        now(),
        CASE WHEN p_status IN ('succeeded', 'failed', 'timed_out') THEN now() ELSE NULL END
    )
    ON CONFLICT (id) DO UPDATE SET
        status          = EXCLUDED.status,
        token_input     = EXCLUDED.token_input,
        token_output    = EXCLUDED.token_output,
        credit_cost     = EXCLUDED.credit_cost,
        billing_status  = EXCLUDED.billing_status,
        completed_at    = EXCLUDED.completed_at;

    -- Upsert stream session
    INSERT INTO execution.stream_sessions (
        run_id,
        lenser_id,
        provider,
        model_key,
        status,
        token_input,
        token_output,
        credit_cost,
        error_code,
        bytes_sent,
        completed_at
    ) VALUES (
        p_run_id,
        p_lenser_id,
        p_provider_key,
        p_model_key,
        CASE p_status
            WHEN 'succeeded' THEN 'completed'
            WHEN 'failed'    THEN 'failed'
            WHEN 'timed_out' THEN 'timed_out'
            ELSE p_status
        END,
        p_token_input,
        p_token_output,
        p_credit_cost,
        p_error_code,
        p_bytes_sent,
        CASE WHEN p_status IN ('succeeded', 'failed', 'timed_out') THEN now() ELSE NULL END
    )
    ON CONFLICT (run_id) DO UPDATE SET
        status       = EXCLUDED.status,
        token_input  = EXCLUDED.token_input,
        token_output = EXCLUDED.token_output,
        credit_cost  = EXCLUDED.credit_cost,
        error_code   = EXCLUDED.error_code,
        bytes_sent   = EXCLUDED.bytes_sent,
        completed_at = EXCLUDED.completed_at;
END;
$$;


ALTER FUNCTION "execution"."insert_stream_run"("p_run_id" "uuid", "p_lenser_id" "uuid", "p_model_id" "uuid", "p_provider_key" "text", "p_model_key" "text", "p_input_snapshot" "jsonb", "p_token_input" integer, "p_token_output" integer, "p_credit_cost" bigint, "p_status" "text", "p_error_code" "text", "p_bytes_sent" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "execution"."insert_stream_run"("p_run_id" "uuid", "p_lenser_id" "uuid", "p_model_id" "uuid", "p_provider_key" "text", "p_model_key" "text", "p_input_snapshot" "jsonb", "p_token_input" integer, "p_token_output" integer, "p_credit_cost" bigint, "p_status" "text", "p_error_code" "text", "p_bytes_sent" integer) IS 'Atomically records a streaming AI execution run across execution.requests, execution.runs, and execution.stream_sessions. Called by the Cloudflare Worker after stream completion or failure.';



CREATE OR REPLACE FUNCTION "execution"."trg_runs_set_completed_at"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'execution'
    AS $$
BEGIN
    IF NEW.status IN ('succeeded', 'failed', 'canceled', 'timed_out')
       AND OLD.status NOT IN ('succeeded', 'failed', 'canceled', 'timed_out')
       AND NEW.completed_at IS NULL THEN
        NEW.completed_at := NOW();
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION "execution"."trg_runs_set_completed_at"() OWNER TO "postgres";


