ALTER FUNCTION "lensers"."fn_create_default_preferences"() OWNER TO "postgres";


COMMENT ON FUNCTION "lensers"."fn_create_default_preferences"() IS 'Trigger function: creates a default preferences row for every new lenser profile. SECURITY DEFINER to bypass RLS on insert.';



CREATE OR REPLACE FUNCTION "lensers"."fn_prevent_preferences_delete"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lensers', 'public'
    AS $$
BEGIN
    -- Allow deletion only when the parent profile is already gone (cascade path).
    -- If the profile still exists, the caller is trying to delete preferences directly.
    IF EXISTS (SELECT 1 FROM lensers.profiles WHERE id = OLD.lenser_id) THEN
        RAISE EXCEPTION
            'Cannot delete lensers.preferences directly for lenser %. '
            'Delete the lensers.profiles row instead — preferences will cascade.',
            OLD.lenser_id
        USING ERRCODE = 'P0001';
    END IF;
    RETURN OLD;
END;
$$;


ALTER FUNCTION "lensers"."fn_prevent_preferences_delete"() OWNER TO "postgres";


COMMENT ON FUNCTION "lensers"."fn_prevent_preferences_delete"() IS 'BEFORE DELETE guard on lensers.preferences. Blocks direct deletion when the parent profile still exists. Cascade deletes from lensers.profiles are still allowed (profile gone before trigger checks).';



CREATE OR REPLACE FUNCTION "lensers"."fn_prevent_self_relationship"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'lensers'
    AS $$
BEGIN
    IF NEW.source_profile_id = NEW.target_profile_id THEN
        RAISE EXCEPTION 'A lenser cannot follow themselves'
            USING ERRCODE = '23514';
    END IF;
    RETURN NEW;
END;
$$;


ALTER FUNCTION "lensers"."fn_prevent_self_relationship"() OWNER TO "postgres";


COMMENT ON FUNCTION "lensers"."fn_prevent_self_relationship"() IS 'BEFORE trigger guard: rejects any INSERT or UPDATE that would create a self-referential relationship (source_profile_id = target_profile_id). Raises SQLSTATE 23514 (check_violation) for consistent client handling. Belt-and-suspenders alongside the chk_no_self_rel CHECK constraint. Added in migration 000056.';



CREATE OR REPLACE FUNCTION "lensers"."fn_relationship_state"("p_viewer_id" "uuid", "p_subject_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'lensers', 'public'
    AS $$
DECLARE
  v_viewer_to_subject lensers.relationship_status;
  v_subject_to_viewer lensers.relationship_status;
  v_is_mutual boolean := false;
  v_is_blocked boolean := false;
  v_is_close_circle boolean := false;
BEGIN
  IF p_viewer_id IS NULL OR p_subject_id IS NULL OR p_viewer_id = p_subject_id THEN
    RETURN jsonb_build_object(
      'viewer_to_subject', null,
      'subject_to_viewer', null,
      'is_mutual', false,
      'is_blocked', false,
      'is_close_circle', false
    );
  END IF;

  SELECT r.status, r.is_close_circle INTO v_viewer_to_subject, v_is_close_circle
  FROM lensers.relationships r
  WHERE r.source_profile_id = p_viewer_id AND r.target_profile_id = p_subject_id
    AND r.status IN ('pending', 'accepted', 'blocked');

  SELECT r.status INTO v_subject_to_viewer
  FROM lensers.relationships r
  WHERE r.source_profile_id = p_subject_id AND r.target_profile_id = p_viewer_id
    AND r.status IN ('pending', 'accepted', 'blocked');

  v_is_blocked := (v_viewer_to_subject = 'blocked') OR (v_subject_to_viewer = 'blocked');
  v_is_mutual := (v_viewer_to_subject = 'accepted') AND (v_subject_to_viewer = 'accepted');

  RETURN jsonb_build_object(
    'viewer_to_subject', v_viewer_to_subject,
    'subject_to_viewer', v_subject_to_viewer,
    'is_mutual', v_is_mutual,
    'is_blocked', v_is_blocked,
    'is_close_circle', v_is_close_circle
  );
END;
$$;


ALTER FUNCTION "lensers"."fn_relationship_state"("p_viewer_id" "uuid", "p_subject_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "lensers"."fn_sync_relationship_counts"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'lensers', 'analytics'
    AS $$
DECLARE
  v_is_mutual boolean;
BEGIN
  -- Handle INSERT
  IF TG_OP = 'INSERT' AND NEW.status = 'accepted' THEN
    INSERT INTO analytics.lenser_stats (lenser_id, follower_count)
      VALUES (NEW.target_profile_id, 1)
      ON CONFLICT (lenser_id) DO UPDATE
        SET follower_count = analytics.lenser_stats.follower_count + 1, updated_at = now();

    INSERT INTO analytics.lenser_stats (lenser_id, following_count)
      VALUES (NEW.source_profile_id, 1)
      ON CONFLICT (lenser_id) DO UPDATE
        SET following_count = analytics.lenser_stats.following_count + 1, updated_at = now();

    -- Check mutual
    SELECT EXISTS (
      SELECT 1 FROM lensers.relationships
      WHERE source_profile_id = NEW.target_profile_id
        AND target_profile_id = NEW.source_profile_id
        AND status = 'accepted'
    ) INTO v_is_mutual;

    IF v_is_mutual THEN
      UPDATE analytics.lenser_stats
        SET mutuals_count = mutuals_count + 1, updated_at = now()
        WHERE lenser_id IN (NEW.source_profile_id, NEW.target_profile_id);
    END IF;

  -- Handle UPDATE (status change)
  ELSIF TG_OP = 'UPDATE' THEN
    -- Became accepted
    IF OLD.status <> 'accepted' AND NEW.status = 'accepted' THEN
      UPDATE analytics.lenser_stats
        SET follower_count = follower_count + 1, updated_at = now()
        WHERE lenser_id = NEW.target_profile_id;
      UPDATE analytics.lenser_stats
        SET following_count = following_count + 1, updated_at = now()
        WHERE lenser_id = NEW.source_profile_id;

      SELECT EXISTS (
        SELECT 1 FROM lensers.relationships
        WHERE source_profile_id = NEW.target_profile_id
          AND target_profile_id = NEW.source_profile_id
          AND status = 'accepted'
      ) INTO v_is_mutual;

      IF v_is_mutual THEN
        UPDATE analytics.lenser_stats
          SET mutuals_count = mutuals_count + 1, updated_at = now()
          WHERE lenser_id IN (NEW.source_profile_id, NEW.target_profile_id);
      END IF;
    END IF;

    -- Was accepted, now not
    IF OLD.status = 'accepted' AND NEW.status <> 'accepted' THEN
      UPDATE analytics.lenser_stats
        SET follower_count = GREATEST(0, follower_count - 1), updated_at = now()
        WHERE lenser_id = NEW.target_profile_id;
      UPDATE analytics.lenser_stats
        SET following_count = GREATEST(0, following_count - 1), updated_at = now()
        WHERE lenser_id = NEW.source_profile_id;

      -- Check if was mutual
      SELECT EXISTS (
        SELECT 1 FROM lensers.relationships
        WHERE source_profile_id = NEW.target_profile_id
          AND target_profile_id = NEW.source_profile_id
          AND status = 'accepted'
      ) INTO v_is_mutual;

      IF v_is_mutual THEN
        UPDATE analytics.lenser_stats
          SET mutuals_count = GREATEST(0, mutuals_count - 1), updated_at = now()
          WHERE lenser_id IN (NEW.source_profile_id, NEW.target_profile_id);
      END IF;
    END IF;

  -- Handle DELETE
  ELSIF TG_OP = 'DELETE' AND OLD.status = 'accepted' THEN
    UPDATE analytics.lenser_stats
      SET follower_count = GREATEST(0, follower_count - 1), updated_at = now()
      WHERE lenser_id = OLD.target_profile_id;
    UPDATE analytics.lenser_stats
      SET following_count = GREATEST(0, following_count - 1), updated_at = now()
      WHERE lenser_id = OLD.source_profile_id;
  END IF;

  RETURN NULL;
END;
$$;


ALTER FUNCTION "lensers"."fn_sync_relationship_counts"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "lensers"."fn_trg_notify_badge_awarded"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lensers', 'public'
    AS $$
DECLARE
  v_handle TEXT;
BEGIN
  SELECT handle INTO v_handle FROM lensers.profiles WHERE id = NEW.lenser_id;

  PERFORM public.fn_insert_notification(
    NEW.lenser_id,
    'badge_awarded',
    'You earned a badge: ' || NEW.label,
    NEW.description,
    '/lenser/' || COALESCE(v_handle, '') || '/badges',
    jsonb_build_object(
      'badge_id',       NEW.id,
      'badge_name',     NEW.label,
      'badge_type',     NEW.type::text,
      'badge_category', NEW.category::text,
      'icon',           NEW.icon
    )
    -- p_actor_id = NULL
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'fn_trg_notify_badge_awarded failed for lenser %: %', NEW.lenser_id, SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "lensers"."fn_trg_notify_badge_awarded"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "lensers"."fn_xp_on_follow"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lensers', 'xp', 'public'
    AS $$
DECLARE
  v_app_id uuid;
BEGIN
  -- Only award XP when the relationship status becomes 'accepted'
  IF NEW.status != 'accepted' THEN
    RETURN NEW;
  END IF;
  -- Skip if this is an UPDATE and the status was already 'accepted'
  IF TG_OP = 'UPDATE' AND OLD.status = 'accepted' THEN
    RETURN NEW;
  END IF;

  -- Resolve platform app_id; fall back to forum app
  SELECT id INTO v_app_id FROM xp.apps WHERE slug = 'platform' LIMIT 1;
  IF v_app_id IS NULL THEN
    SELECT id INTO v_app_id FROM xp.apps WHERE slug = 'forum' LIMIT 1;
  END IF;
  IF v_app_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Award XP to the follower (source). xp.apply enforces daily cap idempotently.
  BEGIN
    PERFORM xp.apply(
      NEW.source_profile_id,
      'INVITE_ACCEPTED',
      'social'::xp.source_enum,
      'relationship',
      NEW.id,
      v_app_id
    );
  EXCEPTION WHEN OTHERS THEN
    NULL; -- non-fatal; never block the follow
  END;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "lensers"."fn_xp_on_follow"() OWNER TO "postgres";


