  END IF;

  -- Only act on REAL login event
  IF NEW.last_sign_in_at IS DISTINCT FROM OLD.last_sign_in_at THEN
    INSERT INTO analytics.lenser_activity (lenser_id, activity_type)
    VALUES (v_lenser_id, 'login');
  END IF;

  RETURN NEW;
END;$$;


