CREATE OR REPLACE FUNCTION "lenses"."fn_build_schedule_condition_context"("p_schedule_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'lenses', 'pg_catalog'
    AS $$
DECLARE
  v_workflow_id uuid;
  v_prior       jsonb;
  v_succeeded   integer;
  v_failed      integer;
  v_total       integer;
BEGIN
  SELECT s.workflow_id INTO v_workflow_id
  FROM lenses.workflow_schedules s
  WHERE s.id = p_schedule_id;

  IF v_workflow_id IS NULL THEN
    RETURN jsonb_build_object(
      'prior_run_result', NULL,
      'last_24h_stats', jsonb_build_object(
        'succeeded', 0, 'failed', 0, 'total', 0
      ),
      'signal_rpc_result', NULL
    );
  END IF;

  -- Most recent run's result block (NULL-safe).
  SELECT r.metadata -> 'result'
    INTO v_prior
  FROM lenses.workflow_runs r
  WHERE r.workflow_id = v_workflow_id
  ORDER BY r.created_at DESC
  LIMIT 1;

  -- 24h aggregate windowed by created_at.
  SELECT
    COALESCE(SUM(CASE WHEN r.status = 'completed' THEN 1 ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN r.status = 'failed'    THEN 1 ELSE 0 END), 0),
    COUNT(*)
  INTO v_succeeded, v_failed, v_total
  FROM lenses.workflow_runs r
  WHERE r.workflow_id = v_workflow_id
    AND r.created_at > now() - interval '24 hours';

  RETURN jsonb_build_object(
    'prior_run_result', v_prior,
    'last_24h_stats', jsonb_build_object(
      'succeeded', v_succeeded,
      'failed',    v_failed,
      'total',     v_total
    ),
    -- Future hook: operators may extend this builder to invoke a signal RPC
    -- (e.g. external KPI fetch) and merge the result here. Today: NULL.
    'signal_rpc_result', NULL
  );
END;
$$;


ALTER FUNCTION "lenses"."fn_build_schedule_condition_context"("p_schedule_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "lenses"."fn_build_schedule_condition_context"("p_schedule_id" "uuid") IS 'Phase W2: builds the jsonb context the dispatcher feeds to automation.fn_eval_filter when a schedule has pre_dispatch_condition. Shape: { prior_run_result, last_24h_stats:{succeeded,failed,total}, signal_rpc_result }. signal_rpc_result is reserved for a future operator hook and is currently always NULL.';



CREATE OR REPLACE FUNCTION "lenses"."fn_check_calendar"("p_calendar_id" "uuid", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'lenses', 'pg_catalog'
    AS $$
DECLARE
  v_kind     text;
  v_dates    date[];
  v_tz       text;
  v_local    date;
  v_in_set   boolean;
BEGIN
  IF p_calendar_id IS NULL THEN
    RETURN true;
  END IF;

  SELECT kind, dates, timezone
    INTO v_kind, v_dates, v_tz
  FROM lenses.schedule_calendars
  WHERE id = p_calendar_id;

  IF NOT FOUND THEN
    RETURN true;
  END IF;

  -- Resolve the wall-clock date in the calendar's timezone.
  BEGIN
    v_local := (p_now AT TIME ZONE v_tz)::date;
  EXCEPTION WHEN OTHERS THEN
    -- Bad timezone string: fail closed-ish — allow dispatch but log nothing.
    RETURN true;
  END;

  v_in_set := v_local = ANY(COALESCE(v_dates, ARRAY[]::date[]));

  IF v_kind = 'skip_dates' THEN
    RETURN NOT v_in_set;
  ELSIF v_kind = 'only_dates' THEN
    RETURN v_in_set;
  END IF;

  -- Defensive: unknown kind => allow.
  RETURN true;
END;
$$;


ALTER FUNCTION "lenses"."fn_check_calendar"("p_calendar_id" "uuid", "p_now" timestamp with time zone) OWNER TO "postgres";


COMMENT ON FUNCTION "lenses"."fn_check_calendar"("p_calendar_id" "uuid", "p_now" timestamp with time zone) IS 'Phase W1: returns TRUE when dispatch is allowed for the calendar overlay at p_now. NULL calendar or missing row => TRUE. Resolves p_now into the calendar timezone before checking date membership.';



CREATE OR REPLACE FUNCTION "lenses"."fn_check_dag_acyclic"("p_workflow_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'lenses'
    AS $$
DECLARE
  v_node_id      uuid;
  v_stack        uuid[];
  v_visited      uuid[];
  v_rec_stack    uuid[];
  v_has_cycle    boolean := false;
  v_adj          record;
  v_current      uuid;
  v_dfs_stack    uuid[];
  v_dfs_parent   uuid[];
BEGIN
  -- Collect all unique node IDs involved in edges for this workflow
  -- Use iterative DFS to avoid stack overflow on deep graphs

  FOR v_node_id IN
    SELECT DISTINCT unnest(ARRAY[source_node_id, target_node_id])
    FROM lenses.workflow_edges
    WHERE workflow_id = p_workflow_id
  LOOP
    -- Skip already fully visited nodes
    IF v_node_id = ANY(v_visited) THEN
      CONTINUE;
    END IF;

    -- Iterative DFS using explicit stack
    v_dfs_stack := ARRAY[v_node_id];
    v_rec_stack := ARRAY[]::uuid[];

    WHILE array_length(v_dfs_stack, 1) > 0 LOOP
      v_current := v_dfs_stack[array_length(v_dfs_stack, 1)];
      v_dfs_stack := v_dfs_stack[1:array_length(v_dfs_stack, 1) - 1];

      -- If current is a sentinel (NULL-marked pop), remove from rec_stack
      IF v_current IS NULL THEN
        IF array_length(v_dfs_stack, 1) > 0 THEN
          v_current := v_dfs_stack[array_length(v_dfs_stack, 1)];
          v_dfs_stack := v_dfs_stack[1:array_length(v_dfs_stack, 1) - 1];
          v_rec_stack := array_remove(v_rec_stack, v_current);
        END IF;
        CONTINUE;
      END IF;

      IF v_current = ANY(v_rec_stack) THEN
        -- Back edge found → cycle
        RETURN false;
      END IF;

      IF v_current = ANY(v_visited) THEN
        CONTINUE;
      END IF;

      v_visited := array_append(v_visited, v_current);
      v_rec_stack := array_append(v_rec_stack, v_current);

      -- Push sentinel to pop from rec_stack when backtracking
      v_dfs_stack := array_append(v_dfs_stack, v_current);
      v_dfs_stack := array_append(v_dfs_stack, NULL::uuid);

      -- Push all neighbors
      FOR v_adj IN
        SELECT target_node_id
        FROM lenses.workflow_edges
        WHERE workflow_id = p_workflow_id
          AND source_node_id = v_current
      LOOP
        IF v_adj.target_node_id = ANY(v_rec_stack) THEN
          RETURN false;  -- Cycle detected
        END IF;
        IF NOT (v_adj.target_node_id = ANY(v_visited)) THEN
          v_dfs_stack := array_append(v_dfs_stack, v_adj.target_node_id);
        END IF;
      END LOOP;
    END LOOP;
  END LOOP;

  RETURN true;  -- No cycles found
END;
$$;


ALTER FUNCTION "lenses"."fn_check_dag_acyclic"("p_workflow_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "lenses"."fn_check_dag_acyclic_kahn"("p_workflow_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'lenses'
    AS $$
DECLARE
  v_total_nodes  integer;
  v_processed    integer := 0;
  v_queue        uuid[];
  v_current      uuid;
  v_qi           integer := 1;
  v_in_degree    record;
BEGIN
  -- Count distinct nodes
  SELECT count(DISTINCT node_id) INTO v_total_nodes
  FROM (
    SELECT source_node_id AS node_id FROM lenses.workflow_edges WHERE workflow_id = p_workflow_id
    UNION
    SELECT target_node_id AS node_id FROM lenses.workflow_edges WHERE workflow_id = p_workflow_id
  ) nodes;

  IF v_total_nodes = 0 THEN
    RETURN true;  -- Empty graph is acyclic
  END IF;

  -- Build in-degree and find roots (in_degree = 0)
  -- Nodes that only appear as source (never as target) have in_degree = 0
  WITH all_nodes AS (
    SELECT DISTINCT node_id FROM (
      SELECT source_node_id AS node_id FROM lenses.workflow_edges WHERE workflow_id = p_workflow_id
      UNION
      SELECT target_node_id AS node_id FROM lenses.workflow_edges WHERE workflow_id = p_workflow_id
    ) n
  ),
  in_degrees AS (
    SELECT an.node_id, coalesce(cnt.c, 0) AS deg
    FROM all_nodes an
    LEFT JOIN (
      SELECT target_node_id, count(*) AS c
      FROM lenses.workflow_edges
      WHERE workflow_id = p_workflow_id
      GROUP BY target_node_id
    ) cnt ON cnt.target_node_id = an.node_id
  )
  SELECT array_agg(node_id) INTO v_queue
  FROM in_degrees
  WHERE deg = 0;

  IF v_queue IS NULL THEN
    RETURN false;  -- All nodes have incoming edges → cycle
  END IF;

  -- Process queue (Kahn's)
  WHILE v_qi <= array_length(v_queue, 1) LOOP
    v_current := v_queue[v_qi];
    v_qi := v_qi + 1;
    v_processed := v_processed + 1;

    -- For each neighbor of current, decrement in-degree conceptually
    -- by checking if all predecessors have been processed
    FOR v_in_degree IN
      SELECT DISTINCT e.target_node_id
      FROM lenses.workflow_edges e
      WHERE e.workflow_id = p_workflow_id
        AND e.source_node_id = v_current
    LOOP
      -- Check if all incoming edges to this target come from already-processed nodes
      IF NOT EXISTS (
        SELECT 1
        FROM lenses.workflow_edges e2
        WHERE e2.workflow_id = p_workflow_id
          AND e2.target_node_id = v_in_degree.target_node_id
          AND e2.source_node_id <> ALL(v_queue[1:v_qi-1])
      ) THEN
        v_queue := array_append(v_queue, v_in_degree.target_node_id);
      END IF;
    END LOOP;
  END LOOP;

  RETURN v_processed = v_total_nodes;
END;
$$;


ALTER FUNCTION "lenses"."fn_check_dag_acyclic_kahn"("p_workflow_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "lenses"."fn_check_workflow_budget"("p_run_id" "uuid", "p_estimated_cost" integer) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses'
    AS $$
DECLARE
  v_budget   integer;
  v_spent    integer;
BEGIN
  -- Lock the run row to prevent concurrent budget checks racing
  PERFORM pg_advisory_xact_lock(hashtext(p_run_id::text));

  SELECT budget_credits, spent_credits
  INTO v_budget, v_spent
  FROM lenses.workflow_runs
  WHERE id = p_run_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN false;
  END IF;

  -- NULL budget = unlimited
  IF v_budget IS NULL THEN
    RETURN true;
  END IF;

  RETURN (v_spent + p_estimated_cost) <= v_budget;
END;
$$;


ALTER FUNCTION "lenses"."fn_check_workflow_budget"("p_run_id" "uuid", "p_estimated_cost" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "lenses"."fn_claim_scheduled_workflow_run"("p_worker_id" "text") RETURNS TABLE("run_id" "uuid", "workflow_id" "uuid", "schedule_id" "uuid", "triggered_by" "uuid", "context_inputs" "jsonb", "global_model_id" "text", "ai_lenser_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'public'
    AS $$
DECLARE
  v_run lenses.workflow_runs;
BEGIN
  SELECT *
  INTO v_run
  FROM lenses.workflow_runs
  WHERE status       = 'pending'
    AND trigger_mode = 'schedule'
  ORDER BY created_at ASC
  LIMIT 1
  FOR UPDATE SKIP LOCKED;

  IF NOT FOUND THEN
    RETURN;
  END IF;

  UPDATE lenses.workflow_runs
  SET status     = 'running',
      started_at = COALESCE(started_at, now())
  WHERE id = v_run.id;

  RETURN QUERY
  SELECT
    v_run.id,
    v_run.workflow_id,
    v_run.schedule_id,
    v_run.triggered_by,
    v_run.context_inputs,
    v_run.global_model_id,
    v_run.ai_lenser_id;
END;
$$;


ALTER FUNCTION "lenses"."fn_claim_scheduled_workflow_run"("p_worker_id" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "lenses"."fn_clone_lens"("p_source_lens_id" "uuid", "p_version_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'content', 'lensers', 'public'
    AS $$
DECLARE
  v_caller_id       uuid;
  v_src_vis         content.visibility_enum;
  v_src_status      content.content_status;
  v_template        text;
  v_title           text;
  v_description     text;
  v_language        text;
  v_resolved_ver_id uuid;
  v_new_lens_id     uuid;
  v_new_version     lenses.versions;
BEGIN
  -- Auth check
  v_caller_id := lensers.get_auth_lenser_id();
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- Fork cooldown: max one fork per 5 minutes per user
  IF EXISTS (
    SELECT 1 FROM lenses.lenses
    WHERE lenser_id = v_caller_id
      AND parent_lens_id IS NOT NULL
      AND created_at > NOW() - INTERVAL '5 minutes'
  ) THEN
    RAISE EXCEPTION 'rate_limit_exceeded'
      USING DETAIL = 'You can only fork a lens once every 5 minutes.',
            ERRCODE = 'P0429';
  END IF;

  -- Source lens must be public + published
  SELECT l.visibility, l.status
    INTO v_src_vis, v_src_status
    FROM lenses.lenses l
   WHERE l.id = p_source_lens_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Source lens % not found', p_source_lens_id
      USING ERRCODE = 'no_data_found';
  END IF;

  IF v_src_vis <> 'public'::"content"."visibility_enum"
     OR v_src_status <> 'published'::"content"."content_status" THEN
    RAISE EXCEPTION 'Cannot clone: source lens must be public and published'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- Resolve template_body + version id from specific published version or latest published
  IF p_version_id IS NOT NULL THEN
    SELECT v.id, v.template_body
      INTO v_resolved_ver_id, v_template
      FROM lenses.versions v
     WHERE v.id      = p_version_id
       AND v.lens_id = p_source_lens_id
       AND v.status  = 'published'::"content"."content_status";

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Published version % not found for lens %',
        p_version_id, p_source_lens_id
        USING ERRCODE = 'no_data_found';
    END IF;
  ELSE
    SELECT v.id, v.template_body
      INTO v_resolved_ver_id, v_template
      FROM lenses.versions v
     WHERE v.lens_id = p_source_lens_id
       AND v.status  = 'published'::"content"."content_status"
     ORDER BY v.version_number DESC
     LIMIT 1;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'No published version found for lens %', p_source_lens_id
        USING ERRCODE = 'no_data_found';
    END IF;
  END IF;

  -- Resolve original translation
  SELECT t.title, t.description, t.language_code
    INTO v_title, v_description, v_language
    FROM content.entity_translations t
   WHERE t.entity_id   = p_source_lens_id
     AND t.entity_type = 'lens'::"content"."entity_type_enum"
     AND t.is_original = true
   LIMIT 1;

  -- Create the new (cloned) lens record — record which version it was forked from
  INSERT INTO lenses.lenses (
    lenser_id, visibility, status,
    parent_lens_id, forked_from_version_id
  ) VALUES (
    v_caller_id,
    'private'::"content"."visibility_enum",
    'published'::"content"."content_status",
    p_source_lens_id,
    v_resolved_ver_id
  )
  RETURNING id INTO v_new_lens_id;

  -- Create initial draft version via upsert (brand-new lens has no prior versions)
  v_new_version := lenses.fn_upsert_draft_version(
    v_new_lens_id,
    v_template,
    'Cloned from ' || coalesce(v_title, 'Untitled')
  );

  -- Set HEAD
  UPDATE lenses.lenses
     SET head_version_id = v_new_version.id
   WHERE id = v_new_lens_id;

  -- Clone version_parameters (label + tool_id) from source version → new version
  INSERT INTO lenses.version_parameters (version_id, label, tool_id)
  SELECT v_new_version.id, vp.label, vp.tool_id
  FROM lenses.version_parameters vp
  WHERE vp.version_id = v_resolved_ver_id
  LIMIT 200;

  -- Clone steps (version-specific + global)
  INSERT INTO lenses.steps (
    lens_id, version_id,
    ordinal, step_type, instruction,
    model_id, input_map, output_key, sub_lens_id
  )
  SELECT
    v_new_lens_id,
    v_new_version.id,
    s.ordinal, s.step_type, s.instruction,
    s.model_id, s.input_map, s.output_key, s.sub_lens_id
  FROM lenses.steps s
  WHERE s.lens_id = p_source_lens_id
    AND (
      p_version_id IS NULL
      OR s.version_id = p_version_id
      OR s.version_id IS NULL
    )
  LIMIT 500;

  -- Copy translation with "Fork of" prefix
  INSERT INTO content.entity_translations (
    entity_type, entity_id, language_code, is_original,
    title, description, content
  ) VALUES (
    'lens'::"content"."entity_type_enum",
    v_new_lens_id,
    coalesce(v_language, 'en'),
    true,
    'Fork of ' || coalesce(v_title, 'Untitled'),
    v_description,
    v_template
  );

  -- Copy tag associations
  INSERT INTO content.tag_map (entity_type, entity_id, tag_id)
  SELECT
    'lens'::"content"."entity_type_enum",
    v_new_lens_id,
    tm.tag_id
  FROM content.tag_map tm
  WHERE tm.entity_type = 'lens'::"content"."entity_type_enum"
    AND tm.entity_id   = p_source_lens_id
  LIMIT 50;

  RETURN v_new_lens_id;
END;
$$;


ALTER FUNCTION "lenses"."fn_clone_lens"("p_source_lens_id" "uuid", "p_version_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "lenses"."fn_clone_lens"("p_source_lens_id" "uuid", "p_version_id" "uuid") IS 'Forks a public published lens into a private draft clone owned by the caller.
   Sets head_version_id and forked_from_version_id (the specific version cloned).
   Clones: version_parameters (label + tool_id), steps (version-specific + global),
   translation (''Fork of'' prefix), and tag associations. SECURITY DEFINER: ownership
   and visibility checked internally.';



CREATE OR REPLACE FUNCTION "lenses"."fn_clone_workflow"("p_source_workflow_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_caller_id       uuid;
  v_src             record;
  v_new_workflow_id uuid;
  v_node_map        jsonb := '{}';
  v_old_node        record;
  v_new_node_id     uuid;
BEGIN
  v_caller_id := lensers.get_auth_lenser_id();
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- Fork cooldown: max one fork per 5 minutes per user
  IF EXISTS (
    SELECT 1 FROM lenses.workflows
    WHERE lenser_id = v_caller_id
      AND parent_workflow_id IS NOT NULL
      AND created_at > NOW() - INTERVAL '5 minutes'
  ) THEN
    RAISE EXCEPTION 'rate_limit_exceeded'
      USING DETAIL = 'You can only fork a workflow once every 5 minutes.',
            ERRCODE = 'P0429';
  END IF;

  -- Source must be public
  SELECT id, title, description, visibility
  INTO v_src
  FROM lenses.workflows
  WHERE id = p_source_workflow_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Workflow not found'
      USING ERRCODE = 'no_data_found';
  END IF;

  IF v_src.visibility <> 'public' THEN
    RAISE EXCEPTION 'Cannot fork: workflow must be public'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- Create forked workflow
  INSERT INTO lenses.workflows (lenser_id, title, description, visibility, parent_workflow_id)
  VALUES (v_caller_id, 'Fork of ' || v_src.title, v_src.description, 'private', p_source_workflow_id)
  RETURNING id INTO v_new_workflow_id;

  -- Update fork count on source
  UPDATE lenses.workflows
  SET fork_count = fork_count + 1
  WHERE id = p_source_workflow_id;

  -- Copy nodes (remap IDs)
  FOR v_old_node IN
    SELECT id, lens_id, version_id, position_x, position_y, label, ordinal, config
    FROM lenses.workflow_nodes
    WHERE workflow_id = p_source_workflow_id
    ORDER BY ordinal
  LOOP
    v_new_node_id := gen_random_uuid();
    INSERT INTO lenses.workflow_nodes (id, workflow_id, lens_id, version_id, position_x, position_y, label, ordinal, config)
    VALUES (v_new_node_id, v_new_workflow_id, v_old_node.lens_id, v_old_node.version_id,
            v_old_node.position_x, v_old_node.position_y, v_old_node.label, v_old_node.ordinal, v_old_node.config);
    v_node_map := v_node_map || jsonb_build_object(v_old_node.id::text, v_new_node_id::text);
  END LOOP;

  -- Copy edges (remap node IDs)
  INSERT INTO lenses.workflow_edges (workflow_id, source_node_id, target_node_id, source_output_key, target_param_label)
  SELECT
    v_new_workflow_id,
    (v_node_map ->> e.source_node_id::text)::uuid,
    (v_node_map ->> e.target_node_id::text)::uuid,
    e.source_output_key,
    e.target_param_label
  FROM lenses.workflow_edges e
  WHERE e.workflow_id = p_source_workflow_id;

  RETURN v_new_workflow_id;
END;
$$;


ALTER FUNCTION "lenses"."fn_clone_workflow"("p_source_workflow_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "lenses"."fn_count_recent_runs"("p_lenser_id" "uuid", "p_window_seconds" integer) RETURNS integer
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'lenses'
    AS $$
  SELECT COUNT(*)::int
  FROM lenses.workflow_runs r
  WHERE r.triggered_by = p_lenser_id
    AND r.created_at > now() - make_interval(secs => GREATEST(p_window_seconds, 0)::numeric);
$$;


ALTER FUNCTION "lenses"."fn_count_recent_runs"("p_lenser_id" "uuid", "p_window_seconds" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "lenses"."fn_count_recent_runs"("p_lenser_id" "uuid", "p_window_seconds" integer) IS 'Phase 9 — returns the number of workflow_runs started by a lenser in the last N seconds (used by rate limiter).';



CREATE TABLE IF NOT EXISTS "lenses"."versions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "lens_id" "uuid" NOT NULL,
    "version_number" integer NOT NULL,
    "template_body" "text" NOT NULL,
    "status" "content"."content_status" DEFAULT 'draft'::"content"."content_status" NOT NULL,
    "changelog" "text",
    "parent_version_id" "uuid",
    "published_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "input_contract" "jsonb",
    "output_contract" "jsonb",
    "content_hash" "bytea",
    "semver" "text",
    CONSTRAINT "lens_versions_published_at_check" CHECK ((("status" <> 'published'::"content"."content_status") OR ("published_at" IS NOT NULL))),
    CONSTRAINT "lens_versions_template_body_min_length" CHECK (("length"(TRIM(BOTH FROM "template_body")) >= 50)),
    CONSTRAINT "template_body_not_blank" CHECK (("length"(TRIM(BOTH FROM "template_body")) > 0)),
    CONSTRAINT "versions_content_hash_length_check" CHECK ((("content_hash" IS NULL) OR ("octet_length"("content_hash") = 32))),
    CONSTRAINT "versions_input_contract_shape_check" CHECK ((("input_contract" IS NULL) OR (("jsonb_typeof"("input_contract") = 'object'::"text") AND ("jsonb_typeof"(("input_contract" -> 'kind'::"text")) = 'string'::"text")))),
    CONSTRAINT "versions_output_contract_shape_check" CHECK ((("output_contract" IS NULL) OR (("jsonb_typeof"("output_contract") = 'object'::"text") AND ("jsonb_typeof"(("output_contract" -> 'kind'::"text")) = 'string'::"text") AND ("jsonb_typeof"(("output_contract" -> 'artifactKind'::"text")) = 'string'::"text")))),
    CONSTRAINT "versions_semver_format_check" CHECK ((("semver" IS NULL) OR ("semver" ~ '^[0-9]+\.[0-9]+\.[0-9]+(-[a-z0-9]+(\.[0-9]+)?)?$'::"text")))
);

ALTER TABLE ONLY "lenses"."versions" FORCE ROW LEVEL SECURITY;


ALTER TABLE "lenses"."versions" OWNER TO "postgres";


COMMENT ON TABLE "lenses"."versions" IS 'Immutable version snapshots of prompt assets. Draft versions are editable; published versions cannot be modified. Parameters belong to versions, not to the parent prompt asset.';



COMMENT ON COLUMN "lenses"."versions"."parent_version_id" IS 'Version-level fork lineage (v3 branched from v2). Distinct from content.lenses.parent_lens_id (asset-level fork).';



COMMENT ON COLUMN "lenses"."versions"."input_contract" IS 'Typed input contract (LensInputContract in libs/types). Optional; when set the workflow engine validates rendered node inputs against it.';



COMMENT ON COLUMN "lenses"."versions"."output_contract" IS 'Typed output contract (LensOutputContract in libs/types). Optional; when set the workflow engine validates the returned envelope against it.';



COMMENT ON COLUMN "lenses"."versions"."content_hash" IS 'sha256 digest (32 bytes) of the canonical Lens Contract body. Populated by the publish RPC; NULL for legacy rows pending backfill.';



COMMENT ON COLUMN "lenses"."versions"."semver" IS 'Semver assigned at publish (e.g. 2.3.1, 2.4.0-rc.1). Bump level enforced by diff against prior stable contract.';



CREATE OR REPLACE FUNCTION "lenses"."fn_create_draft_version"("p_lens_id" "uuid", "p_template_body" "text", "p_changelog" "text" DEFAULT NULL::"text", "p_parent_version_id" "uuid" DEFAULT NULL::"uuid") RETURNS "lenses"."versions"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'content', 'lensers', 'public'
    AS $$
DECLARE
  v_lenser_id  uuid;
  v_next_num   int;
  v_result     lenses.versions;
BEGIN
  -- Auth
  v_lenser_id := lensers.get_auth_lenser_id();
  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- Ownership
  IF NOT EXISTS (
    SELECT 1 FROM lenses.lenses
    WHERE id = p_lens_id AND lenser_id = v_lenser_id
  ) THEN
    RAISE EXCEPTION 'Permission denied: you do not own lens %', p_lens_id
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- Minimum length
  IF length(trim(p_template_body)) < 50 THEN
    RAISE EXCEPTION 'template_body must be at least 50 characters (got %)',
      length(trim(p_template_body))
      USING ERRCODE = 'check_violation';
  END IF;

  -- Next version number (append-only: always one higher than current max)
  SELECT coalesce(max(version_number), 0) + 1
    INTO v_next_num
    FROM lenses.versions
   WHERE lens_id = p_lens_id;

  INSERT INTO lenses.versions (
    lens_id, version_number, template_body,
    status, changelog, parent_version_id
  )
  VALUES (
    p_lens_id,
    v_next_num,
    p_template_body,
    'draft'::"content"."content_status",
    coalesce(p_changelog, 'Draft v' || v_next_num),
    p_parent_version_id
  )
  RETURNING * INTO v_result;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "lenses"."fn_create_draft_version"("p_lens_id" "uuid", "p_template_body" "text", "p_changelog" "text", "p_parent_version_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "lenses"."fn_create_draft_version"("p_lens_id" "uuid", "p_template_body" "text", "p_changelog" "text", "p_parent_version_id" "uuid") IS 'Append-only draft creator: always INSERTs a new lenses.versions row with the next
   sequential version_number. Never updates an existing version. Use for all
   user-initiated edit saves to ensure full edit history is preserved.
   fn_upsert_draft_version is retained for internal creation flows (fn_create_lens,
   fn_clone_lens). SECURITY DEFINER: ownership checked internally.';



CREATE OR REPLACE FUNCTION "lenses"."fn_create_lens"("p_visibility" "content"."visibility_enum", "p_template_body" "text", "p_title" "text", "p_description" "text" DEFAULT NULL::"text", "p_language_code" "text" DEFAULT 'en'::"text", "p_params" "jsonb" DEFAULT '[]'::"jsonb", "p_tag_ids" "uuid"[] DEFAULT '{}'::"uuid"[], "p_parent_lens_id" "uuid" DEFAULT NULL::"uuid", "p_forked_from_execution_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'content', 'lensers', 'public'
    AS $$
DECLARE
  v_caller_id   uuid;
  v_new_lens_id uuid;
  v_new_version lenses.versions;
  v_tag_id      uuid;
  v_param       jsonb;
  v_param_id    uuid;
  v_text_tool   uuid;
  v_uuid_body   text;  -- template_body with [[:uuid]] tokens (stored in versions)
BEGIN
  -- Auth
  v_caller_id := lensers.get_auth_lenser_id();
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  IF length(trim(p_template_body)) < 50 THEN
    RAISE EXCEPTION 'template_body must be at least 50 characters (got %)',
      length(trim(p_template_body))
      USING ERRCODE = 'check_violation';
  END IF;

  -- 1. Insert base lens record
  INSERT INTO lenses.lenses (
    lenser_id, visibility, status,
    parent_lens_id, forked_from_execution_id
  ) VALUES (
    v_caller_id,
    p_visibility,
    'published'::content.content_status,
    p_parent_lens_id,
    p_forked_from_execution_id
  )
  RETURNING id INTO v_new_lens_id;

  -- 2. Create initial draft version (validates 50-char minimum)
  v_new_version := lenses.fn_create_draft_version(
    v_new_lens_id,
    p_template_body,
    'Initial version'
  );

  -- 3. Set HEAD to the initial draft version
  UPDATE lenses.lenses
  SET head_version_id = v_new_version.id
  WHERE id = v_new_lens_id;

  -- 4. Insert version_parameters and rewrite template_body to [[:uuid]] format
  v_uuid_body := p_template_body;

  IF p_params IS NOT NULL AND jsonb_array_length(p_params) > 0 THEN
    SELECT id INTO v_text_tool FROM lenses.tools WHERE key = 'text' LIMIT 1;

    FOR v_param IN SELECT * FROM jsonb_array_elements(p_params) LOOP
      INSERT INTO lenses.version_parameters (version_id, label, tool_id)
      VALUES (
        v_new_version.id,
        v_param->>'label',
        COALESCE(
          NULLIF(v_param->>'tool_id', '')::uuid,
          v_text_tool
        )
      )
      RETURNING id INTO v_param_id;

      -- Replace [[label]] → [[:uuid]] in the stored body
      v_uuid_body := replace(
        v_uuid_body,
        '[[' || (v_param->>'label') || ']]',
        '[[:'|| v_param_id::text ||']]'
      );
    END LOOP;

    -- Update version row with rewritten body ([[:uuid]] format)
    UPDATE lenses.versions
    SET template_body = v_uuid_body
    WHERE id = v_new_version.id;
  END IF;

  -- 5. Insert original translation — keeps human-readable [[label]] format
  INSERT INTO content.entity_translations (
    entity_type, entity_id, language_code, is_original,
    title, description, content
  ) VALUES (
    'lens'::content.entity_type_enum,
    v_new_lens_id,
    COALESCE(p_language_code, 'en'),
    true,
    p_title,
    p_description,
    p_template_body  -- human-readable [[label]] format
  );

  -- 6. Insert tag associations
  IF p_tag_ids IS NOT NULL AND array_length(p_tag_ids, 1) > 0 THEN
    FOREACH v_tag_id IN ARRAY p_tag_ids LOOP
      INSERT INTO content.tag_map (entity_type, entity_id, tag_id)
      VALUES ('lens'::content.entity_type_enum, v_new_lens_id, v_tag_id)
      ON CONFLICT DO NOTHING;
    END LOOP;
  END IF;

  RETURN v_new_lens_id;
END;
$$;


ALTER FUNCTION "lenses"."fn_create_lens"("p_visibility" "content"."visibility_enum", "p_template_body" "text", "p_title" "text", "p_description" "text", "p_language_code" "text", "p_params" "jsonb", "p_tag_ids" "uuid"[], "p_parent_lens_id" "uuid", "p_forked_from_execution_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "lenses"."fn_create_lens"("p_visibility" "content"."visibility_enum", "p_template_body" "text", "p_title" "text", "p_description" "text", "p_language_code" "text", "p_params" "jsonb", "p_tag_ids" "uuid"[], "p_parent_lens_id" "uuid", "p_forked_from_execution_id" "uuid") IS 'GRASP Creator: creates a lens with its initial draft version, version_parameters, translation, and tag associations atomically. p_params is a jsonb array of parameter definition objects — INSERTed into lenses.version_parameters (not entity_translations). Sets head_version_id. SECURITY DEFINER: auth checked internally.';



CREATE OR REPLACE FUNCTION "lenses"."fn_create_workflow_version"("p_workflow_id" "uuid", "p_changelog" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_caller_id     uuid;
  v_owner_id      uuid;
  v_next_version  integer;
  v_version_id    uuid;
  v_node_map      jsonb := '{}';  -- old_node_id → new_node_id
  v_old_node      record;
  v_new_node_id   uuid;
BEGIN
  -- Auth check
  v_caller_id := lensers.get_auth_lenser_id();
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- Ownership check
  SELECT lenser_id INTO v_owner_id
  FROM lenses.workflows
  WHERE id = p_workflow_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Workflow not found'
      USING ERRCODE = 'no_data_found';
  END IF;

  IF v_owner_id <> v_caller_id THEN
    RAISE EXCEPTION 'Only the workflow owner can create versions'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- Compute next version number
  SELECT coalesce(max(version_number), 0) + 1 INTO v_next_version
  FROM lenses.workflow_versions
  WHERE workflow_id = p_workflow_id;

  -- Create version record
  INSERT INTO lenses.workflow_versions (workflow_id, version_number, changelog, status, created_by)
  VALUES (p_workflow_id, v_next_version, p_changelog, 'draft', v_caller_id)
  RETURNING id INTO v_version_id;

  -- Snapshot nodes (need to map old IDs to new IDs for edge references)
  FOR v_old_node IN
    SELECT id, lens_id, version_id, position_x, position_y, label, ordinal, config
    FROM lenses.workflow_nodes
    WHERE workflow_id = p_workflow_id
    ORDER BY ordinal
  LOOP
    v_new_node_id := gen_random_uuid();

    INSERT INTO lenses.workflow_version_nodes (
      id, workflow_version_id, lens_id, version_id,
      position_x, position_y, label, ordinal, config
    ) VALUES (
      v_new_node_id, v_version_id, v_old_node.lens_id, v_old_node.version_id,
      v_old_node.position_x, v_old_node.position_y, v_old_node.label,
      v_old_node.ordinal, v_old_node.config
    );

    v_node_map := v_node_map || jsonb_build_object(v_old_node.id::text, v_new_node_id::text);
  END LOOP;

  -- Snapshot edges (remap node IDs)
  INSERT INTO lenses.workflow_version_edges (
    workflow_version_id, source_node_id, target_node_id,
    source_output_key, target_param_label
  )
  SELECT
    v_version_id,
    (v_node_map ->> e.source_node_id::text)::uuid,
    (v_node_map ->> e.target_node_id::text)::uuid,
    e.source_output_key,
    e.target_param_label
  FROM lenses.workflow_edges e
  WHERE e.workflow_id = p_workflow_id;

  RETURN v_version_id;
END;
$$;


ALTER FUNCTION "lenses"."fn_create_workflow_version"("p_workflow_id" "uuid", "p_changelog" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "lenses"."fn_cron_field_matches"("p_field" "text", "p_value" integer) RETURNS boolean
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'lenses', 'pg_catalog'
    AS $$
DECLARE
  v_part text;
  v_base text;
  v_step integer;
  v_start integer;
  v_end integer;
  v_exact integer;
BEGIN
  IF p_field IS NULL OR btrim(p_field) = '' THEN
    RETURN false;
  END IF;

  IF btrim(p_field) = '*' THEN
    RETURN true;
  END IF;

  FOREACH v_part IN ARRAY regexp_split_to_array(replace(btrim(p_field), ' ', ''), ',') LOOP
    CONTINUE WHEN v_part = '';

    IF position('/' IN v_part) > 0 THEN
      v_base := split_part(v_part, '/', 1);
      v_step := split_part(v_part, '/', 2)::integer;
      CONTINUE WHEN v_step IS NULL OR v_step <= 0;

      IF v_base = '*' THEN
        IF mod(p_value, v_step) = 0 THEN
          RETURN true;
        END IF;
      ELSIF position('-' IN v_base) > 0 THEN
        v_start := split_part(v_base, '-', 1)::integer;
        v_end := split_part(v_base, '-', 2)::integer;
        IF p_value BETWEEN v_start AND v_end
           AND mod(p_value - v_start, v_step) = 0 THEN
          RETURN true;
        END IF;
      ELSE
        v_exact := v_base::integer;
        IF p_value >= v_exact
           AND mod(p_value - v_exact, v_step) = 0 THEN
          RETURN true;
        END IF;
      END IF;
    ELSIF position('-' IN v_part) > 0 THEN
      v_start := split_part(v_part, '-', 1)::integer;
      v_end := split_part(v_part, '-', 2)::integer;
      IF p_value BETWEEN v_start AND v_end THEN
        RETURN true;
      END IF;
    ELSE
      v_exact := v_part::integer;
      IF p_value = v_exact THEN
        RETURN true;
      END IF;
    END IF;
  END LOOP;

  RETURN false;
EXCEPTION
  WHEN invalid_text_representation THEN
    RETURN false;
END;
$$;


ALTER FUNCTION "lenses"."fn_cron_field_matches"("p_field" "text", "p_value" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "lenses"."fn_cron_matches_now"("p_cron_expr" "text", "p_now" timestamp with time zone DEFAULT "now"()) RETURNS boolean
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'lenses', 'pg_catalog'
    AS $$
DECLARE
  v_parts text[];
  v_minute integer := EXTRACT(minute FROM p_now)::integer;
  v_hour integer := EXTRACT(hour FROM p_now)::integer;
  v_dom integer := EXTRACT(day FROM p_now)::integer;
  v_month integer := EXTRACT(month FROM p_now)::integer;
  v_dow0 integer := EXTRACT(dow FROM p_now)::integer;
  v_dow7 integer := CASE WHEN EXTRACT(dow FROM p_now)::integer = 0 THEN 7 ELSE EXTRACT(dow FROM p_now)::integer END;
BEGIN
  v_parts := regexp_split_to_array(trim(COALESCE(p_cron_expr, '')), '\s+');
  IF array_length(v_parts, 1) <> 5 THEN
    RETURN false;
  END IF;

  RETURN lenses.fn_cron_field_matches(v_parts[1], v_minute)
    AND lenses.fn_cron_field_matches(v_parts[2], v_hour)
    AND lenses.fn_cron_field_matches(v_parts[3], v_dom)
    AND lenses.fn_cron_field_matches(v_parts[4], v_month)
    AND (
      lenses.fn_cron_field_matches(v_parts[5], v_dow0)
      OR lenses.fn_cron_field_matches(v_parts[5], v_dow7)
    );
END;
$$;


ALTER FUNCTION "lenses"."fn_cron_matches_now"("p_cron_expr" "text", "p_now" timestamp with time zone) OWNER TO "postgres";


COMMENT ON FUNCTION "lenses"."fn_cron_matches_now"("p_cron_expr" "text", "p_now" timestamp with time zone) IS 'Best-effort 5-field CRON matcher for minute-based workflow schedules. Supports *, comma lists, ranges, and step syntax.';



CREATE OR REPLACE FUNCTION "lenses"."fn_dispatch_scheduled_workflows"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'agents', 'automation', 'public'
    AS $$
DECLARE
  v_now                    timestamptz := now();
  v_scheduled_for          timestamptz := date_trunc('minute', v_now);
  v_schedule               RECORD;
  v_run_id                 uuid;
  v_team_run_id            uuid;
  v_ai_lenser_id           uuid;
  v_assignee_ai_lenser_id  uuid;
  v_log_ai_lenser_id       uuid;
  v_requires_approval      boolean;
  v_team_run_status        text;
  v_approval_status        text;
  v_dispatched             integer := 0;
  v_spending_limit         numeric;
  v_budget_enforce         boolean;
  v_credits_used           numeric;
  v_condition_ctx          jsonb;
  v_condition_pass         boolean;
  v_condition_err          text;
  v_rotation_len           integer;
  v_rotation_idx           integer;
  v_inputs                 jsonb;
BEGIN
  FOR v_schedule IN
    SELECT
      s.id, s.workflow_id, s.cron_expr, s.global_model_id, s.inputs_template,
      s.is_active, s.last_run_at, s.assignee_type, s.assignee_id,
      s.workflow_assignment_id, s.approval_policy, s.calendar_id,
      s.pre_dispatch_condition, s.inputs_rotation, s.last_rotation_index,
      w.lenser_id, w.title
    FROM lenses.workflow_schedules s
    JOIN lenses.workflows w ON w.id = s.workflow_id
    WHERE s.is_active = true
      AND (s.last_run_at IS NULL OR date_trunc('minute', s.last_run_at) < v_scheduled_for)
      AND lenses.fn_cron_matches_now(s.cron_expr, v_now)
    ORDER BY s.created_at ASC
    FOR UPDATE OF s SKIP LOCKED
  LOOP
    SELECT al.id INTO v_ai_lenser_id
    FROM agents.ai_lensers al
    WHERE al.profile_id = v_schedule.lenser_id
    LIMIT 1;

    v_assignee_ai_lenser_id := NULL;
    IF v_schedule.assignee_id IS NOT NULL THEN
      IF v_schedule.assignee_type = 'agent' THEN
        v_assignee_ai_lenser_id := v_schedule.assignee_id;
      ELSIF v_schedule.assignee_type = 'team' THEN
        SELECT t.ai_lenser_id INTO v_assignee_ai_lenser_id
        FROM agents.teams t WHERE t.id = v_schedule.assignee_id LIMIT 1;
      END IF;
    END IF;

    v_log_ai_lenser_id := COALESCE(v_assignee_ai_lenser_id, v_ai_lenser_id);

    -- Budget enforcement gate
    IF v_ai_lenser_id IS NOT NULL THEN
      SELECT pol.spending_limit_credits, pol.budget_enforce
        INTO v_spending_limit, v_budget_enforce
      FROM agents.ai_lensers al
      JOIN agents.policies pol ON pol.id = al.policy_id
      WHERE al.id = v_ai_lenser_id;

      IF v_budget_enforce AND v_spending_limit IS NOT NULL THEN
        SELECT COALESCE(SUM(qs.credits_spent), 0) INTO v_credits_used
        FROM agents.quota_snapshots qs
        WHERE qs.ai_lenser_id = v_ai_lenser_id
          AND qs.period_date = CURRENT_DATE;

        IF v_credits_used >= v_spending_limit THEN
          UPDATE lenses.workflow_schedules
          SET last_dispatch_status = 'budget_exceeded',
              last_error_at = v_now,
              last_error_message = format('spending_limit_credits=%s reached (used=%s today)',
                                          v_spending_limit, v_credits_used)
          WHERE id = v_schedule.id;
          CONTINUE;
        END IF;
      END IF;
    END IF;

    v_requires_approval := COALESCE(
      (v_schedule.approval_policy->>'requiresApproval')::boolean, true);

    IF lenses.fn_workflow_has_cycle(v_schedule.workflow_id) THEN
      UPDATE lenses.workflow_schedules
      SET last_dispatch_status = 'validation_failed',
          last_error_at = v_now, last_error_message = 'cycle_detected'
      WHERE id = v_schedule.id;
      CONTINUE;
    END IF;

    IF EXISTS (
      SELECT 1 FROM lenses.workflow_runs r
      WHERE r.schedule_id = v_schedule.id
        AND r.status IN ('draft','validated','queued','pending','running','streaming','recovered')
    ) THEN
      UPDATE lenses.workflow_schedules
      SET last_dispatch_status = 'skipped_overlap',
          last_error_at = v_now, last_error_message = 'overlap_in_flight'
      WHERE id = v_schedule.id;
      CONTINUE;
    END IF;

    IF NOT lenses.fn_check_calendar(v_schedule.calendar_id, v_now) THEN
      UPDATE lenses.workflow_schedules
      SET last_dispatch_status = 'skipped_calendar',
          last_error_at = v_now, last_error_message = 'calendar_skipped'
      WHERE id = v_schedule.id;
      CONTINUE;
    END IF;

    -- ── D8: pre_dispatch_condition guard with error surfacing ─────────────
    IF v_schedule.pre_dispatch_condition IS NOT NULL THEN
      v_condition_ctx := lenses.fn_build_schedule_condition_context(v_schedule.id);
      v_condition_err := NULL;
      BEGIN
        v_condition_pass := automation.fn_eval_filter(
          v_schedule.pre_dispatch_condition, v_condition_ctx);
      EXCEPTION WHEN OTHERS THEN
        v_condition_pass := false;
        v_condition_err  := left(SQLERRM, 500);
      END;

      IF v_condition_pass IS DISTINCT FROM true THEN
        IF v_condition_err IS NOT NULL THEN
          -- D8: hard error in the DSL → surface as `condition_failed`
          UPDATE lenses.workflow_schedules
          SET last_dispatch_status = 'condition_failed',
              last_error_at = v_now,
              last_error_message = 'fn_eval_filter raised: ' || v_condition_err
          WHERE id = v_schedule.id;
        ELSE
          -- Clean false return → keep `skipped_condition`
          UPDATE lenses.workflow_schedules
          SET last_dispatch_status = 'skipped_condition',
              last_error_at = v_now, last_error_message = 'condition_failed'
          WHERE id = v_schedule.id;
        END IF;
        CONTINUE;
      END IF;
    END IF;
    -- ── End D8 ──────────────────────────────────────────────────────────

    IF v_schedule.inputs_rotation IS NOT NULL
       AND jsonb_typeof(v_schedule.inputs_rotation) = 'array'
       AND jsonb_array_length(v_schedule.inputs_rotation) > 0 THEN
      v_rotation_len := jsonb_array_length(v_schedule.inputs_rotation);
      v_rotation_idx := COALESCE(v_schedule.last_rotation_index, 0) % v_rotation_len;
      v_inputs := COALESCE(v_schedule.inputs_rotation -> v_rotation_idx, '{}'::jsonb);
      UPDATE lenses.workflow_schedules
      SET last_rotation_index = COALESCE(last_rotation_index, 0) + 1
      WHERE id = v_schedule.id;
    ELSE
      v_inputs := COALESCE(v_schedule.inputs_template, '{}'::jsonb);
    END IF;

    BEGIN
      INSERT INTO lenses.workflow_runs (
        workflow_id, triggered_by, status, context_inputs, global_model_id,
        schedule_id, scheduled_for, trigger_mode
      ) VALUES (
        v_schedule.workflow_id, v_schedule.lenser_id, 'pending', v_inputs,
        v_schedule.global_model_id, v_schedule.id, v_scheduled_for, 'schedule'
      ) RETURNING id INTO v_run_id;

      INSERT INTO lenses.workflow_node_results (run_id, node_id, status)
      SELECT v_run_id, n.id, 'pending'
      FROM lenses.workflow_nodes n
      WHERE n.workflow_id = v_schedule.workflow_id;

      IF v_assignee_ai_lenser_id IS NOT NULL THEN
        v_team_run_status := CASE WHEN v_requires_approval THEN 'blocked' ELSE 'queued' END;
        v_approval_status := CASE WHEN v_requires_approval THEN 'pending' ELSE 'not_required' END;

        INSERT INTO agents.team_runs (
          ai_lenser_id, team_id, workflow_id, workflow_run_id,
          workflow_assignment_id, status, approval_status, metadata
        ) VALUES (
          v_assignee_ai_lenser_id,
          CASE WHEN v_schedule.assignee_type = 'team' THEN v_schedule.assignee_id ELSE NULL END,
          v_schedule.workflow_id, v_run_id, v_schedule.workflow_assignment_id,
          v_team_run_status, v_approval_status,
          jsonb_build_object('schedule_id', v_schedule.id,
                             'scheduled_for', v_scheduled_for,
                             'cron_expr', v_schedule.cron_expr)
        ) RETURNING id INTO v_team_run_id;

        INSERT INTO agents.agent_run_events (team_run_id, event_type, payload, occurred_at)
        VALUES (
          v_team_run_id,
          CASE WHEN v_requires_approval THEN 'approval_requested' ELSE 'dispatch_queued' END,
          jsonb_build_object('schedule_id', v_schedule.id,
                             'scheduled_for', v_scheduled_for,
                             'cron_expr', v_schedule.cron_expr,
                             'workflow_id', v_schedule.workflow_id,
                             'workflow_run_id', v_run_id,
                             'requires_approval', v_requires_approval),
          v_now
        );
      END IF;

      UPDATE lenses.workflow_schedules
      SET last_run_at = v_now, last_run_id = v_run_id,
          last_dispatch_status = 'dispatched',
          last_error_at = NULL, last_error_message = NULL
      WHERE id = v_schedule.id;

      v_dispatched := v_dispatched + 1;
    EXCEPTION
      WHEN unique_violation THEN
        UPDATE lenses.workflow_schedules
        SET last_dispatch_status = 'skipped_overlap',
            last_error_at = v_now, last_error_message = 'schedule_slot_exists'
        WHERE id = v_schedule.id;
      WHEN OTHERS THEN
        UPDATE lenses.workflow_schedules
        SET last_dispatch_status = 'dispatch_failed',
            last_error_at = v_now,
            last_error_message = left(SQLERRM, 500)
        WHERE id = v_schedule.id;
    END;
  END LOOP;

  RETURN v_dispatched;
END;
$$;


ALTER FUNCTION "lenses"."fn_dispatch_scheduled_workflows"() OWNER TO "postgres";


COMMENT ON FUNCTION "lenses"."fn_dispatch_scheduled_workflows"() IS 'D8 fix: distinguishes condition_failed (DSL raised an error) from skipped_condition (DSL returned clean false). Operators can now spot a broken rule rather than treating every skip as a normal outcome.';



