CREATE OR REPLACE FUNCTION "lenses"."fn_move_workflow_run_to_dlq"("p_run_id" "uuid", "p_node_id" "text" DEFAULT NULL::"text", "p_error_code" "text" DEFAULT NULL::"text", "p_error_msg" "text" DEFAULT NULL::"text", "p_payload" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
