CREATE OR REPLACE FUNCTION "lenses"."fn_start_workflow_run"("p_workflow_id" "uuid", "p_inputs" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_lenser_id  uuid;
  v_run_id     uuid;
  v_node       RECORD;
BEGIN
  -- Resolve caller
  v_lenser_id := lensers.get_auth_lenser_id();

  -- Validate: caller must own the workflow or it must be public
  IF NOT EXISTS (
    SELECT 1 FROM lenses.workflows w
    WHERE w.id = p_workflow_id
      AND (w.lenser_id = v_lenser_id OR w.visibility = 'public')
  ) THEN
    RAISE EXCEPTION 'Workflow not found or access denied' USING ERRCODE = 'P0001';
  END IF;

  -- Create the run record
  INSERT INTO lenses.workflow_runs (workflow_id, triggered_by, status, context_inputs)
  VALUES (p_workflow_id, v_lenser_id, 'pending', p_inputs)
  RETURNING id INTO v_run_id;

  -- Seed one node_result row per node (all pending)
  FOR v_node IN
    SELECT id FROM lenses.workflow_nodes WHERE workflow_id = p_workflow_id
  LOOP
    INSERT INTO lenses.workflow_node_results (run_id, node_id, status)
    VALUES (v_run_id, v_node.id, 'pending');
  END LOOP;

  RETURN v_run_id;
END;
$$;


ALTER FUNCTION "lenses"."fn_start_workflow_run"("p_workflow_id" "uuid", "p_inputs" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "lenses"."fn_start_workflow_run"("p_workflow_id" "uuid", "p_inputs" "jsonb") IS 'Creates a workflow_run and seeds pending workflow_node_results for every node. Returns the run_id. The CF Worker polls/subscribes to drive actual execution.';



CREATE OR REPLACE FUNCTION "lenses"."fn_start_workflow_run"("p_workflow_id" "uuid", "p_inputs" "jsonb" DEFAULT '{}'::"jsonb", "p_global_model_id" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_lenser_id  uuid;
  v_run_id     uuid;
BEGIN
  v_lenser_id := lensers.get_auth_lenser_id();

  -- Guard: caller must own the workflow or it must be public
  IF NOT EXISTS (
    SELECT 1 FROM lenses.workflows w
    WHERE w.id = p_workflow_id
      AND (w.visibility = 'public' OR w.lenser_id = v_lenser_id)
  ) THEN
    RAISE EXCEPTION 'workflow_not_found_or_forbidden';
  END IF;

  INSERT INTO lenses.workflow_runs (workflow_id, triggered_by, status, context_inputs, global_model_id)
  VALUES (p_workflow_id, v_lenser_id, 'pending', p_inputs, p_global_model_id)
  RETURNING id INTO v_run_id;

  -- Seed one node_result row per node (all pending)
  INSERT INTO lenses.workflow_node_results (run_id, node_id, status)
  SELECT v_run_id, n.id, 'pending'
  FROM lenses.workflow_nodes n
  WHERE n.workflow_id = p_workflow_id;

  RETURN v_run_id;
END;
$$;


ALTER FUNCTION "lenses"."fn_start_workflow_run"("p_workflow_id" "uuid", "p_inputs" "jsonb", "p_global_model_id" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "lenses"."fn_start_workflow_run"("p_workflow_id" "uuid", "p_inputs" "jsonb", "p_global_model_id" "text") IS 'Creates a workflow_run with optional global_model_id and seeds pending workflow_node_results for every node. Returns the run_id. The CF Worker polls/subscribes to drive actual execution.';



CREATE OR REPLACE FUNCTION "lenses"."fn_start_workflow_run"("p_workflow_id" "uuid", "p_inputs" "jsonb" DEFAULT '{}'::"jsonb", "p_global_model_id" "text" DEFAULT NULL::"text", "p_idempotency_key" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_lenser_id        uuid;
  v_run_id           uuid;
  v_rate_window_sec  integer := 60;
  v_rate_limit_count integer := 30;
  v_recent_count     integer;
  v_role             text;
BEGIN
  v_lenser_id := lensers.get_auth_lenser_id();

  IF NOT EXISTS (
    SELECT 1 FROM lenses.workflows w
    WHERE w.id = p_workflow_id
      AND (w.visibility = 'public' OR w.lenser_id = v_lenser_id)
  ) THEN
    RAISE EXCEPTION 'workflow_not_found_or_forbidden'
      USING ERRCODE = '42501';
  END IF;

  -- ── D4: idempotency short-circuit with TTL ─────────────────────────────
  IF p_idempotency_key IS NOT NULL AND length(p_idempotency_key) > 0 THEN
    SELECT id INTO v_run_id
    FROM   lenses.workflow_runs
    WHERE  workflow_id    = p_workflow_id
      AND  idempotency_key = p_idempotency_key
      AND  (idempotency_expires_at IS NULL OR idempotency_expires_at > now())
    ORDER  BY created_at DESC
    LIMIT  1;
    IF v_run_id IS NOT NULL THEN
      RETURN v_run_id;
    END IF;
  END IF;

  -- ── D2: anonymous callers cannot bypass the rate limit. Authenticated
  -- runs are bucketed per-lenser. Anon callers (v_lenser_id IS NULL) and
  -- any caller without an auth profile are rejected via PostgREST role
  -- check below — they should never call this RPC directly.
  BEGIN
    v_role := current_setting('request.jwt.claim.role', true);
  EXCEPTION WHEN OTHERS THEN
    v_role := NULL;
  END;

  IF v_lenser_id IS NULL THEN
    IF v_role = 'anon' THEN
      RAISE EXCEPTION 'fn_start_workflow_run: anon not permitted'
        USING ERRCODE = '42501',
              HINT    = 'D2: rate limit cannot be enforced for anon';
    END IF;
    -- service_role callers (workers/test) intentionally bypass the limit.
  ELSE
    v_recent_count := lenses.fn_count_recent_runs(v_lenser_id, v_rate_window_sec);
    IF v_recent_count >= v_rate_limit_count THEN
      RAISE EXCEPTION
        'rate_limited: % runs in the last % seconds (cap %)',
        v_recent_count, v_rate_window_sec, v_rate_limit_count
        USING ERRCODE = '54000', HINT = 'phase9_run_rate_limit';
    END IF;
  END IF;

  INSERT INTO lenses.workflow_runs (
    workflow_id, triggered_by, status, context_inputs,
    global_model_id, idempotency_key, idempotency_expires_at
  )
  VALUES (
    p_workflow_id, v_lenser_id, 'pending', p_inputs,
    p_global_model_id, p_idempotency_key,
    CASE
      WHEN p_idempotency_key IS NOT NULL AND length(p_idempotency_key) > 0
      THEN now() + interval '24 hours'
      ELSE NULL
    END
  )
  RETURNING id INTO v_run_id;

  INSERT INTO lenses.workflow_node_results (run_id, node_id, status)
  SELECT v_run_id, n.id, 'pending'
  FROM   lenses.workflow_nodes n
  WHERE  n.workflow_id = p_workflow_id;

  RETURN v_run_id;
END;
$$;


ALTER FUNCTION "lenses"."fn_start_workflow_run"("p_workflow_id" "uuid", "p_inputs" "jsonb", "p_global_model_id" "text", "p_idempotency_key" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "lenses"."fn_start_workflow_run"("p_workflow_id" "uuid", "p_inputs" "jsonb", "p_global_model_id" "text", "p_idempotency_key" "text") IS 'D2+D4: anon callers rejected (cannot bypass per-lenser rate limit); idempotency_key window capped at 24h via idempotency_expires_at. Otherwise mirrors phase 9.';



