CREATE OR REPLACE FUNCTION "lenses"."fn_update_lens"("p_lens_id" "uuid", "p_template_body" "text" DEFAULT NULL::"text", "p_visibility" "content"."visibility_enum" DEFAULT NULL::"content"."visibility_enum", "p_title" "text" DEFAULT NULL::"text", "p_description" "text" DEFAULT NULL::"text", "p_tag_ids" "uuid"[] DEFAULT NULL::"uuid"[]) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'content', 'lensers', 'public'
    AS $$
DECLARE
  v_caller_id uuid;
  v_owner_id  uuid;
  v_tag_id    uuid;
BEGIN
  -- Auth
  v_caller_id := lensers.get_auth_lenser_id();
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- Ownership
  SELECT lenser_id INTO v_owner_id
    FROM lenses.lenses
   WHERE id = p_lens_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Lens not found: %', p_lens_id
      USING ERRCODE = 'no_data_found';
  END IF;

  IF v_owner_id <> v_caller_id THEN
    RAISE EXCEPTION 'Permission denied: you do not own this lens'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- 1. Update visibility if provided
  IF p_visibility IS NOT NULL THEN
    UPDATE lenses.lenses SET visibility = p_visibility WHERE id = p_lens_id;
  END IF;

  -- 2. Content change → create a new append-only draft version
  IF p_template_body IS NOT NULL THEN
    IF length(trim(p_template_body)) < 50 THEN
      RAISE EXCEPTION 'template_body must be at least 50 characters (got %)',
        length(trim(p_template_body))
        USING ERRCODE = 'check_violation';
    END IF;

    -- Always append a new draft row (never overwrite existing version)
    PERFORM lenses.fn_create_draft_version(
      p_lens_id,
      p_template_body,
      'Updated via lens edit'
    );
  END IF;

  -- 3. Update translation
  IF p_title IS NOT NULL OR p_description IS NOT NULL
     OR p_template_body IS NOT NULL THEN
    UPDATE content.entity_translations
       SET title       = coalesce(p_title, title),
           description = coalesce(p_description, description),
           content     = coalesce(p_template_body, content)
     WHERE entity_type = 'lens'::"content"."entity_type_enum"
       AND entity_id   = p_lens_id
       AND is_original = true;
  END IF;

  -- 4. Replace tags if provided (NULL = no change, empty array = clear all)
  IF p_tag_ids IS NOT NULL THEN
    DELETE FROM content.tag_map
     WHERE entity_type = 'lens'::"content"."entity_type_enum"
       AND entity_id   = p_lens_id;

    IF array_length(p_tag_ids, 1) > 0 THEN
      FOREACH v_tag_id IN ARRAY p_tag_ids LOOP
        INSERT INTO content.tag_map (entity_type, entity_id, tag_id)
        VALUES ('lens'::"content"."entity_type_enum", p_lens_id, v_tag_id)
        ON CONFLICT DO NOTHING;
      END LOOP;
    END IF;
  END IF;
END;
$$;


ALTER FUNCTION "lenses"."fn_update_lens"("p_lens_id" "uuid", "p_template_body" "text", "p_visibility" "content"."visibility_enum", "p_title" "text", "p_description" "text", "p_tag_ids" "uuid"[]) OWNER TO "postgres";


COMMENT ON FUNCTION "lenses"."fn_update_lens"("p_lens_id" "uuid", "p_template_body" "text", "p_visibility" "content"."visibility_enum", "p_title" "text", "p_description" "text", "p_tag_ids" "uuid"[]) IS 'GRASP Controller: atomic lens update. Updates visibility, template body (via
   fn_create_draft_version — append-only, always inserts new draft row), translation,
   and tags in one transaction. SECURITY DEFINER: ownership checked internally.';



CREATE OR REPLACE FUNCTION "lenses"."fn_update_lens"("p_lens_id" "uuid", "p_template_body" "text" DEFAULT NULL::"text", "p_visibility" "content"."visibility_enum" DEFAULT NULL::"content"."visibility_enum", "p_title" "text" DEFAULT NULL::"text", "p_description" "text" DEFAULT NULL::"text", "p_tag_ids" "uuid"[] DEFAULT NULL::"uuid"[], "p_params" "jsonb" DEFAULT NULL::"jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'content', 'lensers', 'public'
    AS $$
DECLARE
  v_caller_id   uuid;
  v_owner_id    uuid;
  v_tag_id      uuid;
  v_new_version lenses.versions;
  v_param       jsonb;
  v_param_id    uuid;
  v_text_tool   uuid;
  v_uuid_body   text;
BEGIN
  -- Auth
  v_caller_id := lensers.get_auth_lenser_id();
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- Ownership
  SELECT lenser_id INTO v_owner_id
  FROM   lenses.lenses
  WHERE  id = p_lens_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Lens not found: %', p_lens_id
      USING ERRCODE = 'no_data_found';
  END IF;

  IF v_owner_id <> v_caller_id THEN
    RAISE EXCEPTION 'Permission denied: you do not own this lens'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  -- 1. Update visibility
  IF p_visibility IS NOT NULL THEN
    UPDATE lenses.lenses SET visibility = p_visibility WHERE id = p_lens_id;
  END IF;

  -- 2. Content change → new append-only draft version + version_parameters
  IF p_template_body IS NOT NULL THEN
    IF length(trim(p_template_body)) < 50 THEN
      RAISE EXCEPTION 'template_body must be at least 50 characters (got %)',
        length(trim(p_template_body))
        USING ERRCODE = 'check_violation';
    END IF;

    -- Create draft version (receives [[label]] body; we'll rewrite it below)
    v_new_version := lenses.fn_create_draft_version(
      p_lens_id,
      p_template_body,
      'Updated via lens edit'
    );

    -- Insert version_parameters and build [[:uuid]] body
    v_uuid_body := p_template_body;

    IF p_params IS NOT NULL AND jsonb_array_length(p_params) > 0 THEN
      SELECT id INTO v_text_tool FROM lenses.tools WHERE key = 'text' LIMIT 1;

      FOR v_param IN SELECT * FROM jsonb_array_elements(p_params) LOOP
        INSERT INTO lenses.version_parameters (version_id, label, tool_id)
        VALUES (
          v_new_version.id,
          v_param->>'label',
          COALESCE(
            NULLIF(v_param->>'tool_id', '')::uuid,
            v_text_tool
          )
        )
        RETURNING id INTO v_param_id;

        v_uuid_body := replace(
          v_uuid_body,
          '[[' || (v_param->>'label') || ']]',
          '[[:'|| v_param_id::text ||']]'
        );
      END LOOP;

      -- Store the rewritten ([[:uuid]]) body in the version row
      UPDATE lenses.versions
      SET template_body = v_uuid_body
      WHERE id = v_new_version.id;
    END IF;
  END IF;

  -- 3. Update translation — keeps human-readable [[label]] format
  IF p_title IS NOT NULL OR p_description IS NOT NULL OR p_template_body IS NOT NULL THEN
    UPDATE content.entity_translations
    SET
      title       = COALESCE(p_title,        title),
      description = COALESCE(p_description,  description),
      content     = COALESCE(p_template_body, content)  -- [[label]] format
    WHERE entity_type = 'lens'::content.entity_type_enum
      AND entity_id   = p_lens_id
      AND is_original = true;
  END IF;

  -- 4. Replace tags
  IF p_tag_ids IS NOT NULL THEN
    DELETE FROM content.tag_map
    WHERE entity_type = 'lens'::content.entity_type_enum
      AND entity_id   = p_lens_id;

    IF array_length(p_tag_ids, 1) > 0 THEN
      FOREACH v_tag_id IN ARRAY p_tag_ids LOOP
        INSERT INTO content.tag_map (entity_type, entity_id, tag_id)
        VALUES ('lens'::content.entity_type_enum, p_lens_id, v_tag_id)
        ON CONFLICT DO NOTHING;
      END LOOP;
    END IF;
  END IF;
END;
$$;


ALTER FUNCTION "lenses"."fn_update_lens"("p_lens_id" "uuid", "p_template_body" "text", "p_visibility" "content"."visibility_enum", "p_title" "text", "p_description" "text", "p_tag_ids" "uuid"[], "p_params" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "lenses"."fn_upsert_draft_version"("p_lens_id" "uuid", "p_template_body" "text", "p_changelog" "text" DEFAULT NULL::"text", "p_parent_version_id" "uuid" DEFAULT NULL::"uuid") RETURNS "lenses"."versions"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'content', 'public'
    AS $$
DECLARE
  v_draft_id            uuid;
  v_next_number         int;
  v_last_published_body text;
  v_result              lenses.versions;
BEGIN
  -- Validate minimum length
  IF length(trim(p_template_body)) < 50 THEN
    RAISE EXCEPTION 'template_body must be at least 50 characters (got %)',
      length(trim(p_template_body))
      USING ERRCODE = 'check_violation';
  END IF;

  -- Content-change detection: fetch last published version's template_body
  -- Uses idx_lens_versions_published_latest
  SELECT v.template_body
  INTO v_last_published_body
  FROM lenses.versions v
  WHERE v.lens_id = p_lens_id
    AND v.status = 'published'::"content"."content_status"
  ORDER BY v.version_number DESC
  LIMIT 1;

  -- If content is identical to last published version → no-op
  IF v_last_published_body IS NOT NULL
     AND v_last_published_body = p_template_body THEN

    -- Return existing draft if one exists
    SELECT *
    INTO v_result
    FROM lenses.versions
    WHERE lens_id = p_lens_id
      AND status = 'draft'::"content"."content_status"
    ORDER BY version_number DESC
    LIMIT 1;

    IF v_result.id IS NOT NULL THEN
      RETURN v_result;
    END IF;

    -- No draft exists — return last published version
    SELECT *
    INTO v_result
    FROM lenses.versions
    WHERE lens_id = p_lens_id
      AND status = 'published'::"content"."content_status"
    ORDER BY version_number DESC
    LIMIT 1;

    RETURN v_result;
  END IF;

  -- Look for the current draft version (uses idx_lens_versions_draft)
  SELECT id
  INTO v_draft_id
  FROM lenses.versions
  WHERE lens_id = p_lens_id
    AND status = 'draft'::"content"."content_status"
  ORDER BY version_number DESC
  LIMIT 1;

  IF v_draft_id IS NOT NULL THEN
    -- Reuse: update the existing draft in place
    UPDATE lenses.versions
    SET
      template_body = p_template_body,
      changelog     = COALESCE(p_changelog, changelog)
    WHERE id = v_draft_id
    RETURNING * INTO v_result;
  ELSE
    -- All prior versions are published/archived — open a new draft
    SELECT COALESCE(MAX(version_number), 0) + 1
    INTO v_next_number
    FROM lenses.versions
    WHERE lens_id = p_lens_id;

    INSERT INTO lenses.versions (
      lens_id,
      version_number,
      template_body,
      status,
      changelog,
      parent_version_id
    )
    VALUES (
      p_lens_id,
      v_next_number,
      p_template_body,
      'draft'::"content"."content_status",
      COALESCE(p_changelog, 'New version'),
      p_parent_version_id
    )
    RETURNING * INTO v_result;
  END IF;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "lenses"."fn_upsert_draft_version"("p_lens_id" "uuid", "p_template_body" "text", "p_changelog" "text", "p_parent_version_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "lenses"."fn_upsert_draft_version"("p_lens_id" "uuid", "p_template_body" "text", "p_changelog" "text", "p_parent_version_id" "uuid") IS 'GRASP Creator: creates or updates draft lens versions with content-change detection. Skips draft creation/update when new content is identical to the last published version. Validates 50-char minimum on template_body. SECURITY DEFINER: bypasses RLS — caller security enforced by calling function.';



CREATE OR REPLACE FUNCTION "lenses"."fn_upsert_workflow_schedule_internal"("p_workflow_id" "uuid", "p_schedule_id" "uuid" DEFAULT NULL::"uuid", "p_cron_expr" "text" DEFAULT '* * * * *'::"text", "p_timezone" "text" DEFAULT 'UTC'::"text", "p_description" "text" DEFAULT NULL::"text", "p_approval_policy" "jsonb" DEFAULT '{"requiresApproval": true}'::"jsonb", "p_is_active" boolean DEFAULT true, "p_global_model_id" "text" DEFAULT NULL::"text", "p_assignee_id" "uuid" DEFAULT NULL::"uuid", "p_workflow_assignment_id" "uuid" DEFAULT NULL::"uuid", "p_retry_policy" "jsonb" DEFAULT '{"maxRetries": 1}'::"jsonb", "p_failure_policy" "jsonb" DEFAULT '{"mode": "isolate"}'::"jsonb", "p_queue_policy" "jsonb" DEFAULT '{"mode": "parallel"}'::"jsonb", "p_inputs_template" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("id" "uuid", "workflow_id" "uuid", "cron_expr" "text", "timezone" "text", "description" "text", "is_active" boolean, "assignee_type" "text", "assignee_id" "uuid", "workflow_assignment_id" "uuid", "approval_policy" "jsonb", "retry_policy" "jsonb", "failure_policy" "jsonb", "queue_policy" "jsonb", "inputs_template" "jsonb", "global_model_id" "text", "next_run_at" timestamp with time zone, "last_run_at" timestamp with time zone, "last_run_id" "uuid", "last_dispatch_status" "text", "last_error_at" timestamp with time zone, "last_error_message" "text", "last_completed_at" timestamp with time zone, "last_result" "jsonb", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'agents', 'lensers', 'public'
    AS $$
DECLARE
  v_schedule_id uuid;
BEGIN
  IF p_schedule_id IS NULL THEN
    INSERT INTO lenses.workflow_schedules (
      workflow_id,
      cron_expr,
      timezone,
      description,
      global_model_id,
      inputs_template,
      is_active,
      assignee_id,
      workflow_assignment_id,
      approval_policy,
      retry_policy,
      failure_policy,
      queue_policy
    ) VALUES (
      p_workflow_id,
      p_cron_expr,
      COALESCE(NULLIF(trim(p_timezone), ''), 'UTC'),
      p_description,
      p_global_model_id,
      COALESCE(p_inputs_template, '{}'::jsonb),
      p_is_active,
      p_assignee_id,
      p_workflow_assignment_id,
      COALESCE(p_approval_policy, '{"requiresApproval":true}'::jsonb),
      COALESCE(p_retry_policy, '{"maxRetries":1}'::jsonb),
      COALESCE(p_failure_policy, '{"mode":"isolate"}'::jsonb),
      COALESCE(p_queue_policy, '{"mode":"parallel"}'::jsonb)
    )
    RETURNING workflow_schedules.id INTO v_schedule_id;
  ELSE
    UPDATE lenses.workflow_schedules s
    SET
      cron_expr              = p_cron_expr,
      timezone               = COALESCE(NULLIF(trim(p_timezone), ''), s.timezone, 'UTC'),
      description            = COALESCE(p_description, s.description),
      global_model_id        = p_global_model_id,
      inputs_template        = COALESCE(p_inputs_template, '{}'::jsonb),
      is_active              = p_is_active,
      assignee_id            = p_assignee_id,
      workflow_assignment_id = p_workflow_assignment_id,
      approval_policy        = COALESCE(p_approval_policy, s.approval_policy, '{}'::jsonb),
      retry_policy           = COALESCE(p_retry_policy, s.retry_policy, '{}'::jsonb),
      failure_policy         = COALESCE(p_failure_policy, s.failure_policy, '{}'::jsonb),
      queue_policy           = COALESCE(p_queue_policy, s.queue_policy, '{}'::jsonb),
      last_dispatch_status   = CASE
        WHEN p_is_active THEN NULL
        ELSE COALESCE(s.last_dispatch_status, 'paused')
      END,
      last_error_at          = CASE
        WHEN p_is_active THEN NULL
        ELSE s.last_error_at
      END,
      last_error_message     = CASE
        WHEN p_is_active THEN NULL
        ELSE s.last_error_message
      END
    WHERE s.id = p_schedule_id
      AND s.workflow_id = p_workflow_id
    RETURNING s.id INTO v_schedule_id;

    IF v_schedule_id IS NULL THEN
      RAISE EXCEPTION 'Schedule not found or not owned by the active workspace'
        USING ERRCODE = '42501';
    END IF;
  END IF;

  RETURN QUERY
  SELECT
    s.id,
    s.workflow_id,
    s.cron_expr,
    s.timezone,
    s.description,
    s.is_active,
    s.assignee_type,
    s.assignee_id,
    s.workflow_assignment_id,
    s.approval_policy,
    s.retry_policy,
    s.failure_policy,
    s.queue_policy,
    s.inputs_template,
    s.global_model_id,
    s.next_run_at,
    s.last_run_at,
    s.last_run_id,
    s.last_dispatch_status,
    s.last_error_at,
    s.last_error_message,
    s.last_completed_at,
    s.last_result,
    s.created_at
  FROM lenses.workflow_schedules s
  WHERE s.id = v_schedule_id;
END;
$$;


ALTER FUNCTION "lenses"."fn_upsert_workflow_schedule_internal"("p_workflow_id" "uuid", "p_schedule_id" "uuid", "p_cron_expr" "text", "p_timezone" "text", "p_description" "text", "p_approval_policy" "jsonb", "p_is_active" boolean, "p_global_model_id" "text", "p_assignee_id" "uuid", "p_workflow_assignment_id" "uuid", "p_retry_policy" "jsonb", "p_failure_policy" "jsonb", "p_queue_policy" "jsonb", "p_inputs_template" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "lenses"."fn_validate_inputs"("p_version_id" "uuid", "p_inputs" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'media', 'lensers', 'public'
    AS $_$
DECLARE
  vp          RECORD;
  v_raw       text;
  v_schema    jsonb;
  v_min       numeric;
  v_max       numeric;
  v_num       numeric;
  v_caller_id uuid;
BEGIN
  -- No version → nothing to validate (allow ad-hoc / legacy requests)
  IF p_version_id IS NULL THEN
    RETURN;
  END IF;

  v_caller_id := "lensers"."get_auth_lenser_id"();

  -- Join tools to get type, required, options, validation_schema.
  -- Use parameter label as the input key (consistent with fn_create_lens).
  FOR vp IN
    SELECT
      vp_row."label"              AS "key",
      t."type"                    AS "type",
      t."required"                AS "required",
      t."options"                 AS "options",
      t."validation_schema"       AS "validation_schema"
    FROM   "lenses"."version_parameters" vp_row
    JOIN   "lenses"."tools"              t ON t."id" = vp_row."tool_id"
    WHERE  vp_row."version_id" = p_version_id
    ORDER  BY t."sort_order", vp_row."label"
    LIMIT  200
  LOOP
    v_raw    := "p_inputs"->>vp."key";
    v_schema := vp."validation_schema";

    -- 1. Required field must be present and non-empty
    IF vp."required" AND (v_raw IS NULL OR trim(v_raw) = '') THEN
      RAISE EXCEPTION 'Required parameter "%" is missing or empty', vp."key"
        USING ERRCODE = 'check_violation';
    END IF;

    -- Skip type checks for absent optional parameters
    CONTINUE WHEN v_raw IS NULL OR trim(v_raw) = '';

    -- 2. Type-compatibility check + schema enforcement
    BEGIN
      CASE vp."type"

        -- ── Legacy numeric ───────────────────────────────────────────────
        WHEN 'number' THEN
          v_num := v_raw::"numeric";
          IF v_schema IS NOT NULL THEN
            IF v_schema->>'min' IS NOT NULL THEN
              v_min := (v_schema->>'min')::"numeric";
              IF v_num < v_min THEN
                RAISE EXCEPTION 'Parameter "%" value % is below minimum %',
                  vp."key", v_num, v_min USING ERRCODE = 'check_violation';
              END IF;
            END IF;
            IF v_schema->>'max' IS NOT NULL THEN
              v_max := (v_schema->>'max')::"numeric";
              IF v_num > v_max THEN
                RAISE EXCEPTION 'Parameter "%" value % exceeds maximum %',
                  vp."key", v_num, v_max USING ERRCODE = 'check_violation';
              END IF;
            END IF;
          END IF;

        -- ── Integer ──────────────────────────────────────────────────────
        WHEN 'integer' THEN
          v_num := v_raw::"bigint";
          IF v_schema IS NOT NULL THEN
            IF v_schema->>'min' IS NOT NULL THEN
              v_min := (v_schema->>'min')::"numeric";
              IF v_num < v_min THEN
                RAISE EXCEPTION 'Parameter "%" value % is below minimum %',
                  vp."key", v_num, v_min USING ERRCODE = 'check_violation';
              END IF;
            END IF;
            IF v_schema->>'max' IS NOT NULL THEN
              v_max := (v_schema->>'max')::"numeric";
              IF v_num > v_max THEN
                RAISE EXCEPTION 'Parameter "%" value % exceeds maximum %',
                  vp."key", v_num, v_max USING ERRCODE = 'check_violation';
              END IF;
            END IF;
          END IF;

        -- ── Float ────────────────────────────────────────────────────────
        WHEN 'float' THEN
          v_num := v_raw::"double precision";
          IF v_schema IS NOT NULL THEN
            IF v_schema->>'min' IS NOT NULL THEN
              v_min := (v_schema->>'min')::"numeric";
              IF v_num < v_min THEN
                RAISE EXCEPTION 'Parameter "%" value % is below minimum %',
                  vp."key", v_num, v_min USING ERRCODE = 'check_violation';
              END IF;
            END IF;
            IF v_schema->>'max' IS NOT NULL THEN
              v_max := (v_schema->>'max')::"numeric";
              IF v_num > v_max THEN
                RAISE EXCEPTION 'Parameter "%" value % exceeds maximum %',
                  vp."key", v_num, v_max USING ERRCODE = 'check_violation';
              END IF;
            END IF;
          END IF;

        -- ── Decimal / Numeric ─────────────────────────────────────────────
        WHEN 'decimal' THEN
          v_num := v_raw::"numeric";
          IF v_schema IS NOT NULL THEN
            IF v_schema->>'min' IS NOT NULL THEN
              v_min := (v_schema->>'min')::"numeric";
              IF v_num < v_min THEN
                RAISE EXCEPTION 'Parameter "%" value % is below minimum %',
                  vp."key", v_num, v_min USING ERRCODE = 'check_violation';
              END IF;
            END IF;
            IF v_schema->>'max' IS NOT NULL THEN
              v_max := (v_schema->>'max')::"numeric";
              IF v_num > v_max THEN
                RAISE EXCEPTION 'Parameter "%" value % exceeds maximum %',
                  vp."key", v_num, v_max USING ERRCODE = 'check_violation';
              END IF;
            END IF;
          END IF;

        -- ── Boolean ───────────────────────────────────────────────────────
        WHEN 'boolean' THEN
          IF lower(v_raw) NOT IN ('true', 'false', '1', '0') THEN
            RAISE EXCEPTION
              'Parameter "%" must be a boolean value (true/false), got: %',
              vp."key", v_raw
              USING ERRCODE = 'check_violation';
          END IF;

        -- ── JSON ──────────────────────────────────────────────────────────
        WHEN 'json' THEN
          PERFORM v_raw::"jsonb";

        -- ── Select (enum membership) ──────────────────────────────────────
        WHEN 'select' THEN
          IF vp."options" IS NOT NULL
             AND jsonb_typeof(vp."options") = 'array'
             AND NOT EXISTS (
               SELECT 1
               FROM   jsonb_array_elements(vp."options") opt
               WHERE  opt->>'value' = v_raw
             ) THEN
            RAISE EXCEPTION
              'Parameter "%" value "%" is not in the allowed options list',
              vp."key", v_raw
              USING ERRCODE = 'check_violation';
          END IF;

        -- ── URL ───────────────────────────────────────────────────────────
        WHEN 'url' THEN
          -- Must start with http:// or https:// (no scheme injection)
          IF v_raw !~ '^https?://' THEN
            RAISE EXCEPTION
              'Parameter "%" must be a valid URL starting with http:// or https://, got: %',
              vp."key", left(v_raw, 100)
              USING ERRCODE = 'check_violation';
          END IF;
          -- Optional: allowedSchemes from validation_schema
          IF v_schema IS NOT NULL AND v_schema->'urlScheme' IS NOT NULL
             AND jsonb_typeof(v_schema->'urlScheme') = 'array'
             AND NOT EXISTS (
               SELECT 1
               FROM   jsonb_array_elements_text(v_schema->'urlScheme') scheme
               WHERE  lower(v_raw) LIKE lower(scheme) || '://%'
             ) THEN
            RAISE EXCEPTION
              'Parameter "%" URL scheme is not allowed',
              vp."key"
              USING ERRCODE = 'check_violation';
          END IF;

        -- ── Date ──────────────────────────────────────────────────────────
        WHEN 'date' THEN
          PERFORM v_raw::"date";

        -- ── Datetime ──────────────────────────────────────────────────────
        WHEN 'datetime' THEN
          PERFORM v_raw::"timestamptz";

        -- ── File (attachment) ─────────────────────────────────────────────
        WHEN 'file' THEN
          -- Value must be a valid UUID
          IF v_raw !~ '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$' THEN
            RAISE EXCEPTION
              'Parameter "%" must be a media object UUID, got invalid value',
              vp."key"
              USING ERRCODE = 'check_violation';
          END IF;
          -- Referenced media.objects row must exist and be owned by the caller
          IF v_caller_id IS NOT NULL THEN
            IF NOT EXISTS (
              SELECT 1
              FROM   "media"."objects" mo
              WHERE  mo."id"               = v_raw::"uuid"
                AND  mo."owner_lenser_id"  = v_caller_id
                AND  mo."lifecycle_state" IN ('pending', 'active')
            ) THEN
              RAISE EXCEPTION
                'Parameter "%" references a media object that does not exist or is not accessible',
                vp."key"
                USING ERRCODE = 'check_violation';
            END IF;
          END IF;

        ELSE
          NULL;  -- 'text', 'textarea': no structural enforcement
      END CASE;

    EXCEPTION
      WHEN invalid_text_representation
        OR numeric_value_out_of_range
        OR invalid_parameter_value
        OR invalid_datetime_format
      THEN
        RAISE EXCEPTION
          'Parameter "%" has an invalid value for type "%": %',
          vp."key", vp."type", left(v_raw, 200)
          USING ERRCODE = 'check_violation';
    END;
  END LOOP;
END;
$_$;


ALTER FUNCTION "lenses"."fn_validate_inputs"("p_version_id" "uuid", "p_inputs" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "lenses"."fn_validate_inputs"("p_version_id" "uuid", "p_inputs" "jsonb") IS 'GRASP Information Expert: validates execution inputs against the declared version_parameters for a given lens version. Joins lenses.tools via tool_id to resolve type, required, options, and validation_schema. Uses parameter label as the input key. Supports types: text, textarea, number, integer, float, decimal, boolean, json, select, url (regex + scheme allowlist), date, datetime, file (UUID + caller-owned media.objects row). Called by execution.fn_run_lens. SECURITY DEFINER.';



CREATE OR REPLACE FUNCTION "lenses"."fn_workflow_has_cycle"("p_workflow_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'lenses', 'pg_catalog'
    AS $$
  WITH RECURSIVE walk AS (
    SELECT
      e.source_node_id,
      e.target_node_id,
      ARRAY[e.source_node_id, e.target_node_id]::uuid[] AS path,
      e.source_node_id = e.target_node_id AS cycle
    FROM lenses.workflow_edges e
    WHERE e.workflow_id = p_workflow_id

    UNION ALL

    SELECT
      w.source_node_id,
      e.target_node_id,
      w.path || e.target_node_id,
      e.target_node_id = ANY(w.path) AS cycle
    FROM walk w
    JOIN lenses.workflow_edges e
      ON e.workflow_id = p_workflow_id
     AND e.source_node_id = w.target_node_id
    WHERE NOT w.cycle
      AND cardinality(w.path) < 256
  )
  SELECT EXISTS (SELECT 1 FROM walk WHERE cycle);
$$;


ALTER FUNCTION "lenses"."fn_workflow_has_cycle"("p_workflow_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "lenses"."fn_workflow_has_cycle"("p_workflow_id" "uuid") IS 'Returns true when the workflow graph contains a cycle. Used to block schedule activation for invalid DAGs.';



CREATE OR REPLACE FUNCTION "lenses"."fn_xp_on_tutorial_completed"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'xp', 'execution', 'public', 'extensions'
    AS $$
DECLARE
  v_rule_key  TEXT;
  v_forum_app CONSTANT UUID := '00000000-0000-0000-0000-000000000001';
BEGIN
  v_rule_key := CASE NEW.kind
    WHEN 'tutorial'     THEN 'TUTORIAL_COMPLETED'
    WHEN 'walkthrough'  THEN 'WALKTHROUGH_COMPLETED'
    ELSE NULL
  END;

  IF v_rule_key IS NULL THEN
    RETURN NEW;
  END IF;

  PERFORM execution.fn_xp_apply_safe(
    NEW.lenser_id,
    v_rule_key,
    'system'::xp.source_enum,
    'tutorial_completion',
    NEW.id,
    v_forum_app
  );
  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE NOTICE 'fn_xp_on_tutorial_completed: % (completion=%)', SQLERRM, NEW.id;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "lenses"."fn_xp_on_tutorial_completed"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "lenses"."fn_xp_on_workflow_run_received"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'xp', 'execution', 'public', 'extensions'
    AS $$
DECLARE
  v_owner_lenser_id UUID;
  v_forum_app       CONSTANT UUID := '00000000-0000-0000-0000-000000000001';
BEGIN
  -- Only award when a real user triggers a run (not schedule/subflow/system)
  IF NEW.triggered_by IS NULL THEN
    RETURN NEW;
  END IF;

  -- Look up the workflow owner and check visibility in one query
  SELECT w.lenser_id INTO v_owner_lenser_id
  FROM lenses.workflows w
  WHERE w.id = NEW.workflow_id
    AND w.visibility = 'public'
    AND w.lenser_id IS DISTINCT FROM NEW.triggered_by;

  IF v_owner_lenser_id IS NULL THEN
    RETURN NEW;
  END IF;

  PERFORM execution.fn_xp_apply_safe(
    v_owner_lenser_id,
    'WORKFLOW_RUN_RECEIVED',
    'system'::xp.source_enum,
    'workflow_run',
    NEW.id,
    v_forum_app
  );
  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE NOTICE 'fn_xp_on_workflow_run_received: % (run=%)', SQLERRM, NEW.id;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "lenses"."fn_xp_on_workflow_run_received"() OWNER TO "postgres";


