CREATE OR REPLACE FUNCTION "public"."fn_analytics_submit_feedback"("p_product_tag" "text" DEFAULT 'general'::"text", "p_page" "text" DEFAULT NULL::"text", "p_message" "text" DEFAULT NULL::"text", "p_start_date" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_end_date" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'analytics', 'auth'
    AS $$
DECLARE
  v_user_id uuid;
BEGIN
  v_user_id := auth.uid();

  -- Must be authenticated
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'authentication required' USING ERRCODE = '42501';
  END IF;

  -- Message length guard (matches service-layer validation)
  IF p_message IS NOT NULL AND (length(trim(p_message)) < 10 OR length(trim(p_message)) > 2000) THEN
    RAISE EXCEPTION 'feedback message must be between 10 and 2000 characters' USING ERRCODE = '22023';
  END IF;

  -- Validate product_tag before cast to surface a clear error to the client
  IF p_product_tag NOT IN ('bug', 'feature', 'ui_ux', 'general', 'other') THEN
    RAISE EXCEPTION 'invalid product_tag: %. Must be one of: bug, feature, ui_ux, general, other', p_product_tag
      USING ERRCODE = '22023';
  END IF;

  INSERT INTO analytics.product_feedback (
    user_id,
    product_tag,
    page,
    message,
    start_date,
    end_date
  ) VALUES (
    v_user_id,
    p_product_tag::analytics.product_tag_enum,  -- FIX: explicit cast (42804)
    p_page,
    trim(p_message),
    p_start_date,
    p_end_date
  );
END;
$$;


ALTER FUNCTION "public"."fn_analytics_submit_feedback"("p_product_tag" "text", "p_page" "text", "p_message" "text", "p_start_date" timestamp with time zone, "p_end_date" timestamp with time zone) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_analytics_submit_feedback"("p_product_tag" "text", "p_page" "text", "p_message" "text", "p_start_date" timestamp with time zone, "p_end_date" timestamp with time zone) IS 'Inserts a product feedback row for the calling user. Validates message length and product_tag enum value server-side. Fixed in migration 000055: added explicit ::analytics.product_tag_enum cast and enum value guard to resolve 42804 type mismatch.';



CREATE OR REPLACE FUNCTION "public"."fn_analytics_submit_feedback_public"("p_product_tag" "text" DEFAULT 'general'::"text", "p_page" "text" DEFAULT NULL::"text", "p_message" "text" DEFAULT NULL::"text", "p_start_date" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_end_date" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'analytics', 'auth'
    AS $$
DECLARE
  v_user_id uuid;
  v_recent_count int;
BEGIN
  -- Capture caller identity if authenticated (NULL is fine for anon)
  v_user_id := auth.uid();

  -- Message validation
  IF p_message IS NOT NULL AND (
    length(trim(p_message)) < 10 OR
    length(trim(p_message)) > 2000
  ) THEN
    RAISE EXCEPTION 'feedback message must be between 10 and 2000 characters'
      USING ERRCODE = '22023';
  END IF;

  -- Product tag validation
  IF p_product_tag NOT IN ('bug', 'feature', 'ui_ux', 'general', 'other') THEN
    RAISE EXCEPTION 'invalid product_tag: %. Must be one of: bug, feature, ui_ux, general, other',
      p_product_tag USING ERRCODE = '22023';
  END IF;

  -- Rate-limit authenticated users: max 5 per hour
  IF v_user_id IS NOT NULL THEN
    SELECT COUNT(*)
      INTO v_recent_count
      FROM analytics.product_feedback
     WHERE user_id = v_user_id
       AND created_at > now() - interval '1 hour';

    IF v_recent_count >= 5 THEN
      RAISE EXCEPTION 'rate limit exceeded: max 5 feedback submissions per hour'
        USING ERRCODE = '429';
    END IF;
  END IF;

  INSERT INTO analytics.product_feedback (
    user_id,
    product_tag,
    page,
    message,
    start_date,
    end_date
  ) VALUES (
    v_user_id,
    p_product_tag::analytics.product_tag_enum,
    p_page,
    trim(p_message),
    p_start_date,
    p_end_date
  );
END;
$$;


ALTER FUNCTION "public"."fn_analytics_submit_feedback_public"("p_product_tag" "text", "p_page" "text", "p_message" "text", "p_start_date" timestamp with time zone, "p_end_date" timestamp with time zone) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_analytics_submit_feedback_public"("p_product_tag" "text", "p_page" "text", "p_message" "text", "p_start_date" timestamp with time zone, "p_end_date" timestamp with time zone) IS 'Public (anon-accessible) feedback submission. Captures auth.uid() when authenticated. Rate-limits authenticated callers to 5/hour. Anon rate-limiting is handled client-side.';



