CREATE OR REPLACE FUNCTION "public"."fn_backfill_schedule"("p_schedule_id" "uuid", "p_since" timestamp with time zone, "p_dry_run" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses', 'agents'
    AS $_$
DECLARE
  v_caller          uuid := lensers.get_auth_lenser_id();
  v_schedule        record;
  v_parts           text[];
  v_minute          text;
  v_hour            text;
  v_dom             text;
  v_mon             text;
  v_dow             text;
  v_step_minutes    int;
  v_target_hour     int;
  v_target_dow      int;
  v_tick            timestamptz;
  v_dispatched      int := 0;
  v_skipped         int := 0;
  v_ticks           jsonb := '[]'::jsonb;
  v_backfill_key    text;
  v_run_id          uuid;
  v_now             timestamptz := date_trunc('minute', now());
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'not_authenticated' USING ERRCODE = '42501';
  END IF;

  IF p_since IS NULL OR p_since >= now() THEN
    RAISE EXCEPTION 'p_since must be in the past' USING ERRCODE = '22023';
  END IF;

  -- Cap window at 30 days to bound cost.
  IF p_since < now() - interval '30 days' THEN
    RAISE EXCEPTION 'p_since exceeds 30-day backfill window' USING ERRCODE = '22023';
  END IF;

  SELECT s.id,
         s.workflow_id,
         s.cron_expr,
         s.inputs_template,
         s.global_model_id,
         w.lenser_id   AS owner_id
  INTO   v_schedule
  FROM   lenses.workflow_schedules s
  JOIN   lenses.workflows w ON w.id = s.workflow_id
  WHERE  s.id = p_schedule_id;

  IF v_schedule.id IS NULL THEN
    RAISE EXCEPTION 'schedule_not_found: %', p_schedule_id USING ERRCODE = 'P0002';
  END IF;

  IF v_schedule.owner_id IS DISTINCT FROM v_caller THEN
    RAISE EXCEPTION 'not_workflow_owner' USING ERRCODE = '42501';
  END IF;

  -- ── Parse the cron expression ──────────────────────────────────────────
  v_parts := regexp_split_to_array(trim(v_schedule.cron_expr), '\s+');
  IF array_length(v_parts, 1) <> 5 THEN
    RAISE EXCEPTION
      'unsupported_cron_expression: % (expected 5 fields)',
      v_schedule.cron_expr
      USING ERRCODE = '22023';
  END IF;

  v_minute := v_parts[1];
  v_hour   := v_parts[2];
  v_dom    := v_parts[3];
  v_mon    := v_parts[4];
  v_dow    := v_parts[5];

  -- Build the tick stream. Truncate p_since to minute precision.
  IF v_minute = '*' AND v_hour = '*' AND v_dom = '*' AND v_mon = '*' AND v_dow = '*' THEN
    -- every minute
    FOR v_tick IN
      SELECT g
      FROM generate_series(date_trunc('minute', p_since), v_now, interval '1 minute') g
    LOOP
      v_ticks := v_ticks || to_jsonb(v_tick);
    END LOOP;

  ELSIF v_minute LIKE '*/%' AND v_hour = '*' AND v_dom = '*' AND v_mon = '*' AND v_dow = '*' THEN
    -- every N minutes
    BEGIN
      v_step_minutes := substr(v_minute, 3)::int;
    EXCEPTION WHEN OTHERS THEN
      RAISE EXCEPTION 'unsupported_cron_expression: %', v_schedule.cron_expr USING ERRCODE = '22023';
    END;

    IF v_step_minutes <= 0 OR v_step_minutes > 59 THEN
      RAISE EXCEPTION 'unsupported_cron_expression: %', v_schedule.cron_expr USING ERRCODE = '22023';
    END IF;

    FOR v_tick IN
      SELECT g
      FROM generate_series(date_trunc('hour', p_since), v_now, (v_step_minutes::text || ' minutes')::interval) g
      WHERE g >= p_since
    LOOP
      v_ticks := v_ticks || to_jsonb(v_tick);
    END LOOP;

  ELSIF v_minute = '0' AND v_dom = '*' AND v_mon = '*' AND v_dow = '*'
        AND v_hour ~ '^[0-9]+$' THEN
    -- 0 H * * *  (daily at hour H, UTC)
    v_target_hour := v_hour::int;
    IF v_target_hour < 0 OR v_target_hour > 23 THEN
      RAISE EXCEPTION 'unsupported_cron_expression: %', v_schedule.cron_expr USING ERRCODE = '22023';
    END IF;

    FOR v_tick IN
      SELECT g
      FROM generate_series(
        date_trunc('day', p_since AT TIME ZONE 'UTC') AT TIME ZONE 'UTC'
          + (v_target_hour::text || ' hours')::interval,
        v_now,
        interval '1 day'
      ) g
      WHERE g >= p_since AND g <= v_now
    LOOP
      v_ticks := v_ticks || to_jsonb(v_tick);
    END LOOP;

  ELSIF v_minute = '0' AND v_dom = '*' AND v_mon = '*'
        AND v_hour ~ '^[0-9]+$' AND v_dow ~ '^[0-6]$' THEN
    -- 0 H * * DOW  (weekly, hour H, day-of-week DOW; 0=Sun)
    v_target_hour := v_hour::int;
    v_target_dow  := v_dow::int;
    IF v_target_hour < 0 OR v_target_hour > 23 THEN
      RAISE EXCEPTION 'unsupported_cron_expression: %', v_schedule.cron_expr USING ERRCODE = '22023';
    END IF;

    FOR v_tick IN
      SELECT g
      FROM generate_series(
        date_trunc('day', p_since AT TIME ZONE 'UTC') AT TIME ZONE 'UTC'
          + (v_target_hour::text || ' hours')::interval,
        v_now,
        interval '1 day'
      ) g
      WHERE g >= p_since AND g <= v_now
        AND extract(dow from g)::int = v_target_dow
    LOOP
      v_ticks := v_ticks || to_jsonb(v_tick);
    END LOOP;

  ELSE
    RAISE EXCEPTION
      'unsupported_cron_expression: % (supported: ''*/N * * * *'', ''0 H * * *'', ''0 H * * DOW'')',
      v_schedule.cron_expr
      USING ERRCODE = '22023';
  END IF;

  -- ── Dry-run path ───────────────────────────────────────────────────────
  IF p_dry_run THEN
    RETURN jsonb_build_object(
      'would_dispatch', jsonb_array_length(v_ticks),
      'ticks',          v_ticks
    );
  END IF;

  -- ── Execute path ───────────────────────────────────────────────────────
  FOR v_tick IN
    SELECT (value::text)::timestamptz FROM jsonb_array_elements_text(v_ticks)
  LOOP
    v_backfill_key := p_schedule_id::text || ':' ||
                      to_char(v_tick AT TIME ZONE 'UTC', 'YYYY-MM-DD"T"HH24:MI:SS"Z"');

    -- Skip if a run for this exact slot already exists (either via
    -- backfill_id metadata key or via the existing schedule_id+scheduled_for
    -- unique slot index).
    IF EXISTS (
      SELECT 1 FROM lenses.workflow_runs
      WHERE metadata->>'backfill_id' = v_backfill_key
    ) OR EXISTS (
      SELECT 1 FROM lenses.workflow_runs
      WHERE schedule_id = p_schedule_id
        AND scheduled_for = v_tick
    ) THEN
      v_skipped := v_skipped + 1;
      CONTINUE;
    END IF;

    INSERT INTO lenses.workflow_runs (
      workflow_id,
      triggered_by,
      status,
      context_inputs,
      global_model_id,
      schedule_id,
      scheduled_for,
      trigger_mode,
      metadata
    ) VALUES (
      v_schedule.workflow_id,
      v_caller,
      'pending',
      COALESCE(v_schedule.inputs_template, '{}'::jsonb),
      v_schedule.global_model_id,
      p_schedule_id,
      v_tick,
      'schedule',
      jsonb_build_object('backfill_id', v_backfill_key, 'origin', 'backfill')
    )
    RETURNING id INTO v_run_id;

    -- Materialise node placeholders so the worker can pick this run up.
    INSERT INTO lenses.workflow_node_results (run_id, node_id, status)
    SELECT v_run_id, n.id, 'pending'
    FROM   lenses.workflow_nodes n
    WHERE  n.workflow_id = v_schedule.workflow_id;

    v_dispatched := v_dispatched + 1;
  END LOOP;

  RETURN jsonb_build_object(
    'dispatched',       v_dispatched,
    'skipped_existing', v_skipped
  );
END;
$_$;


ALTER FUNCTION "public"."fn_backfill_schedule"("p_schedule_id" "uuid", "p_since" timestamp with time zone, "p_dry_run" boolean) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_backfill_schedule"("p_schedule_id" "uuid", "p_since" timestamp with time zone, "p_dry_run" boolean) IS 'Phase Q1: enumerates missed cron ticks between p_since and now() for a workflow schedule the caller owns and inserts pending workflow_runs the recovery sweeper will pick up. Supports * * * * *, */N * * * *, 0 H * * *, 0 H * * DOW. Dedupes via metadata.backfill_id and (schedule_id, scheduled_for). Returns jsonb with dispatched/skipped or would_dispatch/ticks.';



CREATE OR REPLACE FUNCTION "public"."fn_badge_check_and_award"("p_lenser_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lensers', 'xp', 'public'
    AS $$
DECLARE
  v_total_xp   BIGINT;
  v_level      INT;
  v_streak     INT;
  v_forum_app  CONSTANT uuid := '00000000-0000-0000-0000-000000000001';
BEGIN
  -- Fetch current XP + level
  SELECT total_xp, current_level
    INTO v_total_xp, v_level
    FROM xp.totals
   WHERE lenser_id = p_lenser_id
     AND app_id    = v_forum_app;

  IF NOT FOUND THEN
    RETURN;
  END IF;

  -- Fetch daily streak
  SELECT current_streak
    INTO v_streak
    FROM xp.streaks
   WHERE lenser_id   = p_lenser_id
     AND streak_type = 'daily';

  -- ---- Level milestone badges -------------------------------------------
  -- Newcomer  (level 5)
  IF v_level >= 5 THEN
    INSERT INTO lensers.badges (lenser_id, type, label, description, icon)
    VALUES (p_lenser_id, 'level_milestone_5', 'Newcomer', 'Reached Level 5', '🌱')
    ON CONFLICT DO NOTHING;
  END IF;

  -- Builder (level 10)
  IF v_level >= 10 THEN
    INSERT INTO lensers.badges (lenser_id, type, label, description, icon)
    VALUES (p_lenser_id, 'level_milestone_10', 'Builder', 'Reached Level 10', '🏗️')
    ON CONFLICT DO NOTHING;
  END IF;

  -- Expert (level 25)
  IF v_level >= 25 THEN
    INSERT INTO lensers.badges (lenser_id, type, label, description, icon)
    VALUES (p_lenser_id, 'level_milestone_25', 'Expert', 'Reached Level 25', '⚡')
    ON CONFLICT DO NOTHING;
  END IF;

  -- Architect (level 50)
  IF v_level >= 50 THEN
    INSERT INTO lensers.badges (lenser_id, type, label, description, icon)
    VALUES (p_lenser_id, 'level_milestone_50', 'Architect', 'Reached Level 50', '🏛️')
    ON CONFLICT DO NOTHING;
  END IF;

  -- Legend (level 75)
  IF v_level >= 75 THEN
    INSERT INTO lensers.badges (lenser_id, type, label, description, icon)
    VALUES (p_lenser_id, 'level_milestone_75', 'Legend', 'Reached Level 75', '🌟')
    ON CONFLICT DO NOTHING;
  END IF;

  -- Champion (level 100)
  IF v_level >= 100 THEN
    INSERT INTO lensers.badges (lenser_id, type, label, description, icon)
    VALUES (p_lenser_id, 'level_milestone_100', 'Champion', 'Reached Level 100 — all-time elite', '🏆')
    ON CONFLICT DO NOTHING;
  END IF;

  -- ---- XP milestone badges -----------------------------------------------
  IF v_total_xp >= 1000 THEN
    INSERT INTO lensers.badges (lenser_id, type, label, description, icon)
    VALUES (p_lenser_id, 'xp_1k', '1K XP', 'Earned 1,000 total XP', '💡')
    ON CONFLICT DO NOTHING;
  END IF;

  IF v_total_xp >= 10000 THEN
    INSERT INTO lensers.badges (lenser_id, type, label, description, icon)
    VALUES (p_lenser_id, 'xp_10k', '10K XP', 'Earned 10,000 total XP', '🔥')
    ON CONFLICT DO NOTHING;
  END IF;

  IF v_total_xp >= 50000 THEN
    INSERT INTO lensers.badges (lenser_id, type, label, description, icon)
    VALUES (p_lenser_id, 'xp_50k', '50K XP', 'Earned 50,000 total XP', '💎')
    ON CONFLICT DO NOTHING;
  END IF;

  -- ---- Streak milestone badges -------------------------------------------
  IF v_streak >= 7 THEN
    INSERT INTO lensers.badges (lenser_id, type, label, description, icon)
    VALUES (p_lenser_id, 'streak_7d', '7-Day Streak', 'Logged in 7 days in a row', '🔆')
    ON CONFLICT DO NOTHING;
  END IF;

  IF v_streak >= 30 THEN
    INSERT INTO lensers.badges (lenser_id, type, label, description, icon)
    VALUES (p_lenser_id, 'streak_30d', '30-Day Streak', 'Logged in 30 days in a row', '☀️')
    ON CONFLICT DO NOTHING;
  END IF;

EXCEPTION WHEN OTHERS THEN
  -- Non-fatal: badge award errors must not roll back the parent XP transaction
  RAISE NOTICE 'fn_badge_check_and_award: % (lenser=%)', SQLERRM, p_lenser_id;
END;
$$;


ALTER FUNCTION "public"."fn_badge_check_and_award"("p_lenser_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_badge_check_and_award"("p_lenser_id" "uuid") IS 'CB: Awards milestone badges based on XP totals, level, and streak. SECURITY DEFINER. Non-fatal on error.';



CREATE OR REPLACE FUNCTION "public"."fn_battle_close_voting"("p_battle_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
DECLARE
  v_creator_id uuid;
BEGIN
  SELECT id INTO v_creator_id
  FROM lensers.profiles
  WHERE user_id = auth.uid()
  LIMIT 1;

  IF v_creator_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated.';
  END IF;

  UPDATE battles.battles
  SET
    status           = 'scoring',
    voting_closes_at = now(),
    updated_at       = now()
  WHERE id                = p_battle_id
    AND creator_lenser_id = v_creator_id
    AND status            = 'voting'
    AND deleted_at        IS NULL;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Battle not found, not owned by you, or not in voting status.';
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_battle_close_voting"("p_battle_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_battle_close_voting"("p_battle_id" "uuid") IS 'Transitions a battle from voting to scoring. Sets voting_closes_at = now(). Only callable by the battle creator. SECURITY DEFINER.';



CREATE OR REPLACE FUNCTION "public"."fn_battle_dispatch_agent"("p_battle_id" "uuid", "p_agent_id" "uuid", "p_model_spec" "text", "p_device_id" "uuid" DEFAULT NULL::"uuid", "p_workflow_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'agents', 'lensers', 'execution', 'public'
    AS $$
DECLARE
  v_lenser_id  UUID;
  v_battle     battles.battles%ROWTYPE;
  v_contender  battles.contenders%ROWTYPE;
BEGIN
  -- Resolve caller lenser
  SELECT p.id INTO v_lenser_id
  FROM   lensers.profiles p
  WHERE  p.user_id = auth.uid();

  -- Verify agent ownership
  IF NOT EXISTS (
    SELECT 1 FROM agents.ai_lensers al
    WHERE  al.id = p_agent_id AND al.profile_id = v_lenser_id
  ) THEN
    RAISE EXCEPTION 'dispatch_agent_forbidden: agent not owned by caller';
  END IF;

  -- Verify battle is in a submittable state
  SELECT * INTO v_battle FROM battles.battles WHERE id = p_battle_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'dispatch_agent_battle_not_found: %', p_battle_id;
  END IF;
  IF v_battle.status NOT IN ('open', 'executing') THEN
    RAISE EXCEPTION 'dispatch_agent_battle_not_open: status=%', v_battle.status;
  END IF;

  -- Verify contender registration
  SELECT c.* INTO v_contender
  FROM   battles.contenders c
  JOIN   lensers.profiles p ON p.id = c.lenser_id
  WHERE  c.battle_id = p_battle_id
  AND    p.id = v_lenser_id
  LIMIT  1;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'dispatch_agent_not_registered: join the battle first';
  END IF;

  -- Log dispatch intent
  INSERT INTO audit.events (event_type, actor_type, actor_id, payload)
  VALUES (
    'battle.agent_dispatch_queued',
    'lenser',
    v_lenser_id,
    jsonb_build_object(
      'battle_id',   p_battle_id,
      'agent_id',    p_agent_id,
      'model_spec',  p_model_spec,
      'device_id',   p_device_id,
      'workflow_id', p_workflow_id
    )
  );

  RETURN jsonb_build_object(
    'battle_id',    p_battle_id,
    'agent_id',     p_agent_id,
    'contender_id', v_contender.id,
    'model_spec',   p_model_spec,
    'status',       'queued'
  );
END;
$$;


ALTER FUNCTION "public"."fn_battle_dispatch_agent"("p_battle_id" "uuid", "p_agent_id" "uuid", "p_model_spec" "text", "p_device_id" "uuid", "p_workflow_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battle_force_transition"("p_battle_id" "uuid", "p_target_status" "text", "p_reason" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'audit', 'public'
    AS $$
DECLARE
  v_operator_id UUID;
  v_old_status  TEXT;
BEGIN
  IF NOT public.is_admin() THEN
    RAISE EXCEPTION 'force_transition_forbidden: admin role required';
  END IF;

  SELECT p.id INTO v_operator_id
  FROM   lensers.profiles p
  WHERE  p.user_id = auth.uid();

  SELECT status::TEXT INTO v_old_status
  FROM   battles.battles
  WHERE  id = p_battle_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'force_transition_battle_not_found: %', p_battle_id;
  END IF;

  IF p_target_status NOT IN ('draft', 'open', 'executing', 'voting', 'scoring', 'closed', 'published', 'archived') THEN
    RAISE EXCEPTION 'force_transition_invalid_status: %', p_target_status;
  END IF;

  UPDATE battles.battles
  SET    status       = p_target_status::battles.battle_status_enum,
         updated_at   = now(),
         published_at = CASE WHEN p_target_status = 'published' THEN now() ELSE published_at END,
         finalized_at = CASE WHEN p_target_status IN ('closed', 'published') THEN now() ELSE finalized_at END
  WHERE  id = p_battle_id;

  INSERT INTO audit.events (event_type, actor_type, actor_id, severity, payload)
  VALUES (
    'battle.admin.force_transition',
    'lenser',
    v_operator_id,
    'warn',
    jsonb_build_object(
      'battle_id',     p_battle_id,
      'from_status',   v_old_status,
      'to_status',     p_target_status,
      'reason',        p_reason
    )
  );
END;
$$;


ALTER FUNCTION "public"."fn_battle_force_transition"("p_battle_id" "uuid", "p_target_status" "text", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battle_invite_accept"("p_token" "text", "p_via_qr" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
  v_link  battles.invite_links%ROWTYPE;
BEGIN
  SELECT * INTO v_link
    FROM battles.invite_links
   WHERE token = p_token
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'invite_token_not_found' USING ERRCODE = 'P0001';
  END IF;

  IF v_link.expires_at IS NOT NULL AND v_link.expires_at < NOW() THEN
    RAISE EXCEPTION 'invite_token_expired' USING ERRCODE = 'P0001';
  END IF;

  -- Increment the right counter.
  IF p_via_qr OR v_link.type = 'qr' THEN
    UPDATE battles.invite_links
       SET qr_scan_count = qr_scan_count + 1,
           accepted_at   = COALESCE(accepted_at, NOW())
     WHERE id = v_link.id;
  ELSE
    UPDATE battles.invite_links
       SET click_count  = click_count + 1,
           accepted_at  = COALESCE(accepted_at, NOW())
     WHERE id = v_link.id;
  END IF;

  RETURN jsonb_build_object(
    'battle_id',  v_link.battle_id,
    'type',       v_link.type,
    'invite_url', v_link.invite_url
  );
END;
$$;


ALTER FUNCTION "public"."fn_battle_invite_accept"("p_token" "text", "p_via_qr" boolean) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_battle_invite_accept"("p_token" "text", "p_via_qr" boolean) IS 'Records a click or QR scan on a battle invite token. Granted to anon so it works before the visitor has an account.';



CREATE OR REPLACE FUNCTION "public"."fn_battle_invite_create"("p_battle_id" "uuid", "p_type" "text" DEFAULT 'public'::"text", "p_target_handle" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
  v_caller      UUID;
  v_link_type   battles.invite_link_type;
  v_token       TEXT;
  v_url         TEXT;
  v_id          UUID;
  v_base_url    TEXT := 'https://lenserfight.com';
BEGIN
  v_caller := lensers.get_auth_lenser_id();
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'not_authenticated' USING ERRCODE = '42501';
  END IF;

  -- Validate caller owns the battle.
  IF NOT EXISTS (
    SELECT 1 FROM battles.battles b
     WHERE b.id = p_battle_id
       AND b.creator_lenser_id = v_caller
  ) THEN
    RAISE EXCEPTION 'battle_not_found_or_not_owner' USING ERRCODE = 'P0001';
  END IF;

  -- Validate type.
  BEGIN
    v_link_type := p_type::battles.invite_link_type;
  EXCEPTION WHEN invalid_text_representation THEN
    RAISE EXCEPTION 'invalid_invite_type: %', p_type USING ERRCODE = 'P0001';
  END;

  -- Private requires target_handle.
  IF v_link_type = 'private' AND p_target_handle IS NULL THEN
    RAISE EXCEPTION 'private_invite_requires_target_handle' USING ERRCODE = 'P0001';
  END IF;

  -- Generate token and URL.
  v_token := encode(extensions.gen_random_bytes(10), 'hex');

  -- Build battle slug from battle id (slug stored on battle or fallback to id).
  SELECT COALESCE(
    (SELECT b.slug FROM battles.battles b WHERE b.id = p_battle_id),
    p_battle_id::TEXT
  ) INTO v_url;
  v_url := v_base_url || '/b/' || v_url || '?ref=' || v_token;

  INSERT INTO battles.invite_links (
    battle_id, created_by, type, token, invite_url, target_handle
  ) VALUES (
    p_battle_id, v_caller, v_link_type, v_token, v_url, p_target_handle
  )
  RETURNING id INTO v_id;

  RETURN jsonb_build_object(
    'id',         v_id,
    'token',      v_token,
    'invite_url', v_url,
    'type',       p_type,
    'battle_id',  p_battle_id
  );
END;
$$;


ALTER FUNCTION "public"."fn_battle_invite_create"("p_battle_id" "uuid", "p_type" "text", "p_target_handle" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_battle_invite_create"("p_battle_id" "uuid", "p_type" "text", "p_target_handle" "text") IS 'Creates a battle invite link (public/private/link/qr). Caller must own the battle. Returns id, token, and invite_url.';



CREATE OR REPLACE FUNCTION "public"."fn_battle_invite_list"("p_battle_id" "uuid", "p_limit" integer DEFAULT 50) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
  v_caller UUID;
  v_rows   JSONB;
BEGIN
  v_caller := lensers.get_auth_lenser_id();
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'not_authenticated' USING ERRCODE = '42501';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM battles.battles b
     WHERE b.id = p_battle_id
       AND b.creator_lenser_id = v_caller
  ) THEN
    RAISE EXCEPTION 'battle_not_found_or_not_owner' USING ERRCODE = 'P0001';
  END IF;

  SELECT jsonb_agg(
    jsonb_build_object(
      'id',             il.id,
      'type',           il.type,
      'token',          il.token,
      'invite_url',     il.invite_url,
      'target_handle',  il.target_handle,
      'click_count',    il.click_count,
      'qr_scan_count',  il.qr_scan_count,
      'accepted_at',    il.accepted_at,
      'created_at',     il.created_at,
      'expires_at',     il.expires_at
    )
    ORDER BY il.created_at DESC
  )
  INTO v_rows
  FROM (
    SELECT * FROM battles.invite_links
     WHERE battle_id = p_battle_id
     LIMIT LEAST(p_limit, 200)
  ) il;

  RETURN COALESCE(v_rows, '[]'::JSONB);
END;
$$;


ALTER FUNCTION "public"."fn_battle_invite_list"("p_battle_id" "uuid", "p_limit" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_battle_invite_list"("p_battle_id" "uuid", "p_limit" integer) IS 'Lists invite links for a battle (up to 200). Caller must own the battle.';



CREATE OR REPLACE FUNCTION "public"."fn_battle_invite_stats"("p_battle_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
  v_caller UUID;
BEGIN
  v_caller := lensers.get_auth_lenser_id();
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'not_authenticated' USING ERRCODE = '42501';
  END IF;

  -- Only the battle owner can view stats.
  IF NOT EXISTS (
    SELECT 1 FROM battles.battles b
     WHERE b.id = p_battle_id
       AND b.creator_lenser_id = v_caller
  ) THEN
    RAISE EXCEPTION 'battle_not_found_or_not_owner' USING ERRCODE = 'P0001';
  END IF;

  RETURN (
    SELECT jsonb_build_object(
      'battle_id',    p_battle_id,
      'link_clicks',  COALESCE(SUM(click_count)   FILTER (WHERE type IN ('public','link')), 0),
      'qr_scans',     COALESCE(SUM(qr_scan_count) FILTER (WHERE type = 'qr'),              0),
      'accepted',     COUNT(*) FILTER (WHERE accepted_at IS NOT NULL),
      'total_links',  COUNT(*)
    )
    FROM battles.invite_links
   WHERE battle_id = p_battle_id
  );
END;
$$;


ALTER FUNCTION "public"."fn_battle_invite_stats"("p_battle_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_battle_invite_stats"("p_battle_id" "uuid") IS 'Returns aggregated click, scan, accepted, and total-link counts for a battle. Caller must own the battle.';



CREATE OR REPLACE FUNCTION "public"."fn_battle_open_voting"("p_battle_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
DECLARE
  v_creator_id     uuid;
  v_accepted_count int;
BEGIN
  SELECT id INTO v_creator_id
  FROM lensers.profiles
  WHERE user_id = auth.uid()
  LIMIT 1;

  IF v_creator_id IS NULL THEN
    RAISE EXCEPTION 'Not authenticated.';
  END IF;

  -- Require at least 2 accepted contenders before voting can open
  SELECT COUNT(*) INTO v_accepted_count
  FROM battles.contenders
  WHERE battle_id        = p_battle_id
    AND contender_status = 'accepted';

  IF v_accepted_count < 2 THEN
    RAISE EXCEPTION 'Battle must have at least 2 accepted contenders before voting can open.';
  END IF;

  UPDATE battles.battles
  SET
    status          = 'voting',
    voting_opens_at = now(),
    updated_at      = now()
  WHERE id                = p_battle_id
    AND creator_lenser_id = v_creator_id
    AND status            = 'open'
    AND deleted_at        IS NULL;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Battle not found, not owned by you, or not in open status.';
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_battle_open_voting"("p_battle_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_battle_open_voting"("p_battle_id" "uuid") IS 'Transitions a battle from open to voting. Requires at least 2 accepted contenders. Sets voting_opens_at = now(). Only callable by the battle creator. SECURITY DEFINER.';



CREATE OR REPLACE FUNCTION "public"."fn_battle_set_schedule"("p_battle_id" "uuid", "p_open_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_judge_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_publish_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_auto_judge" boolean DEFAULT true, "p_auto_publish" boolean DEFAULT true) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
DECLARE
  v_lenser_id UUID;
  v_sched_id  UUID;
BEGIN
  SELECT id INTO v_lenser_id
  FROM   lensers.profiles
  WHERE  user_id = auth.uid();

  IF NOT EXISTS (
    SELECT 1 FROM battles.battles
    WHERE id = p_battle_id AND creator_lenser_id = v_lenser_id
  ) AND NOT public.is_admin() THEN
    RAISE EXCEPTION 'set_schedule_forbidden: must be battle creator or admin';
  END IF;

  INSERT INTO battles.schedules (battle_id, open_at, judge_at, publish_at, auto_judge, auto_publish)
  VALUES (p_battle_id, p_open_at, p_judge_at, p_publish_at, p_auto_judge, p_auto_publish)
  ON CONFLICT (battle_id) DO UPDATE
    SET open_at      = EXCLUDED.open_at,
        judge_at     = EXCLUDED.judge_at,
        publish_at   = EXCLUDED.publish_at,
        auto_judge   = EXCLUDED.auto_judge,
        auto_publish = EXCLUDED.auto_publish,
        updated_at   = now()
  RETURNING id INTO v_sched_id;

  RETURN v_sched_id;
END;
$$;


ALTER FUNCTION "public"."fn_battle_set_schedule"("p_battle_id" "uuid", "p_open_at" timestamp with time zone, "p_judge_at" timestamp with time zone, "p_publish_at" timestamp with time zone, "p_auto_judge" boolean, "p_auto_publish" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battle_submit_workflow"("p_battle_id" "uuid", "p_workflow_id" "uuid", "p_run_id" "uuid" DEFAULT NULL::"uuid", "p_agent_id" "uuid" DEFAULT NULL::"uuid", "p_content" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_lenser_id    UUID;
  v_submission_id UUID;
BEGIN
  SELECT p.id INTO v_lenser_id
  FROM   lensers.profiles p
  WHERE  p.user_id = auth.uid();

  -- Verify contender registration
  IF NOT EXISTS (
    SELECT 1 FROM battles.contenders c
    WHERE  c.battle_id  = p_battle_id
    AND    c.lenser_id  = v_lenser_id
  ) THEN
    RAISE EXCEPTION 'submit_workflow_not_registered: join battle first';
  END IF;

  -- Verify workflow ownership or visibility
  IF NOT EXISTS (
    SELECT 1 FROM lenses.workflows w
    WHERE  w.id = p_workflow_id
    AND    (w.lenser_id = v_lenser_id OR w.visibility = 'public')
  ) THEN
    RAISE EXCEPTION 'submit_workflow_not_accessible: workflow % not found or not accessible', p_workflow_id;
  END IF;

  -- Get contender_id
  INSERT INTO battles.submissions (
    battle_id,
    contender_id,
    submission_type,
    workflow_id,
    execution_run_id,
    source_type,
    content_text,
    status
  )
  SELECT
    p_battle_id,
    c.id,
    'workflow',
    p_workflow_id,
    p_run_id,
    CASE WHEN p_run_id IS NOT NULL THEN 'execution_output' ELSE 'manual' END,
    p_content,
    CASE WHEN p_content IS NOT NULL THEN 'submitted' ELSE 'pending' END
  FROM battles.contenders c
  WHERE c.battle_id = p_battle_id
  AND   c.lenser_id = v_lenser_id
  LIMIT 1
  RETURNING id INTO v_submission_id;

  RETURN v_submission_id;
END;
$$;


ALTER FUNCTION "public"."fn_battle_submit_workflow"("p_battle_id" "uuid", "p_workflow_id" "uuid", "p_run_id" "uuid", "p_agent_id" "uuid", "p_content" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battle_update_workflow_submission"("p_submission_id" "uuid", "p_content" "text", "p_execution_run_id" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
DECLARE
  v_lenser_id UUID;
BEGIN
  SELECT p.id INTO v_lenser_id
  FROM   lensers.profiles p
  WHERE  p.user_id = auth.uid();

  UPDATE battles.submissions s
  SET    content_text      = p_content,
         execution_run_id  = COALESCE(p_execution_run_id, s.execution_run_id),
         status            = 'submitted',
         submitted_at      = now(),
         updated_at        = now()
  FROM   battles.contenders c
  WHERE  s.id         = p_submission_id
  AND    c.id         = s.contender_id
  AND    c.lenser_id  = v_lenser_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'update_workflow_submission_forbidden_or_not_found: %', p_submission_id;
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_battle_update_workflow_submission"("p_submission_id" "uuid", "p_content" "text", "p_execution_run_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_archive"("p_battle_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
    v_battle RECORD;
    v_lenser_id uuid;
BEGIN
    v_lenser_id := lensers.get_auth_lenser_id();

    SELECT * INTO v_battle
    FROM battles.battles WHERE id = p_battle_id;

    IF v_battle IS NULL THEN
        RAISE EXCEPTION 'Battle not found';
    END IF;

    IF v_battle.creator_lenser_id != v_lenser_id THEN
        RAISE EXCEPTION 'Only the battle creator can archive';
    END IF;

    IF v_battle.status NOT IN ('closed', 'published') THEN
        RAISE EXCEPTION 'Battle must be closed or published to archive (current: %)', v_battle.status;
    END IF;

    UPDATE battles.battles
    SET status = 'archived',
        updated_at = now()
    WHERE id = p_battle_id;
END;
$$;


ALTER FUNCTION "public"."fn_battles_archive"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_auto_promote"("p_battle_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'audit', 'public'
    AS $$
DECLARE
  v_readiness JSONB;
  v_battle    RECORD;
BEGIN
  SELECT * INTO v_battle FROM battles.battles WHERE id = p_battle_id AND status = 'draft';
  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;

  v_readiness := public.fn_battles_check_readiness(p_battle_id);

  IF NOT (v_readiness ->> 'ready')::BOOLEAN THEN
    RETURN FALSE;
  END IF;

  UPDATE battles.battles
     SET status = 'open',
         updated_at = now()
   WHERE id = p_battle_id
     AND status = 'draft';

  IF FOUND THEN
    INSERT INTO audit.events (actor_id, event_type, resource_type, resource_id, meta)
    VALUES (
      NULL,
      'battle.auto_promoted',
      'battle',
      p_battle_id,
      jsonb_build_object('readiness', v_readiness)
    );
    RETURN TRUE;
  END IF;

  RETURN FALSE;
END;
$$;


ALTER FUNCTION "public"."fn_battles_auto_promote"("p_battle_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_battles_auto_promote"("p_battle_id" "uuid") IS 'CB: Promotes draft→open when readiness check passes. service_role only.';



CREATE OR REPLACE FUNCTION "public"."fn_battles_auto_schedule_contenders"("p_battle_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
DECLARE
  v_max_contenders INT;
  v_existing_count INT;
  v_to_assign      INT;
  v_assigned       INT := 0;
  rec              RECORD;
BEGIN
  -- Read max_contenders; default to 2
  SELECT COALESCE(max_contenders, 2)
    INTO v_max_contenders
    FROM battles.battles
   WHERE id = p_battle_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Battle not found' USING ERRCODE = 'P0002';
  END IF;

  SELECT COUNT(*)
    INTO v_existing_count
    FROM battles.contenders
   WHERE battle_id = p_battle_id;

  v_to_assign := v_max_contenders - v_existing_count;
  IF v_to_assign <= 0 THEN
    RETURN 0;
  END IF;

  FOR rec IN
    SELECT al.id AS lenser_id
      FROM lensers.ai_lensers al
     WHERE al.is_available = TRUE
       AND NOT EXISTS (
         SELECT 1 FROM battles.contenders c
          WHERE c.battle_id = p_battle_id
            AND c.lenser_id = al.id
       )
     ORDER BY al.last_active_at DESC NULLS LAST
     LIMIT v_to_assign
  LOOP
    INSERT INTO battles.contenders (battle_id, lenser_id, slot, status)
    VALUES (p_battle_id, rec.lenser_id,
      CASE WHEN v_assigned = 0 THEN 'A' ELSE 'B' END,
      'pending')
    ON CONFLICT DO NOTHING;
    v_assigned := v_assigned + 1;
  END LOOP;

  RETURN v_assigned;
END;
$$;


