CREATE TABLE IF NOT EXISTS "battles"."templates" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "creator_lenser_id" "uuid" NOT NULL,
    "title" "text" NOT NULL,
    "description" "text",
    "task_prompt" "text" NOT NULL,
    "rubric_id" "uuid",
    "max_contenders" integer DEFAULT 2 NOT NULL,
    "is_public" boolean DEFAULT false NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "deleted_at" timestamp with time zone,
    "recurrence_rule" "text",
    "next_run_at" timestamp with time zone,
    "auto_start_delay_hours" integer DEFAULT 1 NOT NULL,
    "category" "text",
    CONSTRAINT "ck_battles_templates_description_len" CHECK ((("description" IS NULL) OR ("length"("description") <= 2000))),
    CONSTRAINT "ck_battles_templates_task_prompt_len" CHECK ((("task_prompt" IS NULL) OR ("length"("task_prompt") <= 32000))),
    CONSTRAINT "ck_battles_templates_title_len" CHECK ((("title" IS NULL) OR ("length"("title") <= 200))),
    CONSTRAINT "templates_category_check" CHECK ((("category" IS NULL) OR (("char_length"("category") >= 1) AND ("char_length"("category") <= 32)))),
    CONSTRAINT "templates_max_contenders_check" CHECK (("max_contenders" >= 2))
);


