CREATE OR REPLACE FUNCTION "public"."fn_battles_render_prompt"("p_template_id" "uuid", "p_variables" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "text"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'extensions'
    AS $$
DECLARE
  v_template     RECORD;
  v_rendered     TEXT;
  v_var          RECORD;
  v_value        TEXT;
BEGIN
  SELECT id, task_prompt, creator_lenser_id, is_public
    INTO v_template
    FROM battles.templates
   WHERE id = p_template_id
     AND deleted_at IS NULL;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'template_not_found' USING ERRCODE = '42501';
  END IF;

  -- Accessibility: owner OR public template OR anonymous read of public.
  IF NOT v_template.is_public
     AND v_template.creator_lenser_id IS DISTINCT FROM auth.uid() THEN
    RAISE EXCEPTION 'template_not_accessible' USING ERRCODE = '42501';
  END IF;

  v_rendered := v_template.task_prompt;

  FOR v_var IN
    SELECT variable_key, default_value, required
      FROM battles.template_prompt_variables
     WHERE template_id = p_template_id
     ORDER BY ordinal, variable_key
  LOOP
    v_value := COALESCE(
      NULLIF(p_variables->>v_var.variable_key, ''),
      v_var.default_value
    );

    IF v_value IS NULL THEN
      IF v_var.required THEN
        RAISE EXCEPTION 'missing_required_variable: %', v_var.variable_key
          USING ERRCODE = '22023';
      END IF;
      v_value := '';
    END IF;

    -- Plain text substitution, including the braces.
    v_rendered := REPLACE(
      v_rendered,
      '{{' || v_var.variable_key || '}}',
      v_value
    );
  END LOOP;

  RETURN v_rendered;
END $$;


ALTER FUNCTION "public"."fn_battles_render_prompt"("p_template_id" "uuid", "p_variables" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_retract"("p_battle_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
    v_battle RECORD;
    v_lenser_id uuid;
BEGIN
    v_lenser_id := lensers.get_auth_lenser_id();

    SELECT * INTO v_battle
    FROM battles.battles WHERE id = p_battle_id;

    IF v_battle IS NULL THEN
        RAISE EXCEPTION 'Battle not found';
    END IF;

    IF v_battle.creator_lenser_id != v_lenser_id THEN
        RAISE EXCEPTION 'Only the battle creator can retract';
    END IF;

    IF v_battle.status NOT IN ('draft', 'open', 'published') THEN
        RAISE EXCEPTION 'Battle must be in draft, open, or published status to retract (current: %)', v_battle.status;
    END IF;

    UPDATE battles.battles
    SET status = 'archived',
        updated_at = now()
    WHERE id = p_battle_id;

    -- Log the event
    INSERT INTO battles.events (battle_id, event_type, actor_id, metadata)
    VALUES (
        p_battle_id,
        'status_change',
        v_lenser_id,
        jsonb_build_object('from', v_battle.status::text, 'to', 'archived', 'action', 'retracted')
    );
END;
$$;


ALTER FUNCTION "public"."fn_battles_retract"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_revoke_webhook"("p_subscription_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
DECLARE
  v_actor UUID;
  v_rows  INT;
BEGIN
  v_actor := auth.uid();
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'Authentication required' USING ERRCODE = 'P0001';
  END IF;

  UPDATE battles.battle_event_subscriptions
     SET revoked_at = now()
   WHERE id       = p_subscription_id
     AND owner_id = v_actor
     AND revoked_at IS NULL;

  GET DIAGNOSTICS v_rows = ROW_COUNT;

  IF v_rows = 0 THEN
    RAISE EXCEPTION 'Subscription not found or already revoked'
      USING ERRCODE = 'P0002';
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_battles_revoke_webhook"("p_subscription_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_battles_revoke_webhook"("p_subscription_id" "uuid") IS 'Soft-revokes a caller-owned webhook subscription. Idempotent-safe (raises P0002 if already revoked).';



CREATE OR REPLACE FUNCTION "public"."fn_battles_series_create"("p_name" "text", "p_seed_battle_id" "uuid", "p_cron_expr" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public', 'battles', 'lensers'
    AS $_$
DECLARE
  v_caller    uuid;
  v_owner     uuid;
  v_series_id uuid;
  v_slug      text;
  v_parts     text[];
BEGIN
  v_caller := lensers.get_auth_lenser_id();
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'authentication_required' USING ERRCODE = '42501';
  END IF;

  IF p_name IS NULL OR length(btrim(p_name)) = 0 THEN
    RAISE EXCEPTION 'series_name_required' USING ERRCODE = '22023';
  END IF;

  v_parts := regexp_split_to_array(btrim(COALESCE(p_cron_expr, '')), '\s+');
  IF array_length(v_parts, 1) <> 5 THEN
    RAISE EXCEPTION 'invalid_cron_expression: expected 5 fields'
      USING ERRCODE = '22023';
  END IF;

  SELECT creator_lenser_id INTO v_owner
    FROM battles.battles
   WHERE id = p_seed_battle_id
     AND deleted_at IS NULL;

  IF v_owner IS NULL THEN
    RAISE EXCEPTION 'seed_battle_not_found: %', p_seed_battle_id
      USING ERRCODE = 'P0002';
  END IF;

  IF v_owner IS DISTINCT FROM v_caller THEN
    RAISE EXCEPTION 'not_battle_owner' USING ERRCODE = '42501';
  END IF;

  -- Slug: kebab-case from name + 6 random hex; bounded to <= 128 chars.
  v_slug := substr(
    regexp_replace(
      regexp_replace(lower(p_name), '[^a-z0-9]+', '-', 'g'),
      '(^-+|-+$)', '', 'g'
    ),
    1, 110
  );
  IF length(v_slug) = 0 THEN
    v_slug := 'series';
  END IF;
  v_slug := v_slug || '-' || substr(replace(gen_random_uuid()::text, '-', ''), 1, 6);

  INSERT INTO battles.series (
    creator_lenser_id, name, slug, seed_battle_id, cron_expr,
    next_dispatch_at, is_active
  )
  VALUES (
    v_caller, btrim(p_name), v_slug, p_seed_battle_id, btrim(p_cron_expr),
    -- Earliest the dispatcher can pick it up: the next top-of-hour tick.
    date_trunc('hour', now()) + interval '1 hour',
    true
  )
  RETURNING id INTO v_series_id;

  -- Seed at position=1.
  INSERT INTO battles.series_battles (series_id, battle_id, position)
  VALUES (v_series_id, p_seed_battle_id, 1);

  RETURN v_series_id;
END;
$_$;


ALTER FUNCTION "public"."fn_battles_series_create"("p_name" "text", "p_seed_battle_id" "uuid", "p_cron_expr" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_battles_series_create"("p_name" "text", "p_seed_battle_id" "uuid", "p_cron_expr" "text") IS 'Phase V4: create a battle series anchored to a seed battle the caller owns. Inserts the seed at position=1 and primes next_dispatch_at to the next top-of-hour tick. Returns the new series id.';



CREATE OR REPLACE FUNCTION "public"."fn_battles_start_voting"("p_battle_id" "uuid", "p_voting_closes_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
    v_battle RECORD;
    v_pending int;
BEGIN
    SELECT * INTO v_battle
    FROM battles.battles WHERE id = p_battle_id;

    IF v_battle IS NULL THEN
        RAISE EXCEPTION 'Battle not found';
    END IF;

    IF v_battle.creator_lenser_id <> lensers.get_auth_lenser_id() THEN
        RAISE EXCEPTION 'Only the battle creator can start voting';
    END IF;

    IF v_battle.status <> 'open' THEN
        RAISE EXCEPTION 'Battle must be open to start voting (current: %)', v_battle.status;
    END IF;

    -- Check all contenders have submitted
    SELECT COUNT(*) INTO v_pending
    FROM battles.submissions s
    WHERE s.battle_id = p_battle_id AND s.status = 'pending';

    IF v_pending > 0 THEN
        RAISE EXCEPTION '% contender(s) have not submitted yet', v_pending;
    END IF;

    UPDATE battles.battles
    SET status = 'voting',
        voting_opens_at = now(),
        voting_closes_at = p_voting_closes_at,
        updated_at = now()
    WHERE id = p_battle_id;
END;
$$;


ALTER FUNCTION "public"."fn_battles_start_voting"("p_battle_id" "uuid", "p_voting_closes_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_submit"("p_battle_id" "uuid", "p_content_text" "text" DEFAULT NULL::"text", "p_content_url" "text" DEFAULT NULL::"text", "p_content_media" "jsonb" DEFAULT NULL::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
    v_lenser_id uuid;
    v_contender RECORD;
    v_battle RECORD;
    v_submission_id uuid;
BEGIN
    v_lenser_id := lensers.get_auth_lenser_id();
    IF v_lenser_id IS NULL THEN
        RAISE EXCEPTION 'Authentication required';
    END IF;

    SELECT * INTO v_battle
    FROM battles.battles WHERE id = p_battle_id;

    IF v_battle IS NULL OR v_battle.status <> 'open' THEN
        RAISE EXCEPTION 'Battle is not open for submissions';
    END IF;

    SELECT * INTO v_contender
    FROM battles.contenders
    WHERE battle_id = p_battle_id
      AND contender_type = 'human'
      AND contender_ref_id = v_lenser_id;

    IF v_contender IS NULL THEN
        RAISE EXCEPTION 'You are not a contender in this battle';
    END IF;

    IF p_content_text IS NULL AND p_content_url IS NULL THEN
        RAISE EXCEPTION 'At least content_text or content_url is required';
    END IF;

    UPDATE battles.submissions
    SET status = 'submitted',
        content_text = p_content_text,
        content_url = p_content_url,
        content_media = COALESCE(p_content_media, '[]'::jsonb),
        submitted_at = now(),
        updated_at = now()
    WHERE battle_id = p_battle_id AND contender_id = v_contender.id
    RETURNING id INTO v_submission_id;

    RETURN v_submission_id;
END;
$$;


ALTER FUNCTION "public"."fn_battles_submit"("p_battle_id" "uuid", "p_content_text" "text", "p_content_url" "text", "p_content_media" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_submit"("p_battle_id" "uuid", "p_content_text" "text" DEFAULT NULL::"text", "p_content_url" "text" DEFAULT NULL::"text", "p_content_media" "jsonb" DEFAULT NULL::"jsonb", "p_execution_run_id" "uuid" DEFAULT NULL::"uuid", "p_artifact_id" "uuid" DEFAULT NULL::"uuid", "p_source_type" "text" DEFAULT 'manual'::"text", "p_adapter_id" "uuid" DEFAULT NULL::"uuid", "p_model_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers', 'execution'
    AS $$
DECLARE
    v_lenser_id uuid;
    v_contender RECORD;
    v_battle RECORD;
    v_submission_id uuid;
BEGIN
    v_lenser_id := lensers.get_auth_lenser_id();
    IF v_lenser_id IS NULL THEN
        RAISE EXCEPTION 'Authentication required';
    END IF;

    SELECT * INTO v_battle
    FROM battles.battles WHERE id = p_battle_id;

    IF v_battle IS NULL OR v_battle.status <> 'open' THEN
        RAISE EXCEPTION 'Battle is not open for submissions';
    END IF;

    -- Look up contender by contender_ref_id only
    SELECT * INTO v_contender
    FROM battles.contenders
    WHERE battle_id = p_battle_id
      AND contender_ref_id = v_lenser_id;

    IF v_contender IS NULL THEN
        RAISE EXCEPTION 'You are not a contender in this battle';
    END IF;

    IF p_content_text IS NULL AND p_content_url IS NULL AND p_execution_run_id IS NULL THEN
        RAISE EXCEPTION 'At least content_text, content_url, or execution_run_id is required';
    END IF;

    UPDATE battles.submissions
    SET status = 'submitted',
        content_text = p_content_text,
        content_url = p_content_url,
        content_media = COALESCE(p_content_media, '[]'::jsonb),
        submitted_at = now(),
        updated_at = now(),
        execution_run_id = p_execution_run_id,
        artifact_id = p_artifact_id,
        source_type = p_source_type,
        adapter_id = p_adapter_id,
        model_id = p_model_id
    WHERE battle_id = p_battle_id AND contender_id = v_contender.id
    RETURNING id INTO v_submission_id;

    -- Link execution to submission if provided
    IF p_execution_run_id IS NOT NULL THEN
        INSERT INTO execution.links (run_id, entity_type, entity_id)
        VALUES (p_execution_run_id, 'submission', v_submission_id)
        ON CONFLICT DO NOTHING;
    END IF;

    RETURN v_submission_id;
END;
$$;


ALTER FUNCTION "public"."fn_battles_submit"("p_battle_id" "uuid", "p_content_text" "text", "p_content_url" "text", "p_content_media" "jsonb", "p_execution_run_id" "uuid", "p_artifact_id" "uuid", "p_source_type" "text", "p_adapter_id" "uuid", "p_model_id" "uuid") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "battles"."submissions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "battle_id" "uuid" NOT NULL,
    "contender_id" "uuid" NOT NULL,
    "status" "battles"."submission_status_enum" DEFAULT 'pending'::"battles"."submission_status_enum" NOT NULL,
    "content_text" "text",
    "content_url" "text",
    "content_media" "jsonb" DEFAULT '[]'::"jsonb",
    "submitted_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "execution_run_id" "uuid",
    "artifact_id" "uuid",
    "source_type" "text" DEFAULT 'manual'::"text" NOT NULL,
    "model_id" "uuid",
    "integrity_hash" "text",
    "is_final" boolean DEFAULT true NOT NULL,
    "revision_of_id" "uuid",
    "metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "workflow_id" "uuid",
    "submission_type" "text" DEFAULT 'text'::"text" NOT NULL,
    "media_url" "text",
    "mime_type" "text",
    "output_modality" "text",
    CONSTRAINT "ck_battles_submissions_content_text_len" CHECK ((("content_text" IS NULL) OR ("length"("content_text") <= 20000))),
    CONSTRAINT "submissions_content_required" CHECK ((("status" = 'pending'::"battles"."submission_status_enum") OR ("content_text" IS NOT NULL) OR ("content_url" IS NOT NULL))),
    CONSTRAINT "submissions_mime_type_check" CHECK ((("mime_type" IS NULL) OR ("char_length"("mime_type") <= 128))),
    CONSTRAINT "submissions_output_modality_check" CHECK ((("output_modality" IS NULL) OR ("output_modality" = ANY (ARRAY['text'::"text", 'image'::"text", 'video'::"text", 'audio'::"text"])))),
    CONSTRAINT "submissions_source_type_check" CHECK (("source_type" = ANY (ARRAY['manual'::"text", 'execution_output'::"text", 'hybrid'::"text", 'imported'::"text"]))),
    CONSTRAINT "submissions_submission_type_check" CHECK (("submission_type" = ANY (ARRAY['text'::"text", 'workflow'::"text", 'lens'::"text"])))
);


ALTER TABLE "battles"."submissions" OWNER TO "postgres";


COMMENT ON COLUMN "battles"."submissions"."workflow_id" IS 'Workflow that produced or defines this submission. Non-null when submission_type=workflow.';



COMMENT ON COLUMN "battles"."submissions"."submission_type" IS 'Content type of the submission: text (default), workflow (DAG output), lens (lens output).';



COMMENT ON COLUMN "battles"."submissions"."media_url" IS 'Phase AY: signed URL (or proxy URL) pointing at the media artifact produced by the contender. NULL for plain-text submissions.';



COMMENT ON COLUMN "battles"."submissions"."output_modality" IS 'Phase AY: discriminator the UI uses to pick the right renderer.';



CREATE OR REPLACE FUNCTION "public"."fn_battles_submit_media"("p_battle_id" "uuid", "p_contender_id" "uuid", "p_media_url" "text", "p_mime_type" "text", "p_output_modality" "text") RETURNS "battles"."submissions"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'extensions'
    AS $$
DECLARE
  v_uid       UUID := auth.uid();
  v_row       battles.submissions%ROWTYPE;
  v_is_owner  BOOLEAN;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'auth_required' USING ERRCODE = '42501';
  END IF;
  IF p_output_modality IS NULL
     OR p_output_modality NOT IN ('image', 'video', 'audio') THEN
    RAISE EXCEPTION 'invalid_output_modality: %', p_output_modality
      USING ERRCODE = '22023';
  END IF;
  IF p_media_url IS NULL OR char_length(p_media_url) = 0 THEN
    RAISE EXCEPTION 'media_url_required' USING ERRCODE = '22023';
  END IF;

  SELECT EXISTS (
    SELECT 1
      FROM battles.contenders c
      JOIN battles.contender_entity_map cem ON cem.contender_id = c.id
     WHERE c.id           = p_contender_id
       AND c.battle_id    = p_battle_id
       AND cem.profile_id = v_uid
  )
  INTO v_is_owner;

  IF NOT v_is_owner THEN
    RAISE EXCEPTION 'contender_not_owned' USING ERRCODE = '42501';
  END IF;

  INSERT INTO battles.submissions (
    battle_id,
    contender_id,
    content_url,
    media_url,
    mime_type,
    output_modality,
    status
  ) VALUES (
    p_battle_id,
    p_contender_id,
    p_media_url,
    p_media_url,
    p_mime_type,
    p_output_modality,
    'submitted'
  )
  ON CONFLICT (battle_id, contender_id) DO UPDATE
    SET content_url     = EXCLUDED.content_url,
        media_url       = EXCLUDED.media_url,
        mime_type       = EXCLUDED.mime_type,
        output_modality = EXCLUDED.output_modality,
        status          = 'submitted',
        submitted_at    = COALESCE(battles.submissions.submitted_at, now())
  RETURNING * INTO v_row;

  RETURN v_row;
END $$;


ALTER FUNCTION "public"."fn_battles_submit_media"("p_battle_id" "uuid", "p_contender_id" "uuid", "p_media_url" "text", "p_mime_type" "text", "p_output_modality" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_subscribe_webhook"("p_battle_id" "uuid", "p_webhook_url" "text", "p_event_types" "text"[]) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
DECLARE
  v_actor UUID;
  v_sub_id UUID;
  v_secret TEXT;
BEGIN
  v_actor := auth.uid();
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'Authentication required' USING ERRCODE = 'P0001';
  END IF;

  -- Generate HMAC-style secret (random 32 bytes hex-encoded)
  v_secret := encode(gen_random_bytes(32), 'hex');

  INSERT INTO battles.battle_event_subscriptions
    (battle_id, owner_id, webhook_url, event_types, secret_hmac)
  VALUES
    (p_battle_id, v_actor, p_webhook_url, p_event_types, v_secret)
  RETURNING id INTO v_sub_id;

  RETURN v_sub_id;
END;
$$;


ALTER FUNCTION "public"."fn_battles_subscribe_webhook"("p_battle_id" "uuid", "p_webhook_url" "text", "p_event_types" "text"[]) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_battles_subscribe_webhook"("p_battle_id" "uuid", "p_webhook_url" "text", "p_event_types" "text"[]) IS 'CB: Creates a webhook subscription with generated HMAC secret. Owner-only.';



CREATE OR REPLACE FUNCTION "public"."fn_battles_update_template"("p_template_id" "uuid", "p_title" "text" DEFAULT NULL::"text", "p_description" "text" DEFAULT NULL::"text", "p_task_prompt" "text" DEFAULT NULL::"text", "p_category" "text" DEFAULT NULL::"text", "p_max_contenders" integer DEFAULT NULL::integer, "p_is_public" boolean DEFAULT NULL::boolean) RETURNS "battles"."templates"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers', 'extensions'
    AS $$
DECLARE
  v_lenser_id UUID := lensers.get_auth_lenser_id();
  v_row       battles.templates%ROWTYPE;
BEGIN
  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'auth_required' USING ERRCODE = '42501';
  END IF;
  IF p_category IS NOT NULL
     AND p_category NOT IN ('creative','technical','business','gaming') THEN
    RAISE EXCEPTION 'invalid_category: %', p_category USING ERRCODE = '22023';
  END IF;
  IF p_max_contenders IS NOT NULL AND p_max_contenders < 2 THEN
    RAISE EXCEPTION 'max_contenders_too_small' USING ERRCODE = '22023';
  END IF;

  UPDATE battles.templates t
     SET title          = COALESCE(p_title,          t.title),
         description    = COALESCE(p_description,    t.description),
         task_prompt    = COALESCE(p_task_prompt,    t.task_prompt),
         category       = COALESCE(p_category,       t.category),
         max_contenders = COALESCE(p_max_contenders, t.max_contenders),
         is_public      = COALESCE(p_is_public,      t.is_public),
         updated_at     = now()
   WHERE t.id                = p_template_id
     AND t.creator_lenser_id = v_lenser_id
     AND t.deleted_at IS NULL
   RETURNING * INTO v_row;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'template_not_owned' USING ERRCODE = '42501';
  END IF;

  RETURN v_row;
END $$;


ALTER FUNCTION "public"."fn_battles_update_template"("p_template_id" "uuid", "p_title" "text", "p_description" "text", "p_task_prompt" "text", "p_category" "text", "p_max_contenders" integer, "p_is_public" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_vote"("p_battle_id" "uuid", "p_vote" "battles"."vote_value_enum", "p_rationale" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
    v_lenser_id uuid;
    v_battle RECORD;
BEGIN
    v_lenser_id := lensers.get_auth_lenser_id();
    IF v_lenser_id IS NULL THEN
        RAISE EXCEPTION 'Authentication required';
    END IF;

    SELECT * INTO v_battle
    FROM battles.battles WHERE id = p_battle_id;

    IF v_battle IS NULL THEN
        RAISE EXCEPTION 'Battle not found';
    END IF;

    IF v_battle.status <> 'voting' THEN
        RAISE EXCEPTION 'Battle is not in voting phase';
    END IF;

    -- Check voting window
    IF v_battle.voting_closes_at IS NOT NULL AND now() > v_battle.voting_closes_at THEN
        RAISE EXCEPTION 'Voting window has closed';
    END IF;

    -- Prevent contenders from voting on their own battle
    IF EXISTS (
        SELECT 1 FROM battles.contenders c
        WHERE c.battle_id = p_battle_id
          AND c.contender_type = 'human'
          AND c.contender_ref_id = v_lenser_id
    ) THEN
        RAISE EXCEPTION 'Contenders cannot vote on their own battle';
    END IF;

    -- Delete existing vote if any, then insert new
    DELETE FROM battles.votes
    WHERE battle_id = p_battle_id AND voter_lenser_id = v_lenser_id;

    INSERT INTO battles.votes (battle_id, voter_lenser_id, vote_value, rationale)
    VALUES (p_battle_id, v_lenser_id, p_vote, p_rationale);
END;
$$;


ALTER FUNCTION "public"."fn_battles_vote"("p_battle_id" "uuid", "p_vote" "battles"."vote_value_enum", "p_rationale" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_battles_vote"("p_battle_id" "uuid", "p_vote" "battles"."vote_value_enum", "p_rationale" "text" DEFAULT NULL::"text", "p_contender_id" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
    v_lenser_id uuid;
    v_battle RECORD;
    v_voted_contender_id uuid;
    v_is_draw boolean := false;
BEGIN
    v_lenser_id := lensers.get_auth_lenser_id();
    IF v_lenser_id IS NULL THEN
        RAISE EXCEPTION 'Authentication required';
    END IF;

    SELECT * INTO v_battle
    FROM battles.battles WHERE id = p_battle_id;

    IF v_battle IS NULL THEN
        RAISE EXCEPTION 'Battle not found';
    END IF;

    IF v_battle.status <> 'voting' THEN
        RAISE EXCEPTION 'Battle is not in voting phase';
    END IF;

    -- Check voting window
    IF v_battle.voting_closes_at IS NOT NULL AND now() > v_battle.voting_closes_at THEN
        RAISE EXCEPTION 'Voting window has closed';
    END IF;

    -- Prevent contenders from voting on their own battle
    IF EXISTS (
        SELECT 1 FROM battles.contenders c
        WHERE c.battle_id = p_battle_id
          AND c.contender_ref_id = v_lenser_id
    ) THEN
        RAISE EXCEPTION 'Contenders cannot vote on their own battle';
    END IF;

    -- Resolve voted_contender_id
    IF p_contender_id IS NOT NULL THEN
        -- Direct contender vote
        IF NOT EXISTS (
            SELECT 1 FROM battles.contenders WHERE id = p_contender_id AND battle_id = p_battle_id
        ) THEN
            RAISE EXCEPTION 'Contender not found in this battle';
        END IF;
        v_voted_contender_id := p_contender_id;
        v_is_draw := false;
    ELSIF p_vote = 'draw' THEN
        v_voted_contender_id := NULL;
        v_is_draw := true;
    ELSE
        -- Legacy slot-based vote: resolve from vote_value
        SELECT c.id INTO v_voted_contender_id
        FROM battles.contenders c
        WHERE c.battle_id = p_battle_id
          AND c.slot = CASE p_vote
              WHEN 'contender_a' THEN 'A'::bpchar
              WHEN 'contender_b' THEN 'B'::bpchar
          END;
        v_is_draw := false;
    END IF;

    -- Insert the vote (no voter_actor_id)
    INSERT INTO battles.votes (
        battle_id, voter_lenser_id, vote_value, rationale,
        voted_contender_id, is_draw, weight, is_ai_vote
    )
    VALUES (
        p_battle_id, v_lenser_id, p_vote, p_rationale,
        v_voted_contender_id, v_is_draw, 1.0, false
    );

    -- Update vote_aggregates
    IF v_voted_contender_id IS NOT NULL AND NOT v_is_draw THEN
        INSERT INTO battles.vote_aggregates (battle_id, contender_id, raw_vote_count, weighted_vote_sum)
        VALUES (p_battle_id, v_voted_contender_id, 1, 1.0)
        ON CONFLICT (battle_id, contender_id) DO UPDATE
        SET raw_vote_count = battles.vote_aggregates.raw_vote_count + 1,
            weighted_vote_sum = battles.vote_aggregates.weighted_vote_sum + 1.0,
            updated_at = now();
    ELSIF v_is_draw THEN
        INSERT INTO battles.vote_aggregates (battle_id, contender_id, draw_count)
        SELECT p_battle_id, c.id, 1
        FROM battles.contenders c
        WHERE c.battle_id = p_battle_id
        ON CONFLICT (battle_id, contender_id) DO UPDATE
        SET draw_count = battles.vote_aggregates.draw_count + 1,
            updated_at = now();
    END IF;

    -- Log the vote event
    INSERT INTO battles.events (battle_id, event_type, actor_id, metadata)
    VALUES (
        p_battle_id,
        'vote_cast',
        v_lenser_id,
        jsonb_build_object(
            'vote_value', p_vote::text,
            'contender_id', v_voted_contender_id,
            'is_draw', v_is_draw
        )
    );
END;
$$;


ALTER FUNCTION "public"."fn_battles_vote"("p_battle_id" "uuid", "p_vote" "battles"."vote_value_enum", "p_rationale" "text", "p_contender_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_block_profile"("p_target_profile_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'auth'
    AS $$
DECLARE
  v_source_id uuid;
BEGIN
  SELECT id INTO v_source_id
  FROM lensers.profiles WHERE user_id = auth.uid();

  IF v_source_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF v_source_id = p_target_profile_id THEN
    RAISE EXCEPTION 'Cannot block yourself';
  END IF;

  -- Upsert block
  INSERT INTO lensers.relationships (source_profile_id, target_profile_id, status)
  VALUES (v_source_id, p_target_profile_id, 'blocked')
  ON CONFLICT (source_profile_id, target_profile_id)
  DO UPDATE SET status = 'blocked', removed_at = now();

  -- Remove their follow of us if it exists
  UPDATE lensers.relationships
  SET status = 'removed', removed_at = now()
  WHERE source_profile_id = p_target_profile_id
    AND target_profile_id = v_source_id
    AND status = 'accepted';

  RETURN jsonb_build_object('blocked', true);
END;
$$;


ALTER FUNCTION "public"."fn_block_profile"("p_target_profile_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_browse_battles"("p_category" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text", "p_q" "text" DEFAULT NULL::"text", "p_after_created" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_after_id" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 20) RETURNS TABLE("id" "uuid", "title" "text", "slug" "text", "status" "text", "category" "text", "contender_count" integer, "vote_count" integer, "created_at" timestamp with time zone, "template_title" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'extensions'
    AS $$
  WITH bounded AS (
    SELECT
      b.id,
      b.title,
      b.slug,
      b.status::text,
      t.category,
      b.total_vote_count,
      b.created_at,
      t.title AS template_title
    FROM battles.battles b
    LEFT JOIN battles.templates t ON t.id = b.template_id
    WHERE b.deleted_at IS NULL
      AND (
        -- Anonymous browse only exposes published / voting battles. Owners
        -- can see all their own via the existing repository methods.
        b.status::text IN ('open', 'voting', 'scoring', 'published')
      )
      AND (p_category IS NULL OR t.category = p_category)
      AND (p_status   IS NULL OR b.status::text = p_status)
      AND (
        p_q IS NULL
        OR to_tsvector('simple', b.title) @@ plainto_tsquery('simple', p_q)
      )
      AND (
        p_after_created IS NULL
        OR (b.created_at, b.id) < (p_after_created, COALESCE(p_after_id, '00000000-0000-0000-0000-000000000000'::uuid))
      )
    ORDER BY b.created_at DESC, b.id DESC
    LIMIT LEAST(GREATEST(p_limit, 1), 100)
  )
  SELECT
    bounded.id,
    bounded.title,
    bounded.slug,
    bounded.status,
    bounded.category,
    COALESCE((SELECT count(*)::int FROM battles.contenders c WHERE c.battle_id = bounded.id), 0)
      AS contender_count,
    COALESCE(bounded.total_vote_count, 0) AS vote_count,
    bounded.created_at,
    bounded.template_title
  FROM bounded
  ORDER BY bounded.created_at DESC, bounded.id DESC;
$$;


ALTER FUNCTION "public"."fn_browse_battles"("p_category" "text", "p_status" "text", "p_q" "text", "p_after_created" timestamp with time zone, "p_after_id" "uuid", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_byok_key_hint"("p_agent_id" "uuid") RETURNS TABLE("provider" "text", "key_hint" "text", "label" "text", "is_valid" boolean)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'execution', 'agents', 'lensers', 'public'
    AS $$
  SELECT
    bk.provider,
    bk.key_hint,
    bk.label,
    (bk.revoked_at IS NULL AND (bk.expires_at IS NULL OR bk.expires_at > now())) AS is_valid
  FROM execution.byok_keys bk
  WHERE bk.agent_id = p_agent_id
    AND EXISTS (
      SELECT 1 FROM agents.ownerships o
      WHERE o.ai_lenser_id    = p_agent_id
        AND o.owner_lenser_id = lensers.get_auth_human_lenser_id()
        AND o.revoked_at IS NULL
    );
$$;


ALTER FUNCTION "public"."fn_byok_key_hint"("p_agent_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_byok_key_register"("p_agent_id" "uuid", "p_provider" "text", "p_key_encrypted" "text", "p_key_hint" "text" DEFAULT NULL::"text", "p_label" "text" DEFAULT NULL::"text", "p_expires_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'agents', 'lensers', 'public'
    AS $$
DECLARE
  v_key_id uuid;
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM agents.ownerships o
    WHERE  o.ai_lenser_id   = p_agent_id
      AND  o.owner_lenser_id = lensers.get_auth_human_lenser_id()
      AND  o.revoked_at IS NULL
  ) THEN
    RAISE EXCEPTION 'byok_key_register_forbidden: agent % not owned by caller', p_agent_id;
  END IF;

  INSERT INTO execution.byok_keys (agent_id, provider, key_encrypted, key_hint, label, expires_at)
  VALUES (p_agent_id, p_provider, p_key_encrypted, p_key_hint, p_label, p_expires_at)
  ON CONFLICT (agent_id, provider) DO UPDATE
    SET key_encrypted = EXCLUDED.key_encrypted,
        key_hint      = EXCLUDED.key_hint,
        label         = EXCLUDED.label,
        expires_at    = EXCLUDED.expires_at,
        revoked_at    = NULL,
        created_at    = now()
  RETURNING id INTO v_key_id;

  RETURN v_key_id;
END;
$$;


ALTER FUNCTION "public"."fn_byok_key_register"("p_agent_id" "uuid", "p_provider" "text", "p_key_encrypted" "text", "p_key_hint" "text", "p_label" "text", "p_expires_at" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_byok_key_resolve"("p_agent_id" "uuid", "p_provider" "text", "p_model_id" "text" DEFAULT NULL::"text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'billing', 'public', 'pg_catalog'
    AS $$
DECLARE
  v_row     execution.byok_keys%ROWTYPE;
  v_require boolean;
BEGIN
  SELECT byok_require_reservation INTO v_require FROM billing.runtime_settings WHERE id = 1;
  IF COALESCE(v_require, false) THEN
    RAISE EXCEPTION 'E_BYOK_CONTEXT_MISSING: legacy fn_byok_key_resolve is disabled; use fn_byok_key_resolve_v2'
      USING ERRCODE = 'P0001';
  END IF;

  SELECT * INTO v_row
  FROM   execution.byok_keys
  WHERE  agent_id   = p_agent_id
    AND  provider   = p_provider
    AND  revoked_at IS NULL
    AND  (expires_at IS NULL OR expires_at > now());

  IF NOT FOUND THEN
    RETURN NULL;
  END IF;

  IF p_model_id IS NOT NULL
     AND v_row.allowed_model_ids IS NOT NULL
     AND NOT (p_model_id = ANY (v_row.allowed_model_ids)) THEN
    RAISE EXCEPTION 'byok_key_resolve: model % is not in allowed_model_ids for provider %', p_model_id, p_provider
      USING ERRCODE = 'P0001';
  END IF;

  RETURN v_row.key_encrypted;
END;
$$;


ALTER FUNCTION "public"."fn_byok_key_resolve"("p_agent_id" "uuid", "p_provider" "text", "p_model_id" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_byok_key_resolve"("p_agent_id" "uuid", "p_provider" "text", "p_model_id" "text") IS 'AR / CG1: legacy BYOK resolve. Preserved for backward compatibility with lf-gatewayd <= 0.10. Raises E_BYOK_CONTEXT_MISSING when billing.runtime_settings.byok_require_reservation = true.';



CREATE OR REPLACE FUNCTION "public"."fn_byok_key_resolve_v2"("p_agent_id" "uuid", "p_provider" "text", "p_model_id" "text", "p_reservation_id" "uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'billing', 'agents', 'ai', 'public', 'pg_catalog'
    AS $$
DECLARE
  v_key   execution.byok_keys%ROWTYPE;
  v_res   billing.cost_reservations%ROWTYPE;
  v_model_key text;
BEGIN
  IF p_reservation_id IS NULL THEN
    RAISE EXCEPTION 'E_BYOK_CONTEXT_MISSING: reservation_id is required'
      USING ERRCODE = 'P0001';
  END IF;

  SELECT * INTO v_res FROM billing.cost_reservations WHERE id = p_reservation_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'E_BYOK_CONTEXT_INVALID: reservation % not found', p_reservation_id
      USING ERRCODE = 'P0001';
  END IF;

  IF v_res.status <> 'held' THEN
    RAISE EXCEPTION 'E_BYOK_CONTEXT_INVALID: reservation % is not held (status=%)',
      p_reservation_id, v_res.status
      USING ERRCODE = 'P0001';
  END IF;
  IF v_res.held_until <= now() THEN
    RAISE EXCEPTION 'E_BYOK_CONTEXT_EXPIRED: reservation % held_until passed', p_reservation_id
      USING ERRCODE = 'P0001';
  END IF;
  IF v_res.ai_lenser_id <> p_agent_id THEN
    RAISE EXCEPTION 'E_BYOK_CONTEXT_INVALID: reservation/agent mismatch'
      USING ERRCODE = 'P0001';
  END IF;
  IF v_res.provider_key <> p_provider THEN
    RAISE EXCEPTION 'E_BYOK_CONTEXT_INVALID: reservation/provider mismatch'
      USING ERRCODE = 'P0001';
  END IF;

  -- Optional model binding: if p_model_id is given, it must match the
  -- reservation's model_id (look up via ai.models.key).
  IF p_model_id IS NOT NULL AND LENGTH(p_model_id) > 0 THEN
    SELECT key INTO v_model_key FROM ai.models WHERE id = v_res.model_id;
    IF v_model_key IS DISTINCT FROM p_model_id THEN
      RAISE EXCEPTION 'E_BYOK_CONTEXT_INVALID: reservation/model mismatch (expected %, got %)',
        v_model_key, p_model_id
        USING ERRCODE = 'P0001';
    END IF;
  END IF;

  SELECT * INTO v_key
  FROM   execution.byok_keys
  WHERE  agent_id   = p_agent_id
    AND  provider   = p_provider
    AND  revoked_at IS NULL
    AND  (expires_at IS NULL OR expires_at > now());
  IF NOT FOUND THEN
    RETURN NULL;
  END IF;

  IF p_model_id IS NOT NULL
     AND v_key.allowed_model_ids IS NOT NULL
     AND NOT (p_model_id = ANY (v_key.allowed_model_ids)) THEN
    RAISE EXCEPTION 'byok_key_resolve_v2: model % is not in allowed_model_ids for provider %',
      p_model_id, p_provider
      USING ERRCODE = 'P0001';
  END IF;

  -- Audit row: prefer caller-supplied model id, else fall back to the model
  -- key bound by the reservation. fn_byok_log_usage demands NOT NULL.
  IF p_model_id IS NOT NULL AND LENGTH(p_model_id) > 0 THEN
    PERFORM public.fn_byok_log_usage(v_key.id, NULL, p_model_id, 0);
  ELSIF v_model_key IS NOT NULL THEN
    PERFORM public.fn_byok_log_usage(v_key.id, NULL, v_model_key, 0);
  ELSE
    SELECT m.key INTO v_model_key FROM ai.models m WHERE m.id = v_res.model_id;
    PERFORM public.fn_byok_log_usage(v_key.id, NULL, COALESCE(v_model_key, 'unknown'), 0);
  END IF;

  RETURN v_key.key_encrypted;
END;
$$;


ALTER FUNCTION "public"."fn_byok_key_resolve_v2"("p_agent_id" "uuid", "p_provider" "text", "p_model_id" "text", "p_reservation_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_byok_key_resolve_v2"("p_agent_id" "uuid", "p_provider" "text", "p_model_id" "text", "p_reservation_id" "uuid") IS 'CG1: BYOK key resolution bound to a held reservation. The reservation_id is the per-call unforgeable token. Service_role only. Logs every resolve to audit.byok_key_usage via fn_byok_log_usage.';



CREATE OR REPLACE FUNCTION "public"."fn_byok_key_revoke"("p_agent_id" "uuid", "p_provider" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'agents', 'lensers', 'public'
    AS $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM agents.ownerships o
    WHERE  o.ai_lenser_id   = p_agent_id
      AND  o.owner_lenser_id = lensers.get_auth_human_lenser_id()
      AND  o.revoked_at IS NULL
  ) THEN
    RAISE EXCEPTION 'byok_key_revoke_forbidden';
  END IF;

  UPDATE execution.byok_keys
  SET    revoked_at = now()
  WHERE  agent_id = p_agent_id
    AND  provider  = p_provider;
END;
$$;


ALTER FUNCTION "public"."fn_byok_key_revoke"("p_agent_id" "uuid", "p_provider" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_byok_key_rotate"("p_agent_id" "uuid", "p_provider" "text", "p_new_encrypted" "text", "p_new_hint" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'audit', 'public'
    AS $$
DECLARE
  v_actor_id UUID;
  v_rows_updated INT;
BEGIN
  v_actor_id := auth.uid();
  IF v_actor_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required' USING ERRCODE = 'P0001';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM agents.ai_lensers al
    JOIN lensers.profiles p ON p.id = al.profile_id
    WHERE al.id = p_agent_id AND p.id = v_actor_id
  ) THEN
    RAISE EXCEPTION 'byok_key_rotate: caller does not own agent %', p_agent_id
      USING ERRCODE = 'P0001';
  END IF;

  UPDATE execution.byok_keys
  SET
    key_encrypted  = p_new_encrypted,
    key_hint       = p_new_hint,
    revoked_at     = NULL,
    created_at     = now(),
    last_rotated_at = now()
  WHERE agent_id = p_agent_id
    AND provider  = p_provider;

  GET DIAGNOSTICS v_rows_updated = ROW_COUNT;
  IF v_rows_updated = 0 THEN
    RAISE EXCEPTION 'byok_key_rotate: no key found for agent % provider %', p_agent_id, p_provider
      USING ERRCODE = 'P0001';
  END IF;

  INSERT INTO audit.events (event_type, actor_type, severity, payload)
  VALUES (
    'byok.key_rotated',
    'user',
    'info',
    jsonb_build_object(
      'agent_id',      p_agent_id,
      'provider',      p_provider,
      'key_hint',      p_new_hint,
      'rotated_by',    v_actor_id,
      'rotated_at',    now()
    )
  );
END;
$$;


ALTER FUNCTION "public"."fn_byok_key_rotate"("p_agent_id" "uuid", "p_provider" "text", "p_new_encrypted" "text", "p_new_hint" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_byok_key_rotate"("p_agent_id" "uuid", "p_provider" "text", "p_new_encrypted" "text", "p_new_hint" "text") IS 'AR: Rotates an existing BYOK key. Requires the caller to be the agent owner. Atomic UPDATE + audit.events INSERT. SECURITY DEFINER; authenticated role allowed.';



CREATE OR REPLACE FUNCTION "public"."fn_byok_log_usage"("p_key_id" "uuid", "p_battle_id" "uuid", "p_model_id" "text", "p_token_count" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
BEGIN
  INSERT INTO audit.byok_key_usage (key_id, battle_id, model_id, token_count, caller_role)
  VALUES (p_key_id, p_battle_id, p_model_id, COALESCE(p_token_count, 0), 'service_role');
END;
$$;


ALTER FUNCTION "public"."fn_byok_log_usage"("p_key_id" "uuid", "p_battle_id" "uuid", "p_model_id" "text", "p_token_count" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_byok_log_usage"("p_key_id" "uuid", "p_battle_id" "uuid", "p_model_id" "text", "p_token_count" integer) IS 'BZ: Inserts a usage record into audit.byok_key_usage. Called fire-and-forget after each successful model call. SECURITY DEFINER; service_role only. Never exposes key material.';



CREATE TABLE IF NOT EXISTS "execution"."byok_keys" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "agent_id" "uuid" NOT NULL,
    "provider" "text" NOT NULL,
    "key_encrypted" "text" NOT NULL,
    "key_hint" "text",
    "label" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "expires_at" timestamp with time zone,
    "revoked_at" timestamp with time zone,
    "allowed_model_ids" "text"[],
    "last_rotated_at" timestamp with time zone DEFAULT "now"(),
    CONSTRAINT "byok_keys_provider_check" CHECK (("provider" = ANY (ARRAY['openai'::"text", 'anthropic'::"text", 'mistral'::"text", 'google'::"text", 'cohere'::"text", 'custom'::"text"])))
);


ALTER TABLE "execution"."byok_keys" OWNER TO "postgres";


COMMENT ON TABLE "execution"."byok_keys" IS 'Encrypted BYOK API keys for agent-based battle execution. RLS denies all authenticated reads. Accessed only via service_role in trusted workers.';



COMMENT ON COLUMN "execution"."byok_keys"."allowed_model_ids" IS 'AR: Optional allowlist of ai.models.key values this key is permitted to use. NULL means unrestricted. Checked by fn_byok_key_resolve.';



COMMENT ON COLUMN "execution"."byok_keys"."last_rotated_at" IS 'BZ: Timestamp of last key rotation. Used to enforce the 90-day rotation policy. Defaults to now() on INSERT; updated by fn_byok_key_rotate.';



CREATE OR REPLACE FUNCTION "public"."fn_byok_rotation_due"() RETURNS SETOF "execution"."byok_keys"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'execution', 'public'
    AS $$
  SELECT *
  FROM execution.byok_keys
  WHERE revoked_at IS NULL
    AND last_rotated_at < now() - INTERVAL '90 days'
  ORDER BY last_rotated_at ASC;
$$;


ALTER FUNCTION "public"."fn_byok_rotation_due"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_byok_rotation_due"() IS 'BZ: Returns byok_keys rows where last_rotated_at < now() - 90 days and not revoked. Used by the daily rotation-due cron and lf byok check-rotation CLI command.';



CREATE OR REPLACE FUNCTION "public"."fn_byok_send_rotation_notifications"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'audit', 'agents', 'lensers', 'public'
    AS $$
DECLARE
  v_key   execution.byok_keys%ROWTYPE;
  v_owner UUID;
  v_count INT := 0;
BEGIN
  FOR v_key IN (
    SELECT * FROM execution.byok_keys
    WHERE revoked_at    IS NULL
      AND last_rotated_at < now() - INTERVAL '90 days'
  ) LOOP
    -- Resolve owner: byok_keys → ai_lensers → profiles
    SELECT lp.id INTO v_owner
    FROM agents.ai_lensers al
    JOIN lensers.profiles lp ON lp.id = al.profile_id
    WHERE al.id = v_key.agent_id
    LIMIT 1;

    IF v_owner IS NOT NULL THEN
      PERFORM public.fn_send_notification(
        v_owner,
        'byok_rotation_due',
        jsonb_build_object(
          'key_id',          v_key.id,
          'provider',        v_key.provider,
          'agent_id',        v_key.agent_id,
          'last_rotated_at', v_key.last_rotated_at,
          'days_overdue',    EXTRACT(DAY FROM now() - v_key.last_rotated_at - INTERVAL '90 days')::int
        )
      );
      v_count := v_count + 1;
    END IF;
  END LOOP;

  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."fn_byok_send_rotation_notifications"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_byok_send_rotation_notifications"() IS 'BZ: Sends byok_rotation_due notifications for all overdue keys. Called by daily pg_cron job. Returns count of notifications sent.';



CREATE OR REPLACE FUNCTION "public"."fn_byok_validate_for_battle"("p_battle_id" "uuid", "p_contender_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_actor_id       UUID;
  v_ai_lenser_id   UUID;
  v_key_row        execution.byok_keys%ROWTYPE;
  v_allowed_models TEXT[];
BEGIN
  -- Must be authenticated
  v_actor_id := auth.uid();
  IF v_actor_id IS NULL THEN
    RETURN jsonb_build_object('valid', false, 'reason', 'authentication_required');
  END IF;

  -- Resolve the ai_lenser_id for this contender
  SELECT cem.ai_lenser_id INTO v_ai_lenser_id
  FROM battles.contender_entity_map cem
  WHERE cem.contender_id = p_contender_id
    AND cem.ai_lenser_id IS NOT NULL
  LIMIT 1;

  IF v_ai_lenser_id IS NULL THEN
    RETURN jsonb_build_object('valid', false, 'reason', 'contender_has_no_agent');
  END IF;

  -- Caller must own this agent
  IF NOT EXISTS (
    SELECT 1
    FROM agents.ai_lensers al
    JOIN lensers.profiles lp ON lp.id = al.profile_id
    WHERE al.id = v_ai_lenser_id
      AND lp.id = v_actor_id
  ) THEN
    RETURN jsonb_build_object('valid', false, 'reason', 'caller_does_not_own_agent');
  END IF;

  -- Get the first valid key for this agent (provider-agnostic validation)
  SELECT * INTO v_key_row
  FROM execution.byok_keys bk
  WHERE bk.agent_id  = v_ai_lenser_id
    AND bk.revoked_at IS NULL
    AND (bk.expires_at IS NULL OR bk.expires_at > now())
  ORDER BY bk.created_at DESC
  LIMIT 1;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('valid', false, 'reason', 'no_valid_key');
  END IF;

  -- Check model allowlist against battle template
  SELECT bt.allowed_model_ids INTO v_allowed_models
  FROM battles.battles b
  JOIN battles.templates bt ON bt.id = b.template_id
  WHERE b.id = p_battle_id;

  IF v_allowed_models IS NOT NULL
    AND array_length(v_allowed_models, 1) > 0
    AND v_key_row.allowed_model_ids IS NOT NULL
  THEN
    -- Verify intersection is non-empty
    IF NOT EXISTS (
      SELECT 1
      FROM unnest(v_key_row.allowed_model_ids) AS km
      WHERE km = ANY(v_allowed_models)
    ) THEN
      RETURN jsonb_build_object(
        'valid', false,
        'reason', 'model_not_in_template_allowlist'
      );
    END IF;
  END IF;

  RETURN jsonb_build_object('valid', true, 'reason', null, 'key_id', v_key_row.id);
END;
$$;


ALTER FUNCTION "public"."fn_byok_validate_for_battle"("p_battle_id" "uuid", "p_contender_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_byok_validate_for_battle"("p_battle_id" "uuid", "p_contender_id" "uuid") IS 'BZ: Validates that the contender in a battle has a usable BYOK key. Returns {valid, reason} JSON. SECURITY DEFINER; authenticated owner only.';



CREATE OR REPLACE FUNCTION "public"."fn_cancel_account_deletion_on_login"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'auth'
    AS $$
DECLARE
  v_uid uuid;
  v_profile RECORD;
  v_event_type text;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('restored', false, 'reason', 'not_authenticated');
  END IF;

  SELECT id, user_id, status, deletion_deadline_at, deletion_requested_at
  INTO v_profile
  FROM lensers.profiles
  WHERE user_id = v_uid
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('restored', false, 'reason', 'no_profile');
  END IF;

  IF v_profile.status = 'pending_deletion'
     AND (v_profile.deletion_deadline_at IS NULL OR v_profile.deletion_deadline_at > now()) THEN
    UPDATE lensers.profiles
    SET status = 'active',
        deletion_requested_at = null,
        deletion_deadline_at = null,
        updated_at = now()
    WHERE id = v_profile.id;

    PERFORM lensers.log_account_lifecycle_event(
      v_profile.id,
      v_profile.user_id,
      'restored_from_pending_deletion',
      v_profile.status,
      'active'::lensers.lenser_status,
      'signin_restore',
      jsonb_build_object(
        'restored_before_deadline', true,
        'deletion_deadline_at', v_profile.deletion_deadline_at
      )
    );

    RETURN jsonb_build_object('restored', true, 'from_status', 'pending_deletion');
  END IF;

  IF (
    v_profile.status = 'deactivated' OR
    (v_profile.status = 'active' AND v_profile.deletion_requested_at IS NOT NULL)
  ) AND (
    v_profile.deletion_deadline_at IS NULL OR v_profile.deletion_deadline_at > now()
  ) THEN
    UPDATE lensers.profiles
    SET status = 'active',
        deletion_requested_at = null,
        deletion_deadline_at = null,
        updated_at = now()
    WHERE id = v_profile.id;

    v_event_type := CASE
      WHEN v_profile.status = 'active' THEN 'restored_from_pending_deletion'
      ELSE 'restored_from_deactivated'
    END;

    PERFORM lensers.log_account_lifecycle_event(
      v_profile.id,
      v_profile.user_id,
      v_event_type,
      v_profile.status,
      'active'::lensers.lenser_status,
      'signin_restore',
      jsonb_build_object(
        'restored_before_deadline', true,
        'deletion_deadline_at', v_profile.deletion_deadline_at,
        'cleared_stale_deletion_flags', v_profile.status = 'active'
      )
    );

    RETURN jsonb_build_object('restored', true, 'from_status', v_profile.status);
  END IF;

  RETURN jsonb_build_object('restored', false, 'reason', 'no_action_needed');
END;
$$;


ALTER FUNCTION "public"."fn_cancel_account_deletion_on_login"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_cancel_agent_run"("p_team_run_id" "uuid", "p_ai_lenser_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lensers'
    AS $$
DECLARE
  v_lenser_id uuid := lensers.get_auth_human_lenser_id();
BEGIN
  UPDATE agents.team_runs
  SET status = 'cancelled'
  WHERE id = p_team_run_id
    AND ai_lenser_id = p_ai_lenser_id
    AND (
      EXISTS (
        SELECT 1 FROM agents.ownerships o
        WHERE o.ai_lenser_id = p_ai_lenser_id
          AND o.owner_lenser_id = v_lenser_id
          AND o.revoked_at IS NULL
      ) OR public.is_admin()
    );
END;
$$;


ALTER FUNCTION "public"."fn_cancel_agent_run"("p_team_run_id" "uuid", "p_ai_lenser_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_cancel_run"("p_team_run_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_run agents.team_runs;
BEGIN
  SELECT * INTO v_run
    FROM agents.team_runs
   WHERE id = p_team_run_id
   FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'team run not found' USING ERRCODE = 'P0002';
  END IF;

  IF NOT agents.can_manage_ai_lenser(v_run.ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  IF v_run.status IN ('completed','failed','cancelled') THEN
    RAISE EXCEPTION 'run already terminal' USING ERRCODE = '22023';
  END IF;

  UPDATE agents.team_runs
     SET status       = 'cancelled',
         completed_at = now()
   WHERE id = p_team_run_id;

  IF v_run.workflow_run_id IS NOT NULL THEN
    UPDATE lenses.workflow_runs
       SET status       = 'cancelled',
           completed_at = COALESCE(completed_at, now())
     WHERE id = v_run.workflow_run_id
       AND status NOT IN ('completed','failed','cancelled');
  END IF;

  INSERT INTO agents.agent_run_events (
    team_run_id,
    event_type,
    payload,
    occurred_at
  ) VALUES (
    p_team_run_id,
    'run_cancelled',
    jsonb_build_object(
      'cancelled_by',     auth.uid(),
      'previous_status',  v_run.status
    ),
    now()
  );

  INSERT INTO agents.policy_evaluations (
    ai_lenser_id,
    team_run_id,
    evaluation_point,
    policy_type,
    verdict,
    reason,
    context,
    evaluated_at
  ) VALUES (
    v_run.ai_lenser_id,
    p_team_run_id,
    'pre_run',
    'kill_switch',
    'deny',
    'run cancelled by owner',
    jsonb_build_object('cancelled_by', auth.uid()),
    now()
  );
END;
$$;


ALTER FUNCTION "public"."fn_cancel_run"("p_team_run_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_cancel_workflow_run_over_budget"("p_run_id" "uuid", "p_pending_credits" integer DEFAULT 0) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_run            lenses.workflow_runs%ROWTYPE;
  v_projected      integer;
  v_pending        integer := GREATEST(COALESCE(p_pending_credits, 0), 0);
  v_cost_metadata  jsonb;
BEGIN
  SELECT * INTO v_run
  FROM lenses.workflow_runs
  WHERE id = p_run_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;

  -- Never cancel already-terminal runs.
  IF v_run.status IN ('completed', 'failed', 'cancelled', 'timed_out') THEN
    RETURN FALSE;
  END IF;

  IF v_run.budget_credits IS NULL THEN
    RETURN FALSE;
  END IF;

  v_projected := COALESCE(v_run.spent_credits, 0) + v_pending;

  IF v_projected <= v_run.budget_credits THEN
    RETURN FALSE;
  END IF;

  v_cost_metadata := COALESCE(v_run.cost_metadata, '{}'::jsonb)
    || jsonb_build_object(
      'budgetCancellation', jsonb_build_object(
        'cancelledAt', now(),
        'budgetCredits', v_run.budget_credits,
        'spentCredits', v_run.spent_credits,
        'pendingCredits', v_pending,
        'projectedCredits', v_projected,
        'reason', 'budget_exceeded'
      )
    );

  UPDATE lenses.workflow_runs
  SET
    status       = 'cancelled',
    completed_at = now(),
    run_worker_id = NULL,
    cost_metadata = v_cost_metadata
  WHERE id = p_run_id;

  -- Cascade cancellation to any still-running node results so the timeline
  -- view does not keep spinners going forever.
  UPDATE lenses.workflow_node_results
  SET status       = 'cancelled',
      completed_at = now(),
      error_message = COALESCE(error_message, 'budget_exceeded')
  WHERE run_id = p_run_id
    AND status IN ('pending', 'awaiting_dependency', 'queued', 'running', 'streaming', 'retrying');

  -- Append an event so SSE clients see the cancellation immediately.
  INSERT INTO lenses.workflow_run_events (run_id, event_id, type, payload)
  SELECT
    p_run_id,
    COALESCE(MAX(e.event_id), 0) + 1,
    'run.cancelled',
    jsonb_build_object(
      'runId', p_run_id,
      'reason', 'budget_exceeded',
      'budgetCredits', v_run.budget_credits,
      'spentCredits', v_run.spent_credits,
      'pendingCredits', v_pending
    )
  FROM lenses.workflow_run_events e
  WHERE e.run_id = p_run_id;

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."fn_cancel_workflow_run_over_budget"("p_run_id" "uuid", "p_pending_credits" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_cancel_workflow_run_over_budget"("p_run_id" "uuid", "p_pending_credits" integer) IS 'Phase 9 — cancels a run when spent_credits + pendingReservations exceed budget_credits. Cascades to node results and emits run.cancelled event. Invoked periodically by the worker heartbeat loop.';



CREATE OR REPLACE FUNCTION "public"."fn_check_and_upsert_aggregate"("p_recipient_id" "uuid", "p_actor_id" "uuid", "p_type" "text", "p_entity_id" "uuid", "p_window" interval) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers'
    AS $$
DECLARE
  v_agg public.notification_aggregates;
BEGIN
  -- Look for an open window; lock the row to prevent parallel duplicates.
  SELECT *
  INTO   v_agg
  FROM   public.notification_aggregates
  WHERE  recipient_id      = p_recipient_id
    AND  notification_type = p_type
    AND  entity_id         = p_entity_id
    AND  window_end        > now()
  LIMIT  1
  FOR UPDATE SKIP LOCKED;

  IF FOUND THEN
    -- Within the window: append actor (if new) and suppress new notification.
    IF NOT (p_actor_id = ANY(v_agg.actor_ids)) THEN
      UPDATE public.notification_aggregates
      SET    actor_ids = array_append(actor_ids, p_actor_id)
      WHERE  id        = v_agg.id;
    END IF;
    RETURN false;
  END IF;

  -- No open window: create a new one and allow the notification.
  INSERT INTO public.notification_aggregates
    (recipient_id, notification_type, entity_id, window_start, window_end, actor_ids)
  VALUES
    (p_recipient_id, p_type, p_entity_id, now(), now() + p_window, ARRAY[p_actor_id]);

  RETURN true;
EXCEPTION WHEN OTHERS THEN
  RAISE WARNING 'fn_check_and_upsert_aggregate failed: %', SQLERRM;
  RETURN true;  -- fail-open — allow the notification on error
END;
$$;


ALTER FUNCTION "public"."fn_check_and_upsert_aggregate"("p_recipient_id" "uuid", "p_actor_id" "uuid", "p_type" "text", "p_entity_id" "uuid", "p_window" interval) OWNER TO "postgres";


