    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "title" "text" NOT NULL,
    "slug" "text" NOT NULL,
    "creator_lenser_id" "uuid",
    "format" "text" DEFAULT 'single_elimination'::"text" NOT NULL,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "max_contenders" integer DEFAULT 8 NOT NULL,
    "battle_type" "text" DEFAULT 'ai_vs_ai'::"text" NOT NULL,
    "ai_judge_enabled" boolean DEFAULT false NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "tournaments_format_check" CHECK (("format" = ANY (ARRAY['single_elimination'::"text", 'round_robin'::"text", 'swiss'::"text"]))),
    CONSTRAINT "tournaments_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'registration'::"text", 'active'::"text", 'completed'::"text", 'cancelled'::"text"])))
);


