CREATE OR REPLACE FUNCTION "public"."fn_create_workflow"("p_title" "text", "p_description" "text" DEFAULT NULL::"text", "p_visibility" "text" DEFAULT 'public'::"text") RETURNS TABLE("id" "uuid", "lenser_id" "uuid", "title" "text", "description" "text", "visibility" "text", "battle_count" integer, "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_lenser_id uuid;
BEGIN
  v_lenser_id := lensers.get_auth_lenser_id();
  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'Unauthorized' USING ERRCODE = '42501';
  END IF;

  RETURN QUERY
  INSERT INTO lenses.workflows (lenser_id, title, description, visibility)
  VALUES (v_lenser_id, p_title, p_description, p_visibility)
  RETURNING
    lenses.workflows.id,
    lenses.workflows.lenser_id,
    lenses.workflows.title,
    lenses.workflows.description,
    lenses.workflows.visibility,
    lenses.workflows.battle_count,
    lenses.workflows.created_at,
    lenses.workflows.updated_at;
END;
$$;


ALTER FUNCTION "public"."fn_create_workflow"("p_title" "text", "p_description" "text", "p_visibility" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_create_workflow"("p_title" "text", "p_description" "text", "p_visibility" "text") IS 'Creates a workflow. Lenser identity is resolved from JWT via get_auth_lenser_id() — p_lenser_id was removed to prevent identity spoofing.';



CREATE OR REPLACE FUNCTION "public"."fn_create_workspace_record"("p_table_name" "text", "p_data" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lensers'
    AS $$
DECLARE
  v_result    jsonb;
  v_data      jsonb := COALESCE(p_data, '{}'::jsonb);
  v_cols      text;
  v_selects   text;
BEGIN
  IF p_table_name NOT IN (
    'personality_profiles', 'memory_profiles', 'tool_profiles', 'model_profiles',
    'workflow_assignments', 'evaluation_cases', 'evaluation_rubrics',
    'evaluation_baselines', 'tools_registry', 'evaluations',
    'team_members', 'team_edges', 'agent_run_events', 'agent_run_steps'
  ) THEN
    RAISE EXCEPTION 'create_forbidden: table % not in allowlist', p_table_name
      USING ERRCODE = '42501';
  END IF;

  -- Drop fields whose column defaults should fire when the caller omits a
  -- value. Today these are id, created_at, updated_at. Stripping them keeps
  -- the INSERT column list lean so DEFAULT clauses apply.
  v_data := v_data - 'id' - 'created_at' - 'updated_at';

  IF jsonb_typeof(v_data) <> 'object' THEN
    RAISE EXCEPTION 'create_forbidden: p_data must be a JSON object' USING ERRCODE = '22023';
  END IF;

  -- Empty payloads: rely entirely on column defaults / NOT NULL violations
  -- (the caller did not specify any fields).
  IF (SELECT count(*) FROM jsonb_object_keys(v_data)) = 0 THEN
    EXECUTE format(
      'INSERT INTO agents.%I DEFAULT VALUES RETURNING to_jsonb(%I.*)',
      p_table_name, p_table_name
    ) INTO v_result;
    RETURN v_result;
  END IF;

  -- Build the column list and the matching SELECT-from-record list from the
  -- keys actually present in v_data. jsonb_populate_record casts each value
  -- to the column's true type; we then project only those columns so the
  -- omitted ones fall back to their DEFAULT clause on INSERT.
  SELECT
    string_agg(quote_ident(k), ', '            ORDER BY k),
    string_agg(format('r.%I', k), ', '         ORDER BY k)
  INTO v_cols, v_selects
  FROM jsonb_object_keys(v_data) AS k;

  EXECUTE format(
    'INSERT INTO agents.%I (%s) '
    'SELECT %s FROM jsonb_populate_record(NULL::agents.%I, %L::jsonb) AS r '
    'RETURNING to_jsonb(%I.*)',
    p_table_name,
    v_cols,
    v_selects,
    p_table_name,
    v_data::text,
    p_table_name
  ) INTO v_result;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."fn_create_workspace_record"("p_table_name" "text", "p_data" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_create_workspace_record"("p_table_name" "text", "p_data" "jsonb") IS 'Create an agents workspace record. Strips id/created_at/updated_at from the JSONB payload so column defaults (gen_random_uuid, now) fire. Inserts only the columns the caller actually provided. Whitelisted on p_table_name.';



CREATE OR REPLACE FUNCTION "public"."fn_deactivate_account"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'auth'
    AS $$
DECLARE
  v_uid uuid;
  v_profile RECORD;
BEGIN
  v_uid := auth.uid();
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT id, user_id, status
  INTO v_profile
  FROM lensers.profiles
  WHERE user_id = v_uid
  FOR UPDATE;

  IF NOT FOUND OR v_profile.status <> 'active' THEN
    RETURN jsonb_build_object('success', false, 'reason', 'not_active');
  END IF;

  UPDATE lensers.profiles
  SET status = 'deactivated',
      updated_at = now()
  WHERE id = v_profile.id;

  PERFORM lensers.log_account_lifecycle_event(
    v_profile.id,
    v_profile.user_id,
    'account_deactivated',
    v_profile.status,
    'deactivated'::lensers.lenser_status,
    'user_action',
    jsonb_build_object('reason', 'user_requested_deactivation')
  );

  RETURN jsonb_build_object('success', true, 'status', 'deactivated');
END;
$$;


ALTER FUNCTION "public"."fn_deactivate_account"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_decide_approval"("p_team_run_id" "uuid", "p_decision" "text", "p_reason" "text" DEFAULT NULL::"text", "p_modifications" "jsonb" DEFAULT NULL::"jsonb") RETURNS TABLE("request_id" "uuid", "ai_lenser_id" "uuid", "team_id" "uuid", "workflow_id" "uuid", "workflow_run_id" "uuid", "workflow_assignment_id" "uuid", "approval_status" "text", "run_status" "text", "metadata" "jsonb", "decided_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lenses', 'lensers'
    AS $$
DECLARE
  v_actor          uuid;
  v_existing       agents.team_runs%ROWTYPE;
  v_decision_at    timestamptz := now();
  v_event_type     text;
  v_new_metadata   jsonb;
  v_terminal_run   text;
BEGIN
  IF p_decision NOT IN ('approved', 'rejected', 'modified') THEN
    RAISE EXCEPTION 'Invalid decision %. Allowed: approved | rejected | modified.', p_decision
      USING ERRCODE = '22023';
  END IF;

  IF p_decision = 'modified' AND (p_modifications IS NULL OR jsonb_typeof(p_modifications) <> 'object') THEN
    RAISE EXCEPTION 'modify-and-approve requires a non-null jsonb object for p_modifications.'
      USING ERRCODE = '22023';
  END IF;

  v_actor := lensers.get_auth_human_lenser_id();
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'Authentication required.' USING ERRCODE = '42501';
  END IF;

  SELECT * INTO v_existing
  FROM agents.team_runs
  WHERE id = p_team_run_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Approval request % not found.', p_team_run_id
      USING ERRCODE = '42501';
  END IF;

  IF NOT agents.can_manage_ai_lenser(v_existing.ai_lenser_id) THEN
    RAISE EXCEPTION 'Forbidden: you do not own this AI workspace.'
      USING ERRCODE = '42501';
  END IF;

  IF v_existing.approval_status <> 'pending' THEN
    RAISE EXCEPTION 'Request % is in approval_status="%", cannot decide twice.',
      p_team_run_id, v_existing.approval_status
      USING ERRCODE = '22023';
  END IF;

  v_new_metadata := COALESCE(v_existing.metadata, '{}'::jsonb)
    || jsonb_build_object(
         'decision_at', v_decision_at,
         'decision_by_lenser_id', v_actor,
         'decision_reason', p_reason
       );

  IF p_decision = 'modified' THEN
    v_new_metadata := v_new_metadata
      || jsonb_build_object('decision_modifications', p_modifications);
    v_event_type := 'approval_modified';
  ELSIF p_decision = 'approved' THEN
    v_event_type := 'approval_granted';
  ELSE
    v_event_type := 'approval_rejected';
  END IF;

  -- Approved-or-modified resumes the run by flipping team_run + workflow_run
  -- status. Rejected terminates both with `failed`.
  IF p_decision IN ('approved', 'modified') THEN
    UPDATE agents.team_runs
    SET approval_status = CASE WHEN p_decision = 'modified' THEN 'approved' ELSE p_decision END,
        status = 'queued',
        metadata = v_new_metadata,
        updated_at = v_decision_at
    WHERE id = p_team_run_id;

    IF v_existing.workflow_run_id IS NOT NULL THEN
      -- Recovery sweeper picks up `queued` runs; we do not call the engine
      -- directly. Only flip out of `blocked` so we never override an active
      -- transition that another process may have written.
      UPDATE lenses.workflow_runs
      SET status = 'queued'
      WHERE id = v_existing.workflow_run_id
        AND status IN ('pending', 'queued');
    END IF;

    v_terminal_run := 'queued';
  ELSE
    UPDATE agents.team_runs
    SET approval_status = 'rejected',
        status = 'failed',
        completed_at = v_decision_at,
        metadata = v_new_metadata,
        updated_at = v_decision_at
    WHERE id = p_team_run_id;

    IF v_existing.workflow_run_id IS NOT NULL THEN
      UPDATE lenses.workflow_runs
      SET status = 'failed',
          completed_at = COALESCE(completed_at, v_decision_at)
      WHERE id = v_existing.workflow_run_id
        AND status NOT IN ('completed', 'cancelled', 'failed');
    END IF;

    v_terminal_run := 'failed';
  END IF;

  INSERT INTO agents.agent_run_events (team_run_id, event_type, payload, occurred_at)
  VALUES (
    p_team_run_id,
    v_event_type,
    jsonb_build_object(
      'decision', p_decision,
      'reason', p_reason,
      'modifications', p_modifications,
      'decided_by_lenser_id', v_actor,
      'previous_run_status', v_existing.status,
      'next_run_status', v_terminal_run
    ),
    v_decision_at
  );

  RETURN QUERY
  SELECT
    p_team_run_id                                               AS request_id,
    v_existing.ai_lenser_id                                     AS ai_lenser_id,
    v_existing.team_id                                          AS team_id,
    v_existing.workflow_id                                      AS workflow_id,
    v_existing.workflow_run_id                                  AS workflow_run_id,
    v_existing.workflow_assignment_id                           AS workflow_assignment_id,
    CASE WHEN p_decision IN ('approved', 'modified') THEN 'approved' ELSE 'rejected' END AS approval_status,
    v_terminal_run                                              AS run_status,
    v_new_metadata                                              AS metadata,
    v_decision_at                                               AS decided_at;
END;
$$;


ALTER FUNCTION "public"."fn_decide_approval"("p_team_run_id" "uuid", "p_decision" "text", "p_reason" "text", "p_modifications" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_decide_approval"("p_team_run_id" "uuid", "p_decision" "text", "p_reason" "text", "p_modifications" "jsonb") IS 'Atomic owner-decision RPC for approval gates. Writes approval_status, merges decision audit fields into metadata, appends an agent_run_events row, and transitions the underlying workflow_run.';



CREATE OR REPLACE FUNCTION "public"."fn_decide_moderation_override"("p_battle_id" "uuid", "p_entry_id" "uuid", "p_decision" "text", "p_reason" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'audit', 'lensers'
    AS $$
DECLARE
  v_lenser_id        uuid;
  v_creator_lenser_id uuid;
  v_decision_type    text;
  v_new_status       battles.submission_status_enum;
BEGIN
  IF p_decision NOT IN ('allow', 'reject') THEN
    RAISE EXCEPTION 'Invalid decision: must be ''allow'' or ''reject''';
  END IF;

  v_lenser_id := lensers.get_auth_lenser_id();
  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  -- Verify caller is the battle creator
  SELECT creator_lenser_id INTO v_creator_lenser_id
  FROM battles.battles
  WHERE id = p_battle_id;

  IF v_creator_lenser_id IS NULL THEN
    RAISE EXCEPTION 'Battle not found: %', p_battle_id;
  END IF;

  IF v_creator_lenser_id <> v_lenser_id THEN
    RAISE EXCEPTION 'Only the battle creator may override moderation decisions'
      USING ERRCODE = '42501';
  END IF;

  -- Map decision to enum values
  IF p_decision = 'allow' THEN
    v_decision_type := 'restored';
    v_new_status    := 'submitted';
  ELSE
    v_decision_type := 'rejected';
    v_new_status    := 'disqualified';
  END IF;

  -- Update the submission status
  UPDATE battles.submissions
  SET status = v_new_status,
      updated_at = now()
  WHERE id = p_entry_id
    AND battle_id = p_battle_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Submission not found: %', p_entry_id;
  END IF;

  -- Audit the decision
  INSERT INTO audit.moderation_decisions (
    target_entity_schema,
    target_entity_table,
    target_entity_id,
    decision_type,
    reason,
    moderator_lenser_id,
    is_ai_moderated
  ) VALUES (
    'battles',
    'submissions',
    p_entry_id,
    v_decision_type,
    p_reason,
    v_lenser_id,
    false
  );
END;
$$;


ALTER FUNCTION "public"."fn_decide_moderation_override"("p_battle_id" "uuid", "p_entry_id" "uuid", "p_decision" "text", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_decide_tool_invocation"("p_log_id" "uuid", "p_decision" "text", "p_reason" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'platform', 'lenses', 'agents', 'lensers', 'public'
    AS $$
DECLARE
  v_auth_lenser_id uuid;
  v_log            platform.tool_invocation_logs%ROWTYPE;
BEGIN
  IF p_decision NOT IN ('approved', 'rejected') THEN
    RAISE EXCEPTION 'Invalid decision "%" — must be ''approved'' or ''rejected''', p_decision
      USING ERRCODE = '22023';
  END IF;

  v_auth_lenser_id := lensers.get_auth_lenser_id();

  SELECT * INTO v_log
  FROM platform.tool_invocation_logs
  WHERE id = p_log_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'tool_invocation_log % not found', p_log_id
      USING ERRCODE = 'P0002';
  END IF;

  -- Caller must own the ai_lenser that produced this log entry
  IF NOT EXISTS (
    SELECT 1 FROM agents.ai_lensers al
    WHERE al.id = v_log.ai_lenser_id
      AND al.profile_id = v_auth_lenser_id
  ) THEN
    RAISE EXCEPTION 'Not authorised to decide on tool invocation log %', p_log_id
      USING ERRCODE = '42501';
  END IF;

  IF v_log.approval_status <> 'awaiting_approval' THEN
    RAISE EXCEPTION 'Cannot decide on log % with status "%"', p_log_id, v_log.approval_status
      USING ERRCODE = '22023';
  END IF;

  UPDATE platform.tool_invocation_logs
  SET
    approval_status = p_decision,
    decided_at      = now(),
    decided_by      = v_auth_lenser_id
  WHERE id = p_log_id;

  -- Emit a tool_decision event into the run timeline if the log is tied to a run
  IF v_log.run_id IS NOT NULL THEN
    INSERT INTO lenses.workflow_run_events (run_id, type, payload)
    VALUES (
      v_log.run_id,
      'tool_decision',
      jsonb_build_object(
        'log_id',    p_log_id,
        'tool_name', v_log.tool_name,
        'decision',  p_decision,
        'reason',    p_reason,
        'decided_by', v_auth_lenser_id,
        'decided_at', now()
      )
    );
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_decide_tool_invocation"("p_log_id" "uuid", "p_decision" "text", "p_reason" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_decide_tool_invocation"("p_log_id" "uuid", "p_decision" "text", "p_reason" "text") IS 'Records approve/reject decision on platform.tool_invocation_logs and emits a tool_decision event to lenses.workflow_run_events for run timeline visibility.';



