CREATE OR REPLACE FUNCTION "public"."fn_dispatch_scheduled_workflows_with_approval"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'agents', 'platform', 'public'
    AS $$
DECLARE
  v_dispatch_enabled boolean;
  v_result           integer;
BEGIN
  -- Check platform-level autonomy kill switch (populated by Phase 2.9 migration).
  -- If the table or row does not yet exist, default to enabled.
  BEGIN
    SELECT (value::boolean) INTO v_dispatch_enabled
    FROM platform.system_flags
    WHERE key = 'autonomy_dispatch_enabled';
  EXCEPTION WHEN undefined_table OR undefined_column THEN
    v_dispatch_enabled := true;
  END;

  IF v_dispatch_enabled IS NOT DISTINCT FROM false THEN
    RAISE NOTICE 'Autonomous dispatch is disabled (platform.system_flags.autonomy_dispatch_enabled=false). Skipping.';
    RETURN 0;
  END IF;

  -- requiresApproval=false AND spending_limit_credits IS NULL guard:
  -- Log a warning for any schedule that bypasses approval without a spending cap.
  -- The UPSERT guard above should prevent these from being created, but we
  -- audit here as a belt-and-suspenders check.
  PERFORM 1
  FROM lenses.workflow_schedules s
  JOIN lenses.workflows w ON w.id = s.workflow_id
  JOIN agents.ai_lensers al ON al.profile_id = w.lenser_id
  JOIN agents.policies pol ON pol.id = al.policy_id
  WHERE s.is_active = true
    AND COALESCE((s.approval_policy->>'requiresApproval')::boolean, true) = false
    AND pol.spending_limit_credits IS NULL;

  IF FOUND THEN
    RAISE WARNING
      'One or more active schedules have requiresApproval=false and no spending_limit_credits. '
      'These schedules will dispatch without approval gates and without a cost ceiling. '
      'Set a spending limit or re-enable approval to suppress this warning.';
  END IF;

  -- Delegate to the existing approval-aware dispatcher (lenses schema).
  SELECT lenses.fn_dispatch_scheduled_workflows() INTO v_result;
  RETURN COALESCE(v_result, 0);
END;
$$;


ALTER FUNCTION "public"."fn_dispatch_scheduled_workflows_with_approval"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_dispatch_scheduled_workflows_with_approval"() IS 'Phase 2 pg_cron target. Wraps lenses.fn_dispatch_scheduled_workflows() with a platform-level autonomy kill switch check and an approval/spending-limit audit warning. The kill switch is controlled via platform.system_flags.autonomy_dispatch_enabled.';



CREATE OR REPLACE FUNCTION "public"."fn_evaluate_pre_run_policy"("p_ai_lenser_id" "uuid", "p_workflow_id" "uuid", "p_context" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("verdict" "text", "reason" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_settings        agents.workspace_settings;
  v_credits_used    numeric;
  v_active_runs     integer;
  v_workflow_hash   integer;
  v_verdict         text;
  v_reason          text;
  v_policy_type     text;
BEGIN
  IF NOT agents.can_manage_ai_lenser(p_ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  -- Load or default settings
  SELECT * INTO v_settings
    FROM agents.workspace_settings
   WHERE ai_lenser_id = p_ai_lenser_id;

  IF NOT FOUND THEN
    -- All defaults: allow
    v_verdict     := 'allow';
    v_reason      := NULL;
    v_policy_type := 'kill_switch';

    INSERT INTO agents.policy_evaluations (
      ai_lenser_id, team_run_id, tool_invocation_id,
      evaluation_point, policy_type, verdict, reason, context, evaluated_at
    ) VALUES (
      p_ai_lenser_id, NULL, NULL,
      'pre_run', v_policy_type, v_verdict, v_reason,
      COALESCE(p_context, '{}'::jsonb), now()
    );

    RETURN QUERY SELECT v_verdict, v_reason;
    RETURN;
  END IF;

  -- 1. Global kill switch
  IF v_settings.global_kill_switch THEN
    v_verdict     := 'deny';
    v_reason      := 'global kill switch active';
    v_policy_type := 'kill_switch';

  -- 2. Agent paused
  ELSIF v_settings.agent_paused THEN
    v_verdict     := 'pause';
    v_reason      := 'agent is paused';
    v_policy_type := 'pause';

  -- 3. Daily budget
  ELSIF v_settings.budget_enforce THEN
    SELECT COALESCE(SUM(credits_spent), 0)
      INTO v_credits_used
      FROM agents.quota_snapshots
     WHERE ai_lenser_id = p_ai_lenser_id
       AND period_date  = CURRENT_DATE;

    IF v_credits_used >= v_settings.max_daily_credits THEN
      v_verdict     := 'deny';
      v_reason      := 'daily budget exceeded';
      v_policy_type := 'budget';
    END IF;
  END IF;

  -- 4. Parallel run limit (only if not already denied above)
  IF v_verdict IS NULL THEN
    SELECT COUNT(*)
      INTO v_active_runs
      FROM agents.team_runs
     WHERE ai_lenser_id = p_ai_lenser_id
       AND status IN ('queued','running','blocked');

    IF v_active_runs >= v_settings.max_parallel_runs THEN
      v_verdict     := 'deny';
      v_reason      := 'max_parallel_runs limit reached';
      v_policy_type := 'parallel_limit';
    END IF;
  END IF;

  -- 5. Dark launch gating
  IF v_verdict IS NULL
     AND v_settings.dark_launch_enabled
     AND p_workflow_id IS NOT NULL
  THEN
    v_workflow_hash := (('x' || md5(p_workflow_id::text))::bit(32)::int & 2147483647) % 100;
    IF v_workflow_hash >= v_settings.dark_launch_pct THEN
      v_verdict     := 'deny';
      v_reason      := 'outside dark launch percentage';
      v_policy_type := 'dark_launch';
    END IF;
  END IF;

  -- 6. Approval default: require_human
  IF v_verdict IS NULL AND v_settings.approval_default = 'require_human' THEN
    v_verdict     := 'require_approval';
    v_reason      := 'workspace default requires human approval';
    v_policy_type := 'approval';
  END IF;

  -- 7. Approval default: deny-all
  IF v_verdict IS NULL AND v_settings.approval_default = 'deny' THEN
    v_verdict     := 'deny';
    v_reason      := 'workspace approval policy is deny-all';
    v_policy_type := 'approval';
  END IF;

  -- 8. Default: allow
  IF v_verdict IS NULL THEN
    v_verdict     := 'allow';
    v_reason      := NULL;
    v_policy_type := 'kill_switch';
  END IF;

  -- Always audit
  INSERT INTO agents.policy_evaluations (
    ai_lenser_id, team_run_id, tool_invocation_id,
    evaluation_point, policy_type, verdict, reason, context, evaluated_at
  ) VALUES (
    p_ai_lenser_id, NULL, NULL,
    'pre_run', v_policy_type, v_verdict, v_reason,
    COALESCE(p_context, '{}'::jsonb), now()
  );

  RETURN QUERY SELECT v_verdict, v_reason;
END;
$$;


ALTER FUNCTION "public"."fn_evaluate_pre_run_policy"("p_ai_lenser_id" "uuid", "p_workflow_id" "uuid", "p_context" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_execution_persist_response"("p_lenser_id" "uuid", "p_provider" "text", "p_model" "text", "p_status" "text" DEFAULT 'succeeded'::"text", "p_response_text" "text" DEFAULT NULL::"text", "p_response_meta" "jsonb" DEFAULT '{}'::"jsonb", "p_token_input" integer DEFAULT 0, "p_token_output" integer DEFAULT 0, "p_credit_cost" bigint DEFAULT 0) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'public'
    AS $$
DECLARE
    v_request_id     uuid;
    v_run_id         uuid;
    v_model_id       uuid;
    v_billing_status text;
BEGIN
    -- Resolve model_id from provider + model key (best-effort)
    SELECT m.id INTO v_model_id
    FROM ai.models m
    JOIN ai.providers p ON p.id = m.provider_id
    WHERE p.key = p_provider AND m.key = p_model
    LIMIT 1;

    v_billing_status := CASE WHEN p_credit_cost > 0 THEN 'charged' ELSE 'free' END;

    -- Create request row
    INSERT INTO execution.requests (
        requester_lenser_id,
        origin_type,
        model_id,
        funding_source,
        runtime_origin
    ) VALUES (
        p_lenser_id,
        'api',
        v_model_id,
        CASE WHEN p_credit_cost > 0 THEN 'platform_credit' ELSE 'free' END,
        'cloud'
    )
    RETURNING id INTO v_request_id;

    -- Create run row with response
    INSERT INTO execution.runs (
        request_id,
        status,
        model_id,
        token_input,
        token_output,
        credit_cost,
        billing_status,
        response_text,
        response_meta,
        started_at,
        completed_at
    ) VALUES (
        v_request_id,
        p_status,
        v_model_id,
        p_token_input,
        p_token_output,
        p_credit_cost,
        v_billing_status,
        p_response_text,
        p_response_meta,
        now(),
        CASE WHEN p_status IN ('succeeded', 'failed', 'timed_out') THEN now() ELSE NULL END
    )
    RETURNING id INTO v_run_id;

    RETURN v_run_id;
END;
$$;


ALTER FUNCTION "public"."fn_execution_persist_response"("p_lenser_id" "uuid", "p_provider" "text", "p_model" "text", "p_status" "text", "p_response_text" "text", "p_response_meta" "jsonb", "p_token_input" integer, "p_token_output" integer, "p_credit_cost" bigint) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_execution_persist_response"("p_lenser_id" "uuid", "p_provider" "text", "p_model" "text", "p_status" "text", "p_response_text" "text", "p_response_meta" "jsonb", "p_token_input" integer, "p_token_output" integer, "p_credit_cost" bigint) IS 'Persists an AI execution response by creating request + run rows. Called fire-and-forget by the API Worker after provider calls complete.';



CREATE OR REPLACE FUNCTION "public"."fn_expire_byok_keys"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'execution', 'audit', 'public'
    AS $$
DECLARE
  v_count INT;
BEGIN
  UPDATE execution.byok_keys
  SET revoked_at = now()
  WHERE expires_at < now()
    AND revoked_at IS NULL;

  GET DIAGNOSTICS v_count = ROW_COUNT;

  IF v_count > 0 THEN
    INSERT INTO audit.events (event_type, actor_type, severity, payload)
    VALUES (
      'byok.keys_expired',
      'system',
      'info',
      jsonb_build_object('expired_count', v_count, 'expired_at', now())
    );
  END IF;

  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."fn_expire_byok_keys"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_expire_byok_keys"() IS 'AR: Soft-revokes all BYOK keys where expires_at < now(). Called by pg_cron every hour. Returns number of keys revoked. SECURITY DEFINER; service_role only.';



CREATE OR REPLACE FUNCTION "public"."fn_expire_media_objects"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'media', 'audit', 'public'
    AS $$
DECLARE
  v_count INT;
BEGIN
  UPDATE media.objects
  SET lifecycle_state = 'archived'
  WHERE expires_at < now()
    AND lifecycle_state NOT IN ('deleted', 'archived');

  GET DIAGNOSTICS v_count = ROW_COUNT;

  IF v_count > 0 THEN
    INSERT INTO audit.events (event_type, actor_type, severity, payload)
    VALUES (
      'media.objects_expired',
      'system',
      'info',
      jsonb_build_object('archived_count', v_count, 'archived_at', now())
    );
  END IF;

  RETURN v_count;
END;
$$;


