COMMENT ON FUNCTION "public"."fn_expire_media_objects"() IS 'AT: Sets lifecycle_state=archived for objects past expires_at. Called by pg_cron daily at 02:00. SECURITY DEFINER; service_role only.';



CREATE OR REPLACE FUNCTION "public"."fn_expire_stale_approvals"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'agents', 'lenses', 'public'
    AS $$
DECLARE
  v_threshold_hours integer := COALESCE(
    NULLIF(current_setting('app.approval_timeout_hours', true), '')::integer,
    24
  );
  v_cutoff   timestamptz := now() - (v_threshold_hours * interval '1 hour');
  v_expired  integer     := 0;
  r          RECORD;
BEGIN
  FOR r IN
    SELECT id, workflow_run_id
    FROM   agents.team_runs
    WHERE  approval_status = 'pending'
      AND  created_at < v_cutoff
    FOR UPDATE SKIP LOCKED
  LOOP
    BEGIN
      UPDATE agents.team_runs
      SET    approval_status = 'timed_out',
             status          = 'cancelled',
             completed_at    = COALESCE(completed_at, now()),
             metadata        = COALESCE(metadata, '{}'::jsonb)
                                 || jsonb_build_object(
                                      'timed_out_at', now(),
                                      'timeout_hours', v_threshold_hours
                                    ),
             updated_at      = now()
      WHERE  id = r.id;

      IF r.workflow_run_id IS NOT NULL THEN
        UPDATE lenses.workflow_runs
        SET    status        = 'timed_out',
               completed_at  = COALESCE(completed_at, now())
        WHERE  id = r.workflow_run_id
          AND  status NOT IN ('completed', 'cancelled', 'failed', 'timed_out');
      END IF;

      INSERT INTO agents.agent_run_events (team_run_id, event_type, payload, occurred_at)
      VALUES (
        r.id,
        'approval_timed_out',
        jsonb_build_object(
          'timeout_hours',     v_threshold_hours,
          'workflow_run_id',   r.workflow_run_id,
          'expired_at',        now()
        ),
        now()
      );

      v_expired := v_expired + 1;
    EXCEPTION WHEN OTHERS THEN
      RAISE WARNING 'fn_expire_stale_approvals: team_run % failed: %', r.id, SQLERRM;
    END;
  END LOOP;

  RETURN v_expired;
END;
$$;


ALTER FUNCTION "public"."fn_expire_stale_approvals"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_expire_stale_approvals"() IS 'Phase K1: pg_cron target. Expires pending team_runs older than app.approval_timeout_hours (default 24h). Writes approval_status=timed_out, cancels the underlying workflow_run with status=timed_out, and emits an approval_timed_out event. Idempotent and concurrency-safe.';



CREATE OR REPLACE FUNCTION "public"."fn_export_workspace"("p_ai_lenser_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_bundle jsonb;
BEGIN
  IF NOT agents.can_manage_ai_lenser(p_ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  SELECT jsonb_build_object(
    'ai_lenser',        to_jsonb(al),
    'settings',         to_jsonb(ws),
    'teams',            COALESCE((SELECT jsonb_agg(to_jsonb(t))  FROM agents.teams t  WHERE t.ai_lenser_id = al.id), '[]'::jsonb),
    'memory_profiles',  COALESCE((SELECT jsonb_agg(to_jsonb(m))  FROM agents.memory_profiles m WHERE m.ai_lenser_id = al.id), '[]'::jsonb),
    'personality',      COALESCE((SELECT jsonb_agg(to_jsonb(p))  FROM agents.personality_profiles p WHERE p.ai_lenser_id = al.id), '[]'::jsonb),
    'tool_profiles',    COALESCE((SELECT jsonb_agg(to_jsonb(tp)) FROM agents.tool_profiles tp WHERE tp.ai_lenser_id = al.id), '[]'::jsonb),
    'model_profiles',   COALESCE((SELECT jsonb_agg(to_jsonb(mp)) FROM agents.model_profiles mp WHERE mp.ai_lenser_id = al.id), '[]'::jsonb),
    'tool_assignments', COALESCE((SELECT jsonb_agg(to_jsonb(ta)) FROM agents.tool_assignments ta WHERE ta.ai_lenser_id = al.id), '[]'::jsonb),
    'exported_at',      now()
  )
  INTO v_bundle
  FROM agents.ai_lensers al
  LEFT JOIN agents.workspace_settings ws ON ws.ai_lenser_id = al.id
  WHERE al.id = p_ai_lenser_id;

  RETURN v_bundle;
END;
$$;


