ALTER FUNCTION "public"."fn_get_auth_profile_gate"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_auth_profile_gate"() IS 'Security wrapper: return status/deletion/onboarding gate fields for the current user''s profile.';



CREATE OR REPLACE FUNCTION "public"."fn_get_batch_entity_reactions"("p_entity_type" "text", "p_entity_ids" "uuid"[]) RETURNS TABLE("entity_id" "uuid", "lenser_id" "uuid", "reaction" "text", "created_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'content'
    AS $$
  SELECT r.entity_id, r.lenser_id, r.reaction, r.created_at
  FROM content.reactions r
  WHERE r.entity_type::text = p_entity_type
    AND r.entity_id   = ANY(p_entity_ids);
$$;


ALTER FUNCTION "public"."fn_get_batch_entity_reactions"("p_entity_type" "text", "p_entity_ids" "uuid"[]) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_batch_entity_reactions"("p_entity_type" "text", "p_entity_ids" "uuid"[]) IS 'Security wrapper: return all reaction rows for an array of entity IDs (same type).';



CREATE OR REPLACE FUNCTION "public"."fn_get_battle"("p_battle_id" "uuid" DEFAULT NULL::"uuid", "p_slug" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "slug" "text", "title" "text", "task_prompt" "text", "status" "text", "total_vote_count" integer, "published_at" timestamp with time zone, "voting_opens_at" timestamp with time zone, "voting_closes_at" timestamp with time zone, "finalized_at" timestamp with time zone, "battle_type" "text", "voter_eligibility" "text", "handicap_config" "jsonb", "creator_lenser_id" "uuid", "forum_thread_id" "text", "workflow_id" "uuid", "lens_id" "uuid", "execution_starts_at" timestamp with time zone, "auto_publish" boolean, "voting_duration_hours" integer, "vote_velocity" numeric, "og_image_url" "text", "winner_contender_id" "uuid", "parent_battle_id" "uuid", "deleted_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
  SELECT
    b.id, b.slug, b.title, b.task_prompt, b.status, b.total_vote_count,
    b.published_at, b.voting_opens_at, b.voting_closes_at, b.finalized_at,
    b.battle_type, b.voter_eligibility, b.handicap_config, b.creator_lenser_id,
    b.forum_thread_id, b.workflow_id, b.lens_id, b.execution_starts_at,
    b.auto_publish, b.voting_duration_hours, b.vote_velocity, b.og_image_url,
    b.winner_contender_id, b.parent_battle_id, b.deleted_at
  FROM battles.battles b
  WHERE (p_battle_id IS NULL OR b.id   = p_battle_id)
    AND (p_slug      IS NULL OR b.slug = p_slug)
    AND b.deleted_at IS NULL
    AND (
      -- Non-draft battles are public
      b.status <> 'draft'
      -- Drafts are creator-only
      OR b.creator_lenser_id = lensers.get_auth_lenser_id()
    )
  LIMIT 1;
$$;


ALTER FUNCTION "public"."fn_get_battle"("p_battle_id" "uuid", "p_slug" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_battle"("p_battle_id" "uuid", "p_slug" "text") IS 'Security wrapper: look up a battle by id or slug. Public battles are visible to everyone; drafts only to the creator. Returns NULL when not found or draft-and-not-creator.';



CREATE OR REPLACE FUNCTION "public"."fn_get_battle_by_slug"("p_slug" "text") RETURNS TABLE("id" "uuid", "slug" "text", "title" "text", "task_prompt" "text", "status" "text", "total_vote_count" integer, "published_at" timestamp with time zone, "voting_opens_at" timestamp with time zone, "voting_closes_at" timestamp with time zone, "finalized_at" timestamp with time zone, "battle_type" "text", "voter_eligibility" "text", "handicap_config" "jsonb", "creator_lenser_id" "uuid", "forum_thread_id" "text", "workflow_id" "uuid", "lens_id" "uuid", "execution_starts_at" timestamp with time zone, "auto_publish" boolean, "voting_duration_hours" integer, "vote_velocity" numeric, "og_image_url" "text", "winner_contender_id" "uuid", "parent_battle_id" "uuid", "deleted_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
  SELECT * FROM public.fn_get_battle(NULL::uuid, p_slug);
$$;


ALTER FUNCTION "public"."fn_get_battle_by_slug"("p_slug" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_battle_by_slug"("p_slug" "text") IS 'Alias for fn_get_battle(p_slug). Fixes PGRST202 404 in battlesRepository.getBattleBySlug.';



CREATE OR REPLACE FUNCTION "public"."fn_get_battle_comments"("p_battle_id" "uuid", "p_limit" integer DEFAULT 100) RETURNS TABLE("id" "uuid", "battle_id" "uuid", "lenser_id" "uuid", "body" "text", "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "lenser_handle" "text", "lenser_display_name" "text", "lenser_avatar_url" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
  SELECT
    c.id,
    c.battle_id,
    c.lenser_id,
    c.body,
    c.created_at,
    c.updated_at,
    p.handle          AS lenser_handle,
    p.display_name    AS lenser_display_name,
    p.avatar_url      AS lenser_avatar_url
  FROM battles.comments  c
  JOIN lensers.profiles  p ON p.id = c.lenser_id
  WHERE c.battle_id = p_battle_id
  ORDER BY c.created_at ASC
  LIMIT p_limit;
$$;


ALTER FUNCTION "public"."fn_get_battle_comments"("p_battle_id" "uuid", "p_limit" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_get_battle_comments"("p_battle_id" "uuid", "p_limit" integer DEFAULT 50, "p_before_ts" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_before_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "battle_id" "uuid", "lenser_id" "uuid", "body" "text", "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "lenser_handle" "text", "lenser_display_name" "text", "lenser_avatar_url" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'battles', 'lensers', 'public'
    AS $$
  SELECT
    c.id,
    c.battle_id,
    c.lenser_id,
    c.body,
    c.created_at,
    c.updated_at,
    p.handle          AS lenser_handle,
    p.display_name    AS lenser_display_name,
    p.avatar_url      AS lenser_avatar_url
  FROM battles.comments c
  JOIN lensers.profiles p ON p.id = c.lenser_id
  WHERE c.battle_id = p_battle_id
    AND (
      p_before_ts IS NULL
      OR (c.created_at, c.id) < (p_before_ts, p_before_id)
    )
  ORDER BY c.created_at DESC, c.id DESC
  LIMIT p_limit;
$$;


ALTER FUNCTION "public"."fn_get_battle_comments"("p_battle_id" "uuid", "p_limit" integer, "p_before_ts" timestamp with time zone, "p_before_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_get_battle_contenders"("p_battle_id" "uuid") RETURNS TABLE("id" "uuid", "battle_id" "uuid", "slot" "text", "contender_type" "text", "display_name" "text", "contender_ref_id" "uuid", "contender_status" "text", "entry_mode" "text", "joined_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'battles'
    AS $$
  SELECT c.id, c.battle_id, c.slot::text, c.contender_type::text, c.display_name,
         c.contender_ref_id, c.contender_status, c.entry_mode,
         c.joined_at
  FROM battles.contenders c
  WHERE c.battle_id = p_battle_id
  ORDER BY c.slot;
$$;


ALTER FUNCTION "public"."fn_get_battle_contenders"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_get_battle_elo_log"("p_battle_id" "uuid") RETURNS TABLE("battle_id" "uuid", "winner_lenser_id" "uuid", "loser_lenser_id" "uuid", "winner_score_before" numeric, "winner_score_after" numeric, "loser_score_before" numeric, "loser_score_after" numeric, "is_draw" boolean, "k_factor" integer, "computed_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'reputation'
    AS $$
  SELECT
    el.battle_id, el.winner_lenser_id, el.loser_lenser_id,
    el.winner_score_before, el.winner_score_after,
    el.loser_score_before,  el.loser_score_after,
    el.is_draw, el.k_factor, el.computed_at
  FROM reputation.elo_battle_log el
  WHERE el.battle_id = p_battle_id;
$$;


ALTER FUNCTION "public"."fn_get_battle_elo_log"("p_battle_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_battle_elo_log"("p_battle_id" "uuid") IS 'Security wrapper: return ELO score change records for a specific battle.';



CREATE OR REPLACE FUNCTION "public"."fn_get_battle_execution_config"("p_battle_id" "uuid") RETURNS SETOF "jsonb"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
  SELECT to_jsonb(ec.*)
  FROM battles.execution_configs ec
  WHERE ec.battle_id = p_battle_id
    AND EXISTS (
      SELECT 1 FROM battles.battles b
      WHERE b.id = ec.battle_id
        AND (b.creator_lenser_id = lensers.get_auth_lenser_id()
             OR b.status::text IN ('published', 'closed'))
    );
$$;


ALTER FUNCTION "public"."fn_get_battle_execution_config"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_get_battle_execution_jobs"("p_battle_id" "uuid") RETURNS TABLE("id" "uuid", "battle_id" "uuid", "contender_id" "uuid", "slot" "text", "status" "text", "worker_id" "text", "claimed_at" timestamp with time zone, "completed_at" timestamp with time zone, "retry_count" integer, "max_retries" integer, "error_message" "text", "created_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
  SELECT j.id, j.battle_id, j.contender_id, j.slot, j.status, j.worker_id,
         j.claimed_at, j.completed_at, j.retry_count, j.max_retries,
         j.error_message, j.created_at
  FROM battles.battle_execution_jobs j
  JOIN battles.battles b ON b.id = j.battle_id
  WHERE j.battle_id = p_battle_id
    AND (b.creator_lenser_id = lensers.get_auth_lenser_id() OR public.is_admin())
  ORDER BY j.slot;
$$;


ALTER FUNCTION "public"."fn_get_battle_execution_jobs"("p_battle_id" "uuid") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "battles"."battles" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "creator_lenser_id" "uuid" DEFAULT "lensers"."get_auth_lenser_id"() NOT NULL,
    "title" "text" NOT NULL,
    "slug" "text" NOT NULL,
    "task_prompt" "text" NOT NULL,
    "rubric_id" "uuid",
    "status" "battles"."battle_status_enum" DEFAULT 'draft'::"battles"."battle_status_enum" NOT NULL,
    "invite_code" "text",
    "forum_thread_id" "uuid",
    "max_contenders" integer DEFAULT 2 NOT NULL,
    "voting_opens_at" timestamp with time zone,
    "voting_closes_at" timestamp with time zone,
    "published_at" timestamp with time zone,
    "finalized_at" timestamp with time zone,
    "winner_contender_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "deleted_at" timestamp with time zone,
    "total_vote_count" integer DEFAULT 0 NOT NULL,
    "battle_type" "battles"."battle_type_enum" DEFAULT 'human_vs_human_open_votes'::"battles"."battle_type_enum" NOT NULL,
    "voter_eligibility" "battles"."voter_eligibility_enum" DEFAULT 'open'::"battles"."voter_eligibility_enum" NOT NULL,
    "handicap_config" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "workflow_id" "uuid",
    "lens_id" "uuid",
    "content_type" "text" DEFAULT 'text'::"text" NOT NULL,
    "execution_starts_at" timestamp with time zone,
    "executing_started_at" timestamp with time zone,
    "auto_publish" boolean DEFAULT true NOT NULL,
    "voting_duration_hours" integer DEFAULT 24 NOT NULL,
    "vote_velocity" numeric(8,4) DEFAULT 0 NOT NULL,
    "og_image_url" "text",
    "ai_judge_enabled" boolean DEFAULT false,
    "ai_judge_model_key" "text" DEFAULT 'claude-sonnet-4-6'::"text",
    "ai_judge_prompt" "text",
    "parent_battle_id" "uuid",
    "template_id" "uuid",
    "auto_assign_contenders" boolean DEFAULT false NOT NULL,
    "auto_promote" boolean DEFAULT false NOT NULL,
    CONSTRAINT "battles_content_type_check" CHECK (("content_type" = ANY (ARRAY['text'::"text", 'code'::"text", 'poem'::"text", 'drawing'::"text", 'image'::"text", 'video'::"text", 'audio'::"text", 'workflow'::"text", 'map'::"text", 'avatar'::"text", 'image_edit'::"text", 'kaggle'::"text"]))),
    CONSTRAINT "battles_max_contenders_min" CHECK (("max_contenders" >= 2)),
    CONSTRAINT "battles_voting_window_order" CHECK ((("voting_opens_at" IS NULL) OR ("voting_closes_at" IS NULL) OR ("voting_opens_at" < "voting_closes_at"))),
    CONSTRAINT "ck_battles_battles_ai_judge_prompt_len" CHECK ((("ai_judge_prompt" IS NULL) OR ("length"("ai_judge_prompt") <= 8000))),
    CONSTRAINT "ck_battles_battles_invite_code_len" CHECK ((("invite_code" IS NULL) OR ("length"("invite_code") <= 32))),
    CONSTRAINT "ck_battles_battles_task_prompt_len" CHECK ((("task_prompt" IS NULL) OR ("length"("task_prompt") <= 32000))),
    CONSTRAINT "ck_battles_battles_title_len" CHECK ((("title" IS NULL) OR ("length"("title") <= 200))),
    CONSTRAINT "ck_battles_battles_total_vote_count_nonneg" CHECK ((("total_vote_count" IS NULL) OR ("total_vote_count" >= 0)))
);


ALTER TABLE "battles"."battles" OWNER TO "postgres";


COMMENT ON COLUMN "battles"."battles"."battle_type" IS 'Determines who the contenders are: ai_vs_ai, human_vs_human_ai_votes, human_vs_human_open_votes, human_vs_ai.';



COMMENT ON COLUMN "battles"."battles"."voter_eligibility" IS 'Who is allowed to cast votes: open (everyone), human_only, ai_only, verified_lenser.';



COMMENT ON COLUMN "battles"."battles"."handicap_config" IS 'JSONB snapshot of the active ai_handicap_policies row for read-only audit. Authoritative config lives in battles.ai_handicap_policies.';



COMMENT ON COLUMN "battles"."battles"."parent_battle_id" IS 'Phase V1: when this battle was created as a rematch of another battle, this points to the parent. NULL for organic battles. ON DELETE SET NULL preserves rematch history when an upstream parent is hard-deleted.';



COMMENT ON COLUMN "battles"."battles"."template_id" IS 'Phase BF: NULL for ad-hoc battles, populated when created via fn_battles_create_from_template. Used by trg_notify_template_battle_status.';



COMMENT ON COLUMN "battles"."battles"."auto_assign_contenders" IS 'CB: When true, fn_battles_auto_schedule_contenders assigns AI lensers up to max_contenders.';



COMMENT ON COLUMN "battles"."battles"."auto_promote" IS 'CB: When true, fn_battles_auto_promote transitions draft→open when readiness check passes.';



CREATE TABLE IF NOT EXISTS "battles"."contender_entity_map" (
    "contender_id" "uuid" NOT NULL,
    "profile_id" "uuid",
    "ai_lenser_id" "uuid",
    "group_id" "uuid",
    CONSTRAINT "exactly_one_entity_ref" CHECK (((((("profile_id" IS NOT NULL))::integer + (("ai_lenser_id" IS NOT NULL))::integer) + (("group_id" IS NOT NULL))::integer) = 1))
);


ALTER TABLE "battles"."contender_entity_map" OWNER TO "postgres";


COMMENT ON TABLE "battles"."contender_entity_map" IS 'CANONICAL typed identity resolution for battle contenders. battles.contenders.contender_ref_id is a deprecated compatibility alias. CHECK constraint enforces exactly one FK: profile, ai_lenser, or group. Auto-populated by trg_populate_contender_entity_map on contenders INSERT.';



CREATE TABLE IF NOT EXISTS "battles"."contenders" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "battle_id" "uuid" NOT NULL,
    "slot" character(1) NOT NULL,
    "contender_type" "battles"."contender_type_enum" NOT NULL,
    "contender_ref_id" "uuid" NOT NULL,
    "display_name" "text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "team_id" "uuid",
    "entry_mode" "text" DEFAULT 'direct'::"text" NOT NULL,
    "contender_status" "text" DEFAULT 'active'::"text" NOT NULL,
    "joined_at" timestamp with time zone DEFAULT "now"(),
    "accepted_at" timestamp with time zone,
    "withdrawn_at" timestamp with time zone,
    CONSTRAINT "contenders_entry_mode_check" CHECK (("entry_mode" = ANY (ARRAY['direct'::"text", 'invited'::"text", 'qualified'::"text", 'wildcard'::"text", 'auto_join'::"text"]))),
    CONSTRAINT "contenders_slot_letter" CHECK ((("slot" >= 'A'::"bpchar") AND ("slot" <= 'Z'::"bpchar"))),
    CONSTRAINT "contenders_status_check" CHECK (("contender_status" = ANY (ARRAY['pending'::"text", 'accepted'::"text", 'active'::"text", 'withdrawn'::"text", 'disqualified'::"text", 'eliminated'::"text"])))
);


ALTER TABLE "battles"."contenders" OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "battles"."rule_snapshots" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "battle_id" "uuid" NOT NULL,
    "snapshot_hash" "text" NOT NULL,
    "rules_json" "jsonb" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "created_by" "uuid"
);


ALTER TABLE "battles"."rule_snapshots" OWNER TO "postgres";


COMMENT ON TABLE "battles"."rule_snapshots" IS 'Append-only snapshot of battle rules at publication. Frozen by public.fn_publish_battle. snapshot_hash = SHA-256(rules_json::text). One row per publication event (re-publication creates a new row). Required for benchmark validity: result_sets must reference a protocol version derived from this snapshot.';



COMMENT ON COLUMN "battles"."rule_snapshots"."rules_json" IS 'Frozen JSON: {title, task_prompt, battle_type, voter_eligibility, max_contenders, rubric_id, handicap_config, published_at}. Does not include mutable fields (vote counts, winner, etc.).';



CREATE TABLE IF NOT EXISTS "battles"."vote_aggregates" (
    "battle_id" "uuid" NOT NULL,
    "contender_id" "uuid" NOT NULL,
    "raw_vote_count" integer DEFAULT 0 NOT NULL,
    "weighted_vote_sum" numeric DEFAULT 0 NOT NULL,
    "draw_count" integer DEFAULT 0 NOT NULL,
    "rank_position" integer,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "ck_battles_vote_aggregates_draw_count_nonneg" CHECK ((("draw_count" IS NULL) OR ("draw_count" >= 0))),
    CONSTRAINT "ck_battles_vote_aggregates_raw_vote_count_nonneg" CHECK ((("raw_vote_count" IS NULL) OR ("raw_vote_count" >= 0))),
    CONSTRAINT "ck_battles_vote_aggregates_weighted_vote_sum_nonneg" CHECK ((("weighted_vote_sum" IS NULL) OR ("weighted_vote_sum" >= (0)::numeric)))
);


ALTER TABLE "battles"."vote_aggregates" OWNER TO "postgres";


CREATE OR REPLACE VIEW "battles"."v_battle_full" AS
 SELECT "b"."id",
    "b"."slug",
    "b"."title",
    "b"."task_prompt",
    "b"."status",
    "b"."battle_type",
    "b"."voter_eligibility",
    "b"."handicap_config",
    "b"."max_contenders",
    "b"."rubric_id",
    "b"."total_vote_count",
    "b"."published_at",
    "b"."voting_opens_at",
    "b"."voting_closes_at",
    "b"."finalized_at",
    "b"."winner_contender_id",
    "b"."creator_lenser_id",
    "b"."created_at",
    "b"."updated_at",
    "ca"."id" AS "contender_a_id",
    "ca"."display_name" AS "contender_a_name",
    "ca"."contender_type" AS "contender_a_type",
    "ca"."contender_status" AS "contender_a_status",
    "ema"."profile_id" AS "contender_a_profile_id",
    "ema"."ai_lenser_id" AS "contender_a_ai_lenser_id",
    "sa"."id" AS "submission_a_id",
    "sa"."content_text" AS "submission_a_text",
    "sa"."content_url" AS "submission_a_url",
    "sa"."status" AS "submission_a_status",
    "va"."raw_vote_count" AS "votes_a",
    "va"."weighted_vote_sum" AS "score_a",
    "va"."draw_count" AS "draw_count_a",
    "cb"."id" AS "contender_b_id",
    "cb"."display_name" AS "contender_b_name",
    "cb"."contender_type" AS "contender_b_type",
    "cb"."contender_status" AS "contender_b_status",
    "emb"."profile_id" AS "contender_b_profile_id",
    "emb"."ai_lenser_id" AS "contender_b_ai_lenser_id",
    "sb"."id" AS "submission_b_id",
    "sb"."content_text" AS "submission_b_text",
    "sb"."content_url" AS "submission_b_url",
    "sb"."status" AS "submission_b_status",
    "vb"."raw_vote_count" AS "votes_b",
    "vb"."weighted_vote_sum" AS "score_b",
        CASE
            WHEN ("b"."winner_contender_id" = "ca"."id") THEN 'A'::"text"
            WHEN ("b"."winner_contender_id" = "cb"."id") THEN 'B'::"text"
            ELSE NULL::"text"
        END AS "winner_slot",
    "rs"."snapshot_hash" AS "rule_snapshot_hash"
   FROM ((((((((("battles"."battles" "b"
     LEFT JOIN "battles"."contenders" "ca" ON ((("ca"."battle_id" = "b"."id") AND ("ca"."slot" = 'A'::"bpchar"))))
     LEFT JOIN "battles"."contender_entity_map" "ema" ON (("ema"."contender_id" = "ca"."id")))
     LEFT JOIN "battles"."submissions" "sa" ON ((("sa"."contender_id" = "ca"."id") AND ("sa"."is_final" = true) AND ("sa"."status" = 'submitted'::"battles"."submission_status_enum"))))
     LEFT JOIN "battles"."vote_aggregates" "va" ON ((("va"."battle_id" = "b"."id") AND ("va"."contender_id" = "ca"."id"))))
     LEFT JOIN "battles"."contenders" "cb" ON ((("cb"."battle_id" = "b"."id") AND ("cb"."slot" = 'B'::"bpchar"))))
     LEFT JOIN "battles"."contender_entity_map" "emb" ON (("emb"."contender_id" = "cb"."id")))
     LEFT JOIN "battles"."submissions" "sb" ON ((("sb"."contender_id" = "cb"."id") AND ("sb"."is_final" = true) AND ("sb"."status" = 'submitted'::"battles"."submission_status_enum"))))
     LEFT JOIN "battles"."vote_aggregates" "vb" ON ((("vb"."battle_id" = "b"."id") AND ("vb"."contender_id" = "cb"."id"))))
     LEFT JOIN LATERAL ( SELECT "rule_snapshots"."snapshot_hash"
           FROM "battles"."rule_snapshots"
          WHERE ("rule_snapshots"."battle_id" = "b"."id")
          ORDER BY "rule_snapshots"."created_at" DESC
         LIMIT 1) "rs" ON (true))
  WHERE ("b"."deleted_at" IS NULL);


