CREATE OR REPLACE FUNCTION "public"."fn_get_notifications"("p_limit" integer DEFAULT 20, "p_cursor" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS TABLE("id" "uuid", "type" "text", "title" "text", "body" "text", "action_url" "text", "metadata" "jsonb", "read_at" timestamp with time zone, "created_at" timestamp with time zone, "unread_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers'
    AS $$
DECLARE
  v_lenser_id UUID := lensers.get_auth_lenser_id();
  v_unread    BIGINT;
BEGIN
  SELECT COUNT(*) INTO v_unread
  FROM   public.notifications AS _n
  WHERE  _n.lenser_id = v_lenser_id
  AND    _n.read_at IS NULL;

  RETURN QUERY
    SELECT
      n.id, n.type, n.title, n.body, n.action_url, n.metadata, n.read_at, n.created_at,
      v_unread
    FROM   public.notifications n
    WHERE  n.lenser_id = v_lenser_id
    AND    (p_cursor IS NULL OR n.created_at < p_cursor)
    ORDER  BY n.created_at DESC
    LIMIT  p_limit;
END;
$$;


ALTER FUNCTION "public"."fn_get_notifications"("p_limit" integer, "p_cursor" timestamp with time zone) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_get_pending_requests"("p_limit" integer DEFAULT 20, "p_offset" integer DEFAULT 0) RETURNS TABLE("id" "uuid", "source_profile_id" "uuid", "handle" "text", "display_name" "text", "avatar_url" "text", "requested_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'auth'
    AS $$
  SELECT
    r.id,
    r.source_profile_id,
    p.handle,
    p.display_name,
    p.avatar_url,
    r.requested_at
  FROM lensers.relationships r
  JOIN lensers.profiles p ON p.id = r.source_profile_id
  JOIN lensers.profiles me ON me.user_id = auth.uid() AND me.id = r.target_profile_id
  WHERE r.status = 'pending'
    AND p.status = 'active'
  ORDER BY r.requested_at DESC
  LIMIT LEAST(p_limit, 100)
  OFFSET GREATEST(p_offset, 0);
$$;


