COMMENT ON FUNCTION "public"."fn_get_workflow_run_media_manifest"("p_run_id" "uuid") IS 'Security wrapper: get the media_manifest jsonb array for a workflow run owned by the current user.';



CREATE OR REPLACE FUNCTION "public"."fn_get_workflow_run_state"("p_run_id" "uuid") RETURNS TABLE("run_id" "uuid", "workflow_id" "uuid", "status" "text", "active_node_id" "uuid", "pending_count" integer, "waiting_count" integer, "in_flight_count" integer, "executed_count" integer, "failed_count" integer, "is_running" boolean, "started_at" timestamp with time zone, "completed_at" timestamp with time zone, "parent_run_id" "uuid", "recursion_depth" integer, "node_results" "jsonb", "upstream_count" integer, "downstream_count" integer)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
  WITH run AS (
    SELECT *
    FROM lenses.workflow_runs r
    WHERE r.id = p_run_id
      AND EXISTS (
        SELECT 1
        FROM lenses.workflows w
        WHERE w.id = r.workflow_id
          AND (
            r.triggered_by = lensers.get_auth_lenser_id()
            OR w.visibility::text = 'public'
          )
      )
  ),
  results AS (
    SELECT
      nr.*,
      n.label    AS node_label,
      n.ordinal  AS node_ordinal
    FROM lenses.workflow_node_results nr
    LEFT JOIN lenses.workflow_nodes n ON n.id = nr.node_id
    WHERE nr.run_id = p_run_id
  ),
  agg AS (
    SELECT
      COUNT(*) FILTER (WHERE results.status = 'pending')                                                     AS pending_count,
      COUNT(*) FILTER (WHERE results.status IN ('awaiting_dependency', 'queued'))                            AS waiting_count,
      COUNT(*) FILTER (WHERE results.status IN ('running', 'streaming', 'retrying'))                         AS in_flight_count,
      COUNT(*) FILTER (WHERE results.status IN ('completed', 'skipped'))                                     AS executed_count,
      COUNT(*) FILTER (WHERE results.status IN ('failed', 'timed_out', 'blocked', 'invalidated', 'cancelled')) AS failed_count
    FROM results
  ),
  prov AS (
    SELECT
      COUNT(*) FILTER (WHERE p.target_run_id = p_run_id) AS upstream_count,
      COUNT(*) FILTER (WHERE p.source_run_id = p_run_id) AS downstream_count
    FROM lenses.workflow_run_provenance p
    WHERE p.target_run_id = p_run_id OR p.source_run_id = p_run_id
  ),
  ordered_results AS (
    SELECT jsonb_agg(
      jsonb_build_object(
        'id',              results.id,
        'node_id',         results.node_id,
        'node_label',      results.node_label,
        'node_ordinal',    results.node_ordinal,
        'status',          results.status,
        'waiting_reason',  results.waiting_reason,
        'output_data',     results.output_data,
        'error_message',   results.error_message,
        'retry_count',     results.retry_count,
        'duration_ms',     results.duration_ms,
        'ttfb_ms',         results.ttfb_ms,
        'started_at',      results.started_at,
        'completed_at',    results.completed_at
      )
      ORDER BY results.node_ordinal NULLS LAST, results.id
    ) AS data
    FROM results
  )
  SELECT
    run.id,
    run.workflow_id,
    run.status::text,
    run.active_node_id,
    COALESCE(agg.pending_count, 0)::int,
    COALESCE(agg.waiting_count, 0)::int,
    COALESCE(agg.in_flight_count, 0)::int,
    COALESCE(agg.executed_count, 0)::int,
    COALESCE(agg.failed_count, 0)::int,
    (run.status NOT IN ('completed', 'failed', 'cancelled', 'timed_out')) AS is_running,
    run.started_at,
    run.completed_at,
    run.parent_run_id,
    run.recursion_depth,
    COALESCE(ordered_results.data, '[]'::jsonb),
    COALESCE(prov.upstream_count, 0)::int,
    COALESCE(prov.downstream_count, 0)::int
  FROM run
  CROSS JOIN agg
  CROSS JOIN prov
  CROSS JOIN ordered_results;
$$;


ALTER FUNCTION "public"."fn_get_workflow_run_state"("p_run_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_workflow_run_state"("p_run_id" "uuid") IS 'N8N-style canonical run projection. One round-trip returns active node, waiting/executed counts, ordered node results, and provenance edge counts. Drives the workflow execution inspector.';



CREATE OR REPLACE FUNCTION "public"."fn_get_workflow_schedule_history"("p_schedule_id" "uuid") RETURNS TABLE("id" "uuid", "workflow_id" "uuid", "status" "text", "scheduled_for" timestamp with time zone, "started_at" timestamp with time zone, "completed_at" timestamp with time zone, "created_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses', 'lensers'
    AS $$
  SELECT
    wr.id,
    wr.workflow_id,
    wr.status,
    wr.scheduled_for,
    wr.started_at,
    wr.completed_at,
    wr.created_at
  FROM lenses.workflow_runs wr
  JOIN lenses.workflow_schedules ws ON ws.id = wr.schedule_id
  JOIN lenses.workflows w ON w.id = wr.workflow_id
  WHERE wr.schedule_id = p_schedule_id
    AND wr.scheduled_for IS NOT NULL
    AND w.lenser_id = lensers.get_auth_lenser_id()
  ORDER BY wr.scheduled_for DESC
  LIMIT 50;
$$;


ALTER FUNCTION "public"."fn_get_workflow_schedule_history"("p_schedule_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_workflow_schedule_history"("p_schedule_id" "uuid") IS 'Returns the 50 most recent scheduled workflow_runs for a given schedule, newest first.
   Accessible only to the workflow owner via lensers.get_auth_lenser_id().';



CREATE OR REPLACE FUNCTION "public"."fn_get_workflow_schedules"("p_workflow_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "workflow_id" "uuid", "workflow_title" "text", "cron_expr" "text", "timezone" "text", "global_model_id" "text", "inputs_template" "jsonb", "is_active" boolean, "assignee_type" "text", "assignee_id" "uuid", "workflow_assignment_id" "uuid", "approval_policy" "jsonb", "retry_policy" "jsonb", "failure_policy" "jsonb", "queue_policy" "jsonb", "next_run_at" timestamp with time zone, "last_run_at" timestamp with time zone, "last_run_id" "uuid", "last_dispatch_status" "text", "last_error_at" timestamp with time zone, "last_error_message" "text", "last_completed_at" timestamp with time zone, "last_result" "jsonb", "created_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses', 'lensers'
    AS $$
  SELECT
    s.id,
    s.workflow_id,
    w.title AS workflow_title,
    s.cron_expr,
    s.timezone,
    s.global_model_id,
    s.inputs_template,
    s.is_active,
    s.assignee_type,
    s.assignee_id,
    s.workflow_assignment_id,
    s.approval_policy,
    s.retry_policy,
    s.failure_policy,
    s.queue_policy,
    s.next_run_at,
    s.last_run_at,
    s.last_run_id,
    s.last_dispatch_status,
    s.last_error_at,
    s.last_error_message,
    s.last_completed_at,
    s.last_result,
    s.created_at
  FROM lenses.workflow_schedules s
  JOIN lenses.workflows w ON w.id = s.workflow_id
  WHERE w.lenser_id = lensers.get_auth_lenser_id()
    AND (p_workflow_id IS NULL OR s.workflow_id = p_workflow_id)
  ORDER BY s.created_at DESC;
$$;


ALTER FUNCTION "public"."fn_get_workflow_schedules"("p_workflow_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_get_workspace_controls"("p_ai_lenser_id" "uuid", "p_limit" integer DEFAULT 50) RETURNS TABLE("run_id" "uuid", "run_type" "text", "ai_lenser_id" "uuid", "status" "text", "approval_status" "text", "total_cost" numeric, "step_count" bigint, "memory_write_count" bigint, "latest_evaluation_score" numeric, "started_at" timestamp with time zone, "completed_at" timestamp with time zone, "duration_seconds" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lenses', 'lensers', 'auth'
    AS $$
DECLARE
  v_limit integer := LEAST(GREATEST(COALESCE(p_limit, 50), 1), 200);
BEGIN
  IF p_ai_lenser_id IS NULL THEN
    RETURN;
  END IF;

  RETURN QUERY
  SELECT
    v.run_id,
    v.run_type,
    v.ai_lenser_id,
    v.status,
    v.approval_status,
    v.total_cost,
    v.step_count,
    v.memory_write_count,
    v.latest_evaluation_score,
    v.started_at,
    v.completed_at,
    v.duration_seconds
  FROM agents.v_run_unified v
  WHERE v.ai_lenser_id = p_ai_lenser_id
  ORDER BY v.started_at DESC NULLS LAST
  LIMIT v_limit;
END;
$$;


ALTER FUNCTION "public"."fn_get_workspace_controls"("p_ai_lenser_id" "uuid", "p_limit" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_get_workspace_controls"("p_ai_lenser_id" "uuid", "p_limit" integer) IS 'Public SECURITY DEFINER wrapper around agents.v_run_unified. Returns up to p_limit (max 200, default 50) unified runs for the given AI agent. RLS enforcement is via agents.can_manage_ai_lenser inside the view. Returns empty set instead of 404/500 for unknown or inaccessible agents.';



CREATE OR REPLACE FUNCTION "public"."fn_get_workspace_settings"("p_ai_lenser_id" "uuid") RETURNS "jsonb"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lensers'
    AS $$
  SELECT to_jsonb(ws.*)
  FROM agents.workspace_settings ws
  WHERE ws.ai_lenser_id = p_ai_lenser_id
    AND (
      EXISTS (
        SELECT 1 FROM agents.ownerships o
        WHERE o.ai_lenser_id = p_ai_lenser_id
          AND o.owner_lenser_id = lensers.get_auth_human_lenser_id()
          AND o.revoked_at IS NULL
      ) OR public.is_admin()
    )
  LIMIT 1;
$$;


ALTER FUNCTION "public"."fn_get_workspace_settings"("p_ai_lenser_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_grant_standing_approval"("p_ai_lenser_id" "uuid", "p_workflow_id" "uuid" DEFAULT NULL::"uuid", "p_gate_kind" "text" DEFAULT NULL::"text", "p_hours" integer DEFAULT 24) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_caller     uuid := lensers.get_auth_lenser_id();
  v_id         uuid;
  v_expires    timestamptz;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'not_authenticated' USING ERRCODE = '42501';
  END IF;

  IF NOT agents.can_manage_ai_lenser(p_ai_lenser_id) THEN
    RAISE EXCEPTION 'not_owner_of_ai_lenser' USING ERRCODE = '42501';
  END IF;

  IF p_workflow_id IS NULL AND (p_gate_kind IS NULL OR length(trim(p_gate_kind)) = 0) THEN
    RAISE EXCEPTION 'standing approval requires workflow_id or gate_kind' USING ERRCODE = '22023';
  END IF;

  v_expires := CASE
    WHEN p_hours IS NULL OR p_hours <= 0 THEN NULL
    ELSE now() + (p_hours::text || ' hours')::interval
  END;

  INSERT INTO agents.standing_approvals (
    ai_lenser_id, workflow_id, gate_kind, expires_at, created_by
  ) VALUES (
    p_ai_lenser_id, p_workflow_id, NULLIF(trim(p_gate_kind), ''), v_expires, v_caller
  )
  RETURNING id INTO v_id;

  INSERT INTO agents.action_logs (
    ai_lenser_id, action_type, result, metadata
  ) VALUES (
    p_ai_lenser_id,
    'standing_approval_granted',
    'success',
    jsonb_build_object(
      'standing_approval_id', v_id,
      'workflow_id',          p_workflow_id,
      'gate_kind',            NULLIF(trim(p_gate_kind), ''),
      'expires_at',            v_expires,
      'granted_by',            v_caller
    )
  );

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."fn_grant_standing_approval"("p_ai_lenser_id" "uuid", "p_workflow_id" "uuid", "p_gate_kind" "text", "p_hours" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_grant_standing_approval"("p_ai_lenser_id" "uuid", "p_workflow_id" "uuid", "p_gate_kind" "text", "p_hours" integer) IS 'Phase Q2: grants a standing approval for an AI lenser. p_hours<=0 or NULL means no expiry. Returns the standing_approvals.id. Owner-only via agents.can_manage_ai_lenser; writes an action_logs entry.';



