CREATE OR REPLACE FUNCTION "public"."fn_log_model_test_run"("p_battle_id" "uuid", "p_template_id" "uuid", "p_model_provider" "text", "p_model_id" "text", "p_prompt_hash" "text", "p_passed" boolean, "p_duration_ms" integer, "p_raw_output" "jsonb" DEFAULT NULL::"jsonb", "p_violations" "jsonb" DEFAULT '[]'::"jsonb") RETURNS "battles"."model_test_runs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'extensions'
    AS $$
DECLARE
  v_uid UUID := auth.uid();
  v_row battles.model_test_runs%ROWTYPE;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'auth_required' USING ERRCODE = '42501';
  END IF;
  IF p_battle_id IS NULL AND p_template_id IS NULL THEN
    RAISE EXCEPTION 'battle_or_template_required' USING ERRCODE = '22023';
  END IF;

  -- Caller must own the anchor row.
  IF p_battle_id IS NOT NULL
     AND NOT EXISTS (
       SELECT 1 FROM battles.battles
        WHERE id = p_battle_id AND creator_lenser_id = v_uid
     ) THEN
    RAISE EXCEPTION 'battle_not_owned' USING ERRCODE = '42501';
  END IF;
  IF p_template_id IS NOT NULL
     AND NOT EXISTS (
       SELECT 1 FROM battles.templates
        WHERE id = p_template_id AND creator_lenser_id = v_uid
     ) THEN
    RAISE EXCEPTION 'template_not_owned' USING ERRCODE = '42501';
  END IF;

  INSERT INTO battles.model_test_runs (
    battle_id, template_id, model_provider, model_id,
    prompt_hash, passed, duration_ms, raw_output, violations
  ) VALUES (
    p_battle_id, p_template_id, p_model_provider, p_model_id,
    p_prompt_hash, p_passed, p_duration_ms, p_raw_output,
    COALESCE(p_violations, '[]'::jsonb)
  )
  RETURNING * INTO v_row;

  RETURN v_row;
END $$;


ALTER FUNCTION "public"."fn_log_model_test_run"("p_battle_id" "uuid", "p_template_id" "uuid", "p_model_provider" "text", "p_model_id" "text", "p_prompt_hash" "text", "p_passed" boolean, "p_duration_ms" integer, "p_raw_output" "jsonb", "p_violations" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_log_page_view"("p_target_type" "public"."page_view_target_enum", "p_target_id" "text", "p_path" "text", "p_referrer" "text", "p_user_agent" "text", "p_client_ip" "inet") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'auth', 'analytics', 'lensers'
    AS $$
DECLARE
  v_user_id   uuid;
  v_lenser_id uuid;
BEGIN
  -- 1. Validation Logic
  IF p_target_type IS NULL THEN
    RAISE EXCEPTION 'target_type is required';
  END IF;

  IF p_path IS NULL THEN
    RAISE EXCEPTION 'path is required';
  END IF;

  -- 2. Identity Resolution
  v_user_id := auth.uid();

  -- Resilience: Verify user exists in auth.users to prevent FK violations from stale JWTs
  -- If user does not exist (e.g., deleted or stale session), fallback to anonymous logging
  IF v_user_id IS NOT NULL THEN
    IF NOT EXISTS (SELECT 1 FROM auth.users WHERE id = v_user_id) THEN
      v_user_id := NULL;
    END IF;
  END IF;

  -- Resolve lenser profile if user is valid
  IF v_user_id IS NOT NULL THEN
    SELECT id
    INTO v_lenser_id
    FROM lensers.profiles
    WHERE user_id = v_user_id;
  END IF;

  -- 3. Debouncing (Avoid duplicate logs within 5 seconds for same user/path)
  IF v_user_id IS NOT NULL THEN
    IF EXISTS (
      SELECT 1
      FROM analytics.page_views
      WHERE user_id = v_user_id
        AND path = p_path
        AND created_at > NOW() - INTERVAL '5 seconds'
    ) THEN
      RETURN;
    END IF;
  END IF;

  -- 4. Audit Log Execution
  INSERT INTO analytics.page_views (
    lenser_id,
    user_id,
    target_type,
    target_id,
    path,
    referrer,
    user_agent,
    client_ip
  )
  VALUES (
    v_lenser_id,
    v_user_id,
    p_target_type,
    p_target_id,
    p_path,
    p_referrer,
    p_user_agent,
    p_client_ip
  );
END;
$$;


ALTER FUNCTION "public"."fn_log_page_view"("p_target_type" "public"."page_view_target_enum", "p_target_id" "text", "p_path" "text", "p_referrer" "text", "p_user_agent" "text", "p_client_ip" "inet") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_mark_notifications_read"("p_notification_ids" "uuid"[]) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers'
    AS $$
DECLARE
  v_updated INT;
BEGIN
  UPDATE public.notifications
  SET    read_at = now()
  WHERE  id = ANY(p_notification_ids)
  AND    lenser_id = lensers.get_auth_lenser_id()
  AND    read_at IS NULL;

  GET DIAGNOSTICS v_updated = ROW_COUNT;
  RETURN v_updated;
END;
$$;


ALTER FUNCTION "public"."fn_mark_notifications_read"("p_notification_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_mark_tutorial_complete"("p_tutorial_slug" "text", "p_kind" "text" DEFAULT 'tutorial'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'xp', 'public', 'extensions'
    AS $$
DECLARE
  v_lenser_id UUID;
  v_row_id    UUID;
  v_inserted  BOOLEAN := false;
BEGIN
  IF p_kind NOT IN ('tutorial', 'walkthrough') THEN
    RAISE EXCEPTION 'invalid_kind'
      USING ERRCODE = '22023',
            DETAIL  = 'kind must be ''tutorial'' or ''walkthrough''',
            HINT    = 'invalid_kind';
  END IF;

  v_lenser_id := lensers.get_auth_lenser_id();
  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'permission_denied'
      USING ERRCODE = '42501',
            DETAIL  = 'Must be authenticated.',
            HINT    = 'permission_denied';
  END IF;

  INSERT INTO lenses.tutorial_completions (lenser_id, tutorial_slug, kind)
  VALUES (v_lenser_id, p_tutorial_slug, p_kind)
  ON CONFLICT (lenser_id, tutorial_slug, kind) DO NOTHING
  RETURNING id INTO v_row_id;

  v_inserted := v_row_id IS NOT NULL;

  RETURN jsonb_build_object(
    'inserted',       v_inserted,
    'tutorial_slug',  p_tutorial_slug,
    'kind',           p_kind
  );
END;
$$;


ALTER FUNCTION "public"."fn_mark_tutorial_complete"("p_tutorial_slug" "text", "p_kind" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_mark_tutorial_complete"("p_tutorial_slug" "text", "p_kind" "text") IS 'CB-P1b: Marks a tutorial or walkthrough as complete for the calling lenser. Idempotent. Fires XP award trigger on first completion. SECURITY DEFINER.';



CREATE OR REPLACE FUNCTION "public"."fn_media_bind_attachment"("p_object_id" "uuid", "p_entity_type" "text", "p_entity_id" "uuid", "p_binding_key" "text" DEFAULT '_default'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'media', 'lensers', 'public'
    AS $$
DECLARE
    v_owner uuid;
    v_attachment_id uuid;
BEGIN
    SELECT owner_lenser_id INTO v_owner
    FROM media.objects WHERE id = p_object_id;

    IF v_owner IS NULL THEN
        RAISE EXCEPTION 'Media object not found: %', p_object_id;
    END IF;

    IF v_owner <> lensers.get_auth_lenser_id() THEN
        RAISE EXCEPTION 'Permission denied: not object owner';
    END IF;

    INSERT INTO media.attachments (object_id, entity_type, entity_id, binding_key, attached_by)
    VALUES (p_object_id, p_entity_type, p_entity_id, p_binding_key, lensers.get_auth_lenser_id())
    ON CONFLICT (entity_type, entity_id, binding_key)
    DO UPDATE SET object_id = EXCLUDED.object_id, attached_by = EXCLUDED.attached_by, attached_at = now()
    RETURNING id INTO v_attachment_id;

    RETURN v_attachment_id;
END;
$$;


ALTER FUNCTION "public"."fn_media_bind_attachment"("p_object_id" "uuid", "p_entity_type" "text", "p_entity_id" "uuid", "p_binding_key" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_media_bind_attachment"("p_object_id" "uuid", "p_entity_type" "text", "p_entity_id" "uuid", "p_binding_key" "text") IS 'Binds a media object to a business entity via a named slot. Upserts: if the (entity_type, entity_id, binding_key) already exists, replaces the bound object.';



CREATE OR REPLACE FUNCTION "public"."fn_media_finalize_upload"("p_object_id" "uuid", "p_bucket" "text", "p_object_key" "text", "p_byte_size" bigint DEFAULT NULL::bigint, "p_checksum" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'media', 'lensers', 'public'
    AS $$
DECLARE
    v_owner uuid;
BEGIN
    SELECT owner_lenser_id INTO v_owner
    FROM media.objects WHERE id = p_object_id;

    IF v_owner IS NULL THEN
        RAISE EXCEPTION 'Media object not found: %', p_object_id;
    END IF;

    IF v_owner <> lensers.get_auth_lenser_id() THEN
        RAISE EXCEPTION 'Permission denied: not object owner';
    END IF;

    UPDATE media.objects
    SET bucket = p_bucket,
        object_key = p_object_key,
        byte_size = COALESCE(p_byte_size, byte_size),
        checksum_sha256 = COALESCE(p_checksum, checksum_sha256),
        lifecycle_state = 'active',
        updated_at = now()
    WHERE id = p_object_id;
END;
$$;


ALTER FUNCTION "public"."fn_media_finalize_upload"("p_object_id" "uuid", "p_bucket" "text", "p_object_key" "text", "p_byte_size" bigint, "p_checksum" "text") OWNER TO "postgres";


