    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "ck_agents_memories_content_len" CHECK ((("content" IS NULL) OR ("length"("content") <= 20000))),
    CONSTRAINT "memories_confidence_check" CHECK ((("confidence" >= (0)::numeric) AND ("confidence" <= (1)::numeric))),
    CONSTRAINT "memories_scope_check" CHECK (("scope" = ANY (ARRAY['project'::"text", 'conversation'::"text", 'global'::"text"]))),
    CONSTRAINT "memories_source_check" CHECK (("source" = ANY (ARRAY['user'::"text", 'agent'::"text", 'tool'::"text", 'eval'::"text", 'manual'::"text"])))
);


ALTER TABLE "agents"."memories" OWNER TO "postgres";


COMMENT ON TABLE "agents"."memories" IS 'Per-agent memory entries. Profile carries config; entries carry content. Writes are gated to successful runs; reads are logged.';



CREATE OR REPLACE FUNCTION "public"."fn_read_memory_entries"("p_profile_id" "uuid", "p_scope" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 10, "p_team_run_id" "uuid" DEFAULT NULL::"uuid") RETURNS SETOF "agents"."memories"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_profile agents.memory_profiles;
  v_row     agents.memories;
BEGIN
  SELECT * INTO v_profile FROM agents.memory_profiles WHERE id = p_profile_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'memory profile not found' USING ERRCODE = 'P0002';
  END IF;
  IF NOT agents.can_manage_ai_lenser(v_profile.ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  FOR v_row IN
    SELECT *
    FROM agents.memories
    WHERE profile_id = p_profile_id
      AND is_redacted = false
      AND (p_scope IS NULL OR scope = p_scope)
      AND (expires_at IS NULL OR expires_at > now())
    ORDER BY confidence DESC, created_at DESC
    LIMIT GREATEST(COALESCE(p_limit, 10), 1)
  LOOP
    INSERT INTO agents.memory_access_logs (memory_id, team_run_id, action, context)
    VALUES (v_row.id, p_team_run_id, 'read',
            jsonb_build_object('scope', p_scope, 'profile_id', p_profile_id));
    RETURN NEXT v_row;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."fn_read_memory_entries"("p_profile_id" "uuid", "p_scope" "text", "p_limit" integer, "p_team_run_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_record_run_incident"("p_run_report_id" "uuid", "p_incident_type" "text", "p_severity" "text", "p_title" "text", "p_description" "text", "p_context" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_report    agents.run_reports;
  v_id        uuid;
BEGIN
  SELECT * INTO v_report
    FROM agents.run_reports
   WHERE id = p_run_report_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'run report not found' USING ERRCODE = 'P0002';
  END IF;

  IF NOT agents.can_manage_ai_lenser(v_report.ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  IF p_incident_type NOT IN (
    'tool_failure','budget_exceeded','policy_violation','timeout',
    'step_failure','approval_rejected','kill_switch'
  ) THEN
    RAISE EXCEPTION 'invalid incident_type: %', p_incident_type USING ERRCODE = '22023';
  END IF;

  IF p_severity NOT IN ('low','medium','high','critical') THEN
    RAISE EXCEPTION 'invalid severity: %', p_severity USING ERRCODE = '22023';
  END IF;

  INSERT INTO agents.run_incidents (
    run_report_id,
    ai_lenser_id,
    incident_type,
    severity,
    title,
    description,
    context
  ) VALUES (
    p_run_report_id,
    v_report.ai_lenser_id,
    p_incident_type,
    p_severity,
    p_title,
    p_description,
    COALESCE(p_context, '{}'::jsonb)
  )
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."fn_record_run_incident"("p_run_report_id" "uuid", "p_incident_type" "text", "p_severity" "text", "p_title" "text", "p_description" "text", "p_context" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_record_run_provenance"("p_source_run_id" "uuid", "p_source_node_id" "uuid", "p_source_output_path" "text", "p_target_run_id" "uuid", "p_target_node_id" "uuid", "p_target_input_path" "text", "p_transform" "jsonb" DEFAULT NULL::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_caller_id uuid;
  v_id        uuid;
BEGIN
  v_caller_id := lensers.get_auth_lenser_id();

  IF NOT EXISTS (
    SELECT 1
    FROM lenses.workflow_runs r
    JOIN lenses.workflows w ON w.id = r.workflow_id
    WHERE r.id = p_target_run_id
      AND (w.lenser_id = v_caller_id OR w.visibility = 'public')
  ) THEN
    RAISE EXCEPTION 'Unauthorized: caller cannot record provenance for run %', p_target_run_id
      USING ERRCODE = '42501';
  END IF;

  INSERT INTO lenses.workflow_run_provenance (
    source_run_id, source_node_id, source_output_path,
    target_run_id, target_node_id, target_input_path,
    transform
  )
  VALUES (
    p_source_run_id, p_source_node_id, p_source_output_path,
    p_target_run_id, p_target_node_id, p_target_input_path,
    p_transform
  )
  ON CONFLICT (source_run_id, source_node_id, source_output_path,
               target_run_id, target_node_id, target_input_path)
  DO UPDATE SET transform = COALESCE(EXCLUDED.transform, workflow_run_provenance.transform)
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."fn_record_run_provenance"("p_source_run_id" "uuid", "p_source_node_id" "uuid", "p_source_output_path" "text", "p_target_run_id" "uuid", "p_target_node_id" "uuid", "p_target_input_path" "text", "p_transform" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_record_run_provenance"("p_source_run_id" "uuid", "p_source_node_id" "uuid", "p_source_output_path" "text", "p_target_run_id" "uuid", "p_target_node_id" "uuid", "p_target_input_path" "text", "p_transform" "jsonb") IS 'Records a field-level data handoff. Idempotent on the (source, target, path) tuple. Transform JSON may carry mapping expression captured at edge-binding time.';



CREATE OR REPLACE FUNCTION "public"."fn_record_scoring_plugin_signal"("p_battle_id" "uuid", "p_plugin_id" "text", "p_signals" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles'
    AS $$
BEGIN
  IF p_battle_id IS NULL THEN
    RAISE EXCEPTION 'battle_id required' USING ERRCODE = '22023';
  END IF;
  IF p_plugin_id IS NULL OR length(trim(p_plugin_id)) = 0 THEN
    RAISE EXCEPTION 'plugin_id required' USING ERRCODE = '22023';
  END IF;

  INSERT INTO battles.scoring_plugin_signals (battle_id, plugin_id, signals, recorded_at)
  VALUES (p_battle_id, p_plugin_id, COALESCE(p_signals, '{}'::jsonb), now())
  ON CONFLICT (battle_id, plugin_id) DO UPDATE
    SET signals     = EXCLUDED.signals,
        recorded_at = EXCLUDED.recorded_at;
END;
$$;


ALTER FUNCTION "public"."fn_record_scoring_plugin_signal"("p_battle_id" "uuid", "p_plugin_id" "text", "p_signals" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_record_scoring_plugin_signal"("p_battle_id" "uuid", "p_plugin_id" "text", "p_signals" "jsonb") IS 'Phase R2: upserts a (battle_id, plugin_id) row in battles.scoring_plugin_signals. Service-role only — plugins run server side under service_role. battles.fn_battles_finalize is intentionally left untouched in this migration.';



CREATE OR REPLACE FUNCTION "public"."fn_record_signed_attestation"("p_run_id" "uuid", "p_envelope_kid" "uuid", "p_envelope_iat" timestamp with time zone, "p_envelope_nonce" "text", "p_canonical_jcs_b64url" "text", "p_signature_b64url" "text", "p_workflow_hash" "text" DEFAULT NULL::"text", "p_lens_hash" "text" DEFAULT NULL::"text", "p_agent_config_hash" "text" DEFAULT NULL::"text", "p_runner_version" "text" DEFAULT NULL::"text", "p_cli_version" "text" DEFAULT NULL::"text", "p_policy_passed" boolean DEFAULT false) RETURNS "uuid"
    LANGUAGE "sql" SECURITY DEFINER
