    p_run_id, p_envelope_kid, p_envelope_iat, p_envelope_nonce,
    p_canonical_jcs_b64url, p_signature_b64url,
    p_workflow_hash, p_lens_hash, p_agent_config_hash,
    p_runner_version, p_cli_version, p_policy_passed
  );
$$;


ALTER FUNCTION "public"."fn_record_signed_attestation"("p_run_id" "uuid", "p_envelope_kid" "uuid", "p_envelope_iat" timestamp with time zone, "p_envelope_nonce" "text", "p_canonical_jcs_b64url" "text", "p_signature_b64url" "text", "p_workflow_hash" "text", "p_lens_hash" "text", "p_agent_config_hash" "text", "p_runner_version" "text", "p_cli_version" "text", "p_policy_passed" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_redact_memory_entry"("p_memory_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_mem agents.memories;
BEGIN
  SELECT * INTO v_mem FROM agents.memories WHERE id = p_memory_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'memory not found' USING ERRCODE = 'P0002';
  END IF;
  IF NOT agents.can_manage_ai_lenser(v_mem.ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  UPDATE agents.memories
     SET content = '[redacted]',
         is_redacted = true
   WHERE id = p_memory_id;

  INSERT INTO agents.memory_access_logs (memory_id, action, context)
  VALUES (p_memory_id, 'redact', jsonb_build_object('reason', COALESCE(p_reason, '')));
END;
$$;


ALTER FUNCTION "public"."fn_redact_memory_entry"("p_memory_id" "uuid", "p_reason" "text") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "agents"."tools_registry" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "owner_lenser_id" "uuid" NOT NULL,
    "key" "text" NOT NULL,
    "name" "text" NOT NULL,
    "description" "text",
    "category" "text" DEFAULT 'general'::"text" NOT NULL,
    "schema_input" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "schema_output" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "auth_method" "text" DEFAULT 'none'::"text" NOT NULL,
    "requires_approval" boolean DEFAULT false NOT NULL,
    "is_dangerous" boolean DEFAULT false NOT NULL,
    "status" "text" DEFAULT 'active'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "egress_class" "text" DEFAULT 'none'::"text" NOT NULL,
    CONSTRAINT "tools_registry_auth_method_check" CHECK (("auth_method" = ANY (ARRAY['none'::"text", 'api_key'::"text", 'oauth'::"text", 'service_account'::"text"]))),
    CONSTRAINT "tools_registry_egress_class_check" CHECK (("egress_class" = ANY (ARRAY['none'::"text", 'read_only'::"text", 'write'::"text"]))),
    CONSTRAINT "tools_registry_status_check" CHECK (("status" = ANY (ARRAY['active'::"text", 'disabled'::"text", 'deprecated'::"text"])))
);


ALTER TABLE "agents"."tools_registry" OWNER TO "postgres";


COMMENT ON TABLE "agents"."tools_registry" IS 'Per-owner registry of tool definitions. Tool assignments bind a registered tool to an agent.';



COMMENT ON COLUMN "agents"."tools_registry"."egress_class" IS 'Sandbox classification: none (compute-only), read_only (outbound reads), write (mutations). write auto-forces requires_approval.';



CREATE OR REPLACE FUNCTION "public"."fn_register_tool"("p_key" "text", "p_name" "text", "p_description" "text" DEFAULT NULL::"text", "p_category" "text" DEFAULT 'general'::"text", "p_schema_input" "jsonb" DEFAULT '{}'::"jsonb", "p_schema_output" "jsonb" DEFAULT '{}'::"jsonb", "p_auth_method" "text" DEFAULT 'none'::"text", "p_requires_approval" boolean DEFAULT false, "p_is_dangerous" boolean DEFAULT false) RETURNS "agents"."tools_registry"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lensers'
    AS $$
DECLARE
  v_owner uuid := lensers.get_auth_human_lenser_id();
  v_row   agents.tools_registry;
BEGIN
  IF v_owner IS NULL THEN
    RAISE EXCEPTION 'authentication required or no human lenser profile found'
      USING ERRCODE = '42501';
  END IF;

  INSERT INTO agents.tools_registry (
    owner_lenser_id, key, name, description, category,
    schema_input, schema_output, auth_method, requires_approval, is_dangerous
  )
  VALUES (
    v_owner, p_key, p_name, p_description, COALESCE(p_category, 'general'),
    COALESCE(p_schema_input,      '{}'::jsonb),
    COALESCE(p_schema_output,     '{}'::jsonb),
    COALESCE(p_auth_method,       'none'),
    COALESCE(p_requires_approval, false),
    COALESCE(p_is_dangerous,      false)
  )
  ON CONFLICT (owner_lenser_id, key)
  DO UPDATE SET
    name              = EXCLUDED.name,
    description       = EXCLUDED.description,
    category          = EXCLUDED.category,
    schema_input      = EXCLUDED.schema_input,
    schema_output     = EXCLUDED.schema_output,
    auth_method       = EXCLUDED.auth_method,
    requires_approval = EXCLUDED.requires_approval,
    is_dangerous      = EXCLUDED.is_dangerous,
    updated_at        = now()
  RETURNING * INTO v_row;

  RETURN v_row;
END;
$$;


ALTER FUNCTION "public"."fn_register_tool"("p_key" "text", "p_name" "text", "p_description" "text", "p_category" "text", "p_schema_input" "jsonb", "p_schema_output" "jsonb", "p_auth_method" "text", "p_requires_approval" boolean, "p_is_dangerous" boolean) OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "battles"."tournament_contenders" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "tournament_id" "uuid" NOT NULL,
    "lenser_id" "uuid" NOT NULL,
    "seed" integer,
    "status" "text" DEFAULT 'registered'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "tournament_contenders_status_check" CHECK (("status" = ANY (ARRAY['registered'::"text", 'active'::"text", 'eliminated'::"text", 'winner'::"text"])))
);


ALTER TABLE "battles"."tournament_contenders" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_register_tournament_contender"("p_tournament_id" "uuid", "p_lenser_id" "uuid" DEFAULT NULL::"uuid") RETURNS "battles"."tournament_contenders"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'public'
    AS $$
DECLARE
  v_lenser_id UUID;
  v_row       battles.tournament_contenders;
  v_count     INT;
  v_max       INT;
BEGIN
  v_lenser_id := COALESCE(p_lenser_id, auth.uid());

  SELECT max_contenders INTO v_max FROM battles.tournaments WHERE id = p_tournament_id;
  SELECT COUNT(*) INTO v_count FROM battles.tournament_contenders WHERE tournament_id = p_tournament_id;

  IF v_count >= v_max THEN
    RAISE EXCEPTION 'Tournament is full (% max contenders)', v_max;
  END IF;

  INSERT INTO battles.tournament_contenders (tournament_id, lenser_id)
  VALUES (p_tournament_id, v_lenser_id)
  RETURNING * INTO v_row;

  RETURN v_row;
END;
$$;


ALTER FUNCTION "public"."fn_register_tournament_contender"("p_tournament_id" "uuid", "p_lenser_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_reject_follow_request"("p_source_profile_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'auth'
    AS $$
DECLARE
  v_target_id uuid;
BEGIN
  SELECT id INTO v_target_id
  FROM lensers.profiles WHERE user_id = auth.uid();

  IF v_target_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  UPDATE lensers.relationships
  SET status = 'rejected',
      responded_at = now()
  WHERE source_profile_id = p_source_profile_id
    AND target_profile_id = v_target_id
    AND status = 'pending';

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'reason', 'no_pending_request');
  END IF;

  RETURN jsonb_build_object('success', true);
END;
$$;


ALTER FUNCTION "public"."fn_reject_follow_request"("p_source_profile_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_reject_tool_invocation"("p_invocation_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_inv agents.tool_invocations;
BEGIN
  SELECT * INTO v_inv FROM agents.tool_invocations WHERE id = p_invocation_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'invocation not found' USING ERRCODE = 'P0002';
  END IF;
  IF NOT agents.can_manage_ai_lenser(v_inv.ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;
  IF v_inv.approval_status <> 'pending' THEN
    RAISE EXCEPTION 'invocation is not pending approval' USING ERRCODE = '22023';
  END IF;

  UPDATE agents.tool_invocations
     SET approval_status     = 'rejected',
         approval_decided_by = auth.uid(),
         approval_reason     = p_reason,
         status              = 'rejected',
         completed_at        = now()
   WHERE id = p_invocation_id;
END;
$$;


ALTER FUNCTION "public"."fn_reject_tool_invocation"("p_invocation_id" "uuid", "p_reason" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_remap_thread_tags"("p_thread_id" "uuid", "p_tag_ids" "uuid"[]) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'content', 'lensers'
    AS $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM content.threads
    WHERE id = p_thread_id AND lenser_id = lensers.get_auth_lenser_id()
  ) THEN
    RETURN;
  END IF;

  DELETE FROM content.tag_map
  WHERE entity_type::text = 'thread' AND entity_id = p_thread_id;

  IF p_tag_ids IS NOT NULL AND array_length(p_tag_ids, 1) > 0 THEN
    INSERT INTO content.tag_map (entity_type, entity_id, tag_id)
    SELECT 'thread', p_thread_id, unnest(p_tag_ids)
    ON CONFLICT DO NOTHING;
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_remap_thread_tags"("p_thread_id" "uuid", "p_tag_ids" "uuid"[]) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_remap_thread_tags"("p_thread_id" "uuid", "p_tag_ids" "uuid"[]) IS 'Security wrapper: atomically replace all tag mappings for a thread owned by the current user.';



CREATE OR REPLACE FUNCTION "public"."fn_remove_battle_contender"("p_contender_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
  v_lenser_id uuid := lensers.get_auth_lenser_id();
BEGIN
  DELETE FROM battles.contenders c
  USING battles.battles b
  WHERE c.id = p_contender_id
    AND c.battle_id = b.id
    AND b.creator_lenser_id = v_lenser_id;
END;
$$;


ALTER FUNCTION "public"."fn_remove_battle_contender"("p_contender_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_remove_follow"("p_target_profile_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'auth'
    AS $$
DECLARE
  v_source_id uuid;
BEGIN
  SELECT id INTO v_source_id
  FROM lensers.profiles WHERE user_id = auth.uid();

  IF v_source_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  UPDATE lensers.relationships
  SET status = 'removed',
      removed_at = now()
  WHERE source_profile_id = v_source_id
    AND target_profile_id = p_target_profile_id
    AND status IN ('accepted', 'pending');

  RETURN jsonb_build_object('following', false);
END;
$$;


ALTER FUNCTION "public"."fn_remove_follow"("p_target_profile_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_reorder_workflow_phases"("p_workflow_id" "uuid", "p_ordered_ids" "uuid"[]) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses', 'lensers'
    AS $$
DECLARE
  v_id   uuid;
  v_idx  integer := 0;
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM lenses.workflows w
    WHERE w.id = p_workflow_id AND w.lenser_id = lensers.get_auth_lenser_id()
  ) THEN
    RAISE EXCEPTION 'reorder_phases_forbidden' USING ERRCODE = '42501';
  END IF;

  FOREACH v_id IN ARRAY p_ordered_ids LOOP
    UPDATE lenses.workflow_phases SET ordinal = v_idx WHERE id = v_id AND workflow_id = p_workflow_id;
    v_idx := v_idx + 1;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."fn_reorder_workflow_phases"("p_workflow_id" "uuid", "p_ordered_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_reorder_workflow_tasks"("p_phase_id" "uuid", "p_ordered_ids" "uuid"[]) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses', 'lensers'
    AS $$
DECLARE
  v_id   uuid;
  v_idx  integer := 0;
BEGIN
  -- Verify ownership via phase → workflow
  IF NOT EXISTS (
    SELECT 1 FROM lenses.workflow_phases wp
    JOIN lenses.workflows w ON w.id = wp.workflow_id
    WHERE wp.id = p_phase_id AND w.lenser_id = lensers.get_auth_lenser_id()
  ) THEN
    RAISE EXCEPTION 'reorder_tasks_forbidden' USING ERRCODE = '42501';
  END IF;

  FOREACH v_id IN ARRAY p_ordered_ids LOOP
    UPDATE lenses.workflow_tasks SET ordinal = v_idx WHERE id = v_id AND phase_id = p_phase_id;
    v_idx := v_idx + 1;
  END LOOP;
END;
$$;


ALTER FUNCTION "public"."fn_reorder_workflow_tasks"("p_phase_id" "uuid", "p_ordered_ids" "uuid"[]) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_request_follow"("p_target_profile_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'auth'
    AS $$
DECLARE
  v_source_id     uuid;
  v_target        RECORD;
  v_existing      lensers.relationship_status;
  v_new_status    lensers.relationship_status;
BEGIN
  SELECT id INTO v_source_id
  FROM lensers.profiles WHERE user_id = auth.uid();

  IF v_source_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required or profile not found';
  END IF;

  IF v_source_id = p_target_profile_id THEN
    RAISE EXCEPTION 'Cannot follow yourself';
  END IF;

  -- Check target exists and is active
  SELECT p.id, p.status, p.visibility INTO v_target
  FROM lensers.profiles p WHERE p.id = p_target_profile_id;

  IF NOT FOUND OR v_target.status NOT IN ('active') THEN
    RETURN jsonb_build_object('status', 'rejected', 'reason', 'target_unavailable');
  END IF;

  -- Check if blocked in either direction
  IF EXISTS (
    SELECT 1 FROM lensers.relationships
    WHERE status = 'blocked'
      AND (
        (source_profile_id = v_source_id AND target_profile_id = p_target_profile_id)
        OR (source_profile_id = p_target_profile_id AND target_profile_id = v_source_id)
      )
  ) THEN
    RETURN jsonb_build_object('status', 'rejected', 'reason', 'blocked');
  END IF;

  -- Check existing relationship
  SELECT r.status INTO v_existing
  FROM lensers.relationships r
  WHERE r.source_profile_id = v_source_id AND r.target_profile_id = p_target_profile_id;

  IF v_existing = 'accepted' THEN
    RETURN jsonb_build_object('status', 'accepted', 'reason', 'already_following');
  END IF;

  IF v_existing = 'pending' THEN
    RETURN jsonb_build_object('status', 'pending', 'reason', 'already_pending');
  END IF;

  -- Determine status based on target visibility
  IF v_target.visibility IN ('public', 'community') THEN
    v_new_status := 'accepted';
  ELSE
    v_new_status := 'pending';
  END IF;

  INSERT INTO lensers.relationships (source_profile_id, target_profile_id, status, accepted_at)
  VALUES (
    v_source_id,
    p_target_profile_id,
    v_new_status,
    CASE WHEN v_new_status = 'accepted' THEN now() ELSE null END
  )
  ON CONFLICT (source_profile_id, target_profile_id)
  DO UPDATE SET
    status       = v_new_status,
    requested_at = now(),
    responded_at = null,
    accepted_at  = CASE WHEN v_new_status = 'accepted' THEN now() ELSE null END,
    removed_at   = null;

  RETURN jsonb_build_object('status', v_new_status::text);
END;
$$;


ALTER FUNCTION "public"."fn_request_follow"("p_target_profile_id" "uuid") OWNER TO "postgres";


