CREATE OR REPLACE FUNCTION "public"."fn_resolve_vote_anomaly"("p_anomaly_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
DECLARE
  v_actor UUID;
BEGIN
  v_actor := auth.uid();
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'Authentication required' USING ERRCODE = 'P0001';
  END IF;

  IF NOT public.fn_is_super_admin() THEN
    RAISE EXCEPTION 'Forbidden: super_admin required' USING ERRCODE = 'P0003';
  END IF;

  UPDATE audit.vote_anomalies
     SET resolved_at  = now(),
         resolved_by  = v_actor
   WHERE id = p_anomaly_id
     AND resolved_at IS NULL;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Anomaly not found or already resolved' USING ERRCODE = 'P0002';
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_resolve_vote_anomaly"("p_anomaly_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_resolve_vote_anomaly"("p_anomaly_id" "uuid") IS 'CA: Marks an anomaly resolved. Requires super_admin.';



