CREATE OR REPLACE FUNCTION "public"."fn_search_lensers"("p_query" "text", "p_limit" integer DEFAULT 8) RETURNS TABLE("id" "uuid", "handle" "text", "display_name" "text", "avatar_url" "text", "type" "lensers"."lenser_type")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'lensers', 'public'
    AS $$
  SELECT
    p.id,
    p.handle,
    p.display_name,
    p.avatar_url,
    p.type
  FROM lensers.profiles p
  WHERE
    p.status                = 'active'
    AND p.deletion_requested_at IS NULL
    AND (
      p.visibility::text = 'public'
      OR (p.visibility::text = 'community' AND lensers.get_auth_lenser_id() IS NOT NULL)
      OR p.id = lensers.get_auth_lenser_id()
    )
    AND (
      CASE
        WHEN left(p_query, 1) = '@' THEN
          p.handle ILIKE '%' || substring(p_query FROM 2) || '%'
        ELSE
          p.handle       ILIKE '%' || p_query || '%'
          OR p.display_name ILIKE '%' || p_query || '%'
      END
    )
  ORDER BY
    CASE
      WHEN left(p_query, 1) = '@' THEN
        CASE
          WHEN p.handle = lower(substring(p_query FROM 2))              THEN 0
          WHEN p.handle ILIKE lower(substring(p_query FROM 2)) || '%'   THEN 1
          ELSE 2
        END
      ELSE
        CASE
          WHEN p.handle = lower(p_query)     THEN 0
          WHEN p.handle ILIKE p_query || '%' THEN 1
          ELSE 2
        END
    END,
    p.handle
  LIMIT LEAST(COALESCE(p_limit, 8), 20);
$$;


ALTER FUNCTION "public"."fn_search_lensers"("p_query" "text", "p_limit" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_search_lensers"("p_query" "text", "p_limit" integer) IS 'Search lensers by handle or display_name for battle invite / contender picker. Returns lenser type (human|ai) for wizard UI. Respects profile visibility: public=all, community=authenticated, private=self only. Prefix @ to restrict to handle-only search. LIMIT capped at 20. SECURITY DEFINER.';



CREATE OR REPLACE FUNCTION "public"."fn_search_memory_entries"("p_query" "text", "p_profile_id" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 20) RETURNS TABLE("id" "uuid", "profile_id" "uuid", "ai_lenser_id" "uuid", "scope" "text", "source" "text", "content" "text", "confidence" numeric, "is_redacted" boolean, "created_at" timestamp with time zone, "rank" real)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'agents', 'public'
    AS $$
DECLARE
  v_limit integer := LEAST(GREATEST(COALESCE(p_limit, 20), 1), 50);
  v_query tsquery;
BEGIN
  IF p_query IS NULL OR length(trim(p_query)) = 0 THEN
    RETURN;
  END IF;

  v_query := plainto_tsquery('english', p_query);

  IF v_query::text = '' THEN
    -- The query string contained only stopwords; nothing to search for.
    RETURN;
  END IF;

  RETURN QUERY
    SELECT
      m.id,
      m.profile_id,
      m.ai_lenser_id,
      m.scope,
      m.source,
      m.content,
      m.confidence,
      m.is_redacted,
      m.created_at,
      ts_rank(to_tsvector('english', m.content), v_query) AS rank
    FROM agents.memories m
    WHERE
      (p_profile_id IS NULL OR m.profile_id = p_profile_id)
      AND m.is_redacted = false
      AND to_tsvector('english', m.content) @@ v_query
    ORDER BY rank DESC, m.created_at DESC
    LIMIT v_limit;
END;
$$;


ALTER FUNCTION "public"."fn_search_memory_entries"("p_query" "text", "p_profile_id" "uuid", "p_limit" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_search_memory_entries"("p_query" "text", "p_profile_id" "uuid", "p_limit" integer) IS 'Phase N1: Full-text search over agents.memories.content using a plain english tsquery. Honors RLS via SECURITY INVOKER. Returns up to 50 rows ranked by ts_rank.';



CREATE OR REPLACE FUNCTION "public"."fn_security_definer_no_search_path"() RETURNS TABLE("schema_name" "text", "function_name" "text", "full_signature" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
  SELECT
    n.nspname::text                          AS schema_name,
    p.proname::text                          AS function_name,
    pg_catalog.pg_get_function_identity_arguments(p.oid)::text AS full_signature
  FROM pg_catalog.pg_proc p
  JOIN pg_catalog.pg_namespace n ON n.oid = p.pronamespace
  WHERE p.prosecdef = true                          -- SECURITY DEFINER
    AND n.nspname IN ('public', 'agents', 'lenses',
                      'battles', 'audit', 'execution')
    AND NOT EXISTS (
      SELECT 1 FROM pg_catalog.pg_options_to_table(p.proconfig) AS opt(option_name, option_value)
      WHERE opt.option_name = 'search_path'
    )
  ORDER BY n.nspname, p.proname;
$$;


ALTER FUNCTION "public"."fn_security_definer_no_search_path"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_security_definer_no_search_path"() IS 'BY: Returns SECURITY DEFINER functions that have no SET search_path configured. Used by lf security rls-audit CLI command. SECURITY DEFINER; service_role only.';



CREATE OR REPLACE FUNCTION "public"."fn_set_evaluation_baseline"("p_evaluation_id" "uuid", "p_run_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_score  numeric;
  v_result jsonb;
BEGIN
  SELECT score INTO v_score FROM agents.evaluation_runs WHERE id = p_run_id;

  INSERT INTO agents.evaluation_baselines (evaluation_id, run_id, score)
  VALUES (p_evaluation_id, p_run_id, v_score)
  ON CONFLICT (evaluation_id)
  DO UPDATE SET run_id = EXCLUDED.run_id, score = EXCLUDED.score
  RETURNING to_jsonb(agents.evaluation_baselines.*) INTO v_result;

  RETURN v_result;
END;
$$;


