CREATE OR REPLACE FUNCTION "public"."fn_update_agent_profile"("p_ai_lenser_id" "uuid", "p_patch" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lensers', 'agents', 'auth'
    AS $$
DECLARE
  v_profile_id uuid;
BEGIN
  IF NOT EXISTS (
    SELECT 1
    FROM   agents.ownerships o
    WHERE  o.ai_lenser_id   = p_ai_lenser_id
      AND  o.owner_lenser_id = lensers.get_auth_human_lenser_id()
      AND  o.role            = 'owner'
      AND  o.revoked_at IS NULL
  ) THEN
    RAISE EXCEPTION 'Forbidden: you do not own this AI lenser'
      USING ERRCODE = '42501';
  END IF;

  SELECT al.profile_id INTO v_profile_id
  FROM   agents.ai_lensers al
  WHERE  al.id = p_ai_lenser_id;

  IF v_profile_id IS NULL THEN
    RAISE EXCEPTION 'AI lenser not found'
      USING ERRCODE = 'P0002';
  END IF;

  UPDATE lensers.profiles
  SET
    display_name = CASE WHEN p_patch ? 'display_name' THEN p_patch->>'display_name' ELSE display_name END,
    avatar_url   = CASE WHEN p_patch ? 'avatar_url'   THEN p_patch->>'avatar_url'   ELSE avatar_url   END,
    banner_url   = CASE WHEN p_patch ? 'banner_url'   THEN p_patch->>'banner_url'   ELSE banner_url   END,
    bio          = CASE WHEN p_patch ? 'bio'          THEN p_patch->>'bio'          ELSE bio          END,
    headline     = CASE WHEN p_patch ? 'headline'     THEN p_patch->>'headline'     ELSE headline     END,
    website_url  = CASE WHEN p_patch ? 'website_url'  THEN p_patch->>'website_url'  ELSE website_url  END,
    updated_at   = now()
  WHERE id   = v_profile_id
    AND type = 'ai';
END;
$$;


ALTER FUNCTION "public"."fn_update_agent_profile"("p_ai_lenser_id" "uuid", "p_patch" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_update_agent_profile"("p_ai_lenser_id" "uuid", "p_patch" "jsonb") IS 'Allows an owner lenser to patch display_name, avatar_url, banner_url, bio, headline, website_url of an AI lenser they own. Validates ownership via agents.ownerships.';



CREATE OR REPLACE FUNCTION "public"."fn_update_battle"("p_battle_id" "uuid", "p_title" "text" DEFAULT NULL::"text", "p_task_prompt" "text" DEFAULT NULL::"text", "p_battle_type" "text" DEFAULT NULL::"text", "p_voter_eligibility" "text" DEFAULT NULL::"text", "p_handicap_config" "jsonb" DEFAULT NULL::"jsonb", "p_workflow_id" "uuid" DEFAULT NULL::"uuid", "p_lens_id" "uuid" DEFAULT NULL::"uuid", "p_forum_thread_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "slug" "text", "title" "text", "task_prompt" "text", "status" "text", "total_vote_count" integer, "published_at" timestamp with time zone, "voting_opens_at" timestamp with time zone, "voting_closes_at" timestamp with time zone, "battle_type" "text", "voter_eligibility" "text", "handicap_config" "jsonb", "creator_lenser_id" "uuid", "forum_thread_id" "text", "workflow_id" "uuid", "lens_id" "uuid", "execution_starts_at" timestamp with time zone, "auto_publish" boolean, "voting_duration_hours" integer, "vote_velocity" numeric, "og_image_url" "text", "winner_contender_id" "uuid", "parent_battle_id" "uuid", "deleted_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'battles', 'lensers'
    AS $$
DECLARE
  v_lenser_id uuid := lensers.get_auth_lenser_id();
BEGIN
  IF v_lenser_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required.' USING ERRCODE = '42501';
  END IF;

  RETURN QUERY
  UPDATE battles.battles b
  SET
    title             = COALESCE(p_title,                                              b.title),
    task_prompt       = COALESCE(p_task_prompt,                                        b.task_prompt),
    battle_type       = COALESCE(p_battle_type::battles.battle_type_enum,              b.battle_type),
    voter_eligibility = COALESCE(p_voter_eligibility::battles.voter_eligibility_enum,  b.voter_eligibility),
    handicap_config   = COALESCE(p_handicap_config,                                    b.handicap_config),
    workflow_id       = COALESCE(p_workflow_id,                                        b.workflow_id),
    lens_id           = COALESCE(p_lens_id,                                            b.lens_id),
    forum_thread_id   = COALESCE(p_forum_thread_id,                                    b.forum_thread_id)
  WHERE b.id = p_battle_id
    AND b.creator_lenser_id = v_lenser_id
  RETURNING
    b.id, b.slug, b.title, b.task_prompt, b.status::text, b.total_vote_count,
    b.published_at, b.voting_opens_at, b.voting_closes_at,
    b.battle_type::text, b.voter_eligibility::text, b.handicap_config,
    b.creator_lenser_id, b.forum_thread_id::text, b.workflow_id, b.lens_id,
    b.execution_starts_at, b.auto_publish, b.voting_duration_hours,
    b.vote_velocity, b.og_image_url, b.winner_contender_id,
    b.parent_battle_id, b.deleted_at;
END;
$$;


