CREATE OR REPLACE FUNCTION "public"."fn_update_workflow"("p_workflow_id" "uuid", "p_title" "text", "p_description" "text" DEFAULT NULL::"text", "p_visibility" "text" DEFAULT 'public'::"text") RETURNS TABLE("id" "uuid", "lenser_id" "uuid", "title" "text", "description" "text", "visibility" "text", "battle_count" integer, "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
declare
  v_lenser_id uuid;
begin
  if auth.uid() is null then
    raise exception 'Not authenticated';
  end if;

  v_lenser_id := lensers.get_auth_lenser_id();

  if v_lenser_id is null then
    raise exception 'Profile not found';
  end if;

  if char_length(trim(p_title)) < 1 or char_length(trim(p_title)) > 200 then
    raise exception 'Title must be between 1 and 200 characters';
  end if;

  if p_visibility not in ('public', 'private', 'unlisted') then
    raise exception 'Invalid visibility value';
  end if;

  return query
  update lenses.workflows w
  set
    title       = trim(p_title),
    description = p_description,
    visibility  = p_visibility,
    updated_at  = now()
  where w.id        = p_workflow_id
    and w.lenser_id = v_lenser_id
  returning
    w.id,
    w.lenser_id,
    w.title,
    w.description,
    w.visibility,
    w.battle_count,
    w.created_at,
    w.updated_at;

  if not found then
    raise exception 'Workflow not found or not owned by caller';
  end if;
end;
$$;


ALTER FUNCTION "public"."fn_update_workflow"("p_workflow_id" "uuid", "p_title" "text", "p_description" "text", "p_visibility" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_update_workflow"("p_workflow_id" "uuid", "p_title" "text", "p_description" "text", "p_visibility" "text") IS 'Update workflow title, description, and visibility. Ownership resolved via lensers.get_auth_lenser_id() (supports AI lenser context switching). SECURITY DEFINER.';



CREATE OR REPLACE FUNCTION "public"."fn_update_workflow_node_result"("p_run_id" "uuid", "p_node_id" "uuid", "p_status" "text", "p_output_data" "jsonb" DEFAULT NULL::"jsonb", "p_error_message" "text" DEFAULT NULL::"text", "p_retry_count" integer DEFAULT NULL::integer, "p_duration_ms" integer DEFAULT NULL::integer, "p_ttfb_ms" integer DEFAULT NULL::integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_caller_id uuid;
BEGIN
  v_caller_id := lensers.get_auth_lenser_id();

  IF NOT EXISTS (
    SELECT 1
    FROM lenses.workflow_runs r
    JOIN lenses.workflows w ON w.id = r.workflow_id
    WHERE r.id = p_run_id
      AND (w.lenser_id = v_caller_id OR w.visibility = 'public')
  ) THEN
    RAISE EXCEPTION 'Unauthorized: caller cannot update results for run %', p_run_id
      USING ERRCODE = '42501';
  END IF;

  UPDATE lenses.workflow_node_results
  SET
    status        = p_status,
    output_data   = COALESCE(p_output_data, output_data),
    error_message = COALESCE(p_error_message, error_message),
    retry_count   = COALESCE(p_retry_count, retry_count),
    -- Timing metrics are monotonic: once written, later partial updates
    -- (e.g. failed -> retrying -> completed) keep the most recent non-null
    -- value for duration, but ttfb only records the FIRST streamed chunk.
    duration_ms   = COALESCE(p_duration_ms, duration_ms),
    ttfb_ms       = COALESCE(ttfb_ms, p_ttfb_ms),
    started_at    = CASE
                      WHEN p_status IN ('running', 'streaming', 'retrying') AND started_at IS NULL
                        THEN now()
                      ELSE started_at
                    END,
    completed_at  = CASE
                      WHEN p_status IN ('completed', 'failed', 'cancelled',
                                        'skipped', 'timed_out', 'blocked', 'invalidated')
                        THEN now()
                      ELSE completed_at
                    END
  WHERE run_id = p_run_id AND node_id = p_node_id;
END;
$$;


ALTER FUNCTION "public"."fn_update_workflow_node_result"("p_run_id" "uuid", "p_node_id" "uuid", "p_status" "text", "p_output_data" "jsonb", "p_error_message" "text", "p_retry_count" integer, "p_duration_ms" integer, "p_ttfb_ms" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_update_workflow_node_result"("p_run_id" "uuid", "p_node_id" "uuid", "p_status" "text", "p_output_data" "jsonb", "p_error_message" "text", "p_retry_count" integer, "p_duration_ms" integer, "p_ttfb_ms" integer) IS 'Phase 6 overload: persists retry_count / duration_ms / ttfb_ms alongside status + output. All observability args are nullable — callers that omit them preserve prior values.';



CREATE OR REPLACE FUNCTION "public"."fn_update_workflow_node_result"("p_run_id" "uuid", "p_node_id" "uuid", "p_status" "text", "p_output_data" "jsonb" DEFAULT NULL::"jsonb", "p_error_message" "text" DEFAULT NULL::"text", "p_retry_count" integer DEFAULT NULL::integer, "p_duration_ms" integer DEFAULT NULL::integer, "p_ttfb_ms" integer DEFAULT NULL::integer, "p_waiting_reason" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_caller_id uuid;
BEGIN
  v_caller_id := lensers.get_auth_lenser_id();

  IF NOT EXISTS (
    SELECT 1
    FROM lenses.workflow_runs r
    JOIN lenses.workflows w ON w.id = r.workflow_id
    WHERE r.id = p_run_id
      AND (w.lenser_id = v_caller_id OR w.visibility = 'public')
  ) THEN
    RAISE EXCEPTION 'Unauthorized: caller cannot update results for run %', p_run_id
      USING ERRCODE = '42501';
  END IF;

  UPDATE lenses.workflow_node_results
  SET
    status        = p_status,
    output_data   = COALESCE(p_output_data, output_data),
    error_message = COALESCE(p_error_message, error_message),
    retry_count   = COALESCE(p_retry_count, retry_count),
    duration_ms   = COALESCE(p_duration_ms, duration_ms),
    ttfb_ms       = COALESCE(ttfb_ms, p_ttfb_ms),
    -- Waiting reason: explicit overrides existing; null clears once the node
    -- transitions out of a waiting status.
    waiting_reason = CASE
                       WHEN p_status IN ('awaiting_dependency', 'queued', 'retrying')
                         THEN COALESCE(p_waiting_reason, waiting_reason)
                       ELSE NULL
                     END,
    started_at    = CASE
                      WHEN p_status IN ('running', 'streaming', 'retrying') AND started_at IS NULL
                        THEN now()
                      ELSE started_at
                    END,
    completed_at  = CASE
                      WHEN p_status IN ('completed', 'failed', 'cancelled',
                                        'skipped', 'timed_out', 'blocked', 'invalidated')
                        THEN now()
                      ELSE completed_at
                    END
  WHERE run_id = p_run_id AND node_id = p_node_id;

  -- Maintain run-level active node pointer (n8n-style "currently executing").
  -- Active when entering running/streaming/retrying, cleared on terminal.
  IF p_status IN ('running', 'streaming', 'retrying') THEN
    UPDATE lenses.workflow_runs
    SET active_node_id = p_node_id
    WHERE id = p_run_id;
  ELSIF p_status IN ('completed', 'failed', 'cancelled',
                     'skipped', 'timed_out', 'blocked', 'invalidated') THEN
    UPDATE lenses.workflow_runs
    SET active_node_id = NULL
    WHERE id = p_run_id
      AND active_node_id = p_node_id;
  END IF;
END;
$$;


ALTER FUNCTION "public"."fn_update_workflow_node_result"("p_run_id" "uuid", "p_node_id" "uuid", "p_status" "text", "p_output_data" "jsonb", "p_error_message" "text", "p_retry_count" integer, "p_duration_ms" integer, "p_ttfb_ms" integer, "p_waiting_reason" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_update_workflow_node_result"("p_run_id" "uuid", "p_node_id" "uuid", "p_status" "text", "p_output_data" "jsonb", "p_error_message" "text", "p_retry_count" integer, "p_duration_ms" integer, "p_ttfb_ms" integer, "p_waiting_reason" "text") IS 'Canonical n8n-style node result update. Persists status + output + observability metrics, maintains waiting_reason for non-running statuses, and updates workflow_runs.active_node_id so the inspector can render the active step without scanning all node rows.';



CREATE OR REPLACE FUNCTION "public"."fn_update_workflow_run_status"("p_run_id" "uuid", "p_status" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'lensers', 'public'
    AS $$
DECLARE
  v_caller_id uuid;
BEGIN
  v_caller_id := lensers.get_auth_lenser_id();

  IF NOT EXISTS (
    SELECT 1
    FROM lenses.workflow_runs r
    JOIN lenses.workflows w ON w.id = r.workflow_id
    WHERE r.id = p_run_id
      AND (w.lenser_id = v_caller_id OR w.visibility = 'public')
  ) THEN
    RAISE EXCEPTION 'Unauthorized: caller cannot update run %', p_run_id
      USING ERRCODE = '42501';
  END IF;

  UPDATE lenses.workflow_runs
  SET
    status       = p_status,
    started_at   = CASE
                     WHEN p_status IN ('running', 'streaming') AND started_at IS NULL
                       THEN now()
                     ELSE started_at
                   END,
    completed_at = CASE
                     WHEN p_status IN ('completed', 'failed', 'cancelled', 'timed_out')
                       THEN now()
                     ELSE completed_at
                   END,
    -- Clear worker ownership on terminal transitions so stale-claim queries
    -- do not revive a finished run.
    run_worker_id = CASE
                      WHEN p_status IN ('completed', 'failed', 'cancelled', 'timed_out')
                        THEN NULL
                      ELSE run_worker_id
                    END
  WHERE id = p_run_id;
END;
$$;


ALTER FUNCTION "public"."fn_update_workflow_run_status"("p_run_id" "uuid", "p_status" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_update_workflow_run_status"("p_run_id" "uuid", "p_status" "text") IS 'Updates a workflow_run status. Aligned with Phase 1 state machine — started_at written on first transition into running/streaming, completed_at for terminal states (completed, failed, cancelled, timed_out), run_worker_id cleared on terminals.';



CREATE OR REPLACE FUNCTION "public"."fn_update_workspace_settings"("p_ai_lenser_id" "uuid", "p_patch" "jsonb") RETURNS "agents"."workspace_settings"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_row agents.workspace_settings;
BEGIN
  IF NOT agents.can_manage_ai_lenser(p_ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  INSERT INTO agents.workspace_settings (ai_lenser_id)
  VALUES (p_ai_lenser_id)
  ON CONFLICT (ai_lenser_id) DO NOTHING;

  UPDATE agents.workspace_settings
  SET default_model_id     = COALESCE((p_patch->>'default_model_id')::uuid,     default_model_id),
      default_provider_key = COALESCE(p_patch->>'default_provider_key',         default_provider_key),
      approval_default     = COALESCE(p_patch->>'approval_default',             approval_default),
      retention_days       = COALESCE((p_patch->>'retention_days')::integer,     retention_days),
      max_daily_credits    = COALESCE((p_patch->>'max_daily_credits')::integer,  max_daily_credits),
      webhooks             = COALESCE(p_patch->'webhooks',                       webhooks),
      api_access_enabled   = COALESCE((p_patch->>'api_access_enabled')::boolean, api_access_enabled),
      metadata             = COALESCE(p_patch->'metadata',                       metadata),
      max_parallel_runs    = COALESCE((p_patch->>'max_parallel_runs')::integer,  max_parallel_runs),
      global_kill_switch   = COALESCE((p_patch->>'global_kill_switch')::boolean, global_kill_switch),
      agent_paused         = COALESCE((p_patch->>'agent_paused')::boolean,       agent_paused),
      dark_launch_enabled  = COALESCE((p_patch->>'dark_launch_enabled')::boolean,dark_launch_enabled),
      dark_launch_pct      = COALESCE((p_patch->>'dark_launch_pct')::integer,    dark_launch_pct),
      budget_enforce       = COALESCE((p_patch->>'budget_enforce')::boolean,     budget_enforce),
      updated_at           = now()
  WHERE ai_lenser_id = p_ai_lenser_id
  RETURNING * INTO v_row;

  RETURN v_row;
END;
$$;


ALTER FUNCTION "public"."fn_update_workspace_settings"("p_ai_lenser_id" "uuid", "p_patch" "jsonb") OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "agents"."lens_bindings" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "ai_lenser_id" "uuid" NOT NULL,
    "lens_id" "uuid" NOT NULL,
    "version_id" "uuid",
    "is_default" boolean DEFAULT false NOT NULL,
    "category_tags" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "agents"."lens_bindings" OWNER TO "postgres";


COMMENT ON TABLE "agents"."lens_bindings" IS 'Which lenses an AI Lenser may use in battles. version_id NULL means the agent always uses the current head version. Pin version_id for reproducible benchmark submissions.';



CREATE OR REPLACE FUNCTION "public"."fn_upsert_agent_lens_binding"("p_ai_lenser_id" "uuid", "p_lens_id" "uuid", "p_version_id" "uuid" DEFAULT NULL::"uuid", "p_is_default" boolean DEFAULT true) RETURNS SETOF "agents"."lens_bindings"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lensers', 'lenses'
    AS $$
DECLARE
  v_caller_human_id uuid;
  v_profile_id uuid;
  v_binding_id uuid;
BEGIN
  v_caller_human_id := lensers.get_auth_human_lenser_id();
  IF v_caller_human_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT al.profile_id INTO v_profile_id
  FROM agents.ai_lensers al
  JOIN agents.ownerships o ON o.ai_lenser_id = al.id
  WHERE al.id = p_ai_lenser_id
    AND o.owner_lenser_id = v_caller_human_id
    AND o.role IN ('owner', 'co_owner')
    AND o.revoked_at IS NULL
  LIMIT 1;

  IF v_profile_id IS NULL THEN
    RAISE EXCEPTION 'Forbidden: you do not own this AI lenser'
      USING ERRCODE = '42501';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM lenses.lenses l
    WHERE l.id = p_lens_id
      AND l.lenser_id = v_profile_id
  ) THEN
    RAISE EXCEPTION 'Main lens must be owned by the active AI workspace'
      USING ERRCODE = '42501';
  END IF;

  IF p_is_default THEN
    UPDATE agents.lens_bindings
    SET is_default = false
    WHERE ai_lenser_id = p_ai_lenser_id
      AND is_default = true;
  END IF;

  INSERT INTO agents.lens_bindings (ai_lenser_id, lens_id, version_id, is_default)
  VALUES (p_ai_lenser_id, p_lens_id, p_version_id, p_is_default)
  ON CONFLICT (ai_lenser_id, lens_id) DO UPDATE
    SET version_id = EXCLUDED.version_id,
        is_default = EXCLUDED.is_default
  RETURNING id INTO v_binding_id;

  INSERT INTO agents.action_logs (
    ai_lenser_id,
    action_type,
    result,
    metadata
  ) VALUES (
    p_ai_lenser_id,
    'binding_updated',
    'success',
    jsonb_build_object(
      'binding_kind', 'lens',
      'binding_id', v_binding_id,
      'lens_id', p_lens_id,
      'version_id', p_version_id,
      'is_default', p_is_default
    )
  );

  RETURN QUERY
  SELECT lb.*
  FROM agents.lens_bindings lb
  WHERE lb.id = v_binding_id;
END;
$$;


ALTER FUNCTION "public"."fn_upsert_agent_lens_binding"("p_ai_lenser_id" "uuid", "p_lens_id" "uuid", "p_version_id" "uuid", "p_is_default" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_upsert_agent_lens_binding"("p_ai_lenser_id" "uuid", "p_lens_id" "uuid", "p_version_id" "uuid" DEFAULT NULL::"uuid", "p_is_default" boolean DEFAULT true, "p_category_tags" "text"[] DEFAULT '{}'::"text"[]) RETURNS SETOF "agents"."lens_bindings"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lensers', 'lenses'
    AS $$
DECLARE
  v_caller_human_id uuid;
  v_profile_id      uuid;
  v_binding_id      uuid;
  v_is_personality  boolean;
BEGIN
  v_caller_human_id := lensers.get_auth_human_lenser_id();
  IF v_caller_human_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  SELECT al.profile_id INTO v_profile_id
  FROM agents.ai_lensers al
  JOIN agents.ownerships o ON o.ai_lenser_id = al.id
  WHERE al.id = p_ai_lenser_id
    AND o.owner_lenser_id = v_caller_human_id
    AND o.role IN ('owner', 'co_owner')
    AND o.revoked_at IS NULL
  LIMIT 1;

  IF v_profile_id IS NULL THEN
    RAISE EXCEPTION 'Forbidden: you do not own this AI lenser'
      USING ERRCODE = '42501';
  END IF;

  -- Accept lenses that are:
  --   a) owned by the AI workspace profile, OR
  --   b) owned by the calling human co-owner, OR
  --   c) public + published (platform/system lenses accessible to everyone)
  IF NOT EXISTS (
    SELECT 1 FROM lenses.lenses l
    WHERE l.id = p_lens_id
      AND (
        l.lenser_id = v_profile_id
        OR l.lenser_id = v_caller_human_id
        OR (l.visibility = 'public' AND l.status = 'published')
      )
  ) THEN
    RAISE EXCEPTION 'Lens must be owned by the AI workspace, its co-owner, or be a public published lens'
      USING ERRCODE = '42501';
  END IF;

  v_is_personality := 'personality' = ANY(p_category_tags);

  -- Clear the default flag only within the same category scope
  IF p_is_default THEN
    IF v_is_personality THEN
      UPDATE agents.lens_bindings
        SET is_default = false
        WHERE ai_lenser_id = p_ai_lenser_id
          AND is_default = true
          AND 'personality' = ANY(category_tags);
    ELSE
      UPDATE agents.lens_bindings
        SET is_default = false
        WHERE ai_lenser_id = p_ai_lenser_id
          AND is_default = true
          AND NOT ('personality' = ANY(category_tags));
    END IF;
  END IF;

  INSERT INTO agents.lens_bindings
    (ai_lenser_id, lens_id, version_id, is_default, category_tags)
  VALUES
    (p_ai_lenser_id, p_lens_id, p_version_id, p_is_default, p_category_tags)
  ON CONFLICT (ai_lenser_id, lens_id) DO UPDATE
    SET version_id    = EXCLUDED.version_id,
        is_default    = EXCLUDED.is_default,
        category_tags = EXCLUDED.category_tags
  RETURNING id INTO v_binding_id;

  INSERT INTO agents.action_logs (ai_lenser_id, action_type, result, metadata)
  VALUES (
    p_ai_lenser_id,
    'binding_updated',
    'success',
    jsonb_build_object(
      'binding_kind',  'lens',
      'binding_id',    v_binding_id,
      'lens_id',       p_lens_id,
      'version_id',    p_version_id,
      'is_default',    p_is_default,
      'category_tags', p_category_tags
    )
  );

  RETURN QUERY SELECT lb.* FROM agents.lens_bindings lb WHERE lb.id = v_binding_id LIMIT 1;
END;
$$;


ALTER FUNCTION "public"."fn_upsert_agent_lens_binding"("p_ai_lenser_id" "uuid", "p_lens_id" "uuid", "p_version_id" "uuid", "p_is_default" boolean, "p_category_tags" "text"[]) OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "agents"."model_bindings" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "ai_lenser_id" "uuid" NOT NULL,
    "model_id" "uuid" NOT NULL,
    "is_default" boolean DEFAULT false NOT NULL,
    "category_tags" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "byok_adapter" "text",
    "ollama_endpoint" "text",
    CONSTRAINT "model_bindings_byok_adapter_check" CHECK (("byok_adapter" = ANY (ARRAY['openai'::"text", 'anthropic'::"text", 'mistral'::"text", 'google'::"text", 'cohere'::"text", 'custom'::"text"])))
);


ALTER TABLE "agents"."model_bindings" OWNER TO "postgres";


COMMENT ON TABLE "agents"."model_bindings" IS 'Which AI models an AI Lenser is allowed to use. category_tags narrows selection by battle category. is_default selects the fallback when no category match exists.';



COMMENT ON COLUMN "agents"."model_bindings"."byok_adapter" IS 'Provider key for BYOK execution — keys are stored in execution.byok_keys, not here.';



COMMENT ON COLUMN "agents"."model_bindings"."ollama_endpoint" IS 'Local Ollama endpoint URL (e.g. http://localhost:11434). Never proxied to cloud.';



CREATE OR REPLACE FUNCTION "public"."fn_upsert_agent_model_binding"("p_ai_lenser_id" "uuid", "p_model_id" "uuid", "p_is_default" boolean DEFAULT true) RETURNS SETOF "agents"."model_bindings"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lensers', 'ai'
    AS $$
DECLARE
  v_caller_human_id uuid;
  v_binding_id uuid;
BEGIN
  v_caller_human_id := lensers.get_auth_human_lenser_id();
  IF v_caller_human_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM agents.ownerships o
    WHERE o.ai_lenser_id = p_ai_lenser_id
      AND o.owner_lenser_id = v_caller_human_id
      AND o.role IN ('owner', 'co_owner')
      AND o.revoked_at IS NULL
  ) THEN
    RAISE EXCEPTION 'Forbidden: you do not own this AI lenser'
      USING ERRCODE = '42501';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM ai.models m
    WHERE m.id = p_model_id
      AND m.is_active = true
  ) THEN
    RAISE EXCEPTION 'Model not found or inactive'
      USING ERRCODE = 'P0001';
  END IF;

  IF p_is_default THEN
    UPDATE agents.model_bindings
    SET is_default = false
    WHERE ai_lenser_id = p_ai_lenser_id
      AND is_default = true;
  END IF;

  INSERT INTO agents.model_bindings (ai_lenser_id, model_id, is_default)
  VALUES (p_ai_lenser_id, p_model_id, p_is_default)
  ON CONFLICT (ai_lenser_id, model_id) DO UPDATE
    SET is_default = EXCLUDED.is_default
  RETURNING id INTO v_binding_id;

  INSERT INTO agents.action_logs (
    ai_lenser_id,
    action_type,
    result,
    metadata
  ) VALUES (
    p_ai_lenser_id,
    'binding_updated',
    'success',
    jsonb_build_object(
      'binding_kind', 'model',
      'binding_id', v_binding_id,
      'model_id', p_model_id,
      'is_default', p_is_default
    )
  );

  RETURN QUERY
  SELECT mb.*
  FROM agents.model_bindings mb
  WHERE mb.id = v_binding_id;
END;
$$;


ALTER FUNCTION "public"."fn_upsert_agent_model_binding"("p_ai_lenser_id" "uuid", "p_model_id" "uuid", "p_is_default" boolean) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_upsert_agent_ownership"("p_ai_lenser_id" "uuid", "p_owner_lenser_id" "uuid", "p_role" "text", "p_permission_scope" "text"[] DEFAULT '{}'::"text"[]) RETURNS TABLE("id" "uuid", "ai_lenser_id" "uuid", "owner_lenser_id" "uuid", "role" "text", "permission_scope" "text"[], "granted_at" timestamp with time zone, "revoked_at" timestamp with time zone, "owner_handle" "text", "owner_display_name" "text", "owner_avatar_url" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents', 'lensers'
    AS $$
DECLARE
  v_caller_human_id uuid := lensers.get_auth_human_lenser_id();
BEGIN
  IF NOT agents.can_manage_ai_lenser(p_ai_lenser_id) THEN
    RAISE EXCEPTION 'Not authorized to manage this AI Lenser.'
      USING ERRCODE = '42501';
  END IF;

  IF p_role NOT IN ('co_owner', 'operator') THEN
    RAISE EXCEPTION 'Only co_owner and operator may be granted through this RPC.'
      USING ERRCODE = '22023';
  END IF;

  IF p_owner_lenser_id IS NULL THEN
    RAISE EXCEPTION 'Delegate owner_lenser_id is required.'
      USING ERRCODE = '22023';
  END IF;

  IF p_owner_lenser_id = v_caller_human_id THEN
    RAISE EXCEPTION 'The primary owner already has access and cannot be delegated through this RPC.'
      USING ERRCODE = '22023';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM agents.ai_lensers al
    WHERE al.id = p_ai_lenser_id
  ) THEN
    RAISE EXCEPTION 'AI Lenser not found.'
      USING ERRCODE = 'P0002';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM lensers.profiles p
    WHERE p.id = p_owner_lenser_id
      AND p.type = 'human'
      AND p.status = 'active'
  ) THEN
    RAISE EXCEPTION 'Delegate must be an active human Lenser.'
      USING ERRCODE = '22023';
  END IF;

  INSERT INTO agents.ownerships (
    ai_lenser_id,
    owner_lenser_id,
    role,
    permission_scope,
    granted_at,
    revoked_at
  )
  VALUES (
    p_ai_lenser_id,
    p_owner_lenser_id,
    p_role,
    COALESCE(p_permission_scope, '{}'::text[]),
    now(),
    NULL
  )
  ON CONFLICT (ai_lenser_id, owner_lenser_id)
  DO UPDATE SET
    role = EXCLUDED.role,
    permission_scope = EXCLUDED.permission_scope,
    granted_at = now(),
    revoked_at = NULL;

  RETURN QUERY
  SELECT
    o.id,
    o.ai_lenser_id,
    o.owner_lenser_id,
    o.role,
    o.permission_scope,
    o.granted_at,
    o.revoked_at,
    p.handle,
    p.display_name,
    p.avatar_url
  FROM agents.ownerships o
  JOIN lensers.profiles p
    ON p.id = o.owner_lenser_id
  WHERE o.ai_lenser_id = p_ai_lenser_id
    AND o.owner_lenser_id = p_owner_lenser_id
  LIMIT 1;
END;
$$;


