    INSERT INTO lenses.workflow_phases (workflow_id, title, description, ordinal)
    VALUES (p_workflow_id, p_title, p_description, p_ordinal)
    RETURNING to_jsonb(lenses.workflow_phases.*) INTO v_result;
  END IF;

  RETURN v_result;
END;
$$;


