  UPDATE agents.team_runs
  SET status       = p_status,
      completed_at = COALESCE(p_completed_at, CASE WHEN p_status IN ('completed','failed','cancelled') THEN now() ELSE NULL END),
      updated_at   = now()
  WHERE id = p_team_run_id;
$$;


