CREATE OR REPLACE FUNCTION "public"."fn_worker_upsert_node_result"("p_run_id" "uuid", "p_node_id" "uuid", "p_status" "text", "p_output_data" "jsonb" DEFAULT NULL::"jsonb", "p_error_message" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses'
    AS $$
DECLARE
  v_terminal text[] := ARRAY['completed', 'failed', 'timed_out', 'cancelled'];
BEGIN
  INSERT INTO lenses.workflow_node_results
    (run_id, node_id, status, output_data, error_message, started_at, completed_at)
  VALUES (
    p_run_id, p_node_id, p_status, p_output_data, p_error_message,
    CASE WHEN p_status = 'running' THEN now() ELSE NULL END,
    CASE WHEN p_status = ANY(v_terminal) THEN now() ELSE NULL END
  )
  ON CONFLICT (run_id, node_id) DO UPDATE
    SET status        = EXCLUDED.status,
        output_data   = COALESCE(EXCLUDED.output_data,   lenses.workflow_node_results.output_data),
        error_message = COALESCE(EXCLUDED.error_message, lenses.workflow_node_results.error_message),
        started_at    = COALESCE(lenses.workflow_node_results.started_at, EXCLUDED.started_at),
        completed_at  = CASE
          WHEN EXCLUDED.status = ANY(v_terminal) THEN now()
          ELSE lenses.workflow_node_results.completed_at
        END;
END;
$$;


ALTER FUNCTION "public"."fn_worker_upsert_node_result"("p_run_id" "uuid", "p_node_id" "uuid", "p_status" "text", "p_output_data" "jsonb", "p_error_message" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_worker_upsert_node_result"("p_run_id" "uuid", "p_node_id" "uuid", "p_status" "text", "p_output_data" "jsonb", "p_error_message" "text") IS 'Worker-only: upsert a workflow node execution result. Sets started_at on first "running" write; sets completed_at on terminal status. Preserves existing output_data/error_message if new value is NULL.';



CREATE OR REPLACE FUNCTION "public"."fn_workflows_chain_run"("p_parent_run_id" "uuid", "p_child_workflow_id" "uuid", "p_input" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'public'
    AS $$
DECLARE
  v_child_run_id UUID;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM lenses.workflow_runs WHERE id = p_parent_run_id) THEN
    RAISE EXCEPTION 'Parent run not found' USING ERRCODE = 'P0002';
  END IF;

  INSERT INTO lenses.workflow_runs
    (workflow_id, triggered_by, status, context_inputs, trigger_mode)
  VALUES
    (p_child_workflow_id, NULL, 'pending', p_input, 'schedule')
  RETURNING id INTO v_child_run_id;

  INSERT INTO lenses.workflow_run_chains
    (parent_run_id, child_run_id, chain_reason)
  VALUES
    (p_parent_run_id, v_child_run_id, 'chained_run');

  RETURN v_child_run_id;
END;
$$;


ALTER FUNCTION "public"."fn_workflows_chain_run"("p_parent_run_id" "uuid", "p_child_workflow_id" "uuid", "p_input" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_workflows_chain_run"("p_parent_run_id" "uuid", "p_child_workflow_id" "uuid", "p_input" "jsonb") IS 'CD: Creates a child run and records the parent→child chain relationship.';



CREATE OR REPLACE FUNCTION "public"."fn_workflows_dispatch_on_event"("p_event_type" "text", "p_event_payload" "jsonb") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'public'
    AS $$
DECLARE
  rec       RECORD;
  dispatched INT := 0;
BEGIN
  FOR rec IN
    SELECT wt.id AS trigger_id, wt.workflow_id, wt.owner_id
      FROM lenses.workflow_triggers wt
     WHERE wt.enabled = TRUE
       AND wt.trigger_type = p_event_type
       AND public.fn_workflows_evaluate_condition(wt.condition, p_event_payload)
  LOOP
    INSERT INTO lenses.workflow_runs
      (workflow_id, triggered_by, status, context_inputs, trigger_mode)
    VALUES
      (rec.workflow_id, NULL, 'pending', p_event_payload, 'schedule');

    -- Update last_fired_at
    UPDATE lenses.workflow_triggers
       SET last_fired_at = now()
     WHERE id = rec.trigger_id;

    dispatched := dispatched + 1;
  END LOOP;

  RETURN dispatched;
END;
$$;


ALTER FUNCTION "public"."fn_workflows_dispatch_on_event"("p_event_type" "text", "p_event_payload" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_workflows_dispatch_on_event"("p_event_type" "text", "p_event_payload" "jsonb") IS 'CD: Fan-out to enabled triggers matching event_type + condition. Returns dispatched count.';



CREATE OR REPLACE FUNCTION "public"."fn_workflows_evaluate_condition"("p_condition" "jsonb", "p_event" "jsonb") RETURNS boolean
    LANGUAGE "plpgsql" IMMUTABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  k TEXT;
  v JSONB;
BEGIN
  -- Empty condition always matches
  IF p_condition = '{}'::JSONB OR p_condition IS NULL THEN
    RETURN TRUE;
  END IF;

  -- Each key in p_condition must match the corresponding key in p_event
  FOR k, v IN SELECT * FROM jsonb_each(p_condition)
  LOOP
    IF p_event -> k IS DISTINCT FROM v THEN
      RETURN FALSE;
    END IF;
  END LOOP;

  RETURN TRUE;
END;
$$;


ALTER FUNCTION "public"."fn_workflows_evaluate_condition"("p_condition" "jsonb", "p_event" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_workflows_evaluate_condition"("p_condition" "jsonb", "p_event" "jsonb") IS 'CD: IMMUTABLE shallow key-match condition evaluator. Used by trigger fan-out.';



CREATE OR REPLACE FUNCTION "public"."fn_workflows_get_popular"("p_offset" integer DEFAULT 0, "p_limit" integer DEFAULT 12, "p_search" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "lenser_id" "uuid", "title" "text", "description" "text", "visibility" "text", "battle_count" integer, "node_count" bigint, "reaction_totals" "jsonb", "fork_count" integer, "parent_workflow_id" "uuid", "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "hot_score" double precision)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'lenses'
    AS $$
  SELECT
    w.id,
    w.lenser_id,
    w.title,
    w.description,
    w.visibility::text,
    w.battle_count,
    (
      SELECT count(*)
      FROM lenses.workflow_nodes wn
      WHERE wn.workflow_id = w.id
    ) AS node_count,
    w.reaction_totals,
    w.fork_count,
    w.parent_workflow_id,
    w.created_at,
    w.updated_at,
    log(
      GREATEST(
        1,
        5.0 * w.battle_count
        + 3.0 * w.fork_count
        + 4.0 * COALESCE((w.reaction_totals->>'copy')::int, 0)
        + 2.0 * COALESCE((w.reaction_totals->>'like')::int, 0)
        + 1.0 * COALESCE((w.reaction_totals->>'saved')::int, 0)
      )
    ) / NULLIF(
      pow((extract(epoch FROM now() - w.created_at) / 3600.0 + 2), 1.5),
      0
    ) AS hot_score
  FROM lenses.workflows w
  WHERE w.visibility::text = 'public'
    AND (p_search IS NULL OR w.title ILIKE '%' || p_search || '%')
  ORDER BY hot_score DESC, w.created_at DESC
  LIMIT p_limit
  OFFSET p_offset;
$$;


ALTER FUNCTION "public"."fn_workflows_get_popular"("p_offset" integer, "p_limit" integer, "p_search" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_workflows_webhook_trigger"("p_workflow_id" "uuid", "p_secret" "text", "p_payload" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'lenses', 'public'
    AS $$
DECLARE
  v_stored_secret TEXT;
  v_run_id        UUID;
BEGIN
  -- Find the webhook trigger for this workflow
  SELECT webhook_secret INTO v_stored_secret
    FROM lenses.workflow_triggers
   WHERE workflow_id   = p_workflow_id
     AND trigger_type  = 'webhook'
     AND enabled       = TRUE
   LIMIT 1;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'No active webhook trigger for workflow' USING ERRCODE = 'P0002';
  END IF;

  IF v_stored_secret IS DISTINCT FROM p_secret THEN
    RAISE EXCEPTION 'invalid_webhook_secret' USING ERRCODE = 'P0001';
  END IF;

  INSERT INTO lenses.workflow_runs
    (workflow_id, triggered_by, status, context_inputs, trigger_mode)
  VALUES
    (p_workflow_id, NULL, 'pending', p_payload, 'schedule')
  RETURNING id INTO v_run_id;

  RETURN v_run_id;
END;
$$;


ALTER FUNCTION "public"."fn_workflows_webhook_trigger"("p_workflow_id" "uuid", "p_secret" "text", "p_payload" "jsonb") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_workflows_webhook_trigger"("p_workflow_id" "uuid", "p_secret" "text", "p_payload" "jsonb") IS 'CD: HMAC-validated webhook dispatch. Raises P0001 invalid_webhook_secret on mismatch.';



CREATE OR REPLACE FUNCTION "public"."fn_write_memory_entry"("p_profile_id" "uuid", "p_scope" "text", "p_source" "text", "p_content" "text", "p_confidence" numeric DEFAULT 0.5, "p_expires_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_team_run_id" "uuid" DEFAULT NULL::"uuid", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'agents'
    AS $$
DECLARE
  v_profile agents.memory_profiles;
  v_id      uuid;
BEGIN
  SELECT * INTO v_profile FROM agents.memory_profiles WHERE id = p_profile_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'memory profile not found' USING ERRCODE = 'P0002';
  END IF;
  IF NOT agents.can_manage_ai_lenser(v_profile.ai_lenser_id) THEN
    RAISE EXCEPTION 'not authorized for this agent' USING ERRCODE = '42501';
  END IF;

  INSERT INTO agents.memories (
    profile_id, ai_lenser_id, scope, source, content,
    embedding_metadata, confidence, expires_at, team_run_id
  )
  VALUES (
    p_profile_id, v_profile.ai_lenser_id, p_scope, p_source, p_content,
    COALESCE(p_metadata, '{}'::jsonb),
    COALESCE(p_confidence, 0.5),
    p_expires_at,
    p_team_run_id
  )
  RETURNING id INTO v_id;

  INSERT INTO agents.memory_access_logs (memory_id, team_run_id, action, context)
  VALUES (v_id, p_team_run_id, 'write', jsonb_build_object('source', p_source, 'scope', p_scope));

  RETURN v_id;
END;
$$;


ALTER FUNCTION "public"."fn_write_memory_entry"("p_profile_id" "uuid", "p_scope" "text", "p_source" "text", "p_content" "text", "p_confidence" numeric, "p_expires_at" timestamp with time zone, "p_team_run_id" "uuid", "p_metadata" "jsonb") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fn_xp_freeze_content"("p_source_ref_type" "text", "p_source_ref_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'xp', 'public'
    AS $$
DECLARE
  v_count INT;
BEGIN
  -- Restrict to service_role / supabase_admin
  IF current_setting('role', true) NOT IN ('service_role', 'supabase_admin') THEN
    RAISE EXCEPTION 'permission_denied'
      USING ERRCODE = '42501',
            DETAIL  = 'fn_xp_freeze_content is restricted to service_role.',
            HINT    = 'permission_denied';
  END IF;

  -- Mark XP events as frozen in their meta JSONB without deleting the audit trail
  UPDATE xp.events
  SET meta = COALESCE(meta, '{}'::jsonb) || '{"frozen": true, "freeze_reason": "moderated_content"}'::jsonb
  WHERE source_ref_type = p_source_ref_type
    AND source_ref_id   = p_source_ref_id
    AND NOT COALESCE((meta->>'frozen')::boolean, false);

  GET DIAGNOSTICS v_count = ROW_COUNT;

  RAISE NOTICE 'fn_xp_freeze_content: froze % events for %/%', v_count, p_source_ref_type, p_source_ref_id;
  RETURN v_count;
END;
$$;


ALTER FUNCTION "public"."fn_xp_freeze_content"("p_source_ref_type" "text", "p_source_ref_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."fn_xp_freeze_content"("p_source_ref_type" "text", "p_source_ref_id" "uuid") IS 'CB: Marks XP events for moderated/deleted content as frozen. Preserves audit trail; service_role only.';



