CREATE OR REPLACE FUNCTION "public"."fn_xp_get_contributions"("p_lenser_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "lenser_id" "uuid", "context" "text", "contribution_type" "text", "external_ref" "text", "title" "text", "verified_by" "uuid", "xp_event_id" "uuid", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'xp', 'lensers', 'auth'
    AS $$
DECLARE
  v_lenser_id uuid;
BEGIN
  IF p_lenser_id IS NULL THEN
    SELECT id INTO v_lenser_id FROM lensers.profiles WHERE user_id = auth.uid();
  ELSE
    v_lenser_id := p_lenser_id;
  END IF;

  RETURN QUERY
  SELECT
    c.id, c.lenser_id, c.context::text, c.contribution_type::text,
    c.external_ref::text, c.title::text, c.verified_by, c.xp_event_id, c.created_at
  FROM xp.contributions c
  WHERE c.lenser_id = v_lenser_id
  ORDER BY c.created_at DESC;
END;
$$;


