CREATE OR REPLACE FUNCTION "public"."fn_xp_get_level_ups"("p_lenser_id" "uuid", "p_limit" integer DEFAULT 20) RETURNS TABLE("id" "uuid", "old_level" integer, "new_level" integer, "total_xp_at" bigint, "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'xp', 'public'
    AS $$
BEGIN
  IF auth.uid() IS DISTINCT FROM p_lenser_id
     AND current_setting('role', true) NOT IN ('service_role', 'supabase_admin')
  THEN
    RAISE EXCEPTION 'permission_denied'
      USING ERRCODE = '42501',
            DETAIL  = 'You may only read your own level-up history.',
            HINT    = 'permission_denied';
  END IF;

  RETURN QUERY
  SELECT
    lu.id,
    lu.old_level,
    lu.new_level,
    lu.total_xp_at,
    lu.created_at
  FROM xp.level_ups lu
  WHERE lu.lenser_id = p_lenser_id
  ORDER BY lu.created_at DESC
  LIMIT LEAST(p_limit, 100);
END;
$$;


