CREATE OR REPLACE FUNCTION "public"."fn_xp_get_seasons"("p_app_id" "uuid" DEFAULT '00000000-0000-0000-0000-000000000001'::"uuid") RETURNS TABLE("id" "uuid", "slug" "text", "name" "text", "description" "text", "reward_description" "text", "featured_challenges" "jsonb", "starts_at" timestamp with time zone, "ends_at" timestamp with time zone, "is_active" boolean, "status" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'xp', 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    s.id,
    s.slug,
    s.name,
    s.description,
    s.reward_description,
    s.featured_challenges,
    s.starts_at,
    s.ends_at,
    s.is_active,
    CASE
      WHEN s.is_active                    THEN 'active'
      WHEN s.starts_at > now()            THEN 'upcoming'
      ELSE                                     'ended'
    END AS status
  FROM xp.seasons s
  WHERE s.app_id = p_app_id
  ORDER BY s.starts_at DESC;
END;
$$;


