CREATE OR REPLACE FUNCTION "public"."fn_xp_get_streak"("p_lenser_id" "uuid", "p_streak_type" "text" DEFAULT 'daily'::"text") RETURNS TABLE("lenser_id" "uuid", "streak_type" "text", "current_streak" integer, "best_streak" integer, "last_update_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'xp', 'public'
    AS $$
BEGIN
  -- RLS: callers may only read own streak; service_role reads any
  IF auth.uid() IS DISTINCT FROM p_lenser_id
     AND current_setting('role', true) NOT IN ('service_role', 'supabase_admin')
  THEN
    RAISE EXCEPTION 'permission_denied'
      USING ERRCODE = '42501',
            DETAIL  = 'You may only read your own streak.',
            HINT    = 'permission_denied';
  END IF;

  RETURN QUERY
  SELECT
    s.lenser_id,
    s.streak_type,
    s.current_streak,
    s.best_streak,
    s.last_update_at
  FROM xp.streaks s
  WHERE s.lenser_id    = p_lenser_id
    AND s.streak_type  = p_streak_type;
END;
$$;


