CREATE OR REPLACE FUNCTION "xp"."fn_xp_auto_activate_seasons"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'xp', 'public'
    AS $$
DECLARE
  v_deactivated INT := 0;
  v_activated   INT := 0;
BEGIN
  -- 1. Deactivate expired seasons
  UPDATE xp.seasons
  SET is_active = false
  WHERE is_active = true
    AND ends_at IS NOT NULL
    AND ends_at < now();
  GET DIAGNOSTICS v_deactivated = ROW_COUNT;

  -- 2. Activate seasons that should now be running (starts_at passed, not ended,
  --    and no currently-active season exists for that app).
  --    Process one candidate per app at a time (oldest starts_at first) to avoid
  --    violating the no-overlap exclusion constraint.
  WITH candidates AS (
    SELECT
      s.id,
      s.app_id,
      ROW_NUMBER() OVER (PARTITION BY s.app_id ORDER BY s.starts_at) AS rn
    FROM xp.seasons s
    WHERE s.is_active = false
      AND s.starts_at <= now()
      AND (s.ends_at IS NULL OR s.ends_at > now())
      AND NOT EXISTS (
        SELECT 1 FROM xp.seasons a
        WHERE a.app_id   = s.app_id
          AND a.is_active = true
      )
  )
  UPDATE xp.seasons s
  SET is_active = true
  FROM candidates c
  WHERE c.id = s.id
    AND c.rn = 1;
  GET DIAGNOSTICS v_activated = ROW_COUNT;

  IF v_deactivated > 0 OR v_activated > 0 THEN
    RAISE NOTICE 'fn_xp_auto_activate_seasons: deactivated=%, activated=%', v_deactivated, v_activated;
  END IF;
END;
$$;


ALTER FUNCTION "xp"."fn_xp_auto_activate_seasons"() OWNER TO "postgres";


COMMENT ON FUNCTION "xp"."fn_xp_auto_activate_seasons"() IS 'CB-P2: Deactivates expired seasons and activates ready ones. Called by pg_cron. Idempotent and advisory-locked via automation.fn_run_with_lock.';



CREATE OR REPLACE FUNCTION "xp"."fn_xp_auto_activate_seasons_safe"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'xp', 'automation', 'public'
    AS $$
BEGIN
  PERFORM automation.fn_run_with_lock(
    'xp-auto-activate-seasons',
    'SELECT xp.fn_xp_auto_activate_seasons()'
  );
END;
$$;


ALTER FUNCTION "xp"."fn_xp_auto_activate_seasons_safe"() OWNER TO "postgres";


COMMENT ON FUNCTION "xp"."fn_xp_auto_activate_seasons_safe"() IS 'CB-P2: Advisory-lock wrapper for fn_xp_auto_activate_seasons. Called by pg_cron every hour.';



CREATE OR REPLACE FUNCTION "xp"."generate_levels"("p_app_id" "uuid", "p_max_level" integer DEFAULT 200, "p_base_xp" integer DEFAULT 100) RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'xp', 'public'
    AS $$DECLARE
    lvl int;
    min_xp bigint;
    max_xp bigint;
BEGIN
    -- Clear old levels for this app
    DELETE FROM xp.levels WHERE app_id = p_app_id;

    min_xp := 0;

    FOR lvl IN 1..p_max_level LOOP

        -- Level XP curve:
        -- Low levels = fast progression
        -- Mid levels = moderate
        -- High levels = exponential
        max_xp := min_xp + (p_base_xp * lvl * lvl / 5);

        INSERT INTO xp.levels (app_id, level, min_total_xp, max_total_xp, metadata)
        VALUES (
            p_app_id,
            lvl,
            min_xp,
            max_xp,
            jsonb_build_object('generated', true, 'formula', 'quadratic_scaled')
        );

        min_xp := max_xp + 1;
    END LOOP;

END;$$;


ALTER FUNCTION "xp"."generate_levels"("p_app_id" "uuid", "p_max_level" integer, "p_base_xp" integer) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "xp"."get_active_season_id"("p_app_id" "uuid") RETURNS "uuid"
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'xp', 'public'
    AS $$
  SELECT id
  FROM xp.seasons
  WHERE app_id = p_app_id
    AND is_active = true
    AND now() BETWEEN starts_at AND ends_at
  LIMIT 1;
$$;


ALTER FUNCTION "xp"."get_active_season_id"("p_app_id" "uuid") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "xp"."grant_contribution_xp"("p_lenser_id" "uuid", "p_context" "xp"."contribution_context_enum", "p_contribution_type" "text", "p_external_ref" "text" DEFAULT NULL::"text", "p_title" "text" DEFAULT NULL::"text", "p_metadata" "jsonb" DEFAULT NULL::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'xp', 'lensers', 'public'
    AS $$
DECLARE
  v_rule_key    text;
  v_event_id    uuid;
  v_contrib_id  uuid;
BEGIN
  -- Map (context, contribution_type) to rule key
  CASE
    WHEN p_contribution_type = 'pr_merged' AND p_context = 'main_project' THEN
      v_rule_key := 'CONTRIB_PR_MERGED_MAIN';
    WHEN p_contribution_type = 'pr_merged' AND p_context = 'community_plugin' THEN
      v_rule_key := 'CONTRIB_PR_MERGED_COMMUNITY';
    WHEN p_contribution_type = 'pr_merged' AND p_context = 'documentation' THEN
      v_rule_key := 'CONTRIB_PR_MERGED_DOCS';
    WHEN p_contribution_type = 'pr_merged' AND p_context = 'infrastructure' THEN
      v_rule_key := 'CONTRIB_PR_MERGED_COMMUNITY';  -- treat infra same as community
    WHEN p_contribution_type = 'issue_filed' THEN
      v_rule_key := 'CONTRIB_ISSUE_FILED';
    WHEN p_contribution_type = 'review_given' THEN
      v_rule_key := 'CONTRIB_REVIEW_GIVEN';
    ELSE
      RAISE EXCEPTION 'Unknown contribution type: % / %', p_context, p_contribution_type;
  END CASE;

  -- Award XP via the standard pipeline (source = 'contribution', tracked under forum app)
  PERFORM xp.apply(
    p_lenser_id       := p_lenser_id,
    p_rule_key        := v_rule_key,
    p_source          := 'contribution'::xp.source_enum,
    p_source_ref_type := 'contribution',
    p_source_ref_id   := NULL,
    p_app_id          := '00000000-0000-0000-0000-000000000001'::uuid
  );

  -- Fetch the event just created (most recent for this lenser + rule)
  SELECT id INTO v_event_id
  FROM xp.events
  WHERE lenser_id  = p_lenser_id
    AND action_key = v_rule_key
  ORDER BY created_at DESC
  LIMIT 1;

  -- Record the contribution
  INSERT INTO xp.contributions (
    lenser_id, context, contribution_type,
    external_ref, title, verified_by,
    xp_event_id, metadata
  )
  VALUES (
    p_lenser_id, p_context, p_contribution_type,
    p_external_ref, p_title, 'system',
    v_event_id, p_metadata
  )
  RETURNING id INTO v_contrib_id;

  RETURN v_contrib_id;
END;
$$;


ALTER FUNCTION "xp"."grant_contribution_xp"("p_lenser_id" "uuid", "p_context" "xp"."contribution_context_enum", "p_contribution_type" "text", "p_external_ref" "text", "p_title" "text", "p_metadata" "jsonb") OWNER TO "postgres";


