CREATE OR REPLACE FUNCTION "xp"."trg_ai_lenser_battle_xp_fn"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'battles', 'agents', 'xp', 'lensers', 'public'
    AS $$
DECLARE
  v_contender    record;
  v_owner_id     uuid;
  v_is_winner    boolean;
  v_enter_rule   uuid;
  v_win_rule     uuid;
  v_owner_enter  uuid;
  v_owner_win    uuid;
  v_app_id       uuid := '00000000-0000-0000-0000-000000000002';
BEGIN
  -- Only act on finalization (status 'closed' is the finalization status)
  IF NEW.status <> 'closed' OR OLD.status = 'closed' THEN
    RETURN NEW;
  END IF;

  -- Resolve rule IDs
  SELECT id INTO v_enter_rule FROM xp.rules
    WHERE app_id = v_app_id AND action_key = 'AI_LENSER_BATTLE_ENTERED' LIMIT 1;
  SELECT id INTO v_win_rule FROM xp.rules
    WHERE app_id = v_app_id AND action_key = 'AI_LENSER_BATTLE_WON' LIMIT 1;
  SELECT id INTO v_owner_enter FROM xp.rules
    WHERE app_id = v_app_id AND action_key = 'AI_LENSER_OWNER_BATTLE_ENTERED' LIMIT 1;
  SELECT id INTO v_owner_win FROM xp.rules
    WHERE app_id = v_app_id AND action_key = 'AI_LENSER_OWNER_BATTLE_WON' LIMIT 1;

  -- Process each AI contender
  FOR v_contender IN
    SELECT c.id, c.contender_ref_id, cem.ai_lenser_id, cem.profile_id
    FROM battles.contenders c
    JOIN battles.contender_entity_map cem ON cem.contender_id = c.id
    WHERE c.battle_id = NEW.id
      AND c.contender_type IN ('ai_model', 'ai_agent')
      AND cem.ai_lenser_id IS NOT NULL
  LOOP
    v_is_winner := (NEW.winner_contender_id = v_contender.id);

    -- Find the human owner of this AI Lenser
    SELECT o.owner_lenser_id INTO v_owner_id
    FROM agents.ownerships o
    WHERE o.ai_lenser_id = v_contender.ai_lenser_id
      AND o.role = 'owner'
      AND o.revoked_at IS NULL
    LIMIT 1;

    -- Award battle entry XP to AI Lenser's profile
    IF v_enter_rule IS NOT NULL THEN
      INSERT INTO xp.events (lenser_id, app_id, rule_id, action_key, xp, base_xp, source, source_ref_type, source_ref_id)
      SELECT
        al.profile_id, v_app_id, v_enter_rule, 'AI_LENSER_BATTLE_ENTERED',
        20 * coalesce(dm.multiplier, 1.0), 20,
        'action', 'battle', NEW.id
      FROM agents.ai_lensers al
      LEFT JOIN xp.difficulty_multipliers dm ON dm.difficulty = 'hard'
      WHERE al.id = v_contender.ai_lenser_id;
    END IF;

    -- Award battle win XP to AI Lenser
    IF v_is_winner AND v_win_rule IS NOT NULL THEN
      INSERT INTO xp.events (lenser_id, app_id, rule_id, action_key, xp, base_xp, source, source_ref_type, source_ref_id)
      SELECT
        al.profile_id, v_app_id, v_win_rule, 'AI_LENSER_BATTLE_WON',
        50 * coalesce(dm.multiplier, 1.0), 50,
        'action', 'battle', NEW.id
      FROM agents.ai_lensers al
      LEFT JOIN xp.difficulty_multipliers dm ON dm.difficulty = 'legendary'
      WHERE al.id = v_contender.ai_lenser_id;
    END IF;

    -- Award shared XP to human owner
    IF v_owner_id IS NOT NULL THEN
      IF v_owner_enter IS NOT NULL THEN
        INSERT INTO xp.events (lenser_id, app_id, rule_id, action_key, xp, base_xp, source, source_ref_type, source_ref_id)
        SELECT
          v_owner_id, v_app_id, v_owner_enter, 'AI_LENSER_OWNER_BATTLE_ENTERED',
          10 * coalesce(dm.multiplier, 1.0), 10,
          'action', 'battle', NEW.id
        FROM xp.difficulty_multipliers dm WHERE dm.difficulty = 'standard';
      END IF;

      IF v_is_winner AND v_owner_win IS NOT NULL THEN
        INSERT INTO xp.events (lenser_id, app_id, rule_id, action_key, xp, base_xp, source, source_ref_type, source_ref_id)
        SELECT
          v_owner_id, v_app_id, v_owner_win, 'AI_LENSER_OWNER_BATTLE_WON',
          25 * coalesce(dm.multiplier, 1.0), 25,
          'action', 'battle', NEW.id
        FROM xp.difficulty_multipliers dm WHERE dm.difficulty = 'hard';
      END IF;
    END IF;
  END LOOP;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "xp"."trg_ai_lenser_battle_xp_fn"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "xp"."update_daily_streak"("p_lenser_id" "uuid", "p_app_id" "uuid", "p_streak_type" "text", "p_event_date" "date") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'xp', 'lensers', 'public'
    AS $$
DECLARE
  v_current  integer := 0;
  v_longest  integer := 0;
  v_last     date    := NULL;
  v_new_current integer;
  v_new_longest integer;
BEGIN
  -- Fetch existing streak (may not exist)
  BEGIN
    SELECT current_streak, longest_streak, last_occurrence_at
    INTO v_current, v_longest, v_last
    FROM xp.streaks
    WHERE lenser_id  = p_lenser_id
      AND app_id     = p_app_id
      AND streak_type = p_streak_type
    FOR UPDATE;
  EXCEPTION
    WHEN NO_DATA_FOUND THEN
      v_current := 0;
      v_longest := 0;
      v_last    := NULL;
  END;

  -- Calculate new streak
  IF v_last IS NULL THEN
    v_new_current := 1;
  ELSIF p_event_date = v_last THEN
    v_new_current := v_current;  -- same day, keep
  ELSIF p_event_date = v_last + 1 THEN
    v_new_current := v_current + 1;
  ELSE
    v_new_current := 1;  -- streak broken
  END IF;

  v_new_longest := GREATEST(COALESCE(v_longest, 0), v_new_current);

  -- Upsert streak record
  INSERT INTO xp.streaks (
    lenser_id, app_id, streak_type,
    current_streak, longest_streak, last_occurrence_at, updated_at
  )
  VALUES (
    p_lenser_id, p_app_id, p_streak_type,
    v_new_current, v_new_longest, p_event_date, now()
  )
  ON CONFLICT (lenser_id, app_id, streak_type)
  DO UPDATE SET
    current_streak    = EXCLUDED.current_streak,
    longest_streak    = EXCLUDED.longest_streak,
    last_occurrence_at = EXCLUDED.last_occurrence_at,
    updated_at        = EXCLUDED.updated_at;
END;
$$;


ALTER FUNCTION "xp"."update_daily_streak"("p_lenser_id" "uuid", "p_app_id" "uuid", "p_streak_type" "text", "p_event_date" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "xp"."update_season_totals"("p_app_id" "uuid", "p_lenser_id" "uuid", "p_xp" bigint) RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'xp', 'lensers', 'public'
    AS $$declare
  v_season_id uuid;
begin
  -- aktif sezon var mı?
  v_season_id := xp.get_active_season_id(p_app_id);

  if v_season_id is null then
    return; -- aktif sezon yoksa işlem yapma
  end if;

  -- totals güncelle
  insert into xp.season_totals (season_id, app_id, lenser_id, total_xp)
  values (v_season_id, p_app_id, p_lenser_id, p_xp)
  on conflict (season_id, app_id, lenser_id)
  do update set total_xp = xp.season_totals.total_xp + excluded.total_xp;
end;$$;


ALTER FUNCTION "xp"."update_season_totals"("p_app_id" "uuid", "p_lenser_id" "uuid", "p_xp" bigint) OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "xp"."verify_signature"("p_signature" "text", "p_payload" "jsonb") RETURNS boolean
    LANGUAGE "plpgsql"
    SET "search_path" TO 'xp', 'public'
    AS $$BEGIN
  -- Temporary placeholder until signature verification is implemented.
  IF p_signature IS NULL THEN
    RETURN false;
  END IF;
  RETURN true;
END;$$;


