    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


ALTER TABLE "agents"."tool_profiles" OWNER TO "postgres";


CREATE OR REPLACE VIEW "agents"."v_agent_profile" AS
 SELECT "a"."id",
    "a"."id" AS "ai_lenser_id",
    "a"."profile_id",
    "p"."handle",
    "p"."display_name",
    "p"."avatar_url",
    "p"."type" AS "lenser_type",
    "a"."runtime_pref",
    "a"."is_active",
    "a"."suspended_at",
    "a"."suspended_reason",
    "a"."personality_note",
    "a"."created_at",
    "pol"."can_join_battles",
    "pol"."can_vote",
    "pol"."can_create_battles",
    "pol"."can_receive_sponsorship",
    "pol"."model_binding_mode",
    "pol"."max_daily_battles",
    "pol"."max_daily_votes",
    "pol"."spending_limit_credits",
    "pol"."allowed_battle_types",
    "pol"."is_public_policy",
    ( SELECT "count"(*) AS "count"
           FROM "agents"."model_bindings" "mb"
          WHERE ("mb"."ai_lenser_id" = "a"."id")) AS "model_count",
    ( SELECT "count"(*) AS "count"
           FROM "agents"."lens_bindings" "lb"
          WHERE ("lb"."ai_lenser_id" = "a"."id")) AS "lens_count",
    COALESCE("qs"."battles_used", 0) AS "battles_used",
    COALESCE("qs"."votes_used", 0) AS "votes_used",
    COALESCE("qs"."credits_spent", (0)::bigint) AS "credits_spent",
    "own"."owner_lenser_id",
    "op"."handle" AS "owner_handle",
    "op"."display_name" AS "owner_display_name",
    "op"."avatar_url" AS "owner_avatar_url",
    COALESCE(( SELECT "count"(*) AS "count"
           FROM ("battles"."contenders" "c"
             JOIN "battles"."battles" "b" ON (("b"."id" = "c"."battle_id")))
          WHERE (("c"."contender_ref_id" = "a"."id") AND ("b"."status" = ANY (ARRAY['published'::"battles"."battle_status_enum", 'closed'::"battles"."battle_status_enum"])))), (0)::bigint) AS "total_battles",
    COALESCE(( SELECT "count"(*) AS "count"
           FROM ("battles"."contenders" "c"
             JOIN "battles"."battles" "b" ON (("b"."id" = "c"."battle_id")))
          WHERE (("c"."contender_ref_id" = "a"."id") AND ("b"."winner_contender_id" = "c"."id"))), (0)::bigint) AS "battles_won",
    COALESCE(( SELECT "count"(*) AS "count"
           FROM ("battles"."contenders" "c"
             JOIN "battles"."battles" "b" ON (("b"."id" = "c"."battle_id")))
          WHERE (("c"."contender_ref_id" = "a"."id") AND ("b"."status" = ANY (ARRAY['published'::"battles"."battle_status_enum", 'closed'::"battles"."battle_status_enum"])) AND ("b"."winner_contender_id" IS NOT NULL) AND ("b"."winner_contender_id" <> "c"."id"))), (0)::bigint) AS "battles_lost",
    "round"((((COALESCE(( SELECT "count"(*) AS "count"
           FROM ("battles"."contenders" "c"
             JOIN "battles"."battles" "b" ON (("b"."id" = "c"."battle_id")))
          WHERE (("c"."contender_ref_id" = "a"."id") AND ("b"."winner_contender_id" = "c"."id"))), (0)::bigint))::numeric * 100.0) / (NULLIF(COALESCE(( SELECT "count"(*) AS "count"
           FROM ("battles"."contenders" "c"
             JOIN "battles"."battles" "b" ON (("b"."id" = "c"."battle_id")))
          WHERE (("c"."contender_ref_id" = "a"."id") AND ("b"."status" = ANY (ARRAY['published'::"battles"."battle_status_enum", 'closed'::"battles"."battle_status_enum"])))), (0)::bigint), 0))::numeric), 1) AS "win_rate"
   FROM ((((("agents"."ai_lensers" "a"
     JOIN "lensers"."profiles" "p" ON (("p"."id" = "a"."profile_id")))
     LEFT JOIN "agents"."policies" "pol" ON (("pol"."ai_lenser_id" = "a"."id")))
     LEFT JOIN "agents"."quota_snapshots" "qs" ON ((("qs"."ai_lenser_id" = "a"."id") AND ("qs"."period_date" = CURRENT_DATE))))
     LEFT JOIN "agents"."ownerships" "own" ON ((("own"."ai_lenser_id" = "a"."id") AND ("own"."role" = 'owner'::"text") AND ("own"."revoked_at" IS NULL))))
     LEFT JOIN "lensers"."profiles" "op" ON (("op"."id" = "own"."owner_lenser_id")));


ALTER VIEW "agents"."v_agent_profile" OWNER TO "postgres";


COMMENT ON VIEW "agents"."v_agent_profile" IS 'Full AI Lenser management profile. Includes personality_note, battle stats, policy, quota, and ownership fields. Uses owner join to enable human-owner auth checks in SECURITY DEFINER RPCs.';



CREATE OR REPLACE VIEW "agents"."v_gateway_device_health" AS
 SELECT "d"."device_id",
    "d"."owner_id",
    "d"."hostname",
    "d"."daemon_version",
    "d"."last_seen_at",
    "d"."approved_at",
    "d"."revoked_at",
    "d"."kill_switch",
    "d"."created_at",
    COALESCE("c"."pending_commands", (0)::bigint) AS "pending_commands",
    COALESCE("c"."unacked_commands", (0)::bigint) AS "unacked_commands"
   FROM ("agents"."gateway_devices" "d"
     LEFT JOIN LATERAL ( SELECT "count"(*) FILTER (WHERE ("gc"."claimed_at" IS NULL)) AS "pending_commands",
            "count"(*) FILTER (WHERE ("gc"."acked_at" IS NULL)) AS "unacked_commands"
           FROM "agents"."gateway_commands" "gc"
          WHERE ("gc"."device_id" = "d"."device_id")) "c" ON (true));


ALTER VIEW "agents"."v_gateway_device_health" OWNER TO "postgres";


COMMENT ON VIEW "agents"."v_gateway_device_health" IS 'Phase BE: per-device daemon health snapshot (heartbeat + outbox depth).';



CREATE TABLE IF NOT EXISTS "lenses"."workflow_schedules" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "workflow_id" "uuid" NOT NULL,
    "cron_expr" "text" NOT NULL,
    "global_model_id" "text",
    "inputs_template" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "is_active" boolean DEFAULT true NOT NULL,
    "last_run_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "last_run_id" "uuid",
    "last_dispatch_status" "text",
    "last_error_at" timestamp with time zone,
    "last_error_message" "text",
    "timezone" "text" DEFAULT 'UTC'::"text" NOT NULL,
    "next_run_at" timestamp with time zone,
    "assignee_type" "text" DEFAULT 'agent'::"text" NOT NULL,
    "assignee_id" "uuid",
    "workflow_assignment_id" "uuid",
    "approval_policy" "jsonb" DEFAULT '{"requiresApproval": true}'::"jsonb" NOT NULL,
    "retry_policy" "jsonb" DEFAULT '{"maxRetries": 1}'::"jsonb" NOT NULL,
    "failure_policy" "jsonb" DEFAULT '{"mode": "isolate"}'::"jsonb" NOT NULL,
    "queue_policy" "jsonb" DEFAULT '{"mode": "parallel"}'::"jsonb" NOT NULL,
    "last_completed_at" timestamp with time zone,
    "last_result" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "description" "text",
    "calendar_id" "uuid",
    "pre_dispatch_condition" "jsonb",
    "inputs_rotation" "jsonb",
    "last_rotation_index" integer DEFAULT 0 NOT NULL,
    CONSTRAINT "workflow_schedules_assignee_type_check" CHECK (("assignee_type" = ANY (ARRAY['agent'::"text", 'team'::"text"])))
);


ALTER TABLE "lenses"."workflow_schedules" OWNER TO "postgres";


COMMENT ON TABLE "lenses"."workflow_schedules" IS 'CRON schedules for automated workflow runs. RLS: SELECT is scoped to owning lenser; writes must go through fn_upsert_workflow_schedule.';



COMMENT ON COLUMN "lenses"."workflow_schedules"."last_run_id" IS 'Most recent workflow_runs.id dispatched by this schedule.';



COMMENT ON COLUMN "lenses"."workflow_schedules"."last_dispatch_status" IS 'Best-effort scheduler status: dispatched, skipped_overlap, validation_failed, or dispatch_failed.';



COMMENT ON COLUMN "lenses"."workflow_schedules"."last_error_at" IS 'Timestamp of the most recent schedule dispatch failure or validation skip.';



COMMENT ON COLUMN "lenses"."workflow_schedules"."last_error_message" IS 'Human-readable reason for the most recent schedule dispatch failure/skip.';



COMMENT ON COLUMN "lenses"."workflow_schedules"."timezone" IS 'IANA timezone used for CRON evaluation and next-run display.';



COMMENT ON COLUMN "lenses"."workflow_schedules"."assignee_type" IS 'Whether this schedule targets a single agent or an agent team.';



COMMENT ON COLUMN "lenses"."workflow_schedules"."assignee_id" IS 'Polymorphic target identifier. Resolves to agents.ai_lensers.id for agent schedules or agents.teams.id for team schedules.';



COMMENT ON COLUMN "lenses"."workflow_schedules"."workflow_assignment_id" IS 'Optional explicit workflow assignment backing this schedule.';



COMMENT ON COLUMN "lenses"."workflow_schedules"."calendar_id" IS 'Phase W1: optional calendar overlay (skip_dates / only_dates). NULL = no overlay. ON DELETE SET NULL so deleting a calendar does not cascade-delete schedules.';



COMMENT ON COLUMN "lenses"."workflow_schedules"."pre_dispatch_condition" IS 'Phase W2: optional jsonb condition evaluated by automation.fn_eval_filter against lenses.fn_build_schedule_condition_context(...). NULL = no condition. Same DSL as Phase U trigger rules (JSON-Pointer + eq/neq/gt/lt/contains).';



COMMENT ON COLUMN "lenses"."workflow_schedules"."inputs_rotation" IS 'Phase W3: optional jsonb array of input templates. When non-empty, the dispatcher rotates through entries using last_rotation_index. NULL or empty = use inputs_template.';



COMMENT ON COLUMN "lenses"."workflow_schedules"."last_rotation_index" IS 'Phase W3: monotonic counter incremented each tick the rotation array is used. The selected entry index is (last_rotation_index % array_length). Reset to 0 by the operator if the rotation array shape changes.';



CREATE OR REPLACE VIEW "agents"."v_human_fleet_overview" AS
 SELECT "o"."owner_lenser_id" AS "human_lenser_id",
    "count"(DISTINCT "al"."id") AS "agents_total",
    "count"(DISTINCT "al"."id") FILTER (WHERE ("al"."is_active" AND ("al"."suspended_at" IS NULL))) AS "agents_active",
    COALESCE("sum"("qs"."credits_spent"), (0)::numeric) AS "credits_30d",
    "count"(DISTINCT "tr"."id") FILTER (WHERE ("tr"."created_at" >= ("now"() - '24:00:00'::interval))) AS "runs_24h",
    "count"(DISTINCT "tr"."id") FILTER (WHERE ("tr"."approval_status" = 'pending'::"text")) AS "approvals_pending",
    "count"(DISTINCT "ws"."id") FILTER (WHERE "ws"."is_active") AS "schedules_active"
   FROM (((("agents"."ownerships" "o"
     JOIN "agents"."ai_lensers" "al" ON (("al"."id" = "o"."ai_lenser_id")))
     LEFT JOIN "agents"."team_runs" "tr" ON (("tr"."ai_lenser_id" = "al"."id")))
     LEFT JOIN "agents"."quota_snapshots" "qs" ON ((("qs"."ai_lenser_id" = "al"."id") AND ("qs"."period_date" >= (CURRENT_DATE - '30 days'::interval)))))
     LEFT JOIN "lenses"."workflow_schedules" "ws" ON (((("ws"."assignee_type" = 'agent'::"text") AND ("ws"."assignee_id" = "al"."id")) OR (("ws"."assignee_type" = 'team'::"text") AND ("ws"."assignee_id" IN ( SELECT "t"."id"
           FROM "agents"."teams" "t"
          WHERE ("t"."ai_lenser_id" = "al"."id")))))))
  GROUP BY "o"."owner_lenser_id";


ALTER VIEW "agents"."v_human_fleet_overview" OWNER TO "postgres";


COMMENT ON VIEW "agents"."v_human_fleet_overview" IS 'Per-human-owner fleet aggregations across owned agents. Used by the human-mode Overview section.';



CREATE TABLE IF NOT EXISTS "lenses"."workflow_runs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "workflow_id" "uuid" NOT NULL,
    "triggered_by" "uuid",
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "context_inputs" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "started_at" timestamp with time zone,
    "completed_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "global_model_id" "text",
    "budget_credits" integer,
    "spent_credits" integer DEFAULT 0 NOT NULL,
    "cost_metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "idempotency_key" "text",
    "heartbeat_at" timestamp with time zone,
    "run_worker_id" "text",
    "parent_run_id" "uuid",
    "recursion_depth" integer DEFAULT 0 NOT NULL,
    "schedule_id" "uuid",
    "trigger_mode" "text" DEFAULT 'manual'::"text" NOT NULL,
    "active_node_id" "uuid",
    "scheduled_for" timestamp with time zone,
    "ai_lenser_id" "uuid",
    "metadata" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "media_manifest" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "idempotency_expires_at" timestamp with time zone,
    CONSTRAINT "wf_runs_budget_nonneg" CHECK ((("budget_credits" IS NULL) OR ("budget_credits" >= 0))),
    CONSTRAINT "wf_runs_recursion_depth_cap" CHECK ((("recursion_depth" >= 0) AND ("recursion_depth" <= 8))),
    CONSTRAINT "wf_runs_spent_nonneg" CHECK (("spent_credits" >= 0)),
    CONSTRAINT "wf_runs_timestamp_order" CHECK ((("completed_at" IS NULL) OR ("started_at" IS NULL) OR ("completed_at" >= "started_at"))),
    CONSTRAINT "workflow_runs_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'validated'::"text", 'queued'::"text", 'pending'::"text", 'running'::"text", 'streaming'::"text", 'recovered'::"text", 'completed'::"text", 'failed'::"text", 'cancelled'::"text", 'timed_out'::"text"]))),
    CONSTRAINT "workflow_runs_trigger_mode_check" CHECK (("trigger_mode" = ANY (ARRAY['manual'::"text", 'schedule'::"text", 'subflow'::"text"])))
);


ALTER TABLE "lenses"."workflow_runs" OWNER TO "postgres";


COMMENT ON TABLE "lenses"."workflow_runs" IS 'A single execution of a workflow. The CF Worker drives status transitions. context_inputs holds root-level input values for nodes with no incoming edges.';



COMMENT ON COLUMN "lenses"."workflow_runs"."global_model_id" IS 'Default AI model for this run. Individual nodes can override via workflow_nodes.config.model_id.';



COMMENT ON COLUMN "lenses"."workflow_runs"."budget_credits" IS 'Maximum credits allowed for this run. NULL = unlimited.';



COMMENT ON COLUMN "lenses"."workflow_runs"."spent_credits" IS 'Total credits spent so far across all completed nodes.';



COMMENT ON COLUMN "lenses"."workflow_runs"."cost_metadata" IS 'Per-node cost breakdown: { node_id: { input_tokens, output_tokens, cost_credits } }';



COMMENT ON COLUMN "lenses"."workflow_runs"."idempotency_key" IS 'Client-derived sha256(workflow_id || rootInputsCanonicalJson). Prevents double-trigger when the UI retries a submit.';



COMMENT ON COLUMN "lenses"."workflow_runs"."heartbeat_at" IS 'Last heartbeat from the worker currently owning this run. NULL until the first wave begins. Used by the crash-recovery loop (§6.8) to detect stale runs.';



COMMENT ON COLUMN "lenses"."workflow_runs"."run_worker_id" IS 'Opaque identifier for the worker process that currently owns this run. Set by fn_claim_stale_workflow_run; cleared on terminal statuses.';



COMMENT ON COLUMN "lenses"."workflow_runs"."parent_run_id" IS 'Parent workflow_runs.id when this run was spawned by an orchestration lens subflow. NULL for top-level runs.';



COMMENT ON COLUMN "lenses"."workflow_runs"."recursion_depth" IS 'Depth of this run in the orchestration lens chain (0 = top-level). Capped at 8 to prevent runaway subflows (Phase 9 §Orchestration is bounded).';



COMMENT ON COLUMN "lenses"."workflow_runs"."schedule_id" IS 'Owning workflow_schedules.id when the run was dispatched by the scheduler. NULL for manual runs.';



COMMENT ON COLUMN "lenses"."workflow_runs"."trigger_mode" IS 'How the workflow run was triggered: manual, schedule, or subflow.';



COMMENT ON COLUMN "lenses"."workflow_runs"."active_node_id" IS 'The node currently executing for this run (or the most recently active one). Written by fn_update_workflow_node_result whenever a node enters running/streaming/retrying. NULL on terminal runs.';



COMMENT ON COLUMN "lenses"."workflow_runs"."scheduled_for" IS 'Normalized schedule slot (minute precision) that produced this run. NULL for manual or subflow runs.';



COMMENT ON COLUMN "lenses"."workflow_runs"."ai_lenser_id" IS 'The AI lenser acting as the run executor. NULL when the run is created directly by the
   human workspace. Populated by scheduled dispatch and by agent-context executions.';



COMMENT ON COLUMN "lenses"."workflow_runs"."metadata" IS 'Free-form per-run metadata. Reserved keys: backfill_id (for Phase Q1 replay dedup) and origin (e.g. ''backfill'', ''manual'').';



COMMENT ON COLUMN "lenses"."workflow_runs"."media_manifest" IS 'AP: Ordered list of media produced by this run. Each entry: {object_id, media_type, mime_type, node_id, added_at}. Populated by fn_append_workflow_run_media via WorkflowExecutionService.';



COMMENT ON COLUMN "lenses"."workflow_runs"."idempotency_expires_at" IS 'D4: idempotency window. After this time the (workflow_id, idempotency_key) lookup ignores this row, allowing a fresh run with the same key.';



COMMENT ON CONSTRAINT "workflow_runs_status_check" ON "lenses"."workflow_runs" IS 'Aligns with the engine state machine (Phase 1 §5). `recovered` is a transient status written by the crash-recovery loop before the run resumes. Terminal states: completed, failed, cancelled, timed_out.';



CREATE OR REPLACE VIEW "agents"."v_run_unified" AS
 SELECT "tr"."id" AS "run_id",
    'team'::"text" AS "run_type",
    "tr"."ai_lenser_id",
    "tr"."status",
    "tr"."approval_status",
    COALESCE("ti_agg"."total_cost", (0)::numeric) AS "total_cost",
    COALESCE("step_agg"."step_count", (0)::bigint) AS "step_count",
    COALESCE("mem_agg"."memory_write_count", (0)::bigint) AS "memory_write_count",
    "eval_agg"."latest_score" AS "latest_evaluation_score",
    "tr"."started_at",
    "tr"."completed_at",
        CASE
            WHEN (("tr"."started_at" IS NOT NULL) AND ("tr"."completed_at" IS NOT NULL)) THEN EXTRACT(epoch FROM ("tr"."completed_at" - "tr"."started_at"))
            ELSE NULL::numeric
        END AS "duration_seconds"
   FROM (((("agents"."team_runs" "tr"
     LEFT JOIN ( SELECT "tool_invocations"."team_run_id",
            "sum"("tool_invocations"."cost_estimate") AS "total_cost"
           FROM "agents"."tool_invocations"
          GROUP BY "tool_invocations"."team_run_id") "ti_agg" ON (("ti_agg"."team_run_id" = "tr"."id")))
     LEFT JOIN ( SELECT "agent_run_steps"."team_run_id",
            "count"(*) AS "step_count"
           FROM "agents"."agent_run_steps"
          GROUP BY "agent_run_steps"."team_run_id") "step_agg" ON (("step_agg"."team_run_id" = "tr"."id")))
     LEFT JOIN ( SELECT "memories"."team_run_id",
            "count"(*) AS "memory_write_count"
           FROM "agents"."memories"
          WHERE ("memories"."source" = ANY (ARRAY['agent'::"text", 'tool'::"text"]))
          GROUP BY "memories"."team_run_id") "mem_agg" ON (("mem_agg"."team_run_id" = "tr"."id")))
     LEFT JOIN LATERAL ( SELECT "er"."score" AS "latest_score"
           FROM ("agents"."evaluation_runs" "er"
             JOIN "agents"."evaluations" "e" ON (("e"."id" = "er"."evaluation_id")))
          WHERE (("e"."target_type" = 'workflow'::"text") AND ("e"."target_id" = "tr"."workflow_id") AND ("er"."status" = 'completed'::"text"))
          ORDER BY "er"."completed_at" DESC NULLS LAST
         LIMIT 1) "eval_agg" ON (true))
  WHERE (("tr"."workflow_id" IS NOT NULL) AND "agents"."can_manage_ai_lenser"("tr"."ai_lenser_id"))
UNION ALL
 SELECT "wr"."id" AS "run_id",
    'workflow'::"text" AS "run_type",
    "wr"."ai_lenser_id",
    "wr"."status",
    NULL::"text" AS "approval_status",
    COALESCE("wr"."spent_credits", 0) AS "total_cost",
    0 AS "step_count",
    0 AS "memory_write_count",
    NULL::numeric AS "latest_evaluation_score",
    "wr"."started_at",
    "wr"."completed_at",
        CASE
            WHEN (("wr"."started_at" IS NOT NULL) AND ("wr"."completed_at" IS NOT NULL)) THEN EXTRACT(epoch FROM ("wr"."completed_at" - "wr"."started_at"))
            ELSE NULL::numeric
        END AS "duration_seconds"
   FROM "lenses"."workflow_runs" "wr"
  WHERE (("wr"."ai_lenser_id" IS NOT NULL) AND (NOT (EXISTS ( SELECT 1
           FROM "agents"."team_runs" "tr2"
          WHERE ("tr2"."workflow_run_id" = "wr"."id")))) AND "agents"."can_manage_ai_lenser"("wr"."ai_lenser_id"));


ALTER VIEW "agents"."v_run_unified" OWNER TO "postgres";


CREATE OR REPLACE VIEW "agents"."v_team_run_conversation" WITH ("security_invoker"='on') AS
 WITH RECURSIVE "thread" AS (
         SELECT "m"."team_run_id",
            "m"."id" AS "message_id",
            "m"."parent_message_id",
            "m"."from_agent_id",
            "m"."to_agent_id",
            "m"."kind",
            "m"."payload",
            "m"."occurred_at",
            0 AS "depth"
           FROM "agents"."team_messages" "m"
          WHERE ("m"."parent_message_id" IS NULL)
        UNION ALL
         SELECT "m"."team_run_id",
            "m"."id",
            "m"."parent_message_id",
            "m"."from_agent_id",
            "m"."to_agent_id",
            "m"."kind",
            "m"."payload",
            "m"."occurred_at",
            ("t"."depth" + 1)
           FROM ("agents"."team_messages" "m"
             JOIN "thread" "t" ON ((("m"."parent_message_id" = "t"."message_id") AND ("m"."team_run_id" = "t"."team_run_id"))))
          WHERE ("t"."depth" < 50)
        )
 SELECT "team_run_id",
    "message_id",
    "parent_message_id",
    "from_agent_id",
    "to_agent_id",
    "kind",
    "payload",
    "occurred_at",
    "depth"
   FROM "thread";


ALTER VIEW "agents"."v_team_run_conversation" OWNER TO "postgres";


COMMENT ON VIEW "agents"."v_team_run_conversation" IS 'Phase X1 (hardened): security_invoker=on. SELECT through this view is evaluated under the caller''s RLS context against agents.team_messages.';



