    CONSTRAINT "ai_handicap_policies_injected_delay_ms_check" CHECK (("injected_delay_ms" >= 0)),
    CONSTRAINT "ai_handicap_policies_max_context_tokens_check" CHECK ((("max_context_tokens" IS NULL) OR ("max_context_tokens" > 0))),
