);


ALTER TABLE "battles"."ai_handicap_policies" OWNER TO "postgres";


COMMENT ON TABLE "battles"."ai_handicap_policies" IS 'Per-battle AI handicap configuration. Consumed by the CF Worker execution proxy. NULL fields on each axis = no restriction applied. Standard fair defaults for human_vs_ai: injected_delay_ms=2000, time_budget_ms=300000.';



