CREATE TABLE IF NOT EXISTS "execution"."requests" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "requester_lenser_id" "uuid" NOT NULL,
    "origin_type" "text" NOT NULL,
    "origin_id" "uuid",
    "model_id" "uuid",
    "lens_id" "uuid",
    "input_snapshot" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "runtime_origin" "text" DEFAULT 'cloud'::"text" NOT NULL,
    "funding_source" "text" DEFAULT 'platform_credit'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "byok_key_ref_id" "uuid",
    "is_active" boolean DEFAULT true NOT NULL,
    "version_id" "uuid",
    "workspace_id" "uuid",
    "idempotency_key" "text",
    "output_modality" "text",
    CONSTRAINT "requests_funding_source_check" CHECK (("funding_source" = ANY (ARRAY['user_byok_cloud'::"text", 'user_byok_local'::"text", 'platform_credit'::"text", 'sponsored'::"text"]))),
    CONSTRAINT "requests_output_modality_check" CHECK (("output_modality" = ANY (ARRAY['text'::"text", 'image'::"text", 'video'::"text", 'audio'::"text", 'music'::"text"]))),
    CONSTRAINT "requests_runtime_origin_check" CHECK (("runtime_origin" = ANY (ARRAY['cloud'::"text", 'local'::"text", 'hybrid'::"text", 'offline_import'::"text"])))
);


ALTER TABLE "execution"."requests" OWNER TO "postgres";


COMMENT ON COLUMN "execution"."requests"."byok_key_ref_id" IS 'FK to agents.byok_key_refs when funding_source=user_byok_cloud. NULL for platform_credit, user_byok_local (key never reaches cloud DB), or sponsored.';



COMMENT ON COLUMN "execution"."requests"."is_active" IS 'Soft-delete flag. Set to false instead of hard-deleting.';



COMMENT ON COLUMN "execution"."requests"."version_id" IS 'The specific lens version this request was made against. Moved from execution.ray_runs (2026-03-25). NULL for requests created before versioning or without a lens context.';



COMMENT ON COLUMN "execution"."requests"."workspace_id" IS 'Tenant boundary for this execution request. Resolved at request time from the lenser''s active workspace (personal workspace for solo users; org workspace when executing on behalf of an organization). NULL for legacy requests pre-workspace-scoping.';



COMMENT ON COLUMN "execution"."requests"."output_modality" IS 'Output media type requested. NULL means text (backward compat). Set for generative media executions.';



CREATE TABLE IF NOT EXISTS "execution"."runner_device_bindings" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "runner_id" "uuid" NOT NULL,
    "device_id" "uuid" NOT NULL,
    "bound_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "status" "text" DEFAULT 'active'::"text" NOT NULL,
    CONSTRAINT "runner_device_bindings_status_check" CHECK (("status" = ANY (ARRAY['active'::"text", 'paused'::"text", 'revoked'::"text"])))
);


ALTER TABLE "execution"."runner_device_bindings" OWNER TO "postgres";


COMMENT ON TABLE "execution"."runner_device_bindings" IS 'Links a registered runner to a physical trusted device. A runner may be bound to at most one active device at a time. Written only via fn_runner_bind_device.';



CREATE TABLE IF NOT EXISTS "execution"."runners" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "lenser_id" "uuid" NOT NULL,
    "name" "text" NOT NULL,
    "adapter_type" "text" NOT NULL,
    "config" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "is_active" boolean DEFAULT true NOT NULL,
    "last_probed_at" timestamp with time zone,
    "last_probe_status" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "runners_adapter_type_check" CHECK (("adapter_type" = ANY (ARRAY['openai-agents'::"text", 'langchain'::"text", 'crewai'::"text", 'mcp'::"text", 'ollama'::"text", 'http'::"text", 'custom'::"text"]))),
    CONSTRAINT "runners_last_probe_status_check" CHECK (("char_length"("last_probe_status") <= 32)),
    CONSTRAINT "runners_name_check" CHECK ((("char_length"("name") >= 1) AND ("char_length"("name") <= 100)))
);


ALTER TABLE "execution"."runners" OWNER TO "postgres";


COMMENT ON TABLE "execution"."runners" IS 'Workspace runners (adapters) registered by a Lenser. Bound to one or more physical devices via execution.runner_device_bindings. Mutated only via SECURITY DEFINER RPCs.';



CREATE TABLE IF NOT EXISTS "execution"."runs" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "request_id" "uuid" NOT NULL,
    "status" "text" DEFAULT 'queued'::"text" NOT NULL,
    "model_id" "uuid",
    "provider_request_id" "text",
    "execution_hash" "text",
    "input_hash" "text",
    "output_hash" "text",
    "started_at" timestamp with time zone,
    "completed_at" timestamp with time zone,
    "latency_ms" integer,
    "error_code" "text",
    "error_message" "text",
    "cost_estimate" numeric,
    "token_input" integer,
    "token_output" integer,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "credit_cost" bigint,
    "billing_status" "text" DEFAULT 'free'::"text" NOT NULL,
    "is_active" boolean DEFAULT true NOT NULL,
    "response_text" "text",
    "response_meta" "jsonb" DEFAULT '{}'::"jsonb",
    "throttle_applied" boolean DEFAULT false NOT NULL,
    "injected_delay_ms" integer DEFAULT 0 NOT NULL,
    "is_async" boolean DEFAULT false NOT NULL,
    "provider_task_id" "text",
    "last_polled_at" timestamp with time zone,
    CONSTRAINT "runs_billing_status_check" CHECK (("billing_status" = ANY (ARRAY['pending'::"text", 'charged'::"text", 'failed'::"text", 'free'::"text"]))),
    CONSTRAINT "runs_status_check" CHECK (("status" = ANY (ARRAY['queued'::"text", 'running'::"text", 'succeeded'::"text", 'failed'::"text", 'canceled'::"text", 'timed_out'::"text"]))),
    CONSTRAINT "runs_timestamp_order" CHECK ((("completed_at" IS NULL) OR ("started_at" IS NULL) OR ("completed_at" >= "started_at")))
);


ALTER TABLE "execution"."runs" OWNER TO "postgres";


COMMENT ON COLUMN "execution"."runs"."credit_cost" IS 'Platform credits charged for this run. NULL = not billed. Managed by CF Worker (service_role).';



COMMENT ON COLUMN "execution"."runs"."billing_status" IS 'Billing lifecycle: free (default/self-hosted), pending (charge initiated), charged (wallet debited), failed (insufficient balance).';



COMMENT ON COLUMN "execution"."runs"."is_active" IS 'Soft-delete flag. Set to false instead of hard-deleting. Queries should filter WHERE is_active = true by default.';



COMMENT ON COLUMN "execution"."runs"."response_text" IS 'Primary AI response content. Written by the API Worker after provider call completes. NULL for in-progress or failed runs.';



COMMENT ON COLUMN "execution"."runs"."response_meta" IS 'Provider response metadata: model name, finish_reason, provider_request_id, usage stats, etc. Structured as JSONB for provider flexibility.';



COMMENT ON COLUMN "execution"."runs"."throttle_applied" IS 'True if the CF Worker applied a token-rate cap, time deadline, or delay handicap during this run.';



COMMENT ON COLUMN "execution"."runs"."injected_delay_ms" IS 'Actual milliseconds of artificial delay injected by the CF Worker before streaming began.';



COMMENT ON COLUMN "execution"."runs"."is_async" IS 'TRUE for video/audio providers that return a task ID and require polling.';



COMMENT ON COLUMN "execution"."runs"."provider_task_id" IS 'Provider-specific task/job ID returned by async generation APIs (Sora, Veo, Kling, etc).';



COMMENT ON COLUMN "execution"."runs"."last_polled_at" IS 'Set by the async-media-poll-worker each time the provider status endpoint is queried. NULL means the run has not been polled yet. Used for SKIP LOCKED ordering so concurrent workers do not double-poll the same run.';



CREATE TABLE IF NOT EXISTS "execution"."steps" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "run_id" "uuid" NOT NULL,
    "ordinal" integer NOT NULL,
    "step_type" "text" NOT NULL,
    "tool_name" "text",
    "input_snapshot" "jsonb",
    "output_snapshot" "jsonb",
    "input_hash" "text",
    "output_hash" "text",
    "started_at" timestamp with time zone,
    "completed_at" timestamp with time zone,
    "latency_ms" integer,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "step_definition_id" "uuid",
    CONSTRAINT "steps_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'running'::"text", 'succeeded'::"text", 'failed'::"text"]))),
    CONSTRAINT "steps_step_type_check" CHECK (("step_type" = ANY (ARRAY['lens'::"text", 'tool_call'::"text", 'tool_result'::"text", 'model_call'::"text", 'judge_call'::"text", 'retrieval'::"text", 'transform'::"text"])))
);


ALTER TABLE "execution"."steps" OWNER TO "postgres";


COMMENT ON COLUMN "execution"."steps"."step_definition_id" IS 'FK to the lenses.steps definition that spawned this runtime step. NULL for historical runs and ad-hoc steps with no definition. Enables reproducibility diff: what the lens defined vs. what the run executed.';



CREATE TABLE IF NOT EXISTS "execution"."stream_sessions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "run_id" "uuid" NOT NULL,
    "lenser_id" "uuid" NOT NULL,
    "provider" "text" NOT NULL,
    "model_key" "text" NOT NULL,
    "status" "text" DEFAULT 'open'::"text" NOT NULL,
    "bytes_sent" integer DEFAULT 0 NOT NULL,
    "token_input" integer,
    "token_output" integer,
    "credit_cost" bigint,
    "error_code" "text",
    "started_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "completed_at" timestamp with time zone,
    "workspace_id" "uuid",
    CONSTRAINT "stream_sessions_status_check" CHECK (("status" = ANY (ARRAY['open'::"text", 'completed'::"text", 'failed'::"text", 'timed_out'::"text"])))
);


ALTER TABLE "execution"."stream_sessions" OWNER TO "postgres";


COMMENT ON TABLE "execution"."stream_sessions" IS 'One row per /execute/stream request. Tracks SSE lifecycle for observability.';



COMMENT ON COLUMN "execution"."stream_sessions"."run_id" IS 'References execution.runs.id — ties stream session to the billing run.';



COMMENT ON COLUMN "execution"."stream_sessions"."lenser_id" IS 'Denormalized from execution.requests.requester_lenser_id for fast per-user queries.';



COMMENT ON COLUMN "execution"."stream_sessions"."bytes_sent" IS 'Total SSE bytes sent to client before stream closed.';



COMMENT ON COLUMN "execution"."stream_sessions"."workspace_id" IS 'Denormalized workspace_id from execution.requests (via runs). Stored directly for fast per-workspace stream observability queries without joining through runs → requests.';



CREATE TABLE IF NOT EXISTS "execution"."trust_evaluations" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "submission_id" "uuid" NOT NULL,
    "attestation_id" "uuid",
    "trust_level" "text" DEFAULT 'unverified'::"text" NOT NULL,
    "factors" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "evaluated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "trust_evaluations_trust_level_check" CHECK (("trust_level" = ANY (ARRAY['unverified'::"text", 'account_verified'::"text", 'agent_verified'::"text", 'device_verified'::"text", 'runner_verified'::"text", 'execution_verified'::"text", 'fully_trusted'::"text"])))
);


ALTER TABLE "execution"."trust_evaluations" OWNER TO "postgres";


COMMENT ON TABLE "execution"."trust_evaluations" IS 'Computed trust level per battle submission. Updated whenever attestation data changes. One row per submission (UNIQUE constraint).';



CREATE TABLE IF NOT EXISTS "lenses"."workflow_node_results" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "run_id" "uuid" NOT NULL,
    "node_id" "uuid" NOT NULL,
    "execution_run_id" "uuid",
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "output_data" "jsonb",
    "error_message" "text",
    "started_at" timestamp with time zone,
    "completed_at" timestamp with time zone,
    "input_tokens" integer DEFAULT 0 NOT NULL,
    "output_tokens" integer DEFAULT 0 NOT NULL,
    "cost_credits" integer DEFAULT 0 NOT NULL,
    "retry_count" integer DEFAULT 0 NOT NULL,
    "duration_ms" integer,
    "ttfb_ms" integer,
    "waiting_reason" "text",
    CONSTRAINT "ck_lenses_workflow_node_results_retry_count_nonneg" CHECK ((("retry_count" IS NULL) OR ("retry_count" >= 0))),
    CONSTRAINT "wnr_cost_credits_nonneg" CHECK (("cost_credits" >= 0)),
    CONSTRAINT "wnr_duration_ms_nonneg" CHECK ((("duration_ms" IS NULL) OR ("duration_ms" >= 0))),
    CONSTRAINT "wnr_input_tokens_nonneg" CHECK (("input_tokens" >= 0)),
    CONSTRAINT "wnr_output_tokens_nonneg" CHECK (("output_tokens" >= 0)),
    CONSTRAINT "wnr_retry_count_nonneg" CHECK (("retry_count" >= 0)),
    CONSTRAINT "wnr_ttfb_ms_nonneg" CHECK ((("ttfb_ms" IS NULL) OR ("ttfb_ms" >= 0))),
    CONSTRAINT "workflow_node_results_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'awaiting_dependency'::"text", 'queued'::"text", 'running'::"text", 'streaming'::"text", 'retrying'::"text", 'completed'::"text", 'failed'::"text", 'cancelled'::"text", 'skipped'::"text", 'timed_out'::"text", 'blocked'::"text", 'invalidated'::"text"])))
);


ALTER TABLE "lenses"."workflow_node_results" OWNER TO "postgres";


COMMENT ON TABLE "lenses"."workflow_node_results" IS 'Per-node execution result for a workflow run. Seeded with status=pending by fn_start_workflow_run. The CF Worker updates status and output_data as nodes complete. Realtime subscriptions on this table drive the live progress UI.';



COMMENT ON COLUMN "lenses"."workflow_node_results"."retry_count" IS 'Number of provider retries consumed for this node. 0 on first success; increments each time NodeRuntime applies a retry policy before terminal success/failure.';



COMMENT ON COLUMN "lenses"."workflow_node_results"."duration_ms" IS 'Wall-clock duration of the final (successful or terminal) provider attempt, in milliseconds. NULL when the node is skipped/blocked before any attempt.';



COMMENT ON COLUMN "lenses"."workflow_node_results"."ttfb_ms" IS 'Time-to-first-byte on streamed nodes, in milliseconds. Written from the first `partial` chunk observed by NodeRuntime; NULL for non-streaming lenses.';



COMMENT ON COLUMN "lenses"."workflow_node_results"."waiting_reason" IS 'Why this node is currently waiting. NULL when the node is not waiting. Conventional values: dependency, condition_false, rate_limit, retry_backoff, human_input, external_callback, queued.';



COMMENT ON CONSTRAINT "workflow_node_results_status_check" ON "lenses"."workflow_node_results" IS 'Aligns with the engine state machine (Phase 1 §5). Terminal statuses: completed, failed, cancelled, skipped, timed_out, blocked, invalidated. Transient: pending, awaiting_dependency, queued, running, streaming, retrying.';



CREATE OR REPLACE VIEW "execution"."vw_workflow_run_timeline" AS
 SELECT "r"."id" AS "run_id",
    "r"."workflow_id",
    'run_started'::"text" AS "event_type",
    NULL::"uuid" AS "node_id",
    NULL::"uuid" AS "workflow_node_result_id",
    COALESCE("r"."started_at", "r"."created_at") AS "occurred_at",
    "r"."status",
    NULL::"jsonb" AS "output_data",
    NULL::"text" AS "error_message"
   FROM "lenses"."workflow_runs" "r"
UNION ALL
 SELECT "r"."id" AS "run_id",
    "r"."workflow_id",
    'run_completed'::"text" AS "event_type",
    NULL::"uuid" AS "node_id",
    NULL::"uuid" AS "workflow_node_result_id",
    "r"."completed_at" AS "occurred_at",
    "r"."status",
    NULL::"jsonb" AS "output_data",
    NULL::"text" AS "error_message"
   FROM "lenses"."workflow_runs" "r"
  WHERE ("r"."completed_at" IS NOT NULL)
UNION ALL
 SELECT "nr"."run_id",
    "r"."workflow_id",
    'node_started'::"text" AS "event_type",
    "nr"."node_id",
    "nr"."id" AS "workflow_node_result_id",
    "nr"."started_at" AS "occurred_at",
    "nr"."status",
    NULL::"jsonb" AS "output_data",
    NULL::"text" AS "error_message"
   FROM ("lenses"."workflow_node_results" "nr"
     JOIN "lenses"."workflow_runs" "r" ON (("r"."id" = "nr"."run_id")))
  WHERE ("nr"."started_at" IS NOT NULL)
UNION ALL
 SELECT "nr"."run_id",
    "r"."workflow_id",
    'node_completed'::"text" AS "event_type",
    "nr"."node_id",
    "nr"."id" AS "workflow_node_result_id",
    "nr"."completed_at" AS "occurred_at",
    "nr"."status",
    "nr"."output_data",
    "nr"."error_message"
   FROM ("lenses"."workflow_node_results" "nr"
     JOIN "lenses"."workflow_runs" "r" ON (("r"."id" = "nr"."run_id")))
  WHERE ("nr"."completed_at" IS NOT NULL);


ALTER VIEW "execution"."vw_workflow_run_timeline" OWNER TO "postgres";


COMMENT ON VIEW "execution"."vw_workflow_run_timeline" IS 'Chronological event stream for a workflow run: run_started, run_completed, node_started, node_completed. Consumed by the observability UI (Phase 6) to render Gantt-style timelines without client-side joins. Respects the underlying RLS on lenses.workflow_runs and lenses.workflow_node_results.';



CREATE TABLE IF NOT EXISTS "identity_gov"."reserved_namespaces" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "entry_kind" "text" NOT NULL,
    "value" "text" NOT NULL,
    "class" "text" NOT NULL,
    "deny_score" smallint DEFAULT 80 NOT NULL,
    "reason" "text",
    "source" "text" DEFAULT 'manifest'::"text" NOT NULL,
    "expires_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "reserved_namespaces_class_check" CHECK (("class" = ANY (ARRAY['system'::"text", 'security'::"text", 'provider'::"text", 'model'::"text", 'future'::"text", 'verified_only'::"text", 'restricted'::"text"]))),
    CONSTRAINT "reserved_namespaces_deny_score_range" CHECK ((("deny_score" >= 0) AND ("deny_score" <= 100))),
    CONSTRAINT "reserved_namespaces_kind_check" CHECK (("entry_kind" = ANY (ARRAY['exact'::"text", 'prefix'::"text", 'suffix'::"text", 'token'::"text", 'regex'::"text"]))),
    CONSTRAINT "reserved_namespaces_source_check" CHECK (("source" = ANY (ARRAY['canonical'::"text", 'manifest'::"text", 'ai_inferred'::"text"])))
);

ALTER TABLE ONLY "identity_gov"."reserved_namespaces" FORCE ROW LEVEL SECURITY;


ALTER TABLE "identity_gov"."reserved_namespaces" OWNER TO "postgres";


COMMENT ON TABLE "identity_gov"."reserved_namespaces" IS 'Registry of protected handles and patterns. entry_kind drives probe selection: exact=direct match, prefix/suffix=anchored substring, token=combinatorial composition guard, regex=arbitrary pattern for complex cases.';



COMMENT ON COLUMN "identity_gov"."reserved_namespaces"."entry_kind" IS 'exact: normalized handle must equal value. prefix: normalized handle must not start with value. suffix: normalized handle must not end with value. token: normalized handle must not contain value adjacent to a modifier (ai, bot, admin…). regex: normalized handle must not match value as a POSIX regex.';



COMMENT ON COLUMN "identity_gov"."reserved_namespaces"."value" IS 'Already-normalized form: lowercase, ASCII-only where possible. Regex entries use POSIX syntax.';



COMMENT ON COLUMN "identity_gov"."reserved_namespaces"."deny_score" IS 'Minimum risk score returned when this entry matches. system=100, security=95, provider=90, model=85, future=80, verified_only=70, restricted=50.';



COMMENT ON COLUMN "identity_gov"."reserved_namespaces"."expires_at" IS 'NULL = permanent. Set to now()+30d for ai_inferred entries during grace window.';



